def resource_path(name: str) -> Path:
    base = Path(getattr(sys, "_MEIPASS", Path(__file__).resolve().parent))
    return base / name

def app_runtime_dir() -> Path:
    if getattr(sys, "frozen", False):
        try:
            return Path(sys.executable).resolve().parent
        except Exception:
            pass
    return Path(__file__).resolve().parent


def default_app_config_dir() -> Path:
    appdata = os.getenv("APPDATA")
    if appdata:
        return Path(appdata) / APP_CONFIG_DIRNAME
    return Path.home() / f".{APP_CONFIG_DIRNAME.lower()}"


def _unique_paths(paths: Iterable[Path | str]) -> list[Path]:
    result: list[Path] = []
    seen: set[str] = set()
    for candidate in paths:
        try:
            resolved = Path(candidate).expanduser()
        except Exception:
            continue
        key = str(resolved).lower()
        if not key or key in seen:
            continue
        seen.add(key)
        result.append(resolved)
    return result


def _browser_candidate_paths(*parts: str) -> list[Path]:
    roots = []
    for env_name in ("PROGRAMFILES", "PROGRAMFILES(X86)", "LOCALAPPDATA"):
        value = str(os.getenv(env_name) or '').strip()
        if value:
            roots.append(Path(value))
    result: list[Path] = []
    seen: set[str] = set()
    for root in roots:
        try:
            candidate = root.joinpath(*parts)
        except Exception:
            continue
        key = str(candidate).lower()
        if key not in seen:
            seen.add(key)
            result.append(candidate)
    return result


def _existing_browser_path(candidates: Iterable[Path | str]) -> str:
    for candidate in candidates:
        try:
            resolved = Path(candidate).expanduser()
        except Exception:
            continue
        try:
            if resolved.exists() and resolved.is_file():
                return str(resolved)
        except Exception:
            continue
    return ""


def _embedded_tp_browser_paths() -> list[Path]:
    env_browser_exe = str(os.getenv("NISHIZUMI_TP_BROWSER_EXE") or '').strip()
    roots: list[Path | str] = []
    env_browser_dir = str(os.getenv("NISHIZUMI_TP_BROWSER_DIR") or '').strip()
    if env_browser_dir:
        roots.append(env_browser_dir)
    runtime_root = app_runtime_dir()
    resource_root = resource_path("")
    roots.extend(
        [
            runtime_root,
            resource_root,
            runtime_root / "embedded_browser",
            resource_root / "embedded_browser",
            runtime_root / "browser",
            resource_root / "browser",
            runtime_root / "chrome",
            resource_root / "chrome",
            runtime_root / "chrome_runtime",
            resource_root / "chrome_runtime",
            runtime_root / "chrome-portable",
            resource_root / "chrome-portable",
            runtime_root / "ms-playwright",
            resource_root / "ms-playwright",
        ]
    )
    relative_candidates = [
        ("chrome.exe",),
        ("chrome-win64", "chrome.exe"),
        ("chrome-win32", "chrome.exe"),
        ("chrome-win", "chrome.exe"),
        ("Chrome-bin", "chrome.exe"),
        ("bin", "chrome.exe"),
        ("Application", "chrome.exe"),
    ]
    results: list[Path] = []
    seen: set[str] = set()

    def add_candidate(candidate: Path | str) -> None:
        try:
            resolved = Path(candidate).expanduser()
        except Exception:
            return
        key = str(resolved).lower()
        if not key or key in seen:
            return
        try:
            if resolved.exists() and resolved.is_file():
                seen.add(key)
                results.append(resolved)
        except Exception:
            return

    if env_browser_exe:
        add_candidate(env_browser_exe)

    for root in _unique_paths(roots):
        for relative in relative_candidates:
            add_candidate(root.joinpath(*relative))
        try:
            for pattern in (
                "chromium-*/chrome-win*/chrome.exe",
                "ms-playwright/chromium-*/chrome-win*/chrome.exe",
                "playwright/chromium-*/chrome-win*/chrome.exe",
                "chrome-*/chrome.exe",
                "*/chrome-win*/chrome.exe",
            ):
                for candidate in sorted(root.glob(pattern)):
                    add_candidate(candidate)
        except Exception:
            continue
    return results


def _installed_tp_browser_candidates() -> list[dict[str, object]]:
    definitions: list[tuple[str, str, str | None, list[Path | str]]] = [
        (
            "chrome",
            "Google Chrome",
            "chrome",
            [
                *(_browser_candidate_paths("Google", "Chrome", "Application", "chrome.exe")),
                shutil.which("chrome"),
                shutil.which("chrome.exe"),
            ],
        ),
        (
            "msedge",
            "Microsoft Edge",
            "msedge",
            [
                *(_browser_candidate_paths("Microsoft", "Edge", "Application", "msedge.exe")),
                shutil.which("msedge"),
                shutil.which("msedge.exe"),
            ],
        ),
        (
            "brave",
            "Brave",
            None,
            [
                *(_browser_candidate_paths("BraveSoftware", "Brave-Browser", "Application", "brave.exe")),
                shutil.which("brave"),
                shutil.which("brave.exe"),
            ],
        ),
        (
            "chromium",
            "Chromium",
            "chromium",
            [
                *(_browser_candidate_paths("Chromium", "Application", "chrome.exe")),
                shutil.which("chromium"),
                shutil.which("chromium.exe"),
            ],
        ),
    ]
    candidates: list[dict[str, object]] = []
    for name, label, channel, paths in definitions:
        path = _existing_browser_path(paths)
        if not path and not channel:
            continue
        candidates.append(
            {
                "name": name,
                "label": label,
                "channel": channel,
                "path": path,
                "bundled": False,
            }
        )
    return candidates


def resolve_tp_browser_launch_target(browser_channel: str | None = "chrome") -> dict[str, object]:
    requested = str(browser_channel or "chrome").strip().lower() or "chrome"
    embedded_paths = _embedded_tp_browser_paths()
    if embedded_paths:
        embedded_path = str(embedded_paths[0])
        return {
            "available": True,
            "requested": requested,
            "name": "bundled",
            "label": "Bundled Chrome runtime",
            "path": embedded_path,
            "channel": None,
            "bundled": True,
            "launch_kwargs": {"executable_path": embedded_path},
        }

    installed = _installed_tp_browser_candidates()
    by_name = {str(item.get('name') or ''): item for item in installed}
    target = by_name.get(requested)
    if target is None:
        target = by_name.get('chrome')
    if target is None and installed:
        target = installed[0]
    if target is None:
        return {
            "available": False,
            "requested": requested,
            "name": "",
            "label": "",
            "path": "",
            "channel": None,
            "bundled": False,
            "launch_kwargs": {},
        }
    launch_kwargs: dict[str, object] = {}
    channel = str(target.get('channel') or '').strip()
    path = str(target.get('path') or '').strip()
    if path:
        launch_kwargs["executable_path"] = path
    elif channel:
        launch_kwargs["channel"] = channel
    return {
        "available": True,
        "requested": requested,
        "name": str(target.get('name') or ''),
        "label": str(target.get('label') or target.get('name') or "browser"),
        "path": path,
        "channel": channel or None,
        "bundled": False,
        "launch_kwargs": launch_kwargs,
    }


def launch_tp_persistent_context(
    browser_type,
    *,
    user_data_dir: str,
    browser_channel: str | None = "chrome",
    **kwargs,
):
    target = resolve_tp_browser_launch_target(browser_channel)
    if not bool(target.get('available')):
        raise RuntimeError(
            "No bundled or installed Chromium-based browser runtime was found. Put a portable browser in embedded_browser or install Google Chrome/Edge, then try again."
        )
    launch_kwargs = dict(kwargs)
    launch_kwargs.update(dict(target.get('launch_kwargs') or {}))
    context = browser_type.launch_persistent_context(user_data_dir=user_data_dir, **launch_kwargs)
    return context, target



def canonicalize_car_directory(value: str | None) -> str:
    text = str(value or '').strip()
    if not text:
        return ""
    text = text.replace("/", "\\")
    text = re.sub(r"\\+", r"\\", text)
    if "\\" in text:
        parts = [part.strip() for part in text.split("\\") if part.strip()]
        return "\\".join(parts)
    if " " in text:
        parts = [part.strip() for part in text.split() if part.strip()]
        if len(parts) >= 2:
            return "\\".join(parts)
    return text


