class TextureReloadDebouncer:
    def __init__(
        self,
        reader: IracingSdkReader | None,
        session: Session | None,
        debounce_seconds: float = 0.2,
    ) -> None:
        self.reader = reader
        self.session = session
        self.debounce_seconds = max(0.0, float(debounce_seconds))
        self._lock = threading.Lock()
        self._timers: dict[int, threading.Timer] = {}
        self._closed = False

    def _resolve_car_indices(self, saved_items: list[SavedFile]) -> list[int]:
        if self.session is None:
            return []
        seen: set[int] = set()
        result: list[int] = []
        for item in saved_items:
            user = _find_session_user_for_download_id(self.session, item.download_id)
            if user is None or user.car_idx is None:
                continue
            try:
                car_idx = int(user.car_idx)
            except Exception:
                continue
            if car_idx < 0 or car_idx in seen:
                continue
            seen.add(car_idx)
            result.append(car_idx)
        return result

    def _fire(self, car_idx: int) -> None:
        with self._lock:
            self._timers.pop(int(car_idx), None)
            if self._closed:
                return
        try:
            trigger_texture_reload(self.reader, car_idx=int(car_idx))
        except Exception:
            logging.debug("Debounced texture reload failed", exc_info=True)

    def request_saved_items(self, saved_items: list[SavedFile]) -> bool:
        if self.reader is None or self.session is None or not saved_items:
            return False
        ok_to_reload = _read_ok_to_reload_textures(self.reader)
        if ok_to_reload is False:
            return False
        requested_any = False
        for car_idx in self._resolve_car_indices(saved_items):
            timer = threading.Timer(self.debounce_seconds, self._fire, args=(int(car_idx),))
            timer.daemon = True
            with self._lock:
                if self._closed:
                    timer.cancel()
                    break
                previous = self._timers.get(int(car_idx))
                self._timers[int(car_idx)] = timer
            if previous is not None:
                previous.cancel()
            timer.start()
            requested_any = True
        return requested_any

    def flush(self, force: bool = True) -> None:
        with self._lock:
            timers = list(self._timers.items())
            self._timers.clear()
            self._closed = True
        for _car_idx, timer in timers:
            try:
                timer.cancel()
            except Exception:
                pass
        if force:
            fired: set[int] = set()
            for car_idx, _timer in timers:
                if int(car_idx) in fired:
                    continue
                fired.add(int(car_idx))
                try:
                    trigger_texture_reload(self.reader, car_idx=int(car_idx))
                except Exception:
                    logging.debug("Flushed debounced texture reload failed", exc_info=True)


