def session_target_key_from_download_id(download_id: DownloadId) -> tuple[str, int, str]:
    return ("team" if download_id.is_team_paint else "user", int(download_id.user_id), download_id.directory.lower())

def _session_driver_sort_number(number: str) -> tuple[int, str]:
    match = re.search(r"(\d+)", str(number or ''))
    if match:
        return (0, f"{int(match.group(1)):08d}")
    text = str(number or '').strip()
    return (1, text.lower() or "zzzz")

def _session_status_meta(status_code: str) -> tuple[str, str]:
    mapping = {
        "override": ("*", "Override"),
        "queued": ("…", "Queued"),
        "downloading": ("↓", "Downloading"),
        "downloaded": ("✓", "Downloaded"),
        "replay": ("▶", "Replay pack"),
        "fallback": ("↺", "Fallback"),
        "fallback_local": ("↺", "FALLBACK LOCAL"),
        "fallback_online": ("↺", "FALLBACK ONLINE"),
        "missing": ("✕", "Missing"),
        "skipped": ("○", "Skipped"),
    }
    return mapping.get(status_code, ("?", status_code.title()))

_SESSION_ASSET_SLOTS: tuple[str, ...] = ("car", "suit", "helmet")

def _session_asset_slot_for_paint_type(paint_type: PaintType | str | None) -> str | None:
    try:
        normalized = paint_type if isinstance(paint_type, PaintType) else PaintType(str(paint_type or '').strip())
    except Exception:
        return None
    if normalized in {PaintType.CAR, PaintType.CAR_DECAL, PaintType.CAR_NUMBER, PaintType.CAR_SPEC}:
        return "car"
    if normalized is PaintType.SUIT:
        return "suit"
    if normalized is PaintType.HELMET:
        return "helmet"
    return None

def _session_make_asset_statuses(default_code: str = "queued") -> dict[str, str]:
    return {slot: str(default_code or 'queued') for slot in _SESSION_ASSET_SLOTS}

def _session_normalize_asset_statuses(value: object, default_code: str = "queued") -> dict[str, str]:
    normalized = _session_make_asset_statuses(default_code)
    if isinstance(value, dict):
        for slot in _SESSION_ASSET_SLOTS:
            raw = value.get(slot)
            if raw is not None:
                normalized[slot] = str(raw or default_code or 'queued')
        return normalized
    code = str(value or default_code or 'queued')
    for slot in _SESSION_ASSET_SLOTS:
        normalized[slot] = code
    return normalized

def _session_overall_status_code(asset_statuses: dict[str, str]) -> str:
    car_code = str(asset_statuses.get("car") or "missing")
    if car_code not in {"queued", "missing", "skipped"}:
        return car_code
    seen_codes = {str(code or "missing") for code in asset_statuses.values()}
    for preferred in ("downloading", "override", "replay", "fallback_online", "fallback_local", "fallback", "downloaded", "missing", "skipped", "queued"):
        if preferred in seen_codes:
            return preferred
    return car_code or "queued"

def build_session_driver_rows(
    session: Session | None,
    status_by_key: dict[tuple[str, int, str], str | dict[str, str]] | None = None,
) -> list[SessionDriverSnapshot]:
    if session is None:
        return []
    status_by_key = status_by_key or {}
    rows: list[SessionDriverSnapshot] = []
    for user in session.users:
        key = user.effective_target_key()
        asset_statuses = _session_normalize_asset_statuses(status_by_key.get(key, "queued"), default_code="queued")
        status_code = _session_overall_status_code(asset_statuses)
        icon, label = _session_status_meta(status_code)
        car_icon, car_label = _session_status_meta(asset_statuses["car"])
        suit_icon, suit_label = _session_status_meta(asset_statuses["suit"])
        helmet_icon, helmet_label = _session_status_meta(asset_statuses["helmet"])
        rows.append(
            SessionDriverSnapshot(
                target_kind=key[0],
                target_id=int(key[1]),
                iracing_id=int(user.user_id),
                directory=user.directory,
                display_name=user.display_name or (f"AI {user.user_id}" if user.is_ai else f"User {user.user_id}"),
                number=user.number or "0",
                is_ai=bool(user.is_ai),
                irating=user.irating,
                license_label=user.license_label or "-",
                safety_rating=user.safety_rating or "-",
                status_code=status_code,
                status_text=label,
                status_icon=icon,
                car_status_code=asset_statuses["car"],
                car_status_text=car_label,
                car_status_icon=car_icon,
                suit_status_code=asset_statuses["suit"],
                suit_status_text=suit_label,
                suit_status_icon=suit_icon,
                helmet_status_code=asset_statuses["helmet"],
                helmet_status_text=helmet_label,
                helmet_status_icon=helmet_icon,
            )
        )
    rows.sort(key=lambda row: (_session_driver_sort_number(row.number), row.display_name.lower(), row.directory.lower(), row.target_id))
    return rows


def _find_session_user_for_download_id(session: Session | None, download_id: DownloadId) -> SessionUser | None:
    if session is None:
        return None
    wanted_kind = "team" if download_id.is_team_paint else "user"
    wanted_directory = str(download_id.directory or '').lower()
    wanted_id = int(download_id.user_id)
    slot = _session_asset_slot_for_paint_type(download_id.paint_type)
    for user in session.users:
        target_kind, target_id, _target_directory = user.effective_target_key()
        if target_kind != wanted_kind or target_id != wanted_id:
            continue
        if slot in {"helmet", "suit"}:
            return user
        if str(user.directory or '').lower() == wanted_directory:
            return user
    return None


def _session_status_key_for_download_id(session: Session | None, download_id: DownloadId) -> tuple[str, int, str]:
    matched_user = _find_session_user_for_download_id(session, download_id)
    if matched_user is not None:
        return matched_user.effective_target_key()
    return session_target_key_from_download_id(download_id)


def _tp_showroom_slug_from_title(title: object) -> str:
    value = str(title or "").strip()
    if not value:
        return ""
    generic = value.lower()
    if generic in {"previously selected scheme", "collection paint"} or re.fullmatch(r"(?:manual\s+)?scheme\s+\d+", generic):
        return ""
    value = urllib.parse.unquote(value)
    value = unicodedata.normalize("NFKD", value).encode("ascii", "ignore").decode("ascii")
    value = re.sub(r"[^A-Za-z0-9]+", "-", value).strip("-")
    return value[:120].strip("-")


def _normalize_tp_showroom_link(link: object, title: object = "") -> str:
    value = str(link or "").strip()
    if not value:
        return ""
    if value.startswith("/"):
        value = f"https://www.tradingpaints.com{value}"
    match = re.search(r"(https?://(?:www\.)?tradingpaints\.com/showroom/view/(\d+))(?:/([^?#]+))?", value, flags=re.IGNORECASE)
    if not match:
        return value if "/showroom/view/" in value else ""
    base = match.group(1)
    suffix = str(match.group(3) or "").strip("/")
    if suffix:
        return f"{base}/{suffix}"
    slug = _tp_showroom_slug_from_title(title)
    return f"{base}/{slug}" if slug else ""


def _tp_showroom_url_for_scheme_id(scheme_id: object, title: object = "") -> str:
    value = str(scheme_id or "").strip()
    if value and value.isdigit():
        slug = _tp_showroom_slug_from_title(title)
        return f"https://www.tradingpaints.com/showroom/view/{value}/{slug}" if slug else ""
    return ""


def _tp_profile_url_for_user_id(user_id: object) -> str:
    value = normalize_tp_member_id(user_id)
    return f"https://www.tradingpaints.com/profile/{value}" if value > 0 else ""


def _download_id_with_tp_source(
    download_id: DownloadId,
    *,
    scheme_id: object = "",
    title: object = "",
    source_link: object = "",
    source: object = "",
) -> DownloadId:
    normalized_scheme_id = str(scheme_id or "").strip()
    normalized_title = str(title or "").strip()
    normalized_link = _normalize_tp_showroom_link(source_link, normalized_title) or _tp_showroom_url_for_scheme_id(normalized_scheme_id, normalized_title)
    return replace(
        download_id,
        tp_scheme_id=normalized_scheme_id or str(getattr(download_id, "tp_scheme_id", "") or "").strip(),
        tp_title=normalized_title or str(getattr(download_id, "tp_title", "") or "").strip(),
        tp_source_link=normalized_link or str(getattr(download_id, "tp_source_link", "") or "").strip(),
        tp_source=str(source or "").strip() or str(getattr(download_id, "tp_source", "") or "").strip(),
    )


def _annotate_download_files_with_tp_source(
    items: list[DownloadFile],
    *,
    scheme_id: object = "",
    title: object = "",
    source_link: object = "",
    source: object = "",
) -> list[DownloadFile]:
    return [
        replace(
            item,
            download_id=_download_id_with_tp_source(
                item.download_id,
                scheme_id=scheme_id,
                title=title,
                source_link=source_link,
                source=source,
            ),
        )
        for item in items
    ]


def _annotate_saved_files_with_tp_source(
    items: list[SavedFile],
    *,
    scheme_id: object = "",
    title: object = "",
    source_link: object = "",
    source: object = "",
) -> list[SavedFile]:
    return [
        replace(
            item,
            download_id=_download_id_with_tp_source(
                item.download_id,
                scheme_id=scheme_id,
                title=title,
                source_link=source_link,
                source=source,
            ),
        )
        for item in items
    ]


def _apply_saved_file_statuses(
    session: Session | None,
    status_by_key: dict[tuple[str, int, str], dict[str, str]],
    saved_items: list[SavedFile],
    status_code: str,
) -> None:
    for item in saved_items:
        key = _session_status_key_for_download_id(session, item.download_id)
        asset_statuses = _session_normalize_asset_statuses(status_by_key.get(key, "missing"), default_code="missing")
        slot = _session_asset_slot_for_paint_type(item.download_id.paint_type)
        if slot is None:
            continue
        asset_statuses[slot] = str(status_code or "downloaded")
        status_by_key[key] = asset_statuses


def _try_incremental_texture_reload(
    reader: IracingSdkReader | None,
    session: Session | None,
    saved_items: list[SavedFile],
) -> bool:
    if reader is None or session is None or not saved_items:
        return False
    ok_to_reload = _read_ok_to_reload_textures(reader)
    if ok_to_reload is False:
        return False
    triggered_any = False
    seen_car_indices: set[int] = set()
    for item in saved_items:
        user = _find_session_user_for_download_id(session, item.download_id)
        if user is None or user.car_idx is None:
            continue
        car_idx = int(user.car_idx)
        if car_idx < 0 or car_idx in seen_car_indices:
            continue
        seen_car_indices.add(car_idx)
        if trigger_texture_reload(reader, car_idx=car_idx):
            triggered_any = True
    return triggered_any


def _session_user_map(session: Session | None) -> dict[tuple[str, int, str], SessionUser]:
    if session is None:
        return {}
    return {user.effective_target_key(): user for user in session.users}


def _session_row_key(row: SessionDriverSnapshot) -> tuple[str, int, str]:
    return (str(row.target_kind or 'user'), int(row.target_id), str(row.directory or '').lower())


def merge_session_driver_rows(
    session: Session,
    previous_rows: list[SessionDriverSnapshot] | None,
    updated_rows: list[SessionDriverSnapshot] | None,
) -> list[SessionDriverSnapshot]:
    previous_map = {_session_row_key(row): row for row in (previous_rows or [])}
    updated_map = {_session_row_key(row): row for row in (updated_rows or [])}
    merged: list[SessionDriverSnapshot] = []
    for base_row in build_session_driver_rows(session):
        key = _session_row_key(base_row)
        merged.append(updated_map.get(key) or previous_map.get(key) or base_row)
    return merged

def _session_statuses_from_rows(rows: list[SessionDriverSnapshot] | None) -> dict[tuple[str, int, str], dict[str, str]]:
    statuses: dict[tuple[str, int, str], dict[str, str]] = {}
    for row in rows or []:
        statuses[_session_row_key(row)] = {
            "car": str(row.car_status_code or "missing"),
            "suit": str(row.suit_status_code or "missing"),
            "helmet": str(row.helmet_status_code or "missing"),
        }
    return statuses


def merge_saved_files(existing: list[SavedFile], updates: list[SavedFile]) -> list[SavedFile]:
    merged: dict[tuple[bool, int, str, str, bool, str], SavedFile] = {}
    for item in existing:
        key = (
            bool(item.download_id.is_team_paint),
            int(item.download_id.user_id),
            str(item.download_id.directory or '').lower(),
            item.download_id.paint_type.value,
            bool(getattr(item.download_id, 'is_superspeedway_variant', False)),
            str(item.file_path).lower(),
        )
        merged[key] = item
    for item in updates:
        key = (
            bool(item.download_id.is_team_paint),
            int(item.download_id.user_id),
            str(item.download_id.directory or '').lower(),
            item.download_id.paint_type.value,
            bool(getattr(item.download_id, 'is_superspeedway_variant', False)),
            str(item.file_path).lower(),
        )
        merged[key] = item
    return sorted(
        merged.values(),
        key=lambda s: (
            s.download_id.is_team_paint,
            s.download_id.user_id,
            s.download_id.directory.lower(),
            s.download_id.paint_type.value,
            str(s.file_path).lower(),
        ),
    )

def build_session_stage_statuses(
    session: Session,
    wanted_items: list[DownloadFile],
    sync_my_livery_from_server: bool,
) -> dict[tuple[str, int, str], dict[str, str]]:
    wanted_slots_by_key: dict[tuple[str, int, str], set[str]] = {}
    for item in wanted_items:
        slot = _session_asset_slot_for_paint_type(item.download_id.paint_type)
        if slot is None:
            continue
        wanted_slots_by_key.setdefault(_session_status_key_for_download_id(session, item.download_id), set()).add(slot)
    statuses: dict[tuple[str, int, str], dict[str, str]] = {}
    for user in session.users:
        key = user.effective_target_key()
        local_team_match = session_user_uses_team_target(user) and session.local_team_id is not None and user.team_id == session.local_team_id
        local_user_match = session.local_user_id is not None and user.user_id == session.local_user_id
        if not sync_my_livery_from_server and (local_team_match or local_user_match):
            statuses[key] = _session_make_asset_statuses("skipped")
            continue
        asset_statuses = _session_make_asset_statuses("missing")
        for slot in wanted_slots_by_key.get(key, set()):
            asset_statuses[slot] = "downloading"
        statuses[key] = asset_statuses
    return statuses

def build_session_final_statuses(
    session: Session,
    wanted_items: list[DownloadFile],
    server_saved: list[SavedFile],
    fallback_saved: list[SavedFile],
    sync_my_livery_from_server: bool,
    replay_mode: bool = False,
    fallback_mode: str = "local",
) -> dict[tuple[str, int, str], dict[str, str]]:
    wanted_slots_by_key: dict[tuple[str, int, str], set[str]] = {}
    server_slots_by_key: dict[tuple[str, int, str], set[str]] = {}
    fallback_slots_by_key: dict[tuple[str, int, str], set[str]] = {}
    override_slots_by_key: dict[tuple[str, int, str], set[str]] = {}
    for item in wanted_items:
        slot = _session_asset_slot_for_paint_type(item.download_id.paint_type)
        if slot is not None:
            wanted_slots_by_key.setdefault(_session_status_key_for_download_id(session, item.download_id), set()).add(slot)
    for item in server_saved:
        slot = _session_asset_slot_for_paint_type(item.download_id.paint_type)
        if slot is not None:
            key = _session_status_key_for_download_id(session, item.download_id)
            if bool(getattr(item.download_id, "preserve_on_cleanup", False)):
                override_slots_by_key.setdefault(key, set()).add(slot)
            else:
                server_slots_by_key.setdefault(key, set()).add(slot)
    for item in fallback_saved:
        slot = _session_asset_slot_for_paint_type(item.download_id.paint_type)
        if slot is not None:
            key = _session_status_key_for_download_id(session, item.download_id)
            if bool(getattr(item.download_id, "preserve_on_cleanup", False)):
                override_slots_by_key.setdefault(key, set()).add(slot)
            else:
                fallback_slots_by_key.setdefault(key, set()).add(slot)
    normalized_fallback_mode = str(fallback_mode or "local").strip().lower()
    fallback_code = "fallback_online" if normalized_fallback_mode == "online" else "fallback_local"
    statuses: dict[tuple[str, int, str], dict[str, str]] = {}
    for user in session.users:
        key = user.effective_target_key()
        local_team_match = session_user_uses_team_target(user) and session.local_team_id is not None and user.team_id == session.local_team_id
        local_user_match = session.local_user_id is not None and user.user_id == session.local_user_id
        if not sync_my_livery_from_server and (local_team_match or local_user_match):
            statuses[key] = _session_make_asset_statuses("skipped")
            continue
        asset_statuses = _session_make_asset_statuses("missing")
        for slot in wanted_slots_by_key.get(key, set()):
            asset_statuses[slot] = "missing"
        for slot in server_slots_by_key.get(key, set()):
            asset_statuses[slot] = "replay" if replay_mode else "downloaded"
        for slot in fallback_slots_by_key.get(key, set()):
            asset_statuses[slot] = fallback_code
        for slot in override_slots_by_key.get(key, set()):
            asset_statuses[slot] = "override"
        statuses[key] = asset_statuses
    return statuses
class TransferBatchMonitor:
    def __init__(self, stage_name: str, requested_workers: int, total_items: int) -> None:
        self.stage_name = stage_name
        self.requested_workers = max(0, int(requested_workers))
        self.total_items = max(0, int(total_items))
        self._lock = threading.Lock()
        self._active_items = 0
        self._peak_active_items = 0
        self._completed_items = 0
        self._failed_items = 0
        self._total_elapsed_success = 0.0
        self._total_bytes = 0
        self._first_started_at: float | None = None
        self._last_finished_at: float | None = None
    def begin(self) -> float:
        started_at = time.monotonic()
        with self._lock:
            self._active_items += 1
            if self._active_items > self._peak_active_items:
                self._peak_active_items = self._active_items
            if self._first_started_at is None:
                self._first_started_at = started_at
        return started_at
    def end(self, started_at: float, success: bool, bytes_count: int = 0) -> None:
        finished_at = time.monotonic()
        elapsed = max(0.0, finished_at - started_at)
        with self._lock:
            if self._active_items > 0:
                self._active_items -= 1
            self._last_finished_at = finished_at
            if success:
                self._completed_items += 1
                self._total_elapsed_success += elapsed
                self._total_bytes += max(0, int(bytes_count))
            else:
                self._failed_items += 1
    def snapshot(self) -> StageTransferStats:
        with self._lock:
            first_started_at = self._first_started_at
            last_finished_at = self._last_finished_at
            completed_items = self._completed_items
            stage_seconds = 0.0
            if first_started_at is not None and last_finished_at is not None:
                stage_seconds = max(0.0, last_finished_at - first_started_at)
            average_item_seconds = (
                self._total_elapsed_success / completed_items if completed_items > 0 else 0.0
            )
            files_per_second = completed_items / stage_seconds if stage_seconds > 0 else 0.0
            megabits_per_second = (
                (self._total_bytes * 8.0) / stage_seconds / 1_000_000.0 if stage_seconds > 0 else 0.0
            )
            effective_parallelism = files_per_second * average_item_seconds if completed_items > 0 else 0.0
            return StageTransferStats(
                stage_name=self.stage_name,
                requested_workers=self.requested_workers,
                total_items=self.total_items,
                completed_items=completed_items,
                failed_items=self._failed_items,
                peak_active_items=self._peak_active_items,
                stage_seconds=stage_seconds,
                average_item_seconds=average_item_seconds,
                files_per_second=files_per_second,
                megabits_per_second=megabits_per_second,
                total_bytes=self._total_bytes,
                effective_parallelism=effective_parallelism,
            )
_THREAD_LOCAL = threading.local()
def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description=(
            "Nishizumi Paints: watch iRacing sessions, fetch Trading Paints assets, "
            "and install them in your local iRacing paint folder."
        )
    )
    parser.add_argument(
        "--session-yaml",
        default=None,
        help="Path to iRacing session_info YAML dump file.",
    )
    parser.add_argument(
        "--iracing-sdk",
        action="store_true",
        help=(
            "Read live session data from the iRacing SDK instead of a file. "
            "If --session-yaml is omitted, SDK mode is used by default."
        ),
    )
    parser.add_argument(
        "--watch",
        action="store_true",
        help="Keep running and process each new session ID in the YAML file.",
    )
    parser.add_argument(
        "--poll-seconds",
        type=float,
        default=0.8,
        help="Polling interval in seconds when --watch is enabled.",
    )
    parser.add_argument(
        "--paints-dir",
        default=None,
        help="Override iRacing paint directory (default: ~/Documents/iRacing/paint).",
    )
    parser.add_argument(
        "--temp-dir",
        default=None,
        help="Override temp folder (default: system temp + /NishizumiPaints).",
    )
    parser.add_argument(
        "--keep-session-paints",
        action="store_true",
        help="Do not delete old session paints when session changes/exits.",
    )
    parser.add_argument(
        "--max-concurrent-manifests",
        type=int,
        default=10,
        help=(
            "Upper cap for Trading Paints manifest requests. "
            "Auto-tuning chooses a value up to this cap (default: 10)."
        ),
    )
    parser.add_argument(
        "--max-concurrent-downloads",
        type=int,
        default=8,
        help=(
            "Upper cap for paint downloads. "
            "Auto-tuning chooses a value up to this cap (default: 8)."
        ),
    )
    parser.add_argument(
        "--retries",
        type=int,
        default=3,
        help="How many attempts to make for manifest/download requests (default: 3).",
    )
    parser.add_argument(
        "--retry-backoff-seconds",
        type=float,
        default=1.0,
        help="Base retry backoff in seconds. Attempts wait 1x, 2x, 4x... (default: 1.0).",
    )
    launch_group = parser.add_mutually_exclusive_group()
    launch_group.add_argument(
        "--gui",
        action="store_true",
        help="Force the built-in GUI even if a launch preference is saved.",
    )
    launch_group.add_argument(
        "--nogui",
        action="store_true",
        help="Run without the built-in UI.",
    )
    parser.add_argument(
        "--managed-headless",
        action="store_true",
        help=argparse.SUPPRESS,
    )
    parser.add_argument(
        "--autostart-launched",
        action="store_true",
        help=argparse.SUPPRESS,
    )
    parser.add_argument(
        "-v", "--verbose", action="store_true", help="Enable verbose debug logs."
    )
    return parser.parse_args()
def setup_logging(verbose: bool) -> None:
    level = logging.DEBUG if verbose else logging.INFO
    logging.basicConfig(
        level=level,
        format="%(asctime)s %(levelname)s %(message)s",
        datefmt="%Y-%m-%d %H:%M:%S",
        force=True,
    )
def _windows_documents_root() -> Path | None:
    if sys.platform != "win32":
        return None
    try:
        import winreg
        key = winreg.OpenKey(
            winreg.HKEY_CURRENT_USER,
            r"Software\Microsoft\Windows\CurrentVersion\Explorer\User Shell Folders",
        )
        raw_value, _value_type = winreg.QueryValueEx(key, "Personal")
        expanded = os.path.expandvars(str(raw_value or "").strip())
        if expanded:
            return Path(expanded).expanduser()
    except Exception:
        logging.debug("Could not read Windows Documents folder from User Shell Folders", exc_info=True)
    try:
        return Path.home() / "Documents"
    except Exception:
        return None


def _candidate_documents_roots() -> list[Path]:
    roots: list[Path] = []
    seen: set[str] = set()
    for candidate in (_windows_documents_root(), Path.home() / "Documents"):
        if candidate is None:
            continue
        try:
            resolved = candidate.expanduser()
        except Exception:
            continue
        key = str(resolved).lower()
        if key in seen:
            continue
        seen.add(key)
        roots.append(resolved)
    return roots


def _looks_like_iracing_documents_dir(value: str | Path | None) -> bool:
    normalized = normalize_optional_path(value)
    if not normalized:
        return False
    candidate = Path(normalized)
    try:
        if not candidate.exists() or not candidate.is_dir():
            return False
    except Exception:
        return False
    try:
        child_names = {child.name.strip().lower() for child in candidate.iterdir() if child.is_dir()}
    except Exception:
        child_names = set()
    folder_name = candidate.name.strip().lower()
    if folder_name == "iracing" and (not child_names or bool(child_names & {"paint", "replay", "airosters"})):
        return True
    if child_names & {"paint", "replay", "airosters"}:
        return True
    return False


def auto_detect_iracing_documents_dir(search_depth: int = 3) -> Path | None:
    direct_candidates: list[Path] = []
    seen: set[str] = set()
    for root in _candidate_documents_roots():
        for candidate in (root / "iRacing", root / "IRacing", root / "iracing"):
            key = str(candidate).lower()
            if key in seen:
                continue
            seen.add(key)
            direct_candidates.append(candidate)
    for candidate in direct_candidates:
        if _looks_like_iracing_documents_dir(candidate):
            return candidate
    max_depth = max(1, int(search_depth or 1))
    for root in _candidate_documents_roots():
        try:
            if not root.exists() or not root.is_dir():
                continue
        except Exception:
            continue
        try:
            for current, dirs, _files in os.walk(root):
                current_path = Path(current)
                try:
                    depth = len(current_path.relative_to(root).parts)
                except Exception:
                    depth = max_depth + 1
                if depth > max_depth:
                    dirs[:] = []
                    continue
                if current_path.name.strip().lower() == "iracing" and _looks_like_iracing_documents_dir(current_path):
                    return current_path
                if depth >= max_depth:
                    dirs[:] = []
        except Exception:
            logging.debug("Could not scan Documents root for iRacing folder: %s", root, exc_info=True)
    return None


def default_iracing_documents_dir() -> Path:
    detected = auto_detect_iracing_documents_dir()
    if detected is not None:
        return detected
    docs_root = _windows_documents_root() or (Path.home() / "Documents")
    return docs_root / "iRacing"

def normalize_optional_path(value: str | Path | None) -> str:
    text = str(value or '').strip().strip('"')
    if not text:
        return ""
    try:
        return str(Path(text).expanduser())
    except Exception:
        return text

def resolve_iracing_documents_dir(value: AppConfig | str | Path | None = None) -> Path:
    candidate = ""
    if value is not None:
        if hasattr(value, "iracing_documents_dir"):
            candidate = normalize_optional_path(getattr(value, "iracing_documents_dir", ""))
        else:
            candidate = normalize_optional_path(value)
    if not candidate:
        return default_iracing_documents_dir()
    resolved = Path(candidate)
    folder_name = resolved.name.strip().lower()
    if folder_name in {"paint", "replay", "airosters"} and resolved.parent != resolved:
        return resolved.parent
    return resolved

def default_paints_dir(value: AppConfig | str | Path | None = None) -> Path:
    return resolve_iracing_documents_dir(value) / "paint"
def default_ai_rosters_dir(value: AppConfig | str | Path | None = None) -> Path:
    return resolve_iracing_documents_dir(value) / "airosters"
def default_ai_livery_dir() -> Path:
    appdata = os.getenv("APPDATA")
    if appdata:
        return Path(appdata) / "Nishizumi-Paints" / "AiLiveries"
    return Path.home() / "AppData" / "Roaming" / "Nishizumi-Paints" / "AiLiveries"
def default_random_pool_dir() -> Path:
    appdata = os.getenv("APPDATA")
    if appdata:
        return Path(appdata) / "Nishizumi-Paints" / "RandomPool"
    return Path.home() / "AppData" / "Roaming" / "Nishizumi-Paints" / "RandomPool"
