def parse_tp_collection_ids_from_text(value: object) -> list[str]:
    text = str(value or "").strip()
    if not text:
        return []
    collection_ids: list[str] = []
    seen: set[str] = set()
    for token in re.split(r"[\s,;]+", text):
        token = token.strip().strip('"\'')
        if not token:
            continue
        match = (
            re.search(r"/collections/view/(\d+)", token, flags=re.IGNORECASE)
            or re.search(r"[?&]id=(\d+)", token, flags=re.IGNORECASE)
        )
        candidate = match.group(1) if match else (token if token.isdigit() else "")
        if not candidate:
            continue
        candidate = candidate.lstrip("0") or "0"
        if candidate == "0" or candidate in seen:
            continue
        seen.add(candidate)
        collection_ids.append(candidate)
    return collection_ids

def normalize_tp_collection_pool_sources_text(value: object) -> str:
    return ", ".join(parse_tp_collection_ids_from_text(value))

