def _tp_retarget_manifest_items_for_user(session: Session, user: SessionUser, items: list[DownloadFile]) -> list[DownloadFile]:
    target_is_team = session_user_uses_team_target(user)
    target_id = int(user.team_id) if target_is_team else int(user.user_id)
    result: list[DownloadFile] = []
    for item in _select_manifest_variants_for_session(session, items):
        if item.download_id.paint_type not in {PaintType.CAR, PaintType.CAR_NUMBER, PaintType.CAR_SPEC, PaintType.CAR_DECAL}:
            continue
        result.append(
            DownloadFile(
                download_id=replace(
                    item.download_id,
                    user_id=target_id,
                    directory=user.directory,
                    is_team_paint=target_is_team,
                    is_superspeedway_variant=item.download_id.is_superspeedway_variant,
                ),
                url=item.url,
                ai_roster_optional_filename=item.ai_roster_optional_filename,
                ai_roster_dir=item.ai_roster_dir,
            )
        )
    return result

def _tp_retarget_manifest_accessory_items_for_user(user: SessionUser, items: list[DownloadFile], accessory_type: PaintType) -> list[DownloadFile]:
    target_is_team = session_user_uses_team_target(user)
    target_id = int(user.team_id) if target_is_team else int(user.user_id)
    result: list[DownloadFile] = []
    for item in _tp_latest_manifest_items_by_paint_type(items):
        if item.download_id.paint_type is not accessory_type:
            continue
        result.append(
            DownloadFile(
                download_id=replace(
                    item.download_id,
                    user_id=target_id,
                    directory=user.directory,
                    paint_type=accessory_type,
                    is_team_paint=target_is_team,
                    is_superspeedway_variant=False,
                ),
                url=item.url,
            )
        )
    return result


def _tp_asset_unavailable_status(url: str, request_timeout: float = 3.0) -> int | None:
    if not str(url or '').strip():
        return None
    try:
        session = get_thread_http_session()
        with session.get(
            url,
            timeout=(2.5, max(2.5, float(request_timeout))),
            stream=True,
            headers={"Range": "bytes=0-0", "User-Agent": APP_USER_AGENT},
        ) as response:
            status_code = int(response.status_code or 0)
            if status_code in TP_UNAVAILABLE_DOWNLOAD_STATUS_CODES:
                return status_code
    except requests.RequestException as exc:
        response = getattr(exc, "response", None)
        status_code = getattr(response, "status_code", None)
        if isinstance(status_code, int) and status_code in TP_UNAVAILABLE_DOWNLOAD_STATUS_CODES:
            return status_code
    return None


def _tp_required_manifest_assets_unavailable(
    items: Iterable[DownloadFile],
    required_paint_types: set[PaintType],
) -> tuple[bool, str]:
    required_items = [
        item
        for item in _tp_latest_manifest_items_by_paint_type(items)
        if item.download_id.paint_type in required_paint_types
    ]
    for item in required_items:
        status_code = _tp_asset_unavailable_status(item.url)
        if status_code is not None:
            return True, f"{item.download_id.paint_type.value} URL returned HTTP {status_code}"
    return False, ""


def restore_tp_showroom_scheme(
    *,
    directory: str,
    scheme_id: str,
    showroom_link: str = "",
    mapping_path: Path | None,
    profile_dir: Path,
    manifest_member_id: int | None = None,
    baseline_manifest_urls: dict[str, str] | None = None,
    retries: int = 3,
    retry_backoff_seconds: float = 1.5,
    browser_channel: str = "chrome",
    log: Callable[[str], None] | None = None,
    shared_context=None,
    shared_page=None,
    shared_auth_state: dict[str, object] | None = None,
) -> tuple[bool, str]:
    def write(msg: str) -> None:
        if log:
            log(msg)

    target_scheme_id = str(scheme_id or '').strip()
    target_showroom_link = str(showroom_link or '').strip()
    if not target_scheme_id:
        return False, f"No original Trading Paints scheme id was captured for '{directory}'."
    raw_directory = str(directory or '').strip()
    directory_key = canonicalize_car_directory(raw_directory).lower()
    mapping_doc = _load_tp_showroom_mapping(mapping_path)
    cars_map = (mapping_doc.get('cars') or {})
    entry = None
    for candidate in _tp_directory_candidate_keys(directory_key):
        possible = cars_map.get(candidate)
        if isinstance(possible, dict):
            entry = possible
            break
    if not isinstance(entry, dict):
        return False, f"No Trading Paints showroom mapping exists for '{raw_directory or directory_key}'."
    if sync_playwright is None:
        return False, "Playwright is not installed in this build."
    mid = int(entry["mid"])
    category = str(entry.get('category') or "Road")
    slug = str(entry.get('slug') or f"car-{mid}")
    profile_dir.mkdir(parents=True, exist_ok=True)
    owned_context = shared_context is None or shared_page is None
    playwright_manager = None
    context = shared_context
    page = shared_page
    try:
        if owned_context:
            playwright_manager = sync_playwright()
            p = playwright_manager.start()
            playwright_manager = p
            context, _launch_target = launch_tp_persistent_context(
                p.chromium,
                user_data_dir=str(profile_dir),
                browser_channel=browser_channel,
                headless=True,
                viewport={"width": 1280, "height": 900},
            )
            page = context.pages[0] if context.pages else context.new_page()
        start_url = f"https://www.tradingpaints.com/showroom/{category}/{mid}/{slug}"
        current_url = ""
        try:
            current_url = str(page.url or '')
        except Exception:
            current_url = ""
        if owned_context or not current_url.startswith(start_url):
            page.goto(start_url, wait_until="domcontentloaded", timeout=60000)
        auth_checked = bool((shared_auth_state or {}).get('checked')) and not owned_context
        if auth_checked:
            authenticated = bool((shared_auth_state or {}).get('authenticated'))
        else:
            authenticated, auth_source = _tp_context_looks_authenticated(context, [page])
            if shared_auth_state is not None and not owned_context:
                shared_auth_state["checked"] = True
                shared_auth_state["authenticated"] = bool(authenticated)
                shared_auth_state["auth_source"] = str(auth_source or '')
        if not authenticated:
            clear_tp_login_status(profile_dir, "Trading Paints login is required again for the saved browser profile.")
            return False, "Trading Paints login is required again for the saved browser profile."
        dashboard_url = f"https://www.tradingpaints.com/dashboard/{mid}/{slug}/simstamped"
        set_url = f"https://www.tradingpaints.com/js/setScheme.php?id={target_scheme_id}&sub_make=0"

        def _verify_restore_window(timeout_seconds: float) -> tuple[bool, str]:
            verify_deadline = time.monotonic() + max(2.0, float(timeout_seconds))
            last_seen = ""
            while time.monotonic() < verify_deadline:
                current_scheme_id, current_showroom_link, _current_title, _capture_source = _tp_capture_current_scheme_info(
                    context,
                    page,
                    mid=mid,
                    slug=slug,
                    category=category,
                )
                last_seen = current_showroom_link or current_scheme_id
                if current_scheme_id == target_scheme_id:
                    return True, last_seen
                if manifest_member_id is not None and int(manifest_member_id or 0) > 0 and baseline_manifest_urls:
                    manifest_ok = _tp_manifest_matches_url_map(
                        local_user_id=int(manifest_member_id),
                        directory=raw_directory or directory_key,
                        url_map=dict(baseline_manifest_urls),
                        retries=retries,
                        retry_backoff_seconds=retry_backoff_seconds,
                    )
                    if manifest_ok:
                        write(
                            f"Trading Paints restore verification accepted a fresh manifest match for {raw_directory or directory_key} even though the dashboard last showed {last_seen or 'unknown'}."
                        )
                        return True, last_seen
                time.sleep(0.9)
            return False, last_seen

        referers = [dashboard_url, target_showroom_link or dashboard_url, start_url]
        verified = False
        last_capture = ""
        last_error = ""
        for referer in referers:
            try:
                page.goto(dashboard_url, wait_until="domcontentloaded", timeout=45000)
            except Exception:
                pass
            if not _tp_wait_for_scheme_request_cooldown(
                log=write,
                action_label=f"Trading Paints restore direct request for {raw_directory or directory_key}",
            ):
                return False, f"Trading Paints original scheme restore was cancelled for {raw_directory or directory_key}."
            try:
                set_resp = context.request.get(
                    set_url,
                    headers={
                        "X-Requested-With": "XMLHttpRequest",
                        "Accept": "application/json, text/javascript, */*; q=0.01",
                        "Referer": referer,
                        "Cache-Control": "no-cache",
                        "Pragma": "no-cache",
                    },
                    fail_on_status_code=False,
                )
            except Exception as exc:
                set_resp = None
                last_error = str(exc)
            if set_resp is not None and set_resp.ok:
                write(f"Trading Paints restore called setScheme directly for {raw_directory or directory_key}: {target_scheme_id}.")
                verified, last_capture = _verify_restore_window(6.5)
                if verified:
                    break
            else:
                status_text = f"HTTP {set_resp.status}" if set_resp is not None else last_error or "request failed"
                write(f"Trading Paints direct restore request did not confirm for {raw_directory or directory_key}: {status_text}")
        if not verified and target_showroom_link:
            restored_via_ui = _tp_try_activate_showroom_view(page, target_showroom_link, target_scheme_id, log=write)
            if restored_via_ui:
                verified, last_capture = _verify_restore_window(8.0)
        if not verified:
            return False, (
                f"Trading Paints original scheme restore could not be verified for {raw_directory or directory_key}. "
                f"Expected {target_scheme_id}{(' / ' + target_showroom_link) if target_showroom_link else ''}, last seen {last_capture or 'unknown'}."
            )
        write(f"Trading Paints original scheme restored for {raw_directory or directory_key}: {target_scheme_id}")
        return True, f"Trading Paints original scheme restored for {raw_directory or directory_key}: {target_scheme_id}."
    finally:
        if owned_context and context is not None:
            try:
                context.close()
            except Exception:
                pass
        if owned_context and playwright_manager is not None:
            try:
                playwright_manager.stop()
            except Exception:
                pass

def restore_tp_showroom_generic(
    *,
    scheme_id: str,
    category: str,
    mid: int,
    slug: str,
    profile_dir: Path,
    browser_channel: str = "chrome",
    log: Callable[[str], None] | None = None,
    shared_context=None,
    shared_page=None,
    shared_auth_state: dict[str, object] | None = None,
) -> tuple[bool, str]:
    def write(msg: str) -> None:
        if log:
            log(msg)

    target_scheme_id = str(scheme_id or "").strip()
    if not target_scheme_id:
        return False, "No Trading Paints scheme id was provided for restore."
    if sync_playwright is None:
        return False, "Playwright is not installed in this build."
    profile_dir.mkdir(parents=True, exist_ok=True)
    owned_context = shared_context is None or shared_page is None
    playwright_manager = None
    context = shared_context
    page = shared_page
    try:
        if owned_context:
            playwright_manager = sync_playwright()
            p = playwright_manager.start()
            playwright_manager = p
            context, _launch_target = launch_tp_persistent_context(
                p.chromium,
                user_data_dir=str(profile_dir),
                browser_channel=browser_channel,
                headless=True,
                viewport={"width": 1280, "height": 900},
            )
            page = context.pages[0] if context.pages else context.new_page()
        start_url = f"https://www.tradingpaints.com/showroom/{category}/{mid}/{slug}"
        current_url = ""
        try:
            current_url = str(page.url or "")
        except Exception:
            current_url = ""
        if owned_context or not current_url.startswith(start_url):
            page.goto(start_url, wait_until="domcontentloaded", timeout=60000)
        auth_checked = bool((shared_auth_state or {}).get("checked")) and not owned_context
        if auth_checked:
            authenticated = bool((shared_auth_state or {}).get("authenticated"))
        else:
            authenticated, auth_source = _tp_context_looks_authenticated(context, [page])
            if shared_auth_state is not None and not owned_context:
                shared_auth_state["checked"] = True
                shared_auth_state["authenticated"] = bool(authenticated)
                shared_auth_state["auth_source"] = str(auth_source or "")
        if not authenticated:
            clear_tp_login_status(profile_dir, "Trading Paints login is required again for the saved browser profile.")
            return False, "Trading Paints login is required again for the saved browser profile."
        dashboard_url = f"https://www.tradingpaints.com/dashboard/{mid}/{slug}/simstamped"
        set_url = f"https://www.tradingpaints.com/js/setScheme.php?id={target_scheme_id}&sub_make=0"
        try:
            page.goto(dashboard_url, wait_until="domcontentloaded", timeout=45000)
        except Exception:
            pass
        if not _tp_wait_for_scheme_request_cooldown(
            log=write,
            action_label=f"Trading Paints restore direct request for {category}/{mid}/{slug}",
        ):
            return False, f"Trading Paints original scheme restore was cancelled for {category}/{mid}/{slug}."
        set_resp = context.request.get(
            set_url,
            headers={
                "X-Requested-With": "XMLHttpRequest",
                "Accept": "application/json, text/javascript, */*; q=0.01",
                "Referer": dashboard_url,
                "Cache-Control": "no-cache",
                "Pragma": "no-cache",
            },
            fail_on_status_code=False,
        )
        if not set_resp.ok:
            return False, f"Trading Paints restore setScheme failed with HTTP {set_resp.status}."
        verify_deadline = time.monotonic() + 8.0
        while time.monotonic() < verify_deadline:
            try:
                current_scheme_id, _capture_source = _tp_capture_current_scheme_id(
                    context,
                    page,
                    mid=mid,
                    slug=slug,
                    category=category,
                )
            except Exception:
                current_scheme_id = ""
            if current_scheme_id == target_scheme_id:
                write(f"Trading Paints original scheme restored for {category}/{mid}/{slug}: {target_scheme_id}")
                return True, f"Trading Paints original scheme restored for {category}/{mid}/{slug}: {target_scheme_id}."
            time.sleep(0.9)
        return False, f"Trading Paints original scheme restore could not be verified for {category}/{mid}/{slug}."
    finally:
        if owned_context and context is not None:
            try:
                context.close()
            except Exception:
                pass
        if owned_context and playwright_manager is not None:
            try:
                playwright_manager.stop()
            except Exception:
                pass


def _tp_fetch_showroom_page_batch(
    api,
    *,
    mid: int,
    category: str,
    slug: str,
    page_index: int,
    timeout_ms: int | None = None,
) -> list[dict]:
    start_url = f"https://www.tradingpaints.com/showroom/{category}/{mid}/{slug}"
    pos = max(0, int(page_index)) * TP_SHOWROOM_FETCH_PAGE_SIZE
    showroom_url = f"https://www.tradingpaints.com/js/showroom.php?mid={mid}&{DEFAULT_SHOWROOM_PARAMS}&pos={pos}&ts={int(time.time()*1000)}"
    request_kwargs = {
        "headers": {
            "X-Requested-With": "XMLHttpRequest",
            "Accept": "application/json, text/javascript, */*; q=0.01",
            "Referer": start_url,
            "Cache-Control": "no-cache",
            "Pragma": "no-cache",
        },
        "fail_on_status_code": False,
    }
    if timeout_ms is not None:
        try:
            request_kwargs["timeout"] = max(1000, int(timeout_ms))
        except Exception:
            request_kwargs["timeout"] = 1000
    resp = api.get(showroom_url, **request_kwargs)
    if not resp.ok:
        return []
    try:
        payload = json.loads(resp.text())
    except Exception:
        return []
    parsed = ((payload.get('output') or {}).get('cars') or []) if isinstance(payload, dict) else []
    if not isinstance(parsed, list):
        return []
    return [item for item in parsed if isinstance(item, dict)]


def _detect_tp_showroom_total_pages(
    api,
    *,
    mid: int,
    category: str,
    slug: str,
    max_pages: int = 50,
    timeout_seconds: float = 45.0,
    log: Callable[[str], None] | None = None,
) -> int:
    page_limit = max(1, min(int(max_pages or 50), 50))
    started = time.monotonic()
    deadline = started + max(1.0, float(timeout_seconds or 45.0))
    page_has_results: dict[int, bool] = {}
    last_good = 0
    first_page_exists = False

    def _page_exists(page_index: int) -> bool:
        idx = int(page_index)
        if idx in page_has_results:
            return page_has_results[idx]
        remaining_ms = int((deadline - time.monotonic()) * 1000)
        if remaining_ms <= 0:
            raise TimeoutError("Trading Paints showroom total page detection timed out.")
        batch = _tp_fetch_showroom_page_batch(
            api,
            mid=mid,
            category=category,
            slug=slug,
            page_index=idx,
            timeout_ms=min(15000, max(1000, remaining_ms)),
        )
        exists = bool(batch)
        page_has_results[idx] = exists
        return exists

    try:
        first_page_exists = _page_exists(0)
        if not first_page_exists:
            if log:
                log(f"Trading Paints showroom total pages detected for {category}/{mid}/{slug}: 0 page(s) in {time.monotonic() - started:.2f}s")
            return 0

        probe = 1
        while probe < page_limit and _page_exists(probe):
            last_good = probe
            probe *= 2
        low = last_good + 1
        high = min(probe, page_limit - 1)
        while low <= high:
            mid_page = (low + high) // 2
            if _page_exists(mid_page):
                last_good = mid_page
                low = mid_page + 1
            else:
                high = mid_page - 1
        total_pages = last_good + 1
        if log:
            log(f"Trading Paints showroom total pages detected for {category}/{mid}/{slug}: {total_pages} page(s) in {time.monotonic() - started:.2f}s")
        return total_pages
    except TimeoutError:
        total_pages = (last_good + 1) if first_page_exists else 0
        if log:
            log(
                f"Trading Paints showroom total page detection hit the 45s limit for {category}/{mid}/{slug}; "
                f"using {total_pages} confirmed page(s) after {time.monotonic() - started:.2f}s."
            )
        return total_pages


def _fetch_tp_showroom_pool(
    context,
    *,
    mid: int,
    category: str,
    slug: str,
    existing_cars: list[dict] | None = None,
    sampled_pages: set[int] | None = None,
    min_unused_count: int = 1,
    min_random_pages: int = 1,
    max_pages: int = TP_SHOWROOM_MAX_PAGES,
    prefer_official: bool = False,
    exclude_scheme_ids: set[str] | None = None,
    exclude_recent_scheme_ids: set[str] | None = None,
    log: Callable[[str], None] | None = None,
) -> tuple[list[dict], set[int]]:
    api = context.request
    start_url = f"https://www.tradingpaints.com/showroom/{category}/{mid}/{slug}"
    page_limit = max(1, min(int(max_pages or TP_SHOWROOM_MAX_PAGES), 50))
    minimum_page_count = max(1, min(int(min_random_pages or 1), page_limit))
    sampled = set(int(p) for p in (sampled_pages or set()) if int(p) >= 0)
    initial_sampled = set(sampled)
    cars: list[dict] = []
    seen_ids: set[str] = set()
    for car in list(existing_cars or []):
        if not isinstance(car, dict):
            continue
        scheme_id = str(car.get('id') or '').strip()
        if scheme_id and scheme_id in seen_ids:
            continue
        if scheme_id:
            seen_ids.add(scheme_id)
        car_copy = dict(car)
        page_idx_value = car_copy.get('_nishizumi_page_index')
        if page_idx_value is not None:
            try:
                car_copy["_nishizumi_page_index"] = int(page_idx_value)
                car_copy["_nishizumi_page_number"] = int(page_idx_value) + 1
            except Exception:
                pass
        cars.append(car_copy)
    page_choices = list(range(page_limit))
    random.shuffle(page_choices)
    # Keep fetching random unseen pages until the current selection pool can cover the remaining targets.
    # When total-page detection is enabled, we can also intentionally widen the pool across more
    # pages for better variety instead of stopping at the first page that happens to have enough schemes.
    while (
        _showroom_available_count(
            cars,
            prefer_official=prefer_official,
            exclude_scheme_ids=exclude_scheme_ids,
            exclude_recent_scheme_ids=exclude_recent_scheme_ids,
        ) < max(1, int(min_unused_count or 1))
        or len(sampled) < minimum_page_count
    ):
        next_page = None
        for page_idx in page_choices:
            if page_idx not in sampled:
                next_page = page_idx
                break
        if next_page is None:
            break
        sampled.add(next_page)
        batch = _tp_fetch_showroom_page_batch(
            api,
            mid=mid,
            category=category,
            slug=slug,
            page_index=next_page,
        )
        for car in batch:
            scheme_id = str(car.get('id') or '').strip()
            if scheme_id and scheme_id in seen_ids:
                continue
            if scheme_id:
                seen_ids.add(scheme_id)
            car_copy = dict(car)
            car_copy["_nishizumi_page_index"] = int(next_page)
            car_copy["_nishizumi_page_number"] = int(next_page) + 1
            cars.append(car_copy)
    newly_sampled = sorted(sampled - initial_sampled)
    if log and newly_sampled:
        sampled_list = sorted(sampled)
        sampled_human = ", ".join(str(page_idx + 1) for page_idx in sampled_list)
        log(
            f"Trading Paints showroom pool fetched for {category}/{mid}/{slug}: {len(cars)} unique scheme(s) across {len(sampled_list)} random page(s) [pages: {sampled_human}]"
        )
    return cars, sampled


def _tp_build_direct_items_from_url_map(
    *,
    user_id: int,
    directory: str,
    url_map: dict[str, str],
) -> list[DownloadFile]:
    result: list[DownloadFile] = []
    for paint_type in (PaintType.CAR, PaintType.CAR_SPEC, PaintType.CAR_DECAL):
        url = str((url_map or {}).get(paint_type.value) or '').strip()
        if not url:
            continue
        result.append(
            DownloadFile(
                download_id=DownloadId(
                    user_id=int(user_id),
                    directory=directory,
                    paint_type=paint_type,
                    is_team_paint=False,
                    is_superspeedway_variant=False,
                ),
                url=url,
            )
        )
    return result


def _tp_build_public_showroom_car_direct_items(
    *,
    user_id: int,
    directory: str,
    scheme_id: object,
    title: object = "",
    source_link: object = "",
    source: object = "showroom_direct",
) -> list[DownloadFile]:
    normalized_scheme_id = str(scheme_id or "").strip()
    if not normalized_scheme_id:
        return []
    items = _tp_build_direct_items_from_url_map(
        user_id=int(user_id),
        directory=directory,
        url_map={
            PaintType.CAR.value: TRADING_PAINTS_SHOWROOM_COMPRESSED_URL.format(asset_id=normalized_scheme_id),
            PaintType.CAR_SPEC.value: TRADING_PAINTS_SHOWROOM_MIP_URL.format(asset_id=normalized_scheme_id),
        },
    )
    return _annotate_download_files_with_tp_source(
        items,
        scheme_id=normalized_scheme_id,
        title=title,
        source_link=source_link,
        source=source,
    )


def _tp_build_public_showroom_accessory_direct_items(
    *,
    user_id: int,
    accessory_kind: str,
    scheme_id: object,
    title: object = "",
    source_link: object = "",
    source: object = "showroom_direct",
) -> list[DownloadFile]:
    normalized_scheme_id = str(scheme_id or "").strip()
    normalized_kind = str(accessory_kind or "").strip().lower()
    if not normalized_scheme_id or normalized_kind not in {"helmet", "suit"}:
        return []
    paint_type = PaintType.HELMET if normalized_kind == "helmet" else PaintType.SUIT
    items = [
        DownloadFile(
            download_id=DownloadId(
                user_id=int(user_id),
                directory=normalized_kind,
                paint_type=paint_type,
                is_team_paint=False,
                is_superspeedway_variant=False,
            ),
            url=TRADING_PAINTS_SHOWROOM_COMPRESSED_URL.format(asset_id=normalized_scheme_id),
        )
    ]
    return _annotate_download_files_with_tp_source(
        items,
        scheme_id=normalized_scheme_id,
        title=title,
        source_link=source_link,
        source=source,
    )


def _tp_build_accessory_direct_items_from_url_map(
    *,
    user_id: int,
    paint_type: PaintType,
    url_map: dict[str, str],
) -> list[DownloadFile]:
    url = str((url_map or {}).get(paint_type.value) or '').strip()
    if not url:
        return []
    return [
        DownloadFile(
            download_id=DownloadId(
                user_id=int(user_id),
                directory=paint_type.value,
                paint_type=paint_type,
                is_team_paint=False,
                is_superspeedway_variant=False,
            ),
            url=url,
        )
    ]


def _tp_manifest_matches_url_map(
    *,
    local_user_id: int,
    directory: str,
    url_map: dict[str, str],
    retries: int,
    retry_backoff_seconds: float,
) -> bool:
    try:
        manifest = fetch_user_files(local_user_id, retries, retry_backoff_seconds)
    except Exception:
        return False
    filtered = _tp_manifest_items_for_directory(manifest, directory)
    current_urls = _tp_manifest_url_map(filtered)
    if not current_urls or not url_map:
        return False
    return current_urls == dict(url_map)


def choose_and_sync_showroom_paint(
    *,
    directory: str,
    mapping_path: Path | None,
    profile_dir: Path,
    paints_dir: Path,
    manifest_member_id: int | None,
    local_team_id: int | None,
    browser_channel: str = "chrome",
    pages: int = TP_SHOWROOM_MAX_PAGES,
    prefer_official: bool = False,
    choice_mode: str = "random",
    trigger_local_update: bool = True,
    timeout_seconds: float = 35.0,
    retries: int = 3,
    retry_backoff_seconds: float = 1.5,
    original_scheme_id: str = "",
    exclude_scheme_ids: set[str] | None = None,
    exclude_recent_scheme_ids: set[str] | None = None,
    showroom_cars: list[dict] | None = None,
    showroom_sampled_pages: set[int] | None = None,
    detected_total_pages: int | None = None,
    detect_total_pages: bool = False,
    minimum_unused_choices: int = 1,
    log: Callable[[str], None] | None = None,
    shared_context=None,
    shared_page=None,
    shared_auth_state: dict[str, object] | None = None,
    fast_mule_mode: bool = False,
    fast_apply_mode: bool = False,
    baseline_manifest_urls_override: dict[str, str] | None = None,
    forced_scheme_id: str = "",
    forced_scheme_title: str = "",
    force_showroom_ui_activation: bool = False,
    cancel_event: threading.Event | None = None,
    superspeedway_variant: bool = False,
) -> TPShowroomSyncResult:
    def write(msg: str) -> None:
        if log:
            log(msg)

    raw_directory = str(directory or '').strip()
    if _cancel_requested(cancel_event):
        return TPShowroomSyncResult(ok=False, message="Trading Paints showroom fallback cancelled because the iRacing session changed or ended.")
    directory_key = canonicalize_car_directory(raw_directory).lower()
    mapping_doc = _load_tp_showroom_mapping(mapping_path)
    unsupported = (mapping_doc.get('unsupported') or {})
    cars_map = (mapping_doc.get('cars') or {})
    candidate_keys = _tp_directory_candidate_keys(directory_key)
    for candidate in candidate_keys:
        if candidate in unsupported:
            return TPShowroomSyncResult(ok=False, message=f"Trading Paints does not currently have a supported showroom car for '{candidate}'.")
    entry = None
    matched_key = directory_key
    for candidate in candidate_keys:
        possible = cars_map.get(candidate)
        if isinstance(possible, dict):
            entry = possible
            matched_key = candidate
            break
    if not isinstance(entry, dict):
        return TPShowroomSyncResult(ok=False, message=f"No Trading Paints showroom mapping exists for '{directory_key}'.")
    if sync_playwright is None:
        return TPShowroomSyncResult(ok=False, message="Playwright is not installed in this build.")
    if manifest_member_id is None or int(manifest_member_id) <= 0:
        return TPShowroomSyncResult(ok=False, message="The online Trading Paints fallback requires a Trading Paints member id for manifest polling. Set the TP manifest member ID in the app settings first.")
    mid = int(entry["mid"])
    category = str(entry.get('category') or "Road")
    slug = str(entry.get('slug') or f"car-{mid}")
    profile_dir.mkdir(parents=True, exist_ok=True)
    local_member_id = int(manifest_member_id)
    captured_original_scheme_id = str(original_scheme_id or '').strip()
    captured_original_scheme_link = ""
    captured_original_scheme_title = ""
    effective_exclude_scheme_ids = {
        str(item).strip()
        for item in (exclude_scheme_ids or set())
        if str(item).strip()
    }
    if captured_original_scheme_id:
        effective_exclude_scheme_ids.add(captured_original_scheme_id)
    baseline_manifest_items: list[DownloadFile] = []
    if baseline_manifest_urls_override:
        baseline_url_map = dict(baseline_manifest_urls_override)
    else:
        try:
            baseline_manifest_items = _tp_manifest_items_for_directory(
                fetch_user_files(local_member_id, retries, retry_backoff_seconds, cancel_event=cancel_event),
                raw_directory or matched_key,
            )
        except Exception:
            baseline_manifest_items = []
        baseline_url_map = _tp_manifest_url_map(baseline_manifest_items)
    sampled_page_set: set[int] = set(int(p) for p in (showroom_sampled_pages or set()) if int(p) >= 0)
    owned_context = shared_context is None or shared_page is None
    playwright_manager = None
    context = shared_context
    page = shared_page
    try:
        if owned_context:
            playwright_manager = sync_playwright()
            p = playwright_manager.start()
            playwright_manager = p
            context, _launch_target = launch_tp_persistent_context(
                p.chromium,
                user_data_dir=str(profile_dir),
                browser_channel=browser_channel,
                headless=True,
                viewport={"width": 1280, "height": 900},
            )
            page = context.pages[0] if context.pages else context.new_page()
        start_url = f"https://www.tradingpaints.com/showroom/{category}/{mid}/{slug}"
        current_url = ""
        try:
            current_url = str(page.url or '')
        except Exception:
            current_url = ""
        if owned_context or not current_url.startswith(start_url):
            if _cancel_requested(cancel_event):
                return TPShowroomSyncResult(ok=False, message="Trading Paints showroom fallback cancelled because the iRacing session changed or ended.")
            page.goto(start_url, wait_until="domcontentloaded", timeout=60000)
        api = context.request
        detected_total_pages_value = 0
        try:
            if detected_total_pages is not None and int(detected_total_pages or 0) > 0:
                detected_total_pages_value = max(0, int(detected_total_pages or 0))
        except Exception:
            detected_total_pages_value = 0
        if detect_total_pages and detected_total_pages_value <= 0:
            try:
                detected_total_pages_value = _detect_tp_showroom_total_pages(
                    api,
                    mid=mid,
                    category=category,
                    slug=slug,
                    max_pages=50,
                    log=write,
                )
            except Exception as exc:
                write(f"Trading Paints showroom total page detection failed for {category}/{mid}/{slug}: {exc}")
                detected_total_pages_value = 0
        effective_page_limit = max(1, int(detected_total_pages_value or pages or TP_SHOWROOM_MAX_PAGES))
        desired_random_pages = 1
        auth_checked = bool((shared_auth_state or {}).get('checked')) and not owned_context
        if auth_checked:
            authenticated = bool((shared_auth_state or {}).get('authenticated'))
            auth_source = str((shared_auth_state or {}).get('auth_source') or "cached shared context")
        else:
            authenticated, auth_source = _tp_context_looks_authenticated(context, [page])
            if shared_auth_state is not None and not owned_context:
                shared_auth_state["checked"] = True
                shared_auth_state["authenticated"] = bool(authenticated)
                shared_auth_state["auth_source"] = str(auth_source or '')
        if not authenticated:
            clear_tp_login_status(profile_dir, "Trading Paints login is required again for the saved browser profile.")
            return TPShowroomSyncResult(ok=False, auth_required=True, original_scheme_id=captured_original_scheme_id, message="Trading Paints login is required again for the saved browser profile.")
        if not auth_checked:
            write(f"Trading Paints authenticated session confirmed via {auth_source}")
        if fast_mule_mode and not captured_original_scheme_id:
            captured_original_scheme_id, captured_original_scheme_link, captured_original_scheme_title, capture_source = _tp_capture_current_scheme_info_from_dashboard_api(
                api,
                mid=mid,
                slug=slug,
                category=category,
            )
            if captured_original_scheme_id:
                effective_exclude_scheme_ids.add(captured_original_scheme_id)
                extra = f" -> {captured_original_scheme_link}" if captured_original_scheme_link else ""
                write(f"Captured active Trading Paints scheme for {raw_directory or matched_key}: {captured_original_scheme_id} ({capture_source}); excluding it from this fallback pick{extra}")
            elif baseline_url_map:
                write(f"Trading Paints could not identify the active showroom scheme for {raw_directory or matched_key} before the MULE pick; a same-baseline manifest timeout may indicate either a TP propagation delay or that the already-active paint was selected.")
        if (not fast_mule_mode) and not captured_original_scheme_id:
            captured_original_scheme_id, captured_original_scheme_link, captured_original_scheme_title, capture_source = _tp_capture_current_scheme_info(
                context,
                page,
                mid=mid,
                slug=slug,
                category=category,
            )
            if captured_original_scheme_id:
                effective_exclude_scheme_ids.add(captured_original_scheme_id)
                extra = f" -> {captured_original_scheme_link}" if captured_original_scheme_link else ""
                write(f"Captured original Trading Paints scheme for {raw_directory or matched_key}: {captured_original_scheme_id} ({capture_source}); excluding it from this fallback pick{extra}")
            elif baseline_url_map:
                protection_message = (
                    f"Trading Paints primary-account protection is skipping the online fallback for {raw_directory or matched_key}: "
                    "the connected account already has active manifest files for this car, but Trading Paints did not expose a showroom-linked original scheme that could be restored later. "
                    "This target should fall back to the local random pool instead so the primary account paint does not get overwritten."
                )
                write(protection_message)
                return TPShowroomSyncResult(
                    ok=False,
                    original_scheme_id=captured_original_scheme_id,
                    showroom_count=0,
                    showroom_cars=list(showroom_cars or []),
                    showroom_sampled_pages=sorted(sampled_page_set),
                    detected_total_pages=detected_total_pages_value,
                    baseline_manifest_urls=dict(baseline_url_map),
                    original_scheme_link=captured_original_scheme_link,
                    original_scheme_title=captured_original_scheme_title,
                    force_local_fallback=True,
                    message=protection_message,
                )
            else:
                write(f"Trading Paints did not expose a showroom-linked original scheme for {raw_directory or matched_key}, but no active TP manifest files were detected for this car; the online fallback can continue and the app will still keep the local file backup path ready.")
        cars = [item for item in (showroom_cars or []) if isinstance(item, dict)]
        forced_retry_scheme_id = str(forced_scheme_id or "").strip()
        if forced_retry_scheme_id:
            chosen_scheme_id = forced_retry_scheme_id
            chosen_title = str(forced_scheme_title or "").strip() or "previously selected scheme"
            chosen_showroom_link = _tp_showroom_link_for_scheme(cars, chosen_scheme_id) or _tp_showroom_url_for_scheme_id(chosen_scheme_id, chosen_title)
            reused_previous_scheme = False
            reused_recent_history = False
            write(f"Trading Paints showroom fallback retrying timed-out scheme {chosen_scheme_id} for {raw_directory or matched_key}: {chosen_title}")
        else:
            min_choices_needed = max(1, int(minimum_unused_choices or 1))
            if detect_total_pages and detected_total_pages_value > 0:
                # Optional behavior: detect the *real* total number of showroom pages and then
                # keep the same default behavior of sampling a single random page, but now from
                # the real page universe instead of the fixed fallback ceiling.
                desired_random_pages = 1
                write(
                    f"Trading Paints showroom total page detection will be used as the random-page universe for {category}/{mid}/{slug}: choosing 1 random page out of {detected_total_pages_value} detected total page(s)."
                )
            current_available = _showroom_available_count(
                cars,
                prefer_official=prefer_official,
                exclude_scheme_ids=effective_exclude_scheme_ids,
                exclude_recent_scheme_ids=exclude_recent_scheme_ids,
            )
            if current_available < min_choices_needed:
                cars, sampled_page_set = _fetch_tp_showroom_pool(
                    context,
                    mid=mid,
                    category=category,
                    slug=slug,
                    existing_cars=cars,
                    sampled_pages=sampled_page_set,
                    min_unused_count=min_choices_needed,
                    min_random_pages=desired_random_pages,
                    max_pages=effective_page_limit,
                    prefer_official=prefer_official,
                    exclude_scheme_ids=effective_exclude_scheme_ids,
                    exclude_recent_scheme_ids=exclude_recent_scheme_ids,
                    log=write,
                )
            if not cars:
                return TPShowroomSyncResult(
                    ok=False,
                    original_scheme_id=captured_original_scheme_id,
                    showroom_count=0,
                    showroom_cars=cars,
                    showroom_sampled_pages=sorted(sampled_page_set),
                    detected_total_pages=detected_total_pages_value,
                    baseline_manifest_urls=dict(baseline_url_map),
                    original_scheme_link=captured_original_scheme_link,
                    original_scheme_title=captured_original_scheme_title,
                    message=f"No public showroom paints were returned for '{raw_directory or matched_key}'.",
                )
            chosen, reused_previous_scheme, reused_recent_history = _pick_showroom_scheme(
                cars,
                choice_mode=choice_mode,
                prefer_official=prefer_official,
                exclude_scheme_ids=effective_exclude_scheme_ids,
                exclude_recent_scheme_ids=exclude_recent_scheme_ids,
            )
            chosen_scheme_id = str(chosen.get('id') or '').strip()
            chosen_title = str(chosen.get('title') or '').strip()
            chosen_showroom_link = _tp_showroom_link_from_car(chosen) or _tp_showroom_link_for_scheme(cars, chosen_scheme_id) or _tp_showroom_url_for_scheme_id(chosen_scheme_id, chosen_title)
            if baseline_url_map and captured_original_scheme_id and chosen_scheme_id == captured_original_scheme_id:
                message = (
                    f"Trading Paints showroom fallback skipped scheme {chosen_scheme_id} for {raw_directory or matched_key} "
                    "because it is already the active scheme, so the manifest would remain identical to the baseline."
                )
                write(message)
                return TPShowroomSyncResult(
                    ok=False,
                    chosen_scheme_id=chosen_scheme_id,
                    chosen_title=chosen_title,
                    showroom_count=len(cars),
                    original_scheme_id=captured_original_scheme_id,
                    showroom_cars=cars,
                    reused_previous_scheme=True,
                    showroom_sampled_pages=sorted(sampled_page_set),
                    detected_total_pages=detected_total_pages_value,
                    baseline_manifest_urls=dict(baseline_url_map),
                    original_scheme_link=captured_original_scheme_link,
                    original_scheme_title=captured_original_scheme_title,
                    force_local_fallback=True,
                    message=message,
                )
            if reused_previous_scheme:
                write(
                    f"Trading Paints showroom fallback reused a previously used scheme for {raw_directory or matched_key} because no unused showroom schemes remained in the fetched pool."
                )
            elif reused_recent_history:
                write(
                    f"Trading Paints showroom fallback reused a recent prior-session scheme for {raw_directory or matched_key} because no unseen showroom schemes remained in the fetched pool."
                )
            chosen_page_number = chosen.get('_nishizumi_page_number')
            chosen_page_label = "unknown"
            try:
                if chosen_page_number is not None:
                    chosen_page_label = str(int(chosen_page_number))
            except Exception:
                chosen_page_label = str(chosen_page_number or "unknown")
            write(
                f"Trading Paints showroom fallback picked {chosen_scheme_id} for {raw_directory or matched_key}: {chosen_title} [random page {chosen_page_label}]"
            )
        try:
            refreshed_baseline_url_map = _tp_current_manifest_url_map_for_directory(
                local_member_id,
                raw_directory or matched_key,
            )
        except Exception as exc:  # noqa: BLE001
            refreshed_baseline_url_map = {}
            if baseline_url_map:
                write(f"Trading Paints could not refresh the current manifest baseline for {raw_directory or matched_key} before setScheme {chosen_scheme_id}: {exc}")
        if refreshed_baseline_url_map:
            if baseline_url_map and refreshed_baseline_url_map != baseline_url_map:
                active_scheme_id = ""
                active_source = ""
                if forced_retry_scheme_id:
                    try:
                        active_scheme_id, _active_link, _active_title, active_source = _tp_capture_current_scheme_info_from_dashboard_api(
                            api,
                            mid=mid,
                            slug=slug,
                            category=category,
                        )
                    except Exception:
                        active_scheme_id = ""
                        active_source = ""
                    if not active_scheme_id:
                        try:
                            active_scheme_id, active_source = _tp_capture_current_scheme_id(
                                context,
                                page,
                                mid=mid,
                                slug=slug,
                                category=category,
                            )
                        except Exception:
                            active_scheme_id = ""
                            active_source = ""
                if forced_retry_scheme_id and active_scheme_id == chosen_scheme_id:
                    direct_items = _tp_build_direct_items_from_url_map(
                        user_id=local_member_id,
                        directory=raw_directory or matched_key,
                        url_map=refreshed_baseline_url_map,
                    )
                    required_unavailable, required_unavailable_message = _tp_required_manifest_assets_unavailable(
                        direct_items,
                        {PaintType.CAR},
                    )
                    if direct_items and not required_unavailable:
                        write(
                            f"Trading Paints forced retry found scheme {chosen_scheme_id} already active for {raw_directory or matched_key} via {active_source or 'dashboard'}; using the manifest URLs that appeared before reapplying."
                        )
                        return TPShowroomSyncResult(
                            ok=True,
                            chosen_scheme_id=chosen_scheme_id,
                            chosen_title=chosen_title,
                            showroom_count=len(cars),
                            original_scheme_id=captured_original_scheme_id,
                            showroom_cars=cars,
                            showroom_sampled_pages=sorted(sampled_page_set),
                            detected_total_pages=detected_total_pages_value,
                            baseline_manifest_urls=dict(baseline_url_map),
                            direct_items=direct_items,
                            set_scheme_applied=True,
                            reused_previous_scheme=reused_previous_scheme,
                            reused_recent_history=reused_recent_history,
                            original_scheme_link=captured_original_scheme_link,
                            original_scheme_title=captured_original_scheme_title,
                            message=f"Prepared direct Trading Paints asset download for already-active showroom scheme {chosen_scheme_id}.",
                        )
                    if direct_items and required_unavailable:
                        return TPShowroomSyncResult(
                            ok=False,
                            chosen_scheme_id=chosen_scheme_id,
                            chosen_title=chosen_title,
                            showroom_count=len(cars),
                            original_scheme_id=captured_original_scheme_id,
                            showroom_cars=cars,
                            set_scheme_applied=True,
                            showroom_sampled_pages=sorted(sampled_page_set),
                            detected_total_pages=detected_total_pages_value,
                            baseline_manifest_urls=dict(baseline_url_map),
                            original_scheme_link=captured_original_scheme_link,
                            original_scheme_title=captured_original_scheme_title,
                            message=f"The already-active showroom paint exposed manifest URLs, but the required asset was unavailable: {required_unavailable_message}.",
                        )
                if forced_retry_scheme_id and not active_scheme_id:
                    write(
                        f"Trading Paints manifest baseline for {raw_directory or matched_key} changed before forced retry setScheme {chosen_scheme_id}, but the active scheme could not be confirmed; keeping the earlier retry baseline so an already-released paint is not missed."
                    )
                else:
                    if forced_retry_scheme_id and active_scheme_id and active_scheme_id != chosen_scheme_id:
                        write(
                            f"Trading Paints manifest baseline for {raw_directory or matched_key} changed before forced retry setScheme {chosen_scheme_id}, but the active scheme is {active_scheme_id}; using the freshly observed URLs so a delayed prior swap is not mistaken for this retry."
                        )
                    else:
                        write(
                            f"Trading Paints manifest baseline for {raw_directory or matched_key} changed before setScheme {chosen_scheme_id}; using the freshly observed URLs so a delayed prior swap is not mistaken for this pick."
                        )
                    baseline_url_map = dict(refreshed_baseline_url_map)
            else:
                baseline_url_map = dict(refreshed_baseline_url_map)
        activated_via_ui = False
        if force_showroom_ui_activation:
            showroom_link = chosen_showroom_link or _tp_showroom_url_for_scheme_id(chosen_scheme_id, chosen_title)
            write(
                f"Trading Paints showroom fallback direct retry is still waiting for scheme {chosen_scheme_id}; trying the visible showroom button as a manual-flow fallback: {showroom_link}"
            )
            activated_via_ui = _tp_try_activate_showroom_view(
                page,
                showroom_link,
                chosen_scheme_id,
                write,
                action_label="Trading Paints showroom fallback",
                cancel_event=cancel_event,
            )
        if not activated_via_ui:
            set_url = f"https://www.tradingpaints.com/js/setScheme.php?id={chosen_scheme_id}&sub_make=0"
            if not _tp_wait_for_scheme_request_cooldown(
                log=write,
                action_label=f"Trading Paints showroom direct request for {raw_directory or matched_key}",
                cancel_event=cancel_event,
            ):
                return TPShowroomSyncResult(
                    ok=False,
                    chosen_scheme_id=chosen_scheme_id,
                    chosen_title=chosen_title,
                    showroom_count=len(cars),
                    original_scheme_id=captured_original_scheme_id,
                    showroom_cars=cars,
                    showroom_sampled_pages=sorted(sampled_page_set),
                    detected_total_pages=detected_total_pages_value,
                    baseline_manifest_urls=dict(baseline_url_map),
                    original_scheme_link=captured_original_scheme_link,
                    original_scheme_title=captured_original_scheme_title,
                    message=f"Trading Paints showroom request for {chosen_scheme_id} was cancelled while waiting for the {TP_SCHEME_REQUEST_COOLDOWN_SECONDS:.0f}s cooldown.",
                )
            try:
                set_resp = api.get(
                    set_url,
                    headers={
                        "X-Requested-With": "XMLHttpRequest",
                        "Accept": "application/json, text/javascript, */*; q=0.01",
                        "Referer": start_url,
                    },
                    fail_on_status_code=False,
                    timeout=(TP_MULE_SET_SCHEME_TIMEOUT_MS if fast_mule_mode else 30000),
                )
            except Exception as exc:  # noqa: BLE001
                return TPShowroomSyncResult(
                    ok=False,
                    chosen_scheme_id=chosen_scheme_id,
                    chosen_title=chosen_title,
                    showroom_count=len(cars),
                    original_scheme_id=captured_original_scheme_id,
                    showroom_cars=cars,
                    set_scheme_applied=bool(fast_mule_mode),
                    showroom_sampled_pages=sorted(sampled_page_set),
                    detected_total_pages=detected_total_pages_value,
                    baseline_manifest_urls=dict(baseline_url_map),
                    original_scheme_link=captured_original_scheme_link,
                    original_scheme_title=captured_original_scheme_title,
                    message=f"setScheme request failed for {chosen_scheme_id}: {exc}",
                )
            if not set_resp.ok:
                return TPShowroomSyncResult(
                    ok=False,
                    chosen_scheme_id=chosen_scheme_id,
                    chosen_title=chosen_title,
                    showroom_count=len(cars),
                    original_scheme_id=captured_original_scheme_id,
                    showroom_cars=cars,
                    showroom_sampled_pages=sorted(sampled_page_set),
                    detected_total_pages=detected_total_pages_value,
                    baseline_manifest_urls=dict(baseline_url_map),
                    original_scheme_link=captured_original_scheme_link,
                    original_scheme_title=captured_original_scheme_title,
                    message=f"setScheme failed with HTTP {set_resp.status} for {chosen_scheme_id}.",
                )
            rejection_message = _tp_set_scheme_rejection_message(set_resp, chosen_scheme_id)
            if rejection_message:
                write(f"Trading Paints {rejection_message}")
                return TPShowroomSyncResult(
                    ok=False,
                    chosen_scheme_id=chosen_scheme_id,
                    chosen_title=chosen_title,
                    showroom_count=len(cars),
                    original_scheme_id=captured_original_scheme_id,
                    showroom_cars=cars,
                    showroom_sampled_pages=sorted(sampled_page_set),
                    detected_total_pages=detected_total_pages_value,
                    baseline_manifest_urls=dict(baseline_url_map),
                    original_scheme_link=captured_original_scheme_link,
                    original_scheme_title=captured_original_scheme_title,
                    retryable_online_failure=True,
                    message=rejection_message,
                )
        chosen_scheme_confirmed = False
        if fast_mule_mode or fast_apply_mode:
            write(f"Trading Paints showroom scheme {chosen_scheme_id} was requested for {raw_directory or matched_key}; online fallback is skipping the per-fallback dashboard confirmation loop and polling the manifest directly.")
        else:
            confirm_deadline = time.monotonic() + 8.0
            while time.monotonic() < confirm_deadline:
                try:
                    active_scheme_id, _active_source = _tp_capture_current_scheme_id(
                        context,
                        page,
                        mid=mid,
                        slug=slug,
                        category=category,
                    )
                except Exception:
                    active_scheme_id = ""
                if active_scheme_id and active_scheme_id == chosen_scheme_id:
                    chosen_scheme_confirmed = True
                    break
                time.sleep(0.9)
            if chosen_scheme_confirmed:
                write(f"Trading Paints showroom scheme {chosen_scheme_id} is now active for {raw_directory or matched_key}; waiting for manifest refresh.")
            else:
                write(f"Trading Paints showroom scheme {chosen_scheme_id} was requested for {raw_directory or matched_key}, but the dashboard did not confirm the swap quickly; continuing to poll the manifest anyway.")
        direct_items = _tp_wait_for_fetch_user_manifest(
            local_user_id=local_member_id,
            directory=raw_directory or matched_key,
            retries=retries,
            retry_backoff_seconds=retry_backoff_seconds,
            baseline_urls=baseline_url_map,
            timeout_seconds=(TP_MULE_MANIFEST_TIMEOUT_SECONDS if fast_mule_mode else timeout_seconds),
            log=write,
            cancel_event=cancel_event,
            superspeedway_variant=superspeedway_variant,
        )
        if not direct_items:
            return TPShowroomSyncResult(
                ok=False,
                chosen_scheme_id=chosen_scheme_id,
                chosen_title=chosen_title,
                showroom_count=len(cars),
                original_scheme_id=captured_original_scheme_id,
                showroom_cars=cars,
                set_scheme_applied=True,
                reused_previous_scheme=reused_previous_scheme,
                reused_recent_history=reused_recent_history,
                showroom_sampled_pages=sorted(sampled_page_set),
                detected_total_pages=detected_total_pages_value,
                baseline_manifest_urls=dict(baseline_url_map),
                original_scheme_link=captured_original_scheme_link,
                original_scheme_title=captured_original_scheme_title,
                message=(
                    "The showroom paint was selected online, but the local account manifest never exposed fresh car asset URLs in time."
                ),
            )
        required_unavailable, required_unavailable_message = _tp_required_manifest_assets_unavailable(
            direct_items,
            {PaintType.CAR},
        )
        if required_unavailable:
            return TPShowroomSyncResult(
                ok=False,
                chosen_scheme_id=chosen_scheme_id,
                chosen_title=chosen_title,
                showroom_count=len(cars),
                original_scheme_id=captured_original_scheme_id,
                showroom_cars=cars,
                set_scheme_applied=True,
                reused_previous_scheme=reused_previous_scheme,
                reused_recent_history=reused_recent_history,
                showroom_sampled_pages=sorted(sampled_page_set),
                detected_total_pages=detected_total_pages_value,
                baseline_manifest_urls=dict(baseline_url_map),
                original_scheme_link=captured_original_scheme_link,
                original_scheme_title=captured_original_scheme_title,
                message=f"The showroom paint exposed fresh manifest URLs, but the required asset was unavailable: {required_unavailable_message}.",
            )
        return TPShowroomSyncResult(
            ok=True,
            chosen_scheme_id=chosen_scheme_id,
            chosen_title=chosen_title,
            showroom_count=len(cars),
            original_scheme_id=captured_original_scheme_id,
            showroom_cars=cars,
            showroom_sampled_pages=sorted(sampled_page_set),
                detected_total_pages=detected_total_pages_value,
            baseline_manifest_urls=dict(baseline_url_map),
            original_scheme_link=captured_original_scheme_link,
            original_scheme_title=captured_original_scheme_title,
            direct_items=direct_items,
            set_scheme_applied=True,
            reused_previous_scheme=reused_previous_scheme,
            reused_recent_history=reused_recent_history,
            message=f"Prepared direct Trading Paints asset download for showroom scheme {chosen_scheme_id} on {raw_directory or matched_key}.",
        )
    finally:
        if owned_context and context is not None:
            try:
                context.close()
            except Exception:
                pass
        if owned_context and playwright_manager is not None:
            try:
                playwright_manager.stop()
            except Exception:
                pass

def _clone_tp_profile_for_fallback_lane(profile_dir: Path, lane_tag: str) -> tuple[Path, Path | None]:
    source = Path(profile_dir)
    source.mkdir(parents=True, exist_ok=True)
    safe_tag = re.sub(r"[^A-Za-z0-9._-]+", "_", str(lane_tag or 'lane')).strip('._-') or 'lane'
    temp_root = default_temp_dir() / 'TPProfileLanes'
    temp_root.mkdir(parents=True, exist_ok=True)
    lane_dir = Path(tempfile.mkdtemp(prefix=f"{safe_tag}_", dir=str(temp_root)))
    try:
        shutil.copytree(
            source,
            lane_dir,
            dirs_exist_ok=True,
            ignore=shutil.ignore_patterns(
                'SingletonCookie',
                'SingletonLock',
                'SingletonSocket',
                'lockfile',
                'LOCK',
                'LOCKFILE',
            ),
        )
    except Exception:
        shutil.rmtree(lane_dir, ignore_errors=True)
        raise
    return lane_dir, lane_dir


def choose_and_sync_showroom_driver_accessory(
    *,
    accessory_kind: str,
    profile_dir: Path,
    manifest_member_id: int | None,
    browser_channel: str = "chrome",
    pages: int = TP_SHOWROOM_MAX_PAGES,
    choice_mode: str = "random",
    timeout_seconds: float = 20.0,
    retries: int = 3,
    retry_backoff_seconds: float = 1.5,
    original_scheme_id: str = "",
    exclude_scheme_ids: set[str] | None = None,
    exclude_recent_scheme_ids: set[str] | None = None,
    showroom_cars: list[dict] | None = None,
    showroom_sampled_pages: set[int] | None = None,
    detected_total_pages: int | None = None,
    detect_total_pages: bool = False,
    minimum_unused_choices: int = 1,
    log: Callable[[str], None] | None = None,
    shared_context=None,
    shared_page=None,
    shared_auth_state: dict[str, object] | None = None,
    fast_mule_mode: bool = False,
    fast_apply_mode: bool = False,
    baseline_manifest_urls_override: dict[str, str] | None = None,
    forced_scheme_id: str = "",
    forced_scheme_title: str = "",
    force_showroom_ui_activation: bool = False,
    cancel_event: threading.Event | None = None,
) -> TPShowroomSyncResult:
    def write(msg: str) -> None:
        if log:
            log(msg)

    normalized_kind = str(accessory_kind or "").strip().lower()
    if _cancel_requested(cancel_event):
        return TPShowroomSyncResult(ok=False, message="Trading Paints showroom accessory fallback cancelled because the iRacing session changed or ended.")
    if normalized_kind not in {"helmet", "suit"}:
        return TPShowroomSyncResult(ok=False, message=f"Unsupported accessory kind: {accessory_kind}")
    if sync_playwright is None:
        return TPShowroomSyncResult(ok=False, message="Playwright is not installed in this build.")
    if manifest_member_id is None or int(manifest_member_id) <= 0:
        return TPShowroomSyncResult(ok=False, message="The online Trading Paints fallback requires a Trading Paints member id for manifest polling. Set the TP manifest member ID in the app settings first.")

    paint_type = PaintType.HELMET if normalized_kind == "helmet" else PaintType.SUIT
    mid = 118 if normalized_kind == "helmet" else 119
    slug = "Helmets" if normalized_kind == "helmet" else "Suits"
    category = "Driver"
    profile_dir.mkdir(parents=True, exist_ok=True)
    local_member_id = int(manifest_member_id)
    captured_original_scheme_id = str(original_scheme_id or "").strip()
    effective_exclude_scheme_ids = {
        str(item).strip()
        for item in (exclude_scheme_ids or set())
        if str(item).strip()
    }
    if captured_original_scheme_id:
        effective_exclude_scheme_ids.add(captured_original_scheme_id)
    baseline_manifest_items: list[DownloadFile] = []
    if baseline_manifest_urls_override:
        baseline_url_map = dict(baseline_manifest_urls_override)
    else:
        try:
            baseline_manifest_items = _tp_manifest_items_for_accessory(
                fetch_user_files(local_member_id, retries, retry_backoff_seconds, cancel_event=cancel_event),
                paint_type,
            )
        except Exception:
            baseline_manifest_items = []
        baseline_url_map = _tp_manifest_url_map(baseline_manifest_items)
    sampled_page_set: set[int] = set(int(p) for p in (showroom_sampled_pages or set()) if int(p) >= 0)
    owned_context = shared_context is None or shared_page is None
    playwright_manager = None
    context = shared_context
    page = shared_page
    try:
        if owned_context:
            playwright_manager = sync_playwright()
            p = playwright_manager.start()
            playwright_manager = p
            context, _launch_target = launch_tp_persistent_context(
                p.chromium,
                user_data_dir=str(profile_dir),
                browser_channel=browser_channel,
                headless=True,
                viewport={"width": 1280, "height": 900},
            )
            page = context.pages[0] if context.pages else context.new_page()
        start_url = f"https://www.tradingpaints.com/showroom/{category}/{mid}/{slug}"
        current_url = ""
        try:
            current_url = str(page.url or "")
        except Exception:
            current_url = ""
        if owned_context or not current_url.startswith(start_url):
            if _cancel_requested(cancel_event):
                return TPShowroomSyncResult(ok=False, message="Trading Paints showroom accessory fallback cancelled because the iRacing session changed or ended.")
            page.goto(start_url, wait_until="domcontentloaded", timeout=60000)
        api = context.request
        detected_total_pages_value = 0
        try:
            if detected_total_pages is not None and int(detected_total_pages or 0) > 0:
                detected_total_pages_value = max(0, int(detected_total_pages or 0))
        except Exception:
            detected_total_pages_value = 0
        if detect_total_pages and detected_total_pages_value <= 0:
            try:
                detected_total_pages_value = _detect_tp_showroom_total_pages(
                    api,
                    mid=mid,
                    category=category,
                    slug=slug,
                    max_pages=50,
                    log=write,
                )
            except Exception as exc:
                write(f"Trading Paints showroom total page detection failed for {category}/{mid}/{slug}: {exc}")
                detected_total_pages_value = 0
        effective_page_limit = max(1, int(detected_total_pages_value or pages or TP_SHOWROOM_MAX_PAGES))
        desired_random_pages = 1
        auth_checked = bool((shared_auth_state or {}).get("checked")) and not owned_context
        if auth_checked:
            authenticated = bool((shared_auth_state or {}).get("authenticated"))
            auth_source = str((shared_auth_state or {}).get("auth_source") or "cached shared context")
        else:
            authenticated, auth_source = _tp_context_looks_authenticated(context, [page])
            if shared_auth_state is not None and not owned_context:
                shared_auth_state["checked"] = True
                shared_auth_state["authenticated"] = bool(authenticated)
                shared_auth_state["auth_source"] = str(auth_source or "")
        if not authenticated:
            clear_tp_login_status(profile_dir, "Trading Paints login is required again for the saved browser profile.")
            return TPShowroomSyncResult(ok=False, auth_required=True, original_scheme_id=captured_original_scheme_id, message="Trading Paints login is required again for the saved browser profile.")
        if not auth_checked:
            write(f"Trading Paints authenticated session confirmed via {auth_source}")
        if (not fast_mule_mode) and not captured_original_scheme_id:
            captured_original_scheme_id, _orig_link, _orig_title, capture_source = _tp_capture_current_scheme_info(
                context,
                page,
                mid=mid,
                slug=slug,
                category=category,
            )
            if captured_original_scheme_id:
                effective_exclude_scheme_ids.add(captured_original_scheme_id)
                write(f"Captured original Trading Paints {normalized_kind} scheme: {captured_original_scheme_id} ({capture_source}); excluding it from this fallback pick")
            elif baseline_url_map:
                protection_message = (
                    f"Trading Paints primary-account protection is skipping the online {normalized_kind} fallback: "
                    f"the connected account already has active {normalized_kind} manifest files, but Trading Paints did not expose a showroom-linked original scheme that could be restored later. "
                    f"This target should fall back to the local accessory pool instead so the primary account {normalized_kind} does not get overwritten."
                )
                write(protection_message)
                return TPShowroomSyncResult(
                    ok=False,
                    original_scheme_id=captured_original_scheme_id,
                    showroom_count=0,
                    showroom_cars=list(showroom_cars or []),
                    showroom_sampled_pages=sorted(sampled_page_set),
                    detected_total_pages=detected_total_pages_value,
                    baseline_manifest_urls=dict(baseline_url_map),
                    force_local_fallback=True,
                    message=protection_message,
                )
            else:
                write(f"Trading Paints did not expose a showroom-linked original {normalized_kind} scheme, but no active TP manifest files were detected for it; the online fallback can continue and the app will still keep the local file backup path ready.")
        cars = [item for item in (showroom_cars or []) if isinstance(item, dict)]
        forced_retry_scheme_id = str(forced_scheme_id or "").strip()
        if forced_retry_scheme_id:
            chosen_scheme_id = forced_retry_scheme_id
            chosen_title = str(forced_scheme_title or "").strip() or "previously selected scheme"
            chosen_showroom_link = _tp_showroom_link_for_scheme(cars, chosen_scheme_id) or _tp_showroom_url_for_scheme_id(chosen_scheme_id, chosen_title)
            reused_previous_scheme = False
            reused_recent_history = False
            write(f"Trading Paints showroom {normalized_kind} fallback retrying timed-out scheme {chosen_scheme_id}: {chosen_title}")
        else:
            min_choices_needed = max(1, int(minimum_unused_choices or 1))
            if detect_total_pages and detected_total_pages_value > 0:
                write(
                    f"Trading Paints showroom total page detection will be used as the random-page universe for {category}/{mid}/{slug}: choosing 1 random page out of {detected_total_pages_value} detected total page(s)."
                )
            current_available = _showroom_available_count(
                cars,
                prefer_official=False,
                exclude_scheme_ids=effective_exclude_scheme_ids,
                exclude_recent_scheme_ids=exclude_recent_scheme_ids,
            )
            if current_available < min_choices_needed:
                cars, sampled_page_set = _fetch_tp_showroom_pool(
                    context,
                    mid=mid,
                    category=category,
                    slug=slug,
                    existing_cars=cars,
                    sampled_pages=sampled_page_set,
                    min_unused_count=min_choices_needed,
                    min_random_pages=desired_random_pages,
                    max_pages=effective_page_limit,
                    prefer_official=False,
                    exclude_scheme_ids=effective_exclude_scheme_ids,
                    exclude_recent_scheme_ids=exclude_recent_scheme_ids,
                    log=write,
                )
            if not cars:
                return TPShowroomSyncResult(
                    ok=False,
                    original_scheme_id=captured_original_scheme_id,
                    showroom_count=0,
                    showroom_cars=cars,
                    showroom_sampled_pages=sorted(sampled_page_set),
                    detected_total_pages=detected_total_pages_value,
                    baseline_manifest_urls=dict(baseline_url_map),
                    message=f"No public showroom {normalized_kind} paints were returned.",
                )
            chosen, reused_previous_scheme, reused_recent_history = _pick_showroom_scheme(
                cars,
                choice_mode=choice_mode,
                prefer_official=False,
                exclude_scheme_ids=effective_exclude_scheme_ids,
                exclude_recent_scheme_ids=exclude_recent_scheme_ids,
            )
            chosen_scheme_id = str(chosen.get("id") or "").strip()
            chosen_title = str(chosen.get("title") or "").strip()
            chosen_showroom_link = _tp_showroom_link_from_car(chosen) or _tp_showroom_link_for_scheme(cars, chosen_scheme_id) or _tp_showroom_url_for_scheme_id(chosen_scheme_id, chosen_title)
            if baseline_url_map and captured_original_scheme_id and chosen_scheme_id == captured_original_scheme_id:
                message = (
                    f"Trading Paints showroom {normalized_kind} fallback skipped scheme {chosen_scheme_id} "
                    "because it is already the active scheme, so the manifest would remain identical to the baseline."
                )
                write(message)
                return TPShowroomSyncResult(
                    ok=False,
                    chosen_scheme_id=chosen_scheme_id,
                    chosen_title=chosen_title,
                    showroom_count=len(cars),
                    original_scheme_id=captured_original_scheme_id,
                    showroom_cars=cars,
                    reused_previous_scheme=True,
                    showroom_sampled_pages=sorted(sampled_page_set),
                    detected_total_pages=detected_total_pages_value,
                    baseline_manifest_urls=dict(baseline_url_map),
                    force_local_fallback=True,
                    message=message,
                )
            chosen_page_number = chosen.get("_nishizumi_page_number")
            chosen_page_label = "unknown"
            try:
                if chosen_page_number is not None:
                    chosen_page_label = str(int(chosen_page_number))
            except Exception:
                chosen_page_label = str(chosen_page_number or "unknown")
            write(
                f"Trading Paints showroom {normalized_kind} fallback picked {chosen_scheme_id}: {chosen_title} [random page {chosen_page_label}]"
            )
        try:
            refreshed_baseline_url_map = _tp_current_manifest_url_map_for_accessory(
                local_member_id,
                paint_type,
            )
        except Exception as exc:  # noqa: BLE001
            refreshed_baseline_url_map = {}
            if baseline_url_map:
                write(f"Trading Paints could not refresh the current manifest baseline for {normalized_kind} before setScheme {chosen_scheme_id}: {exc}")
        if refreshed_baseline_url_map:
            if baseline_url_map and refreshed_baseline_url_map != baseline_url_map:
                active_scheme_id = ""
                active_source = ""
                if forced_retry_scheme_id:
                    try:
                        active_scheme_id, _active_link, _active_title, active_source = _tp_capture_current_scheme_info_from_dashboard_api(
                            api,
                            mid=mid,
                            slug=slug,
                            category=category,
                        )
                    except Exception:
                        active_scheme_id = ""
                        active_source = ""
                    if not active_scheme_id:
                        try:
                            active_scheme_id, active_source = _tp_capture_current_scheme_id(
                                context,
                                page,
                                mid=mid,
                                slug=slug,
                                category=category,
                            )
                        except Exception:
                            active_scheme_id = ""
                            active_source = ""
                if forced_retry_scheme_id and active_scheme_id == chosen_scheme_id:
                    direct_items = _tp_build_accessory_direct_items_from_url_map(
                        user_id=local_member_id,
                        paint_type=paint_type,
                        url_map=refreshed_baseline_url_map,
                    )
                    required_unavailable, required_unavailable_message = _tp_required_manifest_assets_unavailable(
                        direct_items,
                        {paint_type},
                    )
                    if direct_items and not required_unavailable:
                        write(
                            f"Trading Paints forced {normalized_kind} retry found scheme {chosen_scheme_id} already active via {active_source or 'dashboard'}; using the manifest URLs that appeared before reapplying."
                        )
                        return TPShowroomSyncResult(
                            ok=True,
                            chosen_scheme_id=chosen_scheme_id,
                            chosen_title=chosen_title,
                            showroom_count=len(cars),
                            original_scheme_id=captured_original_scheme_id,
                            showroom_cars=cars,
                            showroom_sampled_pages=sorted(sampled_page_set),
                            detected_total_pages=detected_total_pages_value,
                            baseline_manifest_urls=dict(baseline_url_map),
                            direct_items=direct_items,
                            set_scheme_applied=True,
                            reused_previous_scheme=reused_previous_scheme,
                            reused_recent_history=reused_recent_history,
                            message=f"Prepared direct Trading Paints asset download for already-active showroom {normalized_kind} scheme {chosen_scheme_id}.",
                        )
                    if direct_items and required_unavailable:
                        return TPShowroomSyncResult(
                            ok=False,
                            chosen_scheme_id=chosen_scheme_id,
                            chosen_title=chosen_title,
                            showroom_count=len(cars),
                            original_scheme_id=captured_original_scheme_id,
                            showroom_cars=cars,
                            set_scheme_applied=True,
                            showroom_sampled_pages=sorted(sampled_page_set),
                            detected_total_pages=detected_total_pages_value,
                            baseline_manifest_urls=dict(baseline_url_map),
                            message=f"The already-active showroom {normalized_kind} exposed manifest URLs, but the required asset was unavailable: {required_unavailable_message}.",
                        )
                if forced_retry_scheme_id and not active_scheme_id:
                    write(
                        f"Trading Paints manifest baseline for {normalized_kind} changed before forced retry setScheme {chosen_scheme_id}, but the active scheme could not be confirmed; keeping the earlier retry baseline so an already-released paint is not missed."
                    )
                else:
                    if forced_retry_scheme_id and active_scheme_id and active_scheme_id != chosen_scheme_id:
                        write(
                            f"Trading Paints manifest baseline for {normalized_kind} changed before forced retry setScheme {chosen_scheme_id}, but the active scheme is {active_scheme_id}; using the freshly observed URLs so a delayed prior swap is not mistaken for this retry."
                        )
                    else:
                        write(
                            f"Trading Paints manifest baseline for {normalized_kind} changed before setScheme {chosen_scheme_id}; using the freshly observed URLs so a delayed prior swap is not mistaken for this pick."
                        )
                    baseline_url_map = dict(refreshed_baseline_url_map)
            else:
                baseline_url_map = dict(refreshed_baseline_url_map)
        activated_via_ui = False
        if force_showroom_ui_activation:
            showroom_link = chosen_showroom_link or _tp_showroom_url_for_scheme_id(chosen_scheme_id, chosen_title)
            write(
                f"Trading Paints showroom {normalized_kind} fallback direct retry is still waiting for scheme {chosen_scheme_id}; trying the visible showroom button as a manual-flow fallback: {showroom_link}"
            )
            activated_via_ui = _tp_try_activate_showroom_view(
                page,
                showroom_link,
                chosen_scheme_id,
                write,
                action_label=f"Trading Paints showroom {normalized_kind} fallback",
                cancel_event=cancel_event,
            )
        if not activated_via_ui:
            set_url = f"https://www.tradingpaints.com/js/setScheme.php?id={chosen_scheme_id}&sub_make=0"
            if not _tp_wait_for_scheme_request_cooldown(
                log=write,
                action_label=f"Trading Paints showroom {normalized_kind} direct request",
                cancel_event=cancel_event,
            ):
                return TPShowroomSyncResult(
                    ok=False,
                    chosen_scheme_id=chosen_scheme_id,
                    chosen_title=chosen_title,
                    showroom_count=len(cars),
                    original_scheme_id=captured_original_scheme_id,
                    showroom_cars=cars,
                    showroom_sampled_pages=sorted(sampled_page_set),
                    detected_total_pages=detected_total_pages_value,
                    baseline_manifest_urls=dict(baseline_url_map),
                    original_scheme_link=captured_original_scheme_link,
                    original_scheme_title=captured_original_scheme_title,
                    message=f"Trading Paints showroom {normalized_kind} request for {chosen_scheme_id} was cancelled while waiting for the {TP_SCHEME_REQUEST_COOLDOWN_SECONDS:.0f}s cooldown.",
                )
            try:
                set_resp = api.get(
                    set_url,
                    headers={
                        "X-Requested-With": "XMLHttpRequest",
                        "Accept": "application/json, text/javascript, */*; q=0.01",
                        "Referer": start_url,
                    },
                    fail_on_status_code=False,
                    timeout=(TP_MULE_SET_SCHEME_TIMEOUT_MS if fast_mule_mode else 30000),
                )
            except Exception as exc:  # noqa: BLE001
                return TPShowroomSyncResult(
                    ok=False,
                    chosen_scheme_id=chosen_scheme_id,
                    chosen_title=chosen_title,
                    showroom_count=len(cars),
                    original_scheme_id=captured_original_scheme_id,
                    showroom_cars=cars,
                    set_scheme_applied=bool(fast_mule_mode),
                    showroom_sampled_pages=sorted(sampled_page_set),
                    detected_total_pages=detected_total_pages_value,
                    baseline_manifest_urls=dict(baseline_url_map),
                    message=f"setScheme request failed for {chosen_scheme_id}: {exc}",
                )
            if not set_resp.ok:
                return TPShowroomSyncResult(
                    ok=False,
                    chosen_scheme_id=chosen_scheme_id,
                    chosen_title=chosen_title,
                    showroom_count=len(cars),
                    original_scheme_id=captured_original_scheme_id,
                    showroom_cars=cars,
                    showroom_sampled_pages=sorted(sampled_page_set),
                    detected_total_pages=detected_total_pages_value,
                    baseline_manifest_urls=dict(baseline_url_map),
                    message=f"setScheme failed with HTTP {set_resp.status} for {chosen_scheme_id}.",
                )
            rejection_message = _tp_set_scheme_rejection_message(set_resp, chosen_scheme_id)
            if rejection_message:
                write(f"Trading Paints {rejection_message}")
                return TPShowroomSyncResult(
                    ok=False,
                    chosen_scheme_id=chosen_scheme_id,
                    chosen_title=chosen_title,
                    showroom_count=len(cars),
                    original_scheme_id=captured_original_scheme_id,
                    showroom_cars=cars,
                    showroom_sampled_pages=sorted(sampled_page_set),
                    detected_total_pages=detected_total_pages_value,
                    baseline_manifest_urls=dict(baseline_url_map),
                    retryable_online_failure=True,
                    message=rejection_message,
                )
        if fast_mule_mode or fast_apply_mode:
            write(f"Trading Paints showroom {normalized_kind} scheme {chosen_scheme_id} was requested; online fallback is skipping the dashboard confirmation loop and polling the manifest directly.")
        else:
            confirm_deadline = time.monotonic() + 8.0
            chosen_scheme_confirmed = False
            while time.monotonic() < confirm_deadline:
                try:
                    active_scheme_id, _active_source = _tp_capture_current_scheme_id(
                        context,
                        page,
                        mid=mid,
                        slug=slug,
                        category=category,
                    )
                except Exception:
                    active_scheme_id = ""
                if active_scheme_id and active_scheme_id == chosen_scheme_id:
                    chosen_scheme_confirmed = True
                    break
                time.sleep(0.9)
            if chosen_scheme_confirmed:
                write(f"Trading Paints showroom {normalized_kind} scheme {chosen_scheme_id} is now active; waiting for manifest refresh.")
            else:
                write(f"Trading Paints showroom {normalized_kind} scheme {chosen_scheme_id} was requested, but the dashboard did not confirm the swap quickly; continuing to poll the manifest anyway.")
        direct_items = _tp_wait_for_fetch_user_manifest_accessory(
            local_user_id=local_member_id,
            paint_type=paint_type,
            retries=retries,
            retry_backoff_seconds=retry_backoff_seconds,
            baseline_urls=baseline_url_map,
            timeout_seconds=(TP_MULE_MANIFEST_TIMEOUT_SECONDS if fast_mule_mode else timeout_seconds),
            log=write,
            cancel_event=cancel_event,
        )
        if not direct_items:
            return TPShowroomSyncResult(
                ok=False,
                chosen_scheme_id=chosen_scheme_id,
                chosen_title=chosen_title,
                showroom_count=len(cars),
                original_scheme_id=captured_original_scheme_id,
                showroom_cars=cars,
                set_scheme_applied=True,
                reused_previous_scheme=reused_previous_scheme,
                reused_recent_history=reused_recent_history,
                showroom_sampled_pages=sorted(sampled_page_set),
                detected_total_pages=detected_total_pages_value,
                baseline_manifest_urls=dict(baseline_url_map),
                message=(
                    f"The showroom {normalized_kind} was selected online, but the local account manifest never exposed fresh {normalized_kind} asset URLs in time."
                ),
            )
        required_unavailable, required_unavailable_message = _tp_required_manifest_assets_unavailable(
            direct_items,
            {paint_type},
        )
        if required_unavailable:
            return TPShowroomSyncResult(
                ok=False,
                chosen_scheme_id=chosen_scheme_id,
                chosen_title=chosen_title,
                showroom_count=len(cars),
                original_scheme_id=captured_original_scheme_id,
                showroom_cars=cars,
                set_scheme_applied=True,
                reused_previous_scheme=reused_previous_scheme,
                reused_recent_history=reused_recent_history,
                showroom_sampled_pages=sorted(sampled_page_set),
                detected_total_pages=detected_total_pages_value,
                baseline_manifest_urls=dict(baseline_url_map),
                message=f"The showroom {normalized_kind} exposed fresh manifest URLs, but the required asset was unavailable: {required_unavailable_message}.",
            )
        return TPShowroomSyncResult(
            ok=True,
            chosen_scheme_id=chosen_scheme_id,
            chosen_title=chosen_title,
            showroom_count=len(cars),
            original_scheme_id=captured_original_scheme_id,
            showroom_cars=cars,
            showroom_sampled_pages=sorted(sampled_page_set),
            detected_total_pages=detected_total_pages_value,
            baseline_manifest_urls=dict(baseline_url_map),
            direct_items=direct_items,
            set_scheme_applied=True,
            reused_previous_scheme=reused_previous_scheme,
            reused_recent_history=reused_recent_history,
            message=f"Prepared direct Trading Paints asset download for showroom {normalized_kind} scheme {chosen_scheme_id}.",
        )
    finally:
        if owned_context and context is not None:
            try:
                context.close()
            except Exception:
                pass
        if owned_context and playwright_manager is not None:
            try:
                playwright_manager.stop()
            except Exception:
                pass


def _process_tp_showroom_fallback_lane(
    *,
    lane_index: int,
    users: list[SessionUser],
    session: Session,
    paints_dir: Path,
    mapping_path: Path | None,
    profile_dir: Path,
    manifest_member_id: int | None,
    effective_primary_fast_mode: bool,
    effective_mule_mode: bool,
    detect_showroom_total_pages: bool,
    retries: int,
    retry_backoff_seconds: float,
    saved_callback: Callable[[list[SavedFile], str], None] | None,
    initial_original_cache_entry: dict[str, object] | None,
    initial_recent_scheme_ids: list[str] | None,
    random_pool_dir: Path,
    ai_livery_root: Path,
    local_fallback_used_source_ids: set[str],
    local_fallback_lock: threading.Lock,
    retry_timed_out_fallbacks_indefinitely: bool = True,
    cancel_event: threading.Event | None = None,
) -> dict[str, object]:
    logs: list[str] = []
    fallback_saved: list[SavedFile] = []
    summary = RandomFallbackSummary(attempted_targets=len(users))
    if not users:
        return {
            'saved': fallback_saved,
            'logs': logs,
            'summary': summary,
            'directory_key': '',
            'recent_scheme_ids': [],
            'original_cache_entry': None,
        }

    first_user = users[0]
    directory_key = canonicalize_car_directory(first_user.directory).lower()
    display_directory = first_user.directory
    temp_root = default_temp_dir()
    recent_scheme_ids = [str(item).strip() for item in (initial_recent_scheme_ids or []) if str(item).strip()]
    cached_original_entry = dict(initial_original_cache_entry or {})
    original_scheme_id = str(cached_original_entry.get('scheme_id') or '').strip()
    original_cache_entry_update: dict[str, str] | None = None
    original_baseline_urls: dict[str, str] | None = None
    current_manifest_urls: dict[str, str] = {}
    original_local_backup: dict[str, bytes] = {}
    used_scheme_ids: set[str] = set()
    touched_directory = False
    pool_state: dict[str, object] = {'cars': [], 'sampled_pages': set(), 'total_pages': 0}
    lane_profile_dir = profile_dir
    lane_profile_cleanup: Path | None = None
    lane_tp_context = None
    lane_tp_page = None
    lane_tp_auth_state: dict[str, object] = {}
    lane_tp_playwright_manager = None
    timed_out_online_retries: list[tuple[SessionUser, TPShowroomSyncResult]] = []
    pre_final_online_retry_seed_by_target: dict[tuple[str, int, str], TPShowroomSyncResult] = {}

    def _apply_local_for_user(user: SessionUser, label: str, *, count_missing: bool = True) -> bool:
        nonlocal fallback_saved
        with local_fallback_lock:
            local_saved_items, local_logs, local_reused_source = _apply_local_tp_random_fallback_assets_for_user(
                session=session,
                user=user,
                paints_dir=paints_dir,
                random_pool_dir=random_pool_dir,
                ai_livery_root=ai_livery_root,
                used_source_ids=local_fallback_used_source_ids,
                need_car=True,
                need_helmet=False,
                need_suit=False,
            )
        logs.extend(local_logs)
        if local_saved_items:
            fallback_saved.extend(local_saved_items)
            summary.applied_targets += 1
            if local_reused_source:
                summary.repeated_source_uses += 1
            if saved_callback is not None:
                try:
                    saved_callback(local_saved_items, 'fallback_local')
                except Exception:
                    logging.debug("Local fallback save callback failed on lane %s", lane_index + 1, exc_info=True)
            return True
        if count_missing:
            summary.missing_source_targets += 1
            logs.append(f"Local random fallback had no usable car source for {'AI' if user.is_ai else 'driver'} {label}; online retry may still be required.")
        return False

    def _apply_online_result_for_user(user: SessionUser, result: TPShowroomSyncResult, label: str) -> bool:
        nonlocal current_manifest_urls
        if result.direct_items:
            current_manifest_urls = dict(result.baseline_manifest_urls or current_manifest_urls or {})
            current_manifest_urls.update(_tp_manifest_url_map(result.direct_items))
        retargeted_items = _tp_retarget_manifest_items_for_user(session, user, result.direct_items)
        retargeted_items = _annotate_download_files_with_tp_source(
            retargeted_items,
            scheme_id=result.chosen_scheme_id,
            title=result.chosen_title,
            source_link=_tp_showroom_link_for_sync_result(result),
            source="showroom",
        )
        if not retargeted_items:
            summary.missing_source_targets += 1
            logs.append(f"Trading Paints showroom fallback selected a scheme for {user.directory}, but the current account manifest did not expose any usable car files.")
            return False

        downloaded_items: list[DownloadedFile] = []
        for ordinal, item in enumerate(retargeted_items, start=1):
            downloaded = download_file(
                session.session_id,
                temp_root,
                item,
                retries,
                retry_backoff_seconds,
                ordinal=ordinal,
                total=len(retargeted_items),
                cancel_event=cancel_event,
            )
            if downloaded is not None:
                downloaded_items.append(downloaded)

        applied_items: list[SavedFile] = []
        for downloaded in downloaded_items:
            saved_items = move_or_extract(downloaded, paints_dir, retries=retries, retry_backoff_seconds=retry_backoff_seconds, cancel_event=cancel_event)
            if saved_items:
                fallback_saved.extend(saved_items)
                applied_items.extend(saved_items)

        if applied_items:
            if saved_callback is not None and not _cancel_requested(cancel_event):
                try:
                    saved_callback(applied_items, 'fallback_online')
                except Exception:
                    logging.debug("Online fallback save callback failed on lane %s", lane_index + 1, exc_info=True)
            summary.applied_targets += 1
            logs.append(
                f"Trading Paints showroom fallback applied to {'AI' if user.is_ai else 'driver'} {label} on {user.directory} using scheme {result.chosen_scheme_id} ({result.chosen_title})"
            )
            return True

        summary.missing_source_targets += 1
        logs.append(f"Trading Paints showroom fallback selected a scheme for {user.directory}, but nothing could be downloaded or saved into the target paint slots.")
        return False

    if original_scheme_id:
        logs.append(f"Using cached Trading Paints original scheme for {display_directory}: {original_scheme_id}")

    if (not effective_mule_mode):
        try:
            original_local_backup = _capture_local_tp_backup(
                _candidate_local_tp_paths(
                    paints_dir,
                    [display_directory, directory_key],
                    session.local_user_id,
                    session.local_team_id,
                )
            )
        except Exception:
            original_local_backup = {}

    if sync_playwright is not None:
        try:
            lane_profile_dir, lane_profile_cleanup = _clone_tp_profile_for_fallback_lane(profile_dir, f"lane{lane_index+1}_{directory_key}")
        except Exception:
            logging.debug("Could not clone Trading Paints browser profile for fallback lane %s", lane_index + 1, exc_info=True)
            lane_profile_dir = profile_dir
            lane_profile_cleanup = None
        try:
            lane_tp_playwright_manager = sync_playwright()
            lane_tp_browser = lane_tp_playwright_manager.start()
            lane_tp_playwright_manager = lane_tp_browser
            lane_tp_context, _launch_target = launch_tp_persistent_context(
                lane_tp_browser.chromium,
                user_data_dir=str(lane_profile_dir),
                browser_channel='chrome',
                headless=True,
                viewport={'width': 1280, 'height': 900},
            )
            lane_tp_page = lane_tp_context.pages[0] if lane_tp_context.pages else lane_tp_context.new_page()
        except Exception:
            logging.debug("Could not open Trading Paints browser context for fallback lane %s; falling back to per-call contexts", lane_index + 1, exc_info=True)
            lane_tp_page = None
            if lane_tp_context is not None:
                try:
                    lane_tp_context.close()
                except Exception:
                    pass
            lane_tp_context = None
            if lane_tp_playwright_manager is not None:
                try:
                    lane_tp_playwright_manager.stop()
                except Exception:
                    pass
            lane_tp_playwright_manager = None

    try:
        pending_users = list(users)
        online_apply_attempts_by_target: Counter[tuple[str, int, str]] = Counter()
        online_retry_started_at: dict[tuple[str, int, str], float] = {}
        online_next_attempt_at: dict[tuple[str, int, str], float] = {}
        while pending_users:
            if _cancel_requested(cancel_event):
                logs.append("Trading Paints showroom fallback lane cancelled because the iRacing session changed or ended.")
                break
            user = _wait_for_next_ready_tp_target(pending_users, online_next_attempt_at, cancel_event)
            if user is None:
                continue
            target_key = user.effective_target_key()
            current_attempt_count = int(online_apply_attempts_by_target.get(target_key, 0) or 0)
            target_is_team = session_user_uses_team_target(user)
            target_id = int(user.team_id) if target_is_team else int(user.user_id)
            label = user.display_name or (f"AI {target_id}" if user.is_ai else f"user {target_id}")
            remaining_targets = max(1, len(pending_users) + 1)
            result = None
            pre_final_retry_seed = pre_final_online_retry_seed_by_target.get(target_key)
            is_pre_final_retry_attempt = pre_final_retry_seed is not None
            attempt_excluded_scheme_ids = set(used_scheme_ids)
            if is_pre_final_retry_attempt:
                attempt_excluded_scheme_ids.discard(str(pre_final_retry_seed.chosen_scheme_id or "").strip())
            max_online_apply_attempts = 1
            attempts_this_pass = 1 if effective_mule_mode else max(1, max_online_apply_attempts - current_attempt_count)
            deferred_for_online_retry = False
            for attempt_offset in range(attempts_this_pass):
                online_apply_attempt = current_attempt_count + attempt_offset + 1
                online_apply_attempts_by_target[target_key] = max(
                    int(online_apply_attempts_by_target.get(target_key, 0) or 0),
                    online_apply_attempt,
                )
                forced_scheme_id = str(pre_final_retry_seed.chosen_scheme_id or "").strip() if is_pre_final_retry_attempt else ""
                forced_scheme_title = str(pre_final_retry_seed.chosen_title or "").strip() if is_pre_final_retry_attempt else ""
                baseline_override = (
                    current_manifest_urls
                    or (dict(pre_final_retry_seed.baseline_manifest_urls or {}) if is_pre_final_retry_attempt else None)
                )
                try:
                    result = choose_and_sync_showroom_paint(
                        directory=user.directory,
                        mapping_path=mapping_path,
                        profile_dir=lane_profile_dir,
                        paints_dir=paints_dir,
                        manifest_member_id=manifest_member_id,
                        local_team_id=session.local_team_id,
                        retries=retries,
                        retry_backoff_seconds=retry_backoff_seconds,
                        original_scheme_id=original_scheme_id,
                        exclude_scheme_ids=attempt_excluded_scheme_ids,
                        exclude_recent_scheme_ids=set(recent_scheme_ids),
                        showroom_cars=pool_state.get('cars') if isinstance(pool_state.get('cars'), list) else [],
                        showroom_sampled_pages=pool_state.get('sampled_pages') if isinstance(pool_state.get('sampled_pages'), set) else set(pool_state.get('sampled_pages') or []),
                        detected_total_pages=int(pool_state.get('total_pages') or 0),
                        detect_total_pages=bool(detect_showroom_total_pages),
                        minimum_unused_choices=remaining_targets,
                        log=logging.info,
                        shared_context=lane_tp_context,
                        shared_page=lane_tp_page,
                        shared_auth_state=lane_tp_auth_state,
                        fast_mule_mode=bool(effective_mule_mode),
                        fast_apply_mode=bool(effective_mule_mode or effective_primary_fast_mode),
                        baseline_manifest_urls_override=baseline_override,
                        forced_scheme_id=forced_scheme_id,
                        forced_scheme_title=forced_scheme_title,
                        timeout_seconds=TP_ONLINE_FALLBACK_TARGET_TIMEOUT_SECONDS,
                        cancel_event=cancel_event,
                        superspeedway_variant=bool(session.is_superspeedway_track),
                    )
                except Exception as exc:  # noqa: BLE001
                    logs.append(f"Trading Paints showroom fallback errored for {'AI' if user.is_ai else 'driver'} {label} on {user.directory}: {exc}")
                    logging.debug("Trading Paints showroom fallback exception on lane %s", lane_index + 1, exc_info=True)
                    result = None
                    break

                if result is None:
                    break
                if result.chosen_scheme_id:
                    chosen_attempt_scheme_id = str(result.chosen_scheme_id).strip()
                    if chosen_attempt_scheme_id:
                        attempt_excluded_scheme_ids.add(chosen_attempt_scheme_id)
                        used_scheme_ids.add(chosen_attempt_scheme_id)
                should_retry_online_apply = bool((not result.ok) and (result.set_scheme_applied or result.retryable_online_failure))
                if should_retry_online_apply:
                    if effective_mule_mode:
                        now = time.monotonic()
                        retry_started_at = online_retry_started_at.setdefault(target_key, now)
                        elapsed = now - retry_started_at
                        if elapsed < TP_MULE_PER_TARGET_TIMEOUT_SECONDS:
                            cooldown_seconds = compute_mule_retry_cooldown(online_apply_attempt)
                            online_next_attempt_at[target_key] = time.monotonic() + cooldown_seconds
                            pending_users.append(user)
                            deferred_for_online_retry = True
                            logs.append(
                                f"Trading Paints showroom fallback online attempt {online_apply_attempt} did not produce usable files for {'AI' if user.is_ai else 'driver'} {label} on {user.directory}; Nishizumi Paints will revisit this target after other online targets or a {cooldown_seconds:.1f}s cooldown for up to {TP_MULE_PER_TARGET_TIMEOUT_SECONDS / 60:.0f} minute(s)."
                            )
                            break
                    elif online_apply_attempt < max_online_apply_attempts:
                        logs.append(
                            f"Trading Paints showroom fallback apply attempt {online_apply_attempt}/{max_online_apply_attempts} did not produce usable files for {'AI' if user.is_ai else 'driver'} {label} on {user.directory}. This can happen with PRO-only paints, so Nishizumi Paints will try another showroom scheme."
                        )
                        continue
                    break
                break

            if deferred_for_online_retry:
                continue
            if result is None:
                summary.missing_source_targets += 1
                continue

            retry_started_at = online_retry_started_at.get(target_key)
            if result.ok and retry_started_at is not None:
                elapsed = time.monotonic() - retry_started_at
                logs.append(
                    f"Trading Paints showroom fallback recovered fresh manifest files for {'AI' if user.is_ai else 'driver'} {label} on {user.directory} after {elapsed:.1f}s and {online_apply_attempts_by_target[target_key]} online attempt(s)."
                )
                online_retry_started_at.pop(target_key, None)
                online_next_attempt_at.pop(target_key, None)

            if result.showroom_cars:
                pool_state['cars'] = [item for item in result.showroom_cars if isinstance(item, dict)]
                pool_state['sampled_pages'] = set(int(p) for p in (result.showroom_sampled_pages or []) if str(p).strip())
                if int(getattr(result, 'detected_total_pages', 0) or 0) > 0:
                    pool_state['total_pages'] = int(getattr(result, 'detected_total_pages', 0) or 0)

            if (not effective_mule_mode) and result.original_scheme_id and not original_scheme_id:
                original_scheme_id = str(result.original_scheme_id or '').strip()
                original_cache_entry_update = {
                    'scheme_id': original_scheme_id,
                    'showroom_link': str(result.original_scheme_link or '').strip(),
                    'title': str(result.original_scheme_title or '').strip(),
                    'captured_at': time.strftime('%Y-%m-%dT%H:%M:%S'),
                    'source': 'dashboard',
                }
                link_extra = f" -> {str(result.original_scheme_link or '').strip()}" if str(result.original_scheme_link or '').strip() else ''
                logs.append(f"Captured original Trading Paints scheme for {user.directory}: {original_scheme_id}{link_extra}")

            if result.baseline_manifest_urls and original_baseline_urls is None:
                original_baseline_urls = dict(result.baseline_manifest_urls)
            if result.set_scheme_applied:
                touched_directory = True
            if result.chosen_scheme_id:
                chosen_scheme_id = str(result.chosen_scheme_id).strip()
                used_scheme_ids.add(chosen_scheme_id)
                if result.ok:
                    recent_history_payload = {directory_key: list(recent_scheme_ids)}
                    remember_tp_recent_scheme(recent_history_payload, directory_key, chosen_scheme_id)
                    recent_scheme_ids = list(recent_history_payload.get(directory_key, []))
            if result.reused_previous_scheme:
                summary.repeated_source_uses += 1

            if _cancel_requested(cancel_event):
                logs.append(f"Trading Paints showroom fallback stopped before applying local or online files for {'AI' if user.is_ai else 'driver'} {label} because the iRacing session changed or ended.")
                break

            if result.ok and is_pre_final_retry_attempt:
                pre_final_online_retry_seed_by_target.pop(target_key, None)
                online_next_attempt_at.pop(target_key, None)
                logs.append(
                    f"Trading Paints showroom fallback recovered {'AI' if user.is_ai else 'driver'} {label} on {user.directory} with delayed retry scheme {result.chosen_scheme_id} after {TP_ONLINE_FALLBACK_PRE_FINAL_RETRY_DELAY_SECONDS:.0f}s."
                )

            if not result.ok:
                if getattr(result, 'force_local_fallback', False) or bool(result.set_scheme_applied) or bool(result.retryable_online_failure):
                    retry_started_at = online_retry_started_at.pop(target_key, None)
                    if retry_started_at is not None:
                        elapsed = time.monotonic() - retry_started_at
                        logs.append(
                            f"Trading Paints showroom fallback did not recover fresh manifest files for {'AI' if user.is_ai else 'driver'} {label} on {user.directory} after {elapsed:.1f}s and {online_apply_attempts_by_target[target_key]} online attempt(s)."
                        )
                    if getattr(result, 'force_local_fallback', False):
                        logs.append(f"Trading Paints showroom fallback intentionally deferred {'AI' if user.is_ai else 'driver'} {label} on {user.directory} to the local random pool: {result.message}")
                    elif result.retryable_online_failure:
                        logs.append(
                            f"Trading Paints showroom fallback could not apply a usable online paint for {'AI' if user.is_ai else 'driver'} {label} on {user.directory} after {max_online_apply_attempts} attempt(s). Nishizumi Paints will skip this online target and use the local random pool instead. Last result: {result.message}"
                        )
                    else:
                        if effective_mule_mode and retry_started_at is not None:
                            logs.append(
                                f"Trading Paints showroom fallback could not apply a usable online paint for {'AI' if user.is_ai else 'driver'} {label} on {user.directory} after the {TP_MULE_PER_TARGET_TIMEOUT_SECONDS / 60:.0f}-minute MULE retry window. Nishizumi Paints will skip this online target and use the local random pool instead. Last result: {result.message}"
                            )
                        else:
                            logs.append(
                                f"Trading Paints showroom fallback timed out for {'AI' if user.is_ai else 'driver'} {label} on {user.directory} after {TP_ONLINE_FALLBACK_TARGET_TIMEOUT_SECONDS:.0f}s. Last result: {result.message}"
                            )
                    if _cancel_requested(cancel_event):
                        break
                    can_retry_same_scheme_later = bool(
                        result.set_scheme_applied
                        and result.chosen_scheme_id
                        and not getattr(result, 'force_local_fallback', False)
                        and not bool(result.retryable_online_failure)
                    )
                    if can_retry_same_scheme_later and not effective_mule_mode and not is_pre_final_retry_attempt:
                        pre_final_online_retry_seed_by_target[target_key] = result
                        online_next_attempt_at[target_key] = time.monotonic() + TP_ONLINE_FALLBACK_PRE_FINAL_RETRY_DELAY_SECONDS
                        pending_users.append(user)
                        next_stage_label = "the final retry stage" if retry_timed_out_fallbacks_indefinitely else "the local random pool"
                        logs.append(
                            f"Trading Paints showroom fallback will retry scheme {result.chosen_scheme_id} once more for {'AI' if user.is_ai else 'driver'} {label} on {user.directory} after {TP_ONLINE_FALLBACK_PRE_FINAL_RETRY_DELAY_SECONDS:.0f}s before sending it to {next_stage_label}."
                        )
                        continue
                    if is_pre_final_retry_attempt:
                        pre_final_online_retry_seed_by_target.pop(target_key, None)
                        online_next_attempt_at.pop(target_key, None)
                    if can_retry_same_scheme_later and retry_timed_out_fallbacks_indefinitely:
                        timed_out_online_retries.append((user, result))
                        logs.append(
                            f"Trading Paints showroom fallback will retry scheme {result.chosen_scheme_id} for {'AI' if user.is_ai else 'driver'} {label} at the end for up to {TP_ONLINE_FALLBACK_FINAL_MAX_SECONDS / 60:.0f} minute(s) before using the local random pool."
                        )
                    elif can_retry_same_scheme_later:
                        _apply_local_for_user(user, label)
                    else:
                        _apply_local_for_user(user, label)
                    continue
                summary.missing_source_targets += 1
                logs.append(f"Trading Paints showroom fallback could not fill {'AI' if user.is_ai else 'driver'} {label} on {user.directory}: {result.message}")
                continue

            _apply_online_result_for_user(user, result, label)

        if timed_out_online_retries and not _cancel_requested(cancel_event):
            logs.append(
                f"Trading Paints online fallback final retry stage queued {len(timed_out_online_retries)} timed-out car target(s); each will retry for up to {TP_ONLINE_FALLBACK_FINAL_MAX_SECONDS / 60:.0f} minute(s) before using the local random pool."
            )
        for retry_user, retry_seed_result in timed_out_online_retries:
            if _cancel_requested(cancel_event):
                break
            target_is_team = session_user_uses_team_target(retry_user)
            target_id = int(retry_user.team_id) if target_is_team else int(retry_user.user_id)
            label = retry_user.display_name or (f"AI {target_id}" if retry_user.is_ai else f"user {target_id}")
            retry_attempt = 0
            final_retry_started_at = time.monotonic()
            final_retry_succeeded = False
            final_retry_auth_failed = False
            while not _cancel_requested(cancel_event) and (time.monotonic() - final_retry_started_at) < TP_ONLINE_FALLBACK_FINAL_MAX_SECONDS:
                retry_attempt += 1
                try:
                    retry_result = choose_and_sync_showroom_paint(
                        directory=retry_user.directory,
                        mapping_path=mapping_path,
                        profile_dir=lane_profile_dir,
                        paints_dir=paints_dir,
                        manifest_member_id=manifest_member_id,
                        local_team_id=session.local_team_id,
                        retries=retries,
                        retry_backoff_seconds=retry_backoff_seconds,
                        original_scheme_id=original_scheme_id,
                        exclude_scheme_ids=set(),
                        exclude_recent_scheme_ids=set(recent_scheme_ids),
                        showroom_cars=pool_state.get('cars') if isinstance(pool_state.get('cars'), list) else [],
                        showroom_sampled_pages=pool_state.get('sampled_pages') if isinstance(pool_state.get('sampled_pages'), set) else set(pool_state.get('sampled_pages') or []),
                        detected_total_pages=int(pool_state.get('total_pages') or 0),
                        detect_total_pages=bool(detect_showroom_total_pages),
                        minimum_unused_choices=1,
                        log=logging.info,
                        shared_context=lane_tp_context,
                        shared_page=lane_tp_page,
                        shared_auth_state=lane_tp_auth_state,
                        fast_mule_mode=bool(effective_mule_mode),
                        fast_apply_mode=bool(effective_mule_mode or effective_primary_fast_mode),
                        baseline_manifest_urls_override=current_manifest_urls or dict(retry_seed_result.baseline_manifest_urls or {}),
                        forced_scheme_id=str(retry_seed_result.chosen_scheme_id or ""),
                        forced_scheme_title=str(retry_seed_result.chosen_title or ""),
                        force_showroom_ui_activation=retry_attempt >= TP_ONLINE_FALLBACK_FINAL_UI_RETRY_AFTER_ATTEMPTS,
                        timeout_seconds=TP_ONLINE_FALLBACK_FINAL_POLL_SECONDS,
                        cancel_event=cancel_event,
                        superspeedway_variant=bool(session.is_superspeedway_track),
                    )
                except Exception as exc:  # noqa: BLE001
                    retry_result = TPShowroomSyncResult(ok=False, chosen_scheme_id=retry_seed_result.chosen_scheme_id, chosen_title=retry_seed_result.chosen_title, message=str(exc), set_scheme_applied=True)
                    logging.debug("Trading Paints final retry exception on lane %s", lane_index + 1, exc_info=True)
                if retry_result.ok and _apply_online_result_for_user(retry_user, retry_result, label):
                    final_retry_succeeded = True
                    logs.append(
                        f"Trading Paints final retry succeeded for {'AI' if retry_user.is_ai else 'driver'} {label} on {retry_user.directory} using scheme {retry_result.chosen_scheme_id} after {retry_attempt} final attempt(s)."
                    )
                    if retry_result.chosen_scheme_id:
                        recent_history_payload = {directory_key: list(recent_scheme_ids)}
                        remember_tp_recent_scheme(recent_history_payload, directory_key, str(retry_result.chosen_scheme_id))
                        recent_scheme_ids = list(recent_history_payload.get(directory_key, []))
                    break
                if retry_result.auth_required:
                    final_retry_auth_failed = True
                    summary.missing_source_targets += 1
                    logs.append(
                        f"Trading Paints final retry stopped for {'AI' if retry_user.is_ai else 'driver'} {label} because the saved Trading Paints login is no longer authenticated."
                    )
                    break
                final_retry_elapsed = time.monotonic() - final_retry_started_at
                final_retry_remaining = max(0.0, TP_ONLINE_FALLBACK_FINAL_MAX_SECONDS - final_retry_elapsed)
                logs.append(
                    f"Trading Paints final retry attempt {retry_attempt} is still waiting for {'AI' if retry_user.is_ai else 'driver'} {label} on {retry_user.directory} using scheme {retry_seed_result.chosen_scheme_id}; {final_retry_remaining:.0f}s left before local fallback."
                )
                wait_seconds = min(TP_ONLINE_FALLBACK_FINAL_RETRY_COOLDOWN_SECONDS, final_retry_remaining)
                if wait_seconds <= 0:
                    break
                if cancel_event is not None:
                    cancel_event.wait(wait_seconds)
                else:
                    time.sleep(wait_seconds)
            if (
                not final_retry_succeeded
                and not final_retry_auth_failed
                and not _cancel_requested(cancel_event)
            ):
                logs.append(
                    f"Trading Paints final retry timed out for {'AI' if retry_user.is_ai else 'driver'} {label} on {retry_user.directory} using scheme {retry_seed_result.chosen_scheme_id} after {TP_ONLINE_FALLBACK_FINAL_MAX_SECONDS / 60:.0f} minute(s). Using the local random pool."
                )
                _apply_local_for_user(retry_user, label)

        if _cancel_requested(cancel_event):
            logs.append(f"Trading Paints showroom fallback restore skipped for {display_directory} because the iRacing session changed or ended.")
            return {
                'saved': fallback_saved,
                'logs': logs,
                'summary': summary,
                'directory_key': directory_key,
                'recent_scheme_ids': recent_scheme_ids,
                'original_cache_entry': original_cache_entry_update,
            }

        if effective_mule_mode:
            if touched_directory:
                logs.append(f"Trading Paints original scheme restore skipped for {display_directory} because this profile is using a compatibility path that does not restore the original scheme automatically.")
            return {
                'saved': fallback_saved,
                'logs': logs,
                'summary': summary,
                'directory_key': directory_key,
                'recent_scheme_ids': recent_scheme_ids,
                'original_cache_entry': original_cache_entry_update,
            }

        if touched_directory:
            if not original_scheme_id:
                logs.append(f"Trading Paints original scheme was not captured for {display_directory}. This usually means the active TP paint does not expose a showroom link, so the app will skip the dashboard restore and fall back to the local file backup restore path instead.")
                restore_message = f"Trading Paints original scheme restore skipped for {display_directory}: no showroom-linked original scheme id was captured."
                logs.append(restore_message)
            else:
                try:
                    restored, restore_message = restore_tp_showroom_scheme(
                        directory=display_directory,
                        scheme_id=original_scheme_id,
                        showroom_link=str((original_cache_entry_update or cached_original_entry or {}).get('showroom_link') or '').strip(),
                        mapping_path=mapping_path,
                        profile_dir=lane_profile_dir,
                        manifest_member_id=manifest_member_id,
                        baseline_manifest_urls=original_baseline_urls,
                        retries=retries,
                        retry_backoff_seconds=retry_backoff_seconds,
                        log=logging.info,
                        shared_context=lane_tp_context,
                        shared_page=lane_tp_page,
                        shared_auth_state=lane_tp_auth_state,
                    )
                except Exception as exc:  # noqa: BLE001
                    restored = False
                    restore_message = f"Trading Paints original scheme restore errored for {display_directory}: {exc}"
                    logging.debug("Trading Paints original scheme restore exception on lane %s", lane_index + 1, exc_info=True)
                logs.append(restore_message)

            restored_local_any = False
            if session.local_user_id is not None and int(session.local_user_id or 0) > 0:
                try:
                    refreshed_items = _tp_wait_for_fetch_user_manifest_match(
                        local_user_id=int(session.local_user_id),
                        directory=display_directory,
                        retries=retries,
                        retry_backoff_seconds=retry_backoff_seconds,
                        baseline_urls=original_baseline_urls,
                        timeout_seconds=10.0,
                        log=logging.info,
                        cancel_event=cancel_event,
                        superspeedway_variant=bool(session.is_superspeedway_track),
                    )
                    if refreshed_items:
                        restored_downloads: list[DownloadedFile] = []
                        for ordinal, item in enumerate(refreshed_items, start=1):
                            downloaded = download_file(
                                session.session_id,
                                temp_root,
                                item,
                                retries,
                                retry_backoff_seconds,
                                ordinal=ordinal,
                                total=len(refreshed_items),
                                cancel_event=cancel_event,
                            )
                            if downloaded is not None:
                                restored_downloads.append(downloaded)
                        for downloaded in restored_downloads:
                            saved_items = move_or_extract(downloaded, paints_dir, retries=retries, retry_backoff_seconds=retry_backoff_seconds, cancel_event=cancel_event)
                            if saved_items:
                                restored_local_any = True
                        if restored_local_any:
                            logs.append(f"Trading Paints original local files restored for {display_directory} (user {session.local_user_id}) using fresh manifest URLs.")
                except Exception as exc:  # noqa: BLE001
                    logging.debug("Trading Paints original local file restore exception on lane %s", lane_index + 1, exc_info=True)
                    logs.append(f"Trading Paints original local files could not be restored from fresh manifest for {display_directory}: {exc}")
            if not restored_local_any and original_local_backup:
                try:
                    if _restore_local_tp_backup(original_local_backup):
                        restored_local_any = True
                        logs.append(f"Trading Paints original local files restored for {display_directory} from local backup.")
                except Exception as exc:  # noqa: BLE001
                    logging.debug("Trading Paints local backup restore exception on lane %s", lane_index + 1, exc_info=True)
                    logs.append(f"Trading Paints original local backup restore failed for {display_directory}: {exc}")

        return {
            'saved': fallback_saved,
            'logs': logs,
            'summary': summary,
            'directory_key': directory_key,
            'recent_scheme_ids': recent_scheme_ids,
            'original_cache_entry': original_cache_entry_update,
        }
    finally:
        if lane_tp_context is not None:
            try:
                lane_tp_context.close()
            except Exception:
                pass
        if lane_tp_playwright_manager is not None:
            try:
                lane_tp_playwright_manager.stop()
            except Exception:
                pass
        if lane_profile_cleanup is not None:
            shutil.rmtree(lane_profile_cleanup, ignore_errors=True)



def _process_tp_showroom_accessory_targets(
    *,
    accessory_kind: str,
    users: list[SessionUser],
    session: Session,
    paints_dir: Path,
    profile_dir: Path,
    manifest_member_id: int | None,
    effective_primary_fast_mode: bool,
    effective_mule_mode: bool,
    detect_showroom_total_pages: bool,
    retries: int,
    retry_backoff_seconds: float,
    saved_callback: Callable[[list[SavedFile], str], None] | None,
    initial_recent_scheme_ids: list[str] | None,
    random_pool_dir: Path,
    ai_livery_root: Path,
    local_fallback_used_source_ids: set[str],
    local_fallback_lock: threading.Lock,
    retry_timed_out_fallbacks_indefinitely: bool = True,
    cancel_event: threading.Event | None = None,
) -> dict[str, object]:
    logs: list[str] = []
    fallback_saved: list[SavedFile] = []
    summary = RandomFallbackSummary(attempted_targets=len(users))
    normalized_kind = str(accessory_kind or "").strip().lower()
    if normalized_kind not in {"helmet", "suit"} or not users:
        return {
            "saved": fallback_saved,
            "logs": logs,
            "summary": summary,
            "recent_scheme_ids": [],
            "cache_key": TP_DRIVER_HELMET_CACHE_KEY if normalized_kind == "helmet" else TP_DRIVER_SUIT_CACHE_KEY,
        }

    paint_type = PaintType.HELMET if normalized_kind == "helmet" else PaintType.SUIT
    cache_key = TP_DRIVER_HELMET_CACHE_KEY if normalized_kind == "helmet" else TP_DRIVER_SUIT_CACHE_KEY
    mid = 118 if normalized_kind == "helmet" else 119
    slug = "Helmets" if normalized_kind == "helmet" else "Suits"
    temp_root = default_temp_dir()
    recent_scheme_ids = [str(item).strip() for item in (initial_recent_scheme_ids or []) if str(item).strip()]
    original_scheme_id = ""
    baseline_manifest_urls: dict[str, str] | None = None
    current_manifest_urls: dict[str, str] = {}
    original_local_backup: dict[str, bytes] = {}
    used_scheme_ids: set[str] = set()
    touched_accessory = False
    pool_state: dict[str, object] = {"cars": [], "sampled_pages": set(), "total_pages": 0}
    accessory_profile_dir = profile_dir
    accessory_profile_cleanup: Path | None = None
    accessory_tp_context = None
    accessory_tp_page = None
    accessory_tp_auth_state: dict[str, object] = {}
    accessory_tp_playwright_manager = None
    timed_out_online_retries: list[tuple[SessionUser, TPShowroomSyncResult]] = []
    pre_final_online_retry_seed_by_target: dict[tuple[str, int, str], TPShowroomSyncResult] = {}

    if not effective_mule_mode:
        try:
            original_local_backup = _capture_local_tp_backup(
                _candidate_local_driver_accessory_paths(
                    paints_dir,
                    session.local_user_id,
                    session.local_team_id,
                    normalized_kind,
                )
            )
        except Exception:
            original_local_backup = {}

    if sync_playwright is not None:
        try:
            accessory_profile_dir, accessory_profile_cleanup = _clone_tp_profile_for_fallback_lane(profile_dir, f"{normalized_kind}_lane")
        except Exception:
            logging.debug("Could not clone Trading Paints browser profile for %s fallback lane", normalized_kind, exc_info=True)
            accessory_profile_dir = profile_dir
            accessory_profile_cleanup = None
        try:
            accessory_tp_playwright_manager = sync_playwright()
            accessory_tp_browser = accessory_tp_playwright_manager.start()
            accessory_tp_playwright_manager = accessory_tp_browser
            accessory_tp_context, _launch_target = launch_tp_persistent_context(
                accessory_tp_browser.chromium,
                user_data_dir=str(accessory_profile_dir),
                browser_channel="chrome",
                headless=True,
                viewport={"width": 1280, "height": 900},
            )
            accessory_tp_page = accessory_tp_context.pages[0] if accessory_tp_context.pages else accessory_tp_context.new_page()
        except Exception:
            logging.debug("Could not open Trading Paints browser context for %s fallback lane", normalized_kind, exc_info=True)
            accessory_tp_page = None
            if accessory_tp_context is not None:
                try:
                    accessory_tp_context.close()
                except Exception:
                    pass
            accessory_tp_context = None
            if accessory_tp_playwright_manager is not None:
                try:
                    accessory_tp_playwright_manager.stop()
                except Exception:
                    pass
            accessory_tp_playwright_manager = None

    def _apply_local_for_user(user: SessionUser, *, count_missing: bool = True) -> bool:
        nonlocal fallback_saved
        if _cancel_requested(cancel_event):
            return False
        with local_fallback_lock:
            local_saved_items, local_logs, local_reused_source = _apply_local_tp_random_fallback_assets_for_user(
                session=session,
                user=user,
                paints_dir=paints_dir,
                random_pool_dir=random_pool_dir,
                ai_livery_root=ai_livery_root,
                used_source_ids=local_fallback_used_source_ids,
                need_car=False,
                need_helmet=(normalized_kind == "helmet"),
                need_suit=(normalized_kind == "suit"),
            )
        if local_saved_items:
            fallback_saved.extend(local_saved_items)
            summary.applied_targets += 1
            if local_reused_source:
                summary.repeated_source_uses += 1
            if saved_callback is not None:
                try:
                    saved_callback(local_saved_items, "fallback_local")
                except Exception:
                    logging.debug("Local accessory fallback save callback failed", exc_info=True)
            logs.extend(local_logs)
            return True
        else:
            if count_missing:
                summary.missing_source_targets += 1
        logs.extend(local_logs)
        return False

    def _apply_online_result_for_user(user: SessionUser, result: TPShowroomSyncResult, label: str) -> bool:
        nonlocal current_manifest_urls
        if result.direct_items:
            current_manifest_urls = dict(result.baseline_manifest_urls or current_manifest_urls or {})
            current_manifest_urls.update(_tp_manifest_url_map(result.direct_items))
        retargeted_items = _tp_retarget_manifest_accessory_items_for_user(user, result.direct_items, paint_type)
        retargeted_items = _annotate_download_files_with_tp_source(
            retargeted_items,
            scheme_id=result.chosen_scheme_id,
            title=result.chosen_title,
            source_link=_tp_showroom_link_for_sync_result(result),
            source="showroom",
        )
        if not retargeted_items:
            logs.append(f"Trading Paints showroom {normalized_kind} fallback selected a scheme, but the current account manifest did not expose any usable {normalized_kind} files.")
            _apply_local_for_user(user)
            return False

        downloaded_items: list[DownloadedFile] = []
        for ordinal, item in enumerate(retargeted_items, start=1):
            downloaded = download_file(
                session.session_id,
                temp_root,
                item,
                retries,
                retry_backoff_seconds,
                ordinal=ordinal,
                total=len(retargeted_items),
                cancel_event=cancel_event,
            )
            if downloaded is not None:
                downloaded_items.append(downloaded)

        applied_items: list[SavedFile] = []
        for downloaded in downloaded_items:
            saved_items = move_or_extract(downloaded, paints_dir, retries=retries, retry_backoff_seconds=retry_backoff_seconds, cancel_event=cancel_event)
            if saved_items:
                fallback_saved.extend(saved_items)
                applied_items.extend(saved_items)

        if applied_items:
            if saved_callback is not None and not _cancel_requested(cancel_event):
                try:
                    saved_callback(applied_items, "fallback_online")
                except Exception:
                    logging.debug("Online accessory fallback save callback failed", exc_info=True)
            summary.applied_targets += 1
            logs.append(f"Trading Paints showroom {normalized_kind} fallback applied to {'AI' if user.is_ai else 'driver'} {label} using scheme {result.chosen_scheme_id} ({result.chosen_title})")
            return True

        logs.append(f"Trading Paints showroom {normalized_kind} fallback selected a scheme for {'AI' if user.is_ai else 'driver'} {label}, but nothing could be downloaded or saved.")
        _apply_local_for_user(user)
        return False

    try:
        accessory_fast_mode = bool(effective_mule_mode or effective_primary_fast_mode)
        pending_users = list(users)
        online_apply_attempts_by_target: Counter[tuple[str, int, str]] = Counter()
        online_retry_started_at: dict[tuple[str, int, str], float] = {}
        online_next_attempt_at: dict[tuple[str, int, str], float] = {}
        while pending_users:
            if _cancel_requested(cancel_event):
                logs.append(f"Trading Paints showroom {normalized_kind} fallback lane cancelled because the iRacing session changed or ended.")
                break
            user = _wait_for_next_ready_tp_target(pending_users, online_next_attempt_at, cancel_event)
            if user is None:
                continue
            target_key = user.effective_target_key()
            current_attempt_count = int(online_apply_attempts_by_target.get(target_key, 0) or 0)
            target_is_team = session_user_uses_team_target(user)
            target_id = int(user.team_id) if target_is_team else int(user.user_id)
            label = user.display_name or (f"AI {target_id}" if user.is_ai else f"user {target_id}")
            remaining_targets = max(1, len(pending_users) + 1)
            result = None
            pre_final_retry_seed = pre_final_online_retry_seed_by_target.get(target_key)
            is_pre_final_retry_attempt = pre_final_retry_seed is not None
            attempt_excluded_scheme_ids = set(used_scheme_ids)
            if is_pre_final_retry_attempt:
                attempt_excluded_scheme_ids.discard(str(pre_final_retry_seed.chosen_scheme_id or "").strip())
            max_online_apply_attempts = 1
            attempts_this_pass = 1 if effective_mule_mode else max(1, max_online_apply_attempts - current_attempt_count)
            deferred_for_online_retry = False
            for attempt_offset in range(attempts_this_pass):
                online_apply_attempt = current_attempt_count + attempt_offset + 1
                online_apply_attempts_by_target[target_key] = max(
                    int(online_apply_attempts_by_target.get(target_key, 0) or 0),
                    online_apply_attempt,
                )
                forced_scheme_id = str(pre_final_retry_seed.chosen_scheme_id or "").strip() if is_pre_final_retry_attempt else ""
                forced_scheme_title = str(pre_final_retry_seed.chosen_title or "").strip() if is_pre_final_retry_attempt else ""
                baseline_override = (
                    current_manifest_urls
                    or (dict(pre_final_retry_seed.baseline_manifest_urls or {}) if is_pre_final_retry_attempt else None)
                )
                try:
                    result = choose_and_sync_showroom_driver_accessory(
                        accessory_kind=normalized_kind,
                        profile_dir=accessory_profile_dir,
                        manifest_member_id=manifest_member_id,
                        retries=retries,
                        retry_backoff_seconds=retry_backoff_seconds,
                        original_scheme_id=original_scheme_id,
                        showroom_cars=pool_state.get("cars") if isinstance(pool_state.get("cars"), list) else [],
                        showroom_sampled_pages=pool_state.get("sampled_pages") if isinstance(pool_state.get("sampled_pages"), set) else set(pool_state.get("sampled_pages") or []),
                        detected_total_pages=int(pool_state.get("total_pages") or 0),
                        detect_total_pages=bool(detect_showroom_total_pages),
                        exclude_scheme_ids=attempt_excluded_scheme_ids,
                        exclude_recent_scheme_ids=set(recent_scheme_ids),
                        minimum_unused_choices=remaining_targets,
                        log=logging.info,
                        shared_context=accessory_tp_context,
                        shared_page=accessory_tp_page,
                        shared_auth_state=accessory_tp_auth_state,
                        fast_mule_mode=bool(effective_mule_mode),
                        fast_apply_mode=accessory_fast_mode,
                        baseline_manifest_urls_override=baseline_override,
                        forced_scheme_id=forced_scheme_id,
                        forced_scheme_title=forced_scheme_title,
                        timeout_seconds=TP_ONLINE_FALLBACK_TARGET_TIMEOUT_SECONDS,
                        cancel_event=cancel_event,
                    )
                except Exception as exc:
                    logging.debug("Trading Paints showroom accessory fallback exception", exc_info=True)
                    logs.append(f"Trading Paints showroom {normalized_kind} fallback errored for {'AI' if user.is_ai else 'driver'} {label}: {exc}")
                    result = None
                    break

                if result is None:
                    break
                if result.chosen_scheme_id:
                    chosen_attempt_scheme_id = str(result.chosen_scheme_id).strip()
                    if chosen_attempt_scheme_id:
                        attempt_excluded_scheme_ids.add(chosen_attempt_scheme_id)
                        used_scheme_ids.add(chosen_attempt_scheme_id)
                should_retry_online_apply = bool((not result.ok) and (result.set_scheme_applied or result.retryable_online_failure))
                if should_retry_online_apply:
                    if effective_mule_mode:
                        now = time.monotonic()
                        retry_started_at = online_retry_started_at.setdefault(target_key, now)
                        elapsed = now - retry_started_at
                        if elapsed < TP_MULE_PER_TARGET_TIMEOUT_SECONDS:
                            cooldown_seconds = compute_mule_retry_cooldown(online_apply_attempt)
                            online_next_attempt_at[target_key] = time.monotonic() + cooldown_seconds
                            pending_users.append(user)
                            deferred_for_online_retry = True
                            logs.append(
                                f"Trading Paints showroom {normalized_kind} fallback online attempt {online_apply_attempt} did not produce usable files for {'AI' if user.is_ai else 'driver'} {label}; Nishizumi Paints will revisit this target after other online targets or a {cooldown_seconds:.1f}s cooldown for up to {TP_MULE_PER_TARGET_TIMEOUT_SECONDS / 60:.0f} minute(s)."
                            )
                            break
                    elif online_apply_attempt < max_online_apply_attempts:
                        logs.append(
                            f"Trading Paints showroom {normalized_kind} fallback apply attempt {online_apply_attempt}/{max_online_apply_attempts} did not produce usable files for {'AI' if user.is_ai else 'driver'} {label}. This can happen with PRO-only paints, so Nishizumi Paints will try another showroom scheme."
                        )
                        continue
                    break
                break

            if deferred_for_online_retry:
                continue
            if _cancel_requested(cancel_event):
                logs.append(f"Trading Paints showroom {normalized_kind} fallback stopped before applying local or online files because the iRacing session changed or ended.")
                break
            if result is None:
                _apply_local_for_user(user)
                continue

            retry_started_at = online_retry_started_at.get(target_key)
            if result.ok and retry_started_at is not None:
                elapsed = time.monotonic() - retry_started_at
                logs.append(
                    f"Trading Paints showroom {normalized_kind} fallback recovered fresh manifest files for {'AI' if user.is_ai else 'driver'} {label} after {elapsed:.1f}s and {online_apply_attempts_by_target[target_key]} online attempt(s)."
                )
                online_retry_started_at.pop(target_key, None)
                online_next_attempt_at.pop(target_key, None)

            if result.showroom_cars:
                pool_state["cars"] = [item for item in result.showroom_cars if isinstance(item, dict)]
                pool_state["sampled_pages"] = set(int(p) for p in (result.showroom_sampled_pages or []) if str(p).strip())
                if int(getattr(result, "detected_total_pages", 0) or 0) > 0:
                    pool_state["total_pages"] = int(getattr(result, "detected_total_pages", 0) or 0)

            if result.original_scheme_id and not original_scheme_id:
                original_scheme_id = str(result.original_scheme_id or "").strip()
                logs.append(f"Captured original Trading Paints {normalized_kind} scheme: {original_scheme_id}")
            if result.baseline_manifest_urls and baseline_manifest_urls is None:
                baseline_manifest_urls = dict(result.baseline_manifest_urls)
            if result.set_scheme_applied:
                touched_accessory = True
            if result.chosen_scheme_id:
                chosen_scheme_id = str(result.chosen_scheme_id).strip()
                used_scheme_ids.add(chosen_scheme_id)
                if result.ok:
                    recent_history_payload = {cache_key: list(recent_scheme_ids)}
                    remember_tp_recent_scheme(recent_history_payload, cache_key, chosen_scheme_id)
                    recent_scheme_ids = list(recent_history_payload.get(cache_key, []))
            if result.reused_previous_scheme:
                summary.repeated_source_uses += 1

            if _cancel_requested(cancel_event):
                logs.append(f"Trading Paints showroom {normalized_kind} fallback stopped before applying local or online files for {'AI' if user.is_ai else 'driver'} {label} because the iRacing session changed or ended.")
                break

            if result.ok and is_pre_final_retry_attempt:
                pre_final_online_retry_seed_by_target.pop(target_key, None)
                online_next_attempt_at.pop(target_key, None)
                logs.append(
                    f"Trading Paints showroom {normalized_kind} fallback recovered {'AI' if user.is_ai else 'driver'} {label} with delayed retry scheme {result.chosen_scheme_id} after {TP_ONLINE_FALLBACK_PRE_FINAL_RETRY_DELAY_SECONDS:.0f}s."
                )

            if not result.ok:
                if bool(result.set_scheme_applied) or bool(result.retryable_online_failure):
                    retry_started_at = online_retry_started_at.pop(target_key, None)
                    if retry_started_at is not None:
                        elapsed = time.monotonic() - retry_started_at
                        logs.append(
                            f"Trading Paints showroom {normalized_kind} fallback did not recover fresh manifest files for {'AI' if user.is_ai else 'driver'} {label} after {elapsed:.1f}s and {online_apply_attempts_by_target[target_key]} online attempt(s)."
                        )
                    if bool(result.retryable_online_failure):
                        logs.append(
                            f"Trading Paints showroom {normalized_kind} fallback could not apply a usable online paint for {'AI' if user.is_ai else 'driver'} {label} after {max_online_apply_attempts} attempt(s). Nishizumi Paints will skip this online target and use the local fallback instead. Last result: {result.message}"
                        )
                    elif effective_mule_mode and retry_started_at is not None:
                        logs.append(
                            f"Trading Paints showroom {normalized_kind} fallback could not apply a usable online paint for {'AI' if user.is_ai else 'driver'} {label} after the {TP_MULE_PER_TARGET_TIMEOUT_SECONDS / 60:.0f}-minute MULE retry window. Nishizumi Paints will skip this online target and use the local fallback instead. Last result: {result.message}"
                        )
                    else:
                        logs.append(
                            f"Trading Paints showroom {normalized_kind} fallback timed out for {'AI' if user.is_ai else 'driver'} {label} after {TP_ONLINE_FALLBACK_TARGET_TIMEOUT_SECONDS:.0f}s. Last result: {result.message}"
                        )
                else:
                    logs.append(f"Trading Paints showroom {normalized_kind} fallback could not fill {'AI' if user.is_ai else 'driver'} {label}: {result.message}")
                can_retry_same_scheme_later = bool(
                    result.set_scheme_applied
                    and result.chosen_scheme_id
                    and not getattr(result, "force_local_fallback", False)
                    and not bool(result.retryable_online_failure)
                )
                if can_retry_same_scheme_later and not effective_mule_mode and not is_pre_final_retry_attempt:
                    pre_final_online_retry_seed_by_target[target_key] = result
                    online_next_attempt_at[target_key] = time.monotonic() + TP_ONLINE_FALLBACK_PRE_FINAL_RETRY_DELAY_SECONDS
                    pending_users.append(user)
                    logs.append(
                        f"Trading Paints showroom {normalized_kind} fallback will retry scheme {result.chosen_scheme_id} once more for {'AI' if user.is_ai else 'driver'} {label} after {TP_ONLINE_FALLBACK_PRE_FINAL_RETRY_DELAY_SECONDS:.0f}s before sending it to the final retry stage."
                    )
                    continue
                if is_pre_final_retry_attempt:
                    pre_final_online_retry_seed_by_target.pop(target_key, None)
                    online_next_attempt_at.pop(target_key, None)
                if can_retry_same_scheme_later and retry_timed_out_fallbacks_indefinitely:
                    timed_out_online_retries.append((user, result))
                    logs.append(
                        f"Trading Paints showroom {normalized_kind} fallback will retry scheme {result.chosen_scheme_id} for {'AI' if user.is_ai else 'driver'} {label} at the end for up to {TP_ONLINE_FALLBACK_FINAL_MAX_SECONDS / 60:.0f} minute(s) before using the local random pool."
                    )
                elif can_retry_same_scheme_later:
                    _apply_local_for_user(user)
                else:
                    _apply_local_for_user(user)
                continue

            _apply_online_result_for_user(user, result, label)

        if timed_out_online_retries and not _cancel_requested(cancel_event):
            logs.append(
                f"Trading Paints online {normalized_kind} fallback final retry stage queued {len(timed_out_online_retries)} timed-out target(s); each will retry for up to {TP_ONLINE_FALLBACK_FINAL_MAX_SECONDS / 60:.0f} minute(s) before using the local random pool."
            )
        for retry_user, retry_seed_result in timed_out_online_retries:
            if _cancel_requested(cancel_event):
                break
            target_is_team = session_user_uses_team_target(retry_user)
            target_id = int(retry_user.team_id) if target_is_team else int(retry_user.user_id)
            label = retry_user.display_name or (f"AI {target_id}" if retry_user.is_ai else f"user {target_id}")
            retry_attempt = 0
            final_retry_started_at = time.monotonic()
            final_retry_succeeded = False
            final_retry_auth_failed = False
            while not _cancel_requested(cancel_event) and (time.monotonic() - final_retry_started_at) < TP_ONLINE_FALLBACK_FINAL_MAX_SECONDS:
                retry_attempt += 1
                try:
                    retry_result = choose_and_sync_showroom_driver_accessory(
                        accessory_kind=normalized_kind,
                        profile_dir=accessory_profile_dir,
                        manifest_member_id=manifest_member_id,
                        retries=retries,
                        retry_backoff_seconds=retry_backoff_seconds,
                        original_scheme_id=original_scheme_id,
                        showroom_cars=pool_state.get("cars") if isinstance(pool_state.get("cars"), list) else [],
                        showroom_sampled_pages=pool_state.get("sampled_pages") if isinstance(pool_state.get("sampled_pages"), set) else set(pool_state.get("sampled_pages") or []),
                        detected_total_pages=int(pool_state.get("total_pages") or 0),
                        detect_total_pages=bool(detect_showroom_total_pages),
                        exclude_scheme_ids=set(),
                        exclude_recent_scheme_ids=set(recent_scheme_ids),
                        minimum_unused_choices=1,
                        log=logging.info,
                        shared_context=accessory_tp_context,
                        shared_page=accessory_tp_page,
                        shared_auth_state=accessory_tp_auth_state,
                        fast_mule_mode=bool(effective_mule_mode),
                        fast_apply_mode=accessory_fast_mode,
                        baseline_manifest_urls_override=current_manifest_urls or dict(retry_seed_result.baseline_manifest_urls or {}),
                        forced_scheme_id=str(retry_seed_result.chosen_scheme_id or ""),
                        forced_scheme_title=str(retry_seed_result.chosen_title or ""),
                        force_showroom_ui_activation=retry_attempt >= TP_ONLINE_FALLBACK_FINAL_UI_RETRY_AFTER_ATTEMPTS,
                        timeout_seconds=TP_ONLINE_FALLBACK_FINAL_POLL_SECONDS,
                        cancel_event=cancel_event,
                    )
                except Exception as exc:
                    retry_result = TPShowroomSyncResult(ok=False, chosen_scheme_id=retry_seed_result.chosen_scheme_id, chosen_title=retry_seed_result.chosen_title, message=str(exc), set_scheme_applied=True)
                    logging.debug("Trading Paints final %s retry exception", normalized_kind, exc_info=True)
                if retry_result.ok and _apply_online_result_for_user(retry_user, retry_result, label):
                    final_retry_succeeded = True
                    logs.append(
                        f"Trading Paints final {normalized_kind} retry succeeded for {'AI' if retry_user.is_ai else 'driver'} {label} using scheme {retry_result.chosen_scheme_id} after {retry_attempt} final attempt(s)."
                    )
                    if retry_result.chosen_scheme_id:
                        recent_history_payload = {cache_key: list(recent_scheme_ids)}
                        remember_tp_recent_scheme(recent_history_payload, cache_key, str(retry_result.chosen_scheme_id))
                        recent_scheme_ids = list(recent_history_payload.get(cache_key, []))
                    break
                if retry_result.auth_required:
                    final_retry_auth_failed = True
                    summary.missing_source_targets += 1
                    logs.append(
                        f"Trading Paints final {normalized_kind} retry stopped for {'AI' if retry_user.is_ai else 'driver'} {label} because the saved Trading Paints login is no longer authenticated."
                    )
                    break
                final_retry_elapsed = time.monotonic() - final_retry_started_at
                final_retry_remaining = max(0.0, TP_ONLINE_FALLBACK_FINAL_MAX_SECONDS - final_retry_elapsed)
                logs.append(
                    f"Trading Paints final {normalized_kind} retry attempt {retry_attempt} is still waiting for {'AI' if retry_user.is_ai else 'driver'} {label} using scheme {retry_seed_result.chosen_scheme_id}; {final_retry_remaining:.0f}s left before local fallback."
                )
                wait_seconds = min(TP_ONLINE_FALLBACK_FINAL_RETRY_COOLDOWN_SECONDS, final_retry_remaining)
                if wait_seconds <= 0:
                    break
                if cancel_event is not None:
                    cancel_event.wait(wait_seconds)
                else:
                    time.sleep(wait_seconds)
            if (
                not final_retry_succeeded
                and not final_retry_auth_failed
                and not _cancel_requested(cancel_event)
            ):
                logs.append(
                    f"Trading Paints final {normalized_kind} retry timed out for {'AI' if retry_user.is_ai else 'driver'} {label} using scheme {retry_seed_result.chosen_scheme_id} after {TP_ONLINE_FALLBACK_FINAL_MAX_SECONDS / 60:.0f} minute(s). Using the local random pool."
                )
                _apply_local_for_user(retry_user)

        if _cancel_requested(cancel_event):
            logs.append(f"Trading Paints original {normalized_kind} restore skipped because the iRacing session changed or ended.")
            return {
                "saved": fallback_saved,
                "logs": logs,
                "summary": summary,
                "recent_scheme_ids": recent_scheme_ids,
                "cache_key": cache_key,
            }

        if effective_mule_mode:
            if touched_accessory:
                logs.append(f"Trading Paints original {normalized_kind} restore skipped because this profile is using a compatibility path that does not restore the original asset automatically.")
            return {
                "saved": fallback_saved,
                "logs": logs,
                "summary": summary,
                "recent_scheme_ids": recent_scheme_ids,
                "cache_key": cache_key,
            }

        if touched_accessory:
            if not original_scheme_id:
                logs.append(f"Trading Paints original {normalized_kind} scheme was not captured. The app will skip the dashboard restore and fall back to the local file backup path instead.")
            else:
                try:
                    _restored_acc, restore_message = restore_tp_showroom_generic(
                        scheme_id=original_scheme_id,
                        category="Driver",
                        mid=mid,
                        slug=slug,
                        profile_dir=accessory_profile_dir,
                        log=logging.info,
                        shared_context=accessory_tp_context,
                        shared_page=accessory_tp_page,
                        shared_auth_state=accessory_tp_auth_state,
                    )
                except Exception as exc:
                    restore_message = f"Trading Paints original {normalized_kind} restore errored: {exc}"
                    logging.debug("Trading Paints original accessory restore exception", exc_info=True)
                logs.append(restore_message)

            restored_local_any = False
            if session.local_user_id is not None and int(session.local_user_id or 0) > 0:
                try:
                    refreshed_items = _tp_wait_for_fetch_user_manifest_accessory_match(
                        local_user_id=int(session.local_user_id),
                        paint_type=paint_type,
                        retries=retries,
                        retry_backoff_seconds=retry_backoff_seconds,
                        baseline_urls=baseline_manifest_urls,
                        timeout_seconds=8.0,
                        log=logging.info,
                        cancel_event=cancel_event,
                    )
                    if refreshed_items:
                        restored_downloads: list[DownloadedFile] = []
                        for ordinal, item in enumerate(refreshed_items, start=1):
                            downloaded = download_file(
                                session.session_id,
                                temp_root,
                                item,
                                retries,
                                retry_backoff_seconds,
                                ordinal=ordinal,
                                total=len(refreshed_items),
                            )
                            if downloaded is not None:
                                restored_downloads.append(downloaded)
                        for downloaded in restored_downloads:
                            saved_items = move_or_extract(downloaded, paints_dir, retries=retries, retry_backoff_seconds=retry_backoff_seconds)
                            if saved_items:
                                restored_local_any = True
                        if restored_local_any:
                            logs.append(f"Trading Paints original local {normalized_kind} files restored using fresh manifest URLs.")
                except Exception as exc:
                    logging.debug("Trading Paints original accessory restore exception", exc_info=True)
                    logs.append(f"Trading Paints original local {normalized_kind} files could not be restored from fresh manifest: {exc}")
            if not restored_local_any and original_local_backup:
                try:
                    if _restore_local_tp_backup(original_local_backup):
                        logs.append(f"Trading Paints original local {normalized_kind} files restored from local backup state.")
                except Exception as exc:
                    logging.debug("Trading Paints accessory local backup restore exception", exc_info=True)
                    logs.append(f"Trading Paints original local {normalized_kind} backup restore failed: {exc}")

        return {
            "saved": fallback_saved,
            "logs": logs,
            "summary": summary,
            "recent_scheme_ids": recent_scheme_ids,
            "cache_key": cache_key,
        }
    finally:
        if accessory_tp_context is not None:
            try:
                accessory_tp_context.close()
            except Exception:
                pass
        if accessory_tp_playwright_manager is not None:
            try:
                accessory_tp_playwright_manager.stop()
            except Exception:
                pass
        if accessory_profile_cleanup is not None:
            shutil.rmtree(accessory_profile_cleanup, ignore_errors=True)

def _tp_collection_scheme_id(item: dict) -> str:
    if not isinstance(item, dict):
        return ""
    for key in ("id", "scheme_id", "showroom_id"):
        value = str(item.get(key) or "").strip()
        if value and value.isdigit() and int(value) > 0:
            return value
    for key in ("slink", "showroom_link", "link", "url"):
        value = str(item.get(key) or "").strip()
        match = re.search(r"/showroom/view/(\d+)", value, flags=re.IGNORECASE)
        if match:
            return match.group(1)
    return ""

def _tp_showroom_identity_from_link(link: object) -> tuple[str, int, str] | None:
    value = str(link or "").strip()
    if not value:
        return None
    match = re.search(r"/showroom/([^/?#]+)/(\d+)/([^/?#]+)", value, flags=re.IGNORECASE)
    if not match:
        return None
    try:
        mid = int(match.group(2))
    except Exception:
        return None
    return urllib.parse.unquote(match.group(1)), mid, urllib.parse.unquote(match.group(3))

def _tp_collection_item_mid(item: dict) -> int | None:
    if not isinstance(item, dict):
        return None
    for link_key in ("clink", "car_link", "make_link", "category_link"):
        identity = _tp_showroom_identity_from_link(item.get(link_key))
        if identity is not None:
            return identity[1]
    for key in ("car_make", "mid", "make_id", "parent_id"):
        value = _to_int_or_none(item.get(key))
        if value is not None and value > 0:
            return value
    return None

def _tp_collection_item_kind(item: dict) -> str:
    mid = _tp_collection_item_mid(item)
    if mid == 118:
        return "helmet"
    if mid == 119:
        return "suit"
    return "car"

def _tp_collection_title(item: dict) -> str:
    if not isinstance(item, dict):
        return ""
    for key in ("title", "name", "showroom_title"):
        value = str(item.get(key) or "").strip()
        if value:
            return value
    scheme_id = _tp_collection_scheme_id(item)
    return f"scheme {scheme_id}" if scheme_id else "collection paint"


def _tp_collection_showroom_link(item: dict) -> str:
    if not isinstance(item, dict):
        return ""
    title = _tp_collection_title(item)
    for key in ("slink", "showroom_link", "link", "url"):
        normalized = _normalize_tp_showroom_link(item.get(key), title)
        if normalized:
            return normalized
    return _tp_showroom_url_for_scheme_id(_tp_collection_scheme_id(item), title)

def _tp_collection_source_id(item: dict, kind: str) -> str:
    scheme_id = _tp_collection_scheme_id(item)
    return f"collection:{kind}:{scheme_id}"

def _tp_collection_used_source_ids_from_saved(saved_items: Iterable[SavedFile] | None) -> set[str]:
    used_source_ids: set[str] = set()
    for item in saved_items or []:
        download_id = item.download_id
        if str(getattr(download_id, "tp_source", "") or "").strip().lower() != "collection":
            continue
        scheme_id = str(getattr(download_id, "tp_scheme_id", "") or "").strip()
        if not scheme_id:
            continue
        paint_type = download_id.paint_type
        if paint_type in {PaintType.CAR, PaintType.CAR_SPEC, PaintType.CAR_DECAL}:
            kind = "car"
        elif paint_type is PaintType.HELMET:
            kind = "helmet"
        elif paint_type is PaintType.SUIT:
            kind = "suit"
        else:
            continue
        used_source_ids.add(f"collection:{kind}:{scheme_id}")
    return used_source_ids

def _tp_collection_cache_dir(
    collection_pool_dir: Path,
    collection_id: str,
    kind: str,
    directory: str,
    scheme_id: str,
) -> Path:
    safe_collection_id = str(collection_id or "").strip()
    safe_collection_id = safe_collection_id if safe_collection_id.isdigit() and int(safe_collection_id) > 0 else "unknown"
    safe_kind = str(kind or "car").strip().lower()
    if safe_kind not in {"car", "helmet", "suit"}:
        safe_kind = "car"
    safe_scheme_id = re.sub(r"[^A-Za-z0-9._-]+", "_", str(scheme_id or "").strip()).strip("._-") or "unknown"
    bucket = _safe_random_pool_bucket(directory) if safe_kind == "car" else "driver"
    return Path(collection_pool_dir) / safe_collection_id / safe_kind / bucket / safe_scheme_id

def _tp_collection_cached_entry(
    collection_pool_dir: Path,
    item: dict,
    kind: str,
    directory: str,
) -> RandomPoolEntry | None:
    scheme_id = _tp_collection_scheme_id(item)
    collection_id = str(item.get("_nishizumi_collection_id") or "").strip()
    if not scheme_id or not collection_id:
        return None
    cache_dir = _tp_collection_cache_dir(collection_pool_dir, collection_id, kind, directory, scheme_id)
    car_file = cache_dir / "car.tga"
    spec_file = cache_dir / "car_spec.mip"
    decal_file = cache_dir / "decal.tga"
    helmet_file = cache_dir / "helmet.tga"
    suit_file = cache_dir / "suit.tga"
    if kind == "car":
        if not car_file.exists():
            return None
        return RandomPoolEntry(
            source_id=_tp_collection_source_id(item, kind),
            directory=directory,
            car_file=car_file,
            spec_file=spec_file if spec_file.exists() else None,
            decal_file=decal_file if decal_file.exists() else None,
            source_kind="collection_pool",
        )
    if kind == "helmet" and helmet_file.exists():
        return RandomPoolEntry(
            source_id=_tp_collection_source_id(item, kind),
            directory=directory,
            helmet_file=helmet_file,
            source_kind="collection_pool",
        )
    if kind == "suit" and suit_file.exists():
        return RandomPoolEntry(
            source_id=_tp_collection_source_id(item, kind),
            directory=directory,
            suit_file=suit_file,
            source_kind="collection_pool",
        )
    return None

def archive_saved_to_tp_collection_pool(
    saved_items: list[SavedFile],
    collection_pool_dir: Path,
    collection_id: str,
    kind: str,
    directory: str,
    scheme_id: str,
    title: str = "",
) -> tuple[int, int]:
    safe_kind = str(kind or "").strip().lower()
    if safe_kind not in {"car", "helmet", "suit"}:
        return 0, 0
    cache_dir = _tp_collection_cache_dir(collection_pool_dir, collection_id, safe_kind, directory, scheme_id)
    cache_dir.mkdir(parents=True, exist_ok=True)
    paint_destinations = {
        PaintType.CAR: cache_dir / "car.tga",
        PaintType.CAR_SPEC: cache_dir / "car_spec.mip",
        PaintType.CAR_DECAL: cache_dir / "decal.tga",
        PaintType.HELMET: cache_dir / "helmet.tga",
        PaintType.SUIT: cache_dir / "suit.tga",
    }
    allowed_types = {PaintType.CAR, PaintType.CAR_SPEC, PaintType.CAR_DECAL} if safe_kind == "car" else {PaintType.HELMET if safe_kind == "helmet" else PaintType.SUIT}
    copied_files = 0
    touched_destinations: set[Path] = set()
    for item in saved_items:
        paint_type = item.download_id.paint_type
        if paint_type not in allowed_types:
            continue
        destination = paint_destinations.get(paint_type)
        if destination is None or destination in touched_destinations:
            continue
        source = item.file_path
        if source is None or not source.exists():
            continue
        temp_destination = destination.with_name(destination.name + ".tmp")
        temp_destination.unlink(missing_ok=True)
        shutil.copy2(source, temp_destination)
        os.replace(temp_destination, destination)
        touched_destinations.add(destination)
        copied_files += 1
    if copied_files:
        meta = {
            "collection_id": str(collection_id),
            "kind": safe_kind,
            "directory": str(directory or ""),
            "scheme_id": str(scheme_id or ""),
            "title": str(title or ""),
            "cached_at": time.time(),
        }
        (cache_dir / "meta.json").write_text(json.dumps(meta, indent=2, ensure_ascii=False), encoding="utf-8")
    return (1 if copied_files else 0), copied_files

def fetch_tp_collection_items(
    collection_id: str,
    retries: int,
    retry_backoff_seconds: float,
    cancel_event: threading.Event | None = None,
) -> list[dict]:
    safe_collection_id = str(collection_id or "").strip()
    if not safe_collection_id.isdigit() or int(safe_collection_id) <= 0:
        return []
    url = TRADING_PAINTS_COLLECTION_POOL_URL.format(collection_id=safe_collection_id)
    last_exc: Exception | None = None
    for attempt in range(1, max(1, int(retries)) + 1):
        if _cancel_requested(cancel_event):
            return []
        try:
            session = get_thread_http_session()
            response = session.get(
                f"{url}&ts={int(time.time() * 1000)}",
                timeout=30,
                headers={
                    "Accept": "application/json,text/javascript,*/*;q=0.8",
                    "X-Requested-With": "XMLHttpRequest",
                    "Referer": f"https://www.tradingpaints.com/collections/view/{safe_collection_id}",
                },
            )
            response.raise_for_status()
            payload = response.json()
            output = payload.get("output") if isinstance(payload, dict) else payload
            cars = output.get("cars") if isinstance(output, dict) else output
            if not isinstance(cars, list):
                return []
            items: list[dict] = []
            for raw in cars:
                if not isinstance(raw, dict):
                    continue
                scheme_id = _tp_collection_scheme_id(raw)
                if not scheme_id:
                    continue
                item = dict(raw)
                item["_nishizumi_collection_id"] = safe_collection_id
                item["_nishizumi_page_index"] = 0
                item["_nishizumi_page_number"] = 1
                items.append(item)
            return items
        except (requests.RequestException, ValueError, TypeError, json.JSONDecodeError) as exc:
            last_exc = exc
            if attempt >= max(1, int(retries)):
                break
            delay = compute_retry_delay(retry_backoff_seconds, attempt)
            if cancel_event is not None:
                cancel_event.wait(delay)
            else:
                time.sleep(delay)
    if last_exc is not None:
        raise last_exc
    return []

def fetch_tp_collection_pool(
    collection_ids: Iterable[str],
    retries: int,
    retry_backoff_seconds: float,
    cancel_event: threading.Event | None = None,
) -> dict[str, list[dict]]:
    pool: dict[str, list[dict]] = {}
    for collection_id in collection_ids:
        if _cancel_requested(cancel_event):
            break
        safe_collection_id = str(collection_id or "").strip()
        if not safe_collection_id:
            continue
        try:
            pool[safe_collection_id] = fetch_tp_collection_items(
                safe_collection_id,
                retries=retries,
                retry_backoff_seconds=retry_backoff_seconds,
                cancel_event=cancel_event,
            )
        except Exception as exc:
            logging.warning("Trading Paints collection %s could not be loaded: %s", safe_collection_id, exc)
            pool[safe_collection_id] = []
    return pool

def _tp_collection_candidates_for_car(items: list[dict], directory: str, mapping_path: Path | None) -> list[dict]:
    directory_key = canonicalize_car_directory(directory).lower()
    mapping_doc = _load_tp_showroom_mapping(mapping_path)
    cars_map = mapping_doc.get("cars") or {}
    entry = None
    for candidate_key in _tp_directory_candidate_keys(directory_key):
        possible = cars_map.get(candidate_key)
        if isinstance(possible, dict):
            entry = possible
            break
    if not isinstance(entry, dict):
        return []
    wanted_mid = _to_int_or_none(entry.get("mid"))
    if wanted_mid is None or wanted_mid <= 0:
        return []
    return [
        item
        for item in items
        if isinstance(item, dict)
        and _tp_collection_item_kind(item) == "car"
        and _tp_collection_item_mid(item) == wanted_mid
        and _tp_showroom_scheme_usable_for_online_fallback(item)
    ]

def _tp_collection_candidates_for_accessory(items: list[dict], kind: str) -> list[dict]:
    normalized_kind = str(kind or "").strip().lower()
    if normalized_kind not in {"helmet", "suit"}:
        return []
    return [
        item
        for item in items
        if isinstance(item, dict)
        and _tp_collection_item_kind(item) == normalized_kind
        and _tp_showroom_scheme_usable_for_online_fallback(item)
    ]

def _choose_tp_collection_candidate(
    candidates: list[dict],
    kind: str,
    used_source_ids: set[str],
    *,
    allow_repeating_when_exhausted: bool = False,
) -> tuple[dict | None, bool]:
    if not candidates:
        return None, False
    available = [item for item in candidates if _tp_collection_source_id(item, kind) not in used_source_ids]
    if not available:
        if not allow_repeating_when_exhausted:
            return None, False
        chosen = random.choice(candidates)
        source_id = _tp_collection_source_id(chosen, kind)
        if source_id:
            used_source_ids.add(source_id)
        return chosen, True
    chosen = random.choice(available)
    source_id = _tp_collection_source_id(chosen, kind)
    if source_id:
        used_source_ids.add(source_id)
    return chosen, False

def _apply_cached_tp_collection_item_for_user(
    *,
    session: Session,
    user: SessionUser,
    paints_dir: Path,
    collection_pool_dir: Path,
    item: dict,
    kind: str,
) -> list[SavedFile]:
    entry = _tp_collection_cached_entry(collection_pool_dir, item, kind, user.directory)
    if entry is None:
        return []
    target_is_team = session_user_uses_team_target(user)
    target_id = int(user.team_id) if target_is_team else int(user.user_id)
    base_kwargs = {
        "user_id": target_id,
        "directory": user.directory,
        "is_team_paint": target_is_team,
        "tp_scheme_id": _tp_collection_scheme_id(item),
        "tp_title": _tp_collection_title(item),
        "tp_source_link": _tp_collection_showroom_link(item),
        "tp_source": "collection",
    }
    saved_items: list[SavedFile] = []
    if kind == "car":
        for paint_type, source_path in (
            (PaintType.CAR, entry.car_file),
            (PaintType.CAR_SPEC, entry.spec_file),
            (PaintType.CAR_DECAL, entry.decal_file),
        ):
            copied = _copy_source_file_to_saved_targets(
                source_path,
                session.session_id,
                DownloadId(
                    paint_type=paint_type,
                    is_superspeedway_variant=False,
                    **base_kwargs,
                ),
                paints_dir,
            )
            if copied:
                saved_items.extend(copied)
        return saved_items
    paint_type = PaintType.HELMET if kind == "helmet" else PaintType.SUIT
    source_path = entry.helmet_file if kind == "helmet" else entry.suit_file
    return _copy_source_file_to_saved_targets(
        source_path,
        session.session_id,
        DownloadId(
            paint_type=paint_type,
            is_superspeedway_variant=False,
            **base_kwargs,
        ),
        paints_dir,
    )

def _tp_collection_public_direct_result(
    *,
    item: dict,
    kind: str,
    directory: str,
) -> TPShowroomSyncResult | None:
    normalized_kind = str(kind or "").strip().lower()
    if normalized_kind not in {"car", "helmet", "suit"}:
        return None
    if not isinstance(item, dict) or not _tp_showroom_scheme_usable_for_online_fallback(item):
        return None
    scheme_id = _tp_collection_scheme_id(item)
    if not scheme_id:
        return None
    title = _tp_collection_title(item)
    source_link = _tp_collection_showroom_link(item)
    if normalized_kind == "car":
        direct_items = _tp_build_public_showroom_car_direct_items(
            user_id=int(scheme_id),
            directory=directory,
            scheme_id=scheme_id,
            title=title,
            source_link=source_link,
            source="collection",
        )
    else:
        paint_type = PaintType.HELMET if normalized_kind == "helmet" else PaintType.SUIT
        direct_items = _tp_build_accessory_direct_items_from_url_map(
            user_id=int(scheme_id),
            paint_type=paint_type,
            url_map={paint_type.value: TRADING_PAINTS_SHOWROOM_COMPRESSED_URL.format(asset_id=scheme_id)},
        )
        direct_items = _annotate_download_files_with_tp_source(
            direct_items,
            scheme_id=scheme_id,
            title=title,
            source_link=source_link,
            source="collection",
        )
    if not direct_items:
        return None
    return TPShowroomSyncResult(
        ok=True,
        chosen_scheme_id=scheme_id,
        chosen_title=title,
        showroom_count=1,
        message="Using direct public collection asset download.",
        direct_items=direct_items,
        showroom_cars=[dict(item)],
    )

def _tp_collection_saved_items_have_primary_kind(saved_items: Iterable[SavedFile], kind: str) -> bool:
    normalized_kind = str(kind or "").strip().lower()
    if normalized_kind == "car":
        wanted_type = PaintType.CAR
    elif normalized_kind == "helmet":
        wanted_type = PaintType.HELMET
    elif normalized_kind == "suit":
        wanted_type = PaintType.SUIT
    else:
        return False
    return any(item.download_id.paint_type is wanted_type for item in (saved_items or []))

def _download_and_save_tp_collection_result(
    *,
    session: Session,
    user: SessionUser,
    result: TPShowroomSyncResult,
    kind: str,
    temp_dir: Path,
    paints_dir: Path,
    retries: int,
    retry_backoff_seconds: float,
    cancel_event: threading.Event | None = None,
) -> list[SavedFile]:
    if kind == "car":
        retargeted_items = _tp_retarget_manifest_items_for_user(session, user, result.direct_items)
    else:
        accessory_type = PaintType.HELMET if kind == "helmet" else PaintType.SUIT
        retargeted_items = _tp_retarget_manifest_accessory_items_for_user(user, result.direct_items, accessory_type)
    retargeted_items = _annotate_download_files_with_tp_source(
        retargeted_items,
        scheme_id=result.chosen_scheme_id,
        title=result.chosen_title,
        source_link=_tp_showroom_link_for_sync_result(result),
        source="collection",
    )
    if not retargeted_items:
        return []
    downloaded_items: list[DownloadedFile] = []
    for ordinal, item in enumerate(retargeted_items, start=1):
        downloaded = download_file(
            session.session_id,
            temp_dir,
            item,
            retries,
            retry_backoff_seconds,
            ordinal=ordinal,
            total=len(retargeted_items),
            cancel_event=cancel_event,
        )
        if downloaded is not None:
            downloaded_items.append(downloaded)
    saved_items: list[SavedFile] = []
    for downloaded in downloaded_items:
        saved = move_or_extract(
            downloaded,
            paints_dir,
            retries=retries,
            retry_backoff_seconds=retry_backoff_seconds,
            cancel_event=cancel_event,
        )
        if saved:
            saved_items.extend(saved)
    return saved_items

def _mark_tp_collection_saved_targets(
    saved_items: list[SavedFile],
    existing_car_targets: set[tuple[bool, int, str]],
    existing_helmet_targets: set[tuple[bool, int]],
    existing_suit_targets: set[tuple[bool, int]],
) -> None:
    for item in saved_items:
        car_key = (bool(item.download_id.is_team_paint), int(item.download_id.user_id), item.download_id.directory.lower())
        accessory_key = (bool(item.download_id.is_team_paint), int(item.download_id.user_id))
        if item.download_id.paint_type is PaintType.CAR:
            existing_car_targets.add(car_key)
        elif item.download_id.paint_type is PaintType.HELMET:
            existing_helmet_targets.add(accessory_key)
        elif item.download_id.paint_type is PaintType.SUIT:
            existing_suit_targets.add(accessory_key)

def _restore_tp_collection_source_scheme(
    *,
    kind: str,
    directory: str,
    result: TPShowroomSyncResult,
    mapping_path: Path | None,
    profile_dir: Path,
    manifest_member_id: int | None,
    retries: int,
    retry_backoff_seconds: float,
    logs: list[str],
) -> None:
    if not result.set_scheme_applied:
        return
    original_scheme_id = str(result.original_scheme_id or "").strip()
    if not original_scheme_id:
        logs.append(f"Trading Paints collection pool could not restore the previous {kind} scheme because no original scheme id was captured.")
        return
    try:
        if kind == "car":
            _restored, message = restore_tp_showroom_scheme(
                directory=directory,
                scheme_id=original_scheme_id,
                showroom_link=str(result.original_scheme_link or "").strip(),
                mapping_path=mapping_path,
                profile_dir=profile_dir,
                manifest_member_id=manifest_member_id,
                baseline_manifest_urls=dict(result.baseline_manifest_urls or {}),
                retries=retries,
                retry_backoff_seconds=retry_backoff_seconds,
                log=logging.info,
            )
        else:
            accessory_mid = 118 if kind == "helmet" else 119
            accessory_slug = "Helmets" if kind == "helmet" else "Suits"
            _restored, message = restore_tp_showroom_generic(
                scheme_id=original_scheme_id,
                category="Driver",
                mid=accessory_mid,
                slug=accessory_slug,
                profile_dir=profile_dir,
                log=logging.info,
            )
        logs.append(message)
    except Exception as exc:
        logging.debug("Trading Paints collection original scheme restore failed", exc_info=True)
        logs.append(f"Trading Paints collection pool original {kind} restore failed: {exc}")

def apply_tp_collection_pool_fallbacks(
    session: Session,
    saved: list[SavedFile],
    paints_dir: Path,
    temp_dir: Path,
    collection_ids: Iterable[str],
    enable_real_drivers: bool,
    enable_ai: bool,
    sync_my_livery_from_server: bool,
    random_helmets: bool = False,
    random_suits: bool = False,
    random_helmets_real_drivers: bool = False,
    random_helmets_ai: bool = False,
    random_suits_real_drivers: bool = False,
    random_suits_ai: bool = False,
    disable_random_in_team_events: bool = False,
    disable_random_for_local_user: bool = False,
    mapping_path: Path | None = None,
    profile_dir: Path | None = None,
    manifest_member_id: int | None = None,
    retries: int = 3,
    retry_backoff_seconds: float = 1.5,
    saved_callback: Callable[[list[SavedFile], str], None] | None = None,
    used_source_ids_seed: Iterable[str] | None = None,
    cancel_event: threading.Event | None = None,
    strict_collection_only: bool = False,
    allow_repeating_when_exhausted: bool = False,
    _thread_handoff_done: bool = False,
) -> tuple[list[SavedFile], list[str], RandomFallbackSummary]:
    source_text = collection_ids if isinstance(collection_ids, str) else " ".join(str(item) for item in collection_ids)
    parsed_collection_ids = parse_tp_collection_ids_from_text(source_text)
    seeded_source_ids = {str(item).strip() for item in (used_source_ids_seed or []) if str(item or "").strip()}
    logs: list[str] = []
    fallback_saved: list[SavedFile] = []
    summary = RandomFallbackSummary()
    if not parsed_collection_ids:
        return fallback_saved, logs, summary
    if _cancel_requested(cancel_event):
        logs.append("Trading Paints collection pool fallback cancelled before it started because the iRacing session changed or ended.")
        return fallback_saved, logs, summary

    collection_pool_dir = default_tp_collection_pool_dir()
    mapping_path = mapping_path or default_tp_showroom_mapping_path()
    try:
        removed_collections, removed_files, freed_bytes = reconcile_tp_collection_pool_cache(collection_pool_dir, parsed_collection_ids)
        if removed_collections:
            logs.append(
                f"Trading Paints collection pool removed {removed_collections} cached collection(s) that are no longer configured ({removed_files} file(s), {freed_bytes / float(1024 ** 3):.2f} GB)."
            )
    except Exception as exc:
        logs.append(f"Trading Paints collection pool cache reconciliation failed: {exc}")

    try:
        pool_by_collection = fetch_tp_collection_pool(parsed_collection_ids, retries, retry_backoff_seconds, cancel_event=cancel_event)
    except Exception as exc:
        logs.append(f"Trading Paints collection pool could not load the configured collections: {exc}")
        return fallback_saved, logs, summary

    all_items: list[dict] = []
    for collection_id in parsed_collection_ids:
        items = list(pool_by_collection.get(collection_id) or [])
        logs.append(f"Trading Paints collection pool loaded collection {collection_id}: {len(items)} paint(s).")
        all_items.extend(items)
    if not all_items:
        logs.append("Trading Paints collection pool found no usable paints in the configured collections.")
        return fallback_saved, logs, summary

    logs.append("This no-browser copy reuses cached collection paints first and now tries direct public downloads for usable non-PRO collection items.")

    existing_car_targets = {
        (bool(item.download_id.is_team_paint), int(item.download_id.user_id), item.download_id.directory.lower())
        for item in saved
        if item.download_id.paint_type is PaintType.CAR
    }
    existing_helmet_targets = {
        (bool(item.download_id.is_team_paint), int(item.download_id.user_id))
        for item in saved
        if item.download_id.paint_type is PaintType.HELMET
    }
    existing_suit_targets = {
        (bool(item.download_id.is_team_paint), int(item.download_id.user_id))
        for item in saved
        if item.download_id.paint_type is PaintType.SUIT
    }
    used_source_ids: set[str] = set(seeded_source_ids)
    used_source_ids.update(_tp_collection_used_source_ids_from_saved(saved))
    if used_source_ids:
        logs.append(f"Trading Paints collection pool will avoid {len(used_source_ids)} source(s) already used from configured collections in this session.")
    skipped_team_event_targets = 0
    skipped_local_targets = 0
    car_candidates_by_directory: dict[str, list[dict]] = {}
    accessory_candidates_by_kind: dict[str, list[dict]] = {}

    def _car_candidates_for_directory(directory: str) -> list[dict]:
        directory_key = canonicalize_car_directory(directory).lower()
        if directory_key not in car_candidates_by_directory:
            car_candidates_by_directory[directory_key] = _tp_collection_candidates_for_car(all_items, directory, mapping_path)
        return car_candidates_by_directory[directory_key]

    def _accessory_candidates_for_kind(kind: str) -> list[dict]:
        normalized_kind = str(kind or "").strip().lower()
        if normalized_kind not in accessory_candidates_by_kind:
            accessory_candidates_by_kind[normalized_kind] = _tp_collection_candidates_for_accessory(all_items, normalized_kind)
        return accessory_candidates_by_kind[normalized_kind]

    def _record_saved(saved_items: list[SavedFile]) -> None:
        if not saved_items:
            return
        fallback_saved.extend(saved_items)
        _mark_tp_collection_saved_targets(saved_items, existing_car_targets, existing_helmet_targets, existing_suit_targets)
        if saved_callback is not None and not _cancel_requested(cancel_event):
            try:
                saved_callback(saved_items, "fallback_online")
            except Exception:
                logging.debug("Collection pool save callback failed", exc_info=True)

    def _apply_choice(user: SessionUser, kind: str, candidates: list[dict]) -> bool:
        target_is_team = session_user_uses_team_target(user)
        target_id = int(user.team_id) if target_is_team else int(user.user_id)
        label = user.display_name or (f"AI {target_id}" if user.is_ai else f"user {target_id}")
        summary.attempted_targets += 1
        chosen, reused_existing_source = _choose_tp_collection_candidate(
            candidates,
            kind,
            used_source_ids,
            allow_repeating_when_exhausted=bool(allow_repeating_when_exhausted),
        )
        if chosen is None:
            summary.missing_source_targets += 1
            if candidates:
                if strict_collection_only:
                    logs.append(
                        f"Trading Paints collection-only mode ran out of unused {kind} paints for "
                        f"{'AI' if user.is_ai else 'driver'} {label} on {user.directory}. "
                        f"The selected collections do not have another allowed {kind} source, so this target will be left unchanged."
                    )
                else:
                    logs.append(f"Trading Paints collection pool exhausted its non-repeating {kind} sources for {'AI' if user.is_ai else 'driver'} {label} on {user.directory}; normal online fallback may cover this target.")
            else:
                if strict_collection_only:
                    logs.append(
                        f"Trading Paints collection-only mode found no usable {kind} paint in the selected collections for "
                        f"{'AI' if user.is_ai else 'driver'} {label} on {user.directory}. "
                        f"This target will be left unchanged."
                    )
                else:
                    logs.append(f"Trading Paints collection pool had no usable {kind} source for {'AI' if user.is_ai else 'driver'} {label} on {user.directory}.")
            return False
        if reused_existing_source:
            summary.repeated_source_uses += 1
            logs.append(
                f"Trading Paints collection pool reused an already used {kind} source from the selected collections for "
                f"{'AI' if user.is_ai else 'driver'} {label} on {user.directory} because repeat mode is enabled and no unused collection paints remained."
            )
        collection_id = str(chosen.get("_nishizumi_collection_id") or "").strip()
        scheme_id = _tp_collection_scheme_id(chosen)
        title = _tp_collection_title(chosen)
        cached_items = _apply_cached_tp_collection_item_for_user(
            session=session,
            user=user,
            paints_dir=paints_dir,
            collection_pool_dir=collection_pool_dir,
            item=chosen,
            kind=kind,
        )
        if cached_items:
            _record_saved(cached_items)
            summary.applied_targets += 1
            logs.append(f"Trading Paints collection pool applied cached {kind} to {'AI' if user.is_ai else 'driver'} {label} using collection {collection_id}, scheme {scheme_id} ({title}).")
            return True
        result = _tp_collection_public_direct_result(
            item=chosen,
            kind=kind,
            directory=user.directory,
        )
        if result is None:
            summary.missing_source_targets += 1
            logs.append(
                f"Trading Paints collection pool picked uncached {kind} scheme {scheme_id} from collection {collection_id} for "
                f"{'AI' if user.is_ai else 'driver'} {label}, but that item is not exposed as a usable public showroom asset."
            )
            return False
        try:
            saved_items = _download_and_save_tp_collection_result(
                session=session,
                user=user,
                result=result,
                kind=kind,
                temp_dir=temp_dir,
                paints_dir=paints_dir,
                retries=retries,
                retry_backoff_seconds=retry_backoff_seconds,
                cancel_event=cancel_event,
            )
        except Exception as exc:
            logging.debug("Trading Paints browserless collection pool public download exception", exc_info=True)
            summary.missing_source_targets += 1
            logs.append(f"Trading Paints collection pool errored while downloading public {kind} scheme {scheme_id} from collection {collection_id}: {exc}")
            return False
        if not _tp_collection_saved_items_have_primary_kind(saved_items, kind):
            if saved_items:
                delete_saved(saved_items, paints_root=paints_dir)
            summary.missing_source_targets += 1
            logs.append(
                f"Trading Paints collection pool selected uncached public {kind} scheme {scheme_id} from collection {collection_id}, "
                f"but the primary public asset was unavailable."
            )
            return False
        archive_saved_to_tp_collection_pool(saved_items, collection_pool_dir, collection_id, kind, user.directory, scheme_id, title)
        _record_saved(saved_items)
        summary.applied_targets += 1
        logs.append(
            f"Trading Paints collection pool downloaded and cached public {kind} for "
            f"{'AI' if user.is_ai else 'driver'} {label} using collection {collection_id}, scheme {scheme_id} ({title})."
        )
        return True

    for user in sorted(session.users, key=lambda u: (u.is_ai, u.directory.lower(), u.user_id, u.team_id or 0)):
        if _cancel_requested(cancel_event):
            logs.append("Trading Paints collection pool fallback cancelled because the iRacing session changed or ended.")
            break
        if disable_random_in_team_events and session_user_uses_team_target(user):
            skipped_team_event_targets += 1
            continue
        if user.is_ai:
            car_enabled_for_user = bool(enable_ai)
            helmet_enabled_for_user = bool(random_helmets_ai)
            suit_enabled_for_user = bool(random_suits_ai)
        else:
            car_enabled_for_user = bool(enable_real_drivers)
            helmet_enabled_for_user = bool(random_helmets_real_drivers)
            suit_enabled_for_user = bool(random_suits_real_drivers)
        if not (car_enabled_for_user or helmet_enabled_for_user or suit_enabled_for_user):
            continue
        is_local_target = session_user_is_local_target(session, user)
        if disable_random_for_local_user and is_local_target:
            skipped_local_targets += 1
            continue
        if is_local_target and not sync_my_livery_from_server:
            continue
        target_is_team = session_user_uses_team_target(user)
        target_id = int(user.team_id) if target_is_team else int(user.user_id)
        target_key = (target_is_team, target_id, user.directory.lower())
        accessory_target_key = (target_is_team, target_id)
        missing_strict_collection_car = False
        if car_enabled_for_user and target_key not in existing_car_targets:
            car_applied = _apply_choice(user, "car", _car_candidates_for_directory(user.directory))
            missing_strict_collection_car = bool(strict_collection_only and not car_applied)
            if missing_strict_collection_car:
                label = user.display_name or (f"AI {target_id}" if user.is_ai else f"user {target_id}")
                logs.append(
                    f"Trading Paints collection-only mode will not assign helmet or suit fallback to "
                    f"{'AI' if user.is_ai else 'driver'} {label} on {user.directory} because no collection car paint could be applied."
                )
        if not missing_strict_collection_car and bool(random_helmets) and helmet_enabled_for_user and accessory_target_key not in existing_helmet_targets:
            _apply_choice(user, "helmet", _accessory_candidates_for_kind("helmet"))
        if not missing_strict_collection_car and bool(random_suits) and suit_enabled_for_user and accessory_target_key not in existing_suit_targets:
            _apply_choice(user, "suit", _accessory_candidates_for_kind("suit"))
    if skipped_team_event_targets > 0:
        logs.append(f"Random fallback in team events is disabled, so Nishizumi Paints skipped {skipped_team_event_targets} team target(s).")
    if skipped_local_targets > 0:
        logs.append("Collection pool random fallback skipped the local driver because 'Do not apply random paints to myself' is enabled.")
    return fallback_saved, logs, summary

def apply_tp_showroom_fallbacks_public(
    session: Session,
    saved: list[SavedFile],
    paints_dir: Path,
    enable_real_drivers: bool,
    enable_ai: bool,
    sync_my_livery_from_server: bool,
    random_helmets: bool = False,
    random_suits: bool = False,
    random_helmets_real_drivers: bool = False,
    random_helmets_ai: bool = False,
    random_suits_real_drivers: bool = False,
    random_suits_ai: bool = False,
    disable_random_in_team_events: bool = False,
    disable_random_for_local_user: bool = False,
    mapping_path: Path | None = None,
    detect_showroom_total_pages: bool = False,
    showroom_sources: object = TP_SHOWROOM_DEFAULT_SOURCES,
    retries: int = 3,
    retry_backoff_seconds: float = 1.5,
    saved_callback: Callable[[list[SavedFile], str], None] | None = None,
    cancel_event: threading.Event | None = None,
) -> tuple[list[SavedFile], list[str], RandomFallbackSummary]:
    logs: list[str] = []
    fallback_saved: list[SavedFile] = []
    summary = RandomFallbackSummary()
    showroom_sources_text = normalize_tp_showroom_sources(showroom_sources)
    showroom_source_keys = tp_showroom_sources_list(showroom_sources_text)
    logs.append("Trading Paints online fallback is using public showroom direct downloads. No Trading Paints login, browser profile, or manifest member ID is required.")
    logs.append(f"Trading Paints public showroom random source(s): {tp_showroom_sources_label(showroom_sources_text)}.")
    if detect_showroom_total_pages:
        logs.append("Trading Paints public showroom total page detection is skipped for random fallback so downloads can start immediately.")
        detect_showroom_total_pages = False
    if _cancel_requested(cancel_event):
        logs.append("Trading Paints public showroom fallback cancelled before it started because the iRacing session changed or ended.")
        return fallback_saved, logs, summary

    existing_car_targets = {
        (bool(item.download_id.is_team_paint), int(item.download_id.user_id), item.download_id.directory.lower())
        for item in saved
        if item.download_id.paint_type is PaintType.CAR
    }
    existing_helmet_targets = {
        (bool(item.download_id.is_team_paint), int(item.download_id.user_id))
        for item in saved
        if item.download_id.paint_type is PaintType.HELMET
    }
    existing_suit_targets = {
        (bool(item.download_id.is_team_paint), int(item.download_id.user_id))
        for item in saved
        if item.download_id.paint_type is PaintType.SUIT
    }
    recent_schemes_by_directory = load_tp_recent_schemes()
    recent_history_changed = False
    used_showroom_scheme_ids: set[str] = set()
    random_pool_dir = default_random_pool_dir()
    ai_livery_root = default_ai_livery_dir()
    local_fallback_used_source_ids: set[str] = set()
    matched_ai_users = 0
    skipped_team_event_targets = 0
    skipped_local_targets = 0
    temp_root = default_temp_dir()
    showroom_cache_by_directory: dict[tuple[str, str], dict[str, object]] = {}
    showroom_cache_by_accessory_kind: dict[tuple[str, str], dict[str, object]] = {}

    def _record_saved_items(items: list[SavedFile]) -> None:
        for item in items:
            key = (bool(item.download_id.is_team_paint), int(item.download_id.user_id), item.download_id.directory.lower())
            accessory_key = (bool(item.download_id.is_team_paint), int(item.download_id.user_id))
            if item.download_id.paint_type is PaintType.CAR:
                existing_car_targets.add(key)
            elif item.download_id.paint_type is PaintType.HELMET:
                existing_helmet_targets.add(accessory_key)
            elif item.download_id.paint_type is PaintType.SUIT:
                existing_suit_targets.add(accessory_key)

    def _apply_public_accessory_fallback_for_user(
        *,
        user: SessionUser,
        label: str,
        accessory_kind: str,
        applied_items_for_target: list[SavedFile],
    ) -> bool:
        nonlocal recent_history_changed
        normalized_kind = str(accessory_kind or "").strip().lower()
        if normalized_kind not in {"helmet", "suit"}:
            return False
        showroom_source = choose_tp_showroom_source(showroom_source_keys)
        accessory_cache_key = (normalized_kind, showroom_source)
        accessory_cache = showroom_cache_by_accessory_kind.setdefault(
            accessory_cache_key,
            {"cars": [], "sampled_pages": set(), "detected_total_pages": 0},
        )
        recent_key = f"driver:{normalized_kind}"
        recent_scheme_ids = {
            str(item).strip()
            for item in recent_schemes_by_directory.get(recent_key, [])
            if str(item).strip()
        }
        for _attempt in range(1, 5):
            if _cancel_requested(cancel_event):
                break
            result = choose_showroom_accessory_direct(
                accessory_kind=normalized_kind,
                pages=TP_SHOWROOM_MAX_PAGES,
                prefer_official=False,
                choice_mode="random",
                showroom_sources=[showroom_source],
                exclude_scheme_ids=used_showroom_scheme_ids,
                exclude_recent_scheme_ids=recent_scheme_ids,
                showroom_cars=list(accessory_cache.get("cars") or []),
                showroom_sampled_pages=set(accessory_cache.get("sampled_pages") or set()),
                detected_total_pages=int(accessory_cache.get("detected_total_pages") or 0),
                detect_total_pages=detect_showroom_total_pages,
                minimum_unused_choices=1,
                allow_reuse_existing_scheme=False,
                log=logs.append,
                cancel_event=cancel_event,
            )
            if result.showroom_cars:
                accessory_cache["cars"] = list(result.showroom_cars)
            if result.showroom_sampled_pages:
                accessory_cache["sampled_pages"] = set(int(item) for item in result.showroom_sampled_pages)
            if int(result.detected_total_pages or 0) > 0:
                accessory_cache["detected_total_pages"] = int(result.detected_total_pages or 0)
            if not result.ok:
                logs.append(f"Public showroom random {normalized_kind} fallback could not select a paint for {label}: {result.message}")
                break
            chosen_scheme_id = str(result.chosen_scheme_id or "").strip()
            if chosen_scheme_id:
                used_showroom_scheme_ids.add(chosen_scheme_id)
            saved_items = _download_and_save_direct_showroom_accessory_result(
                session=session,
                user=user,
                result=result,
                accessory_kind=normalized_kind,
                temp_dir=temp_root,
                paints_dir=paints_dir,
                retries=retries,
                retry_backoff_seconds=retry_backoff_seconds,
                source_label="fallback_online",
                preserve_on_cleanup=False,
                cancel_event=cancel_event,
            )
            if not saved_items:
                logs.append(
                    f"Public showroom paint {chosen_scheme_id or '(unknown)'} for {label} {normalized_kind} was unavailable or could not be saved; trying another paint."
                )
                continue
            applied_items_for_target.extend(saved_items)
            fallback_saved.extend(saved_items)
            _record_saved_items(saved_items)
            if saved_callback is not None and not _cancel_requested(cancel_event):
                try:
                    saved_callback(saved_items, "fallback_online")
                except Exception:
                    logging.debug("Public showroom accessory fallback save callback failed", exc_info=True)
            if chosen_scheme_id:
                remember_tp_recent_scheme(recent_schemes_by_directory, recent_key, chosen_scheme_id)
                recent_history_changed = True
            if result.reused_previous_scheme:
                summary.repeated_source_uses += 1
            title = str(result.chosen_title or "").strip()
            source_label = tp_showroom_source_label(result.showroom_source or showroom_source)
            logs.append(
                f"Public showroom random {normalized_kind} fallback applied to {'AI' if user.is_ai else 'driver'} {label}: scheme {chosen_scheme_id}{f' - {title}' if title else ''} [{source_label}]."
            )
            return True
        logs.append(f"Public showroom {normalized_kind} fallback could not cover {label}; using the local random pool backup if available.")
        return False

    try:
        for user in sorted(session.users, key=lambda u: (u.is_ai, u.directory.lower(), u.user_id, u.team_id or 0)):
            if _cancel_requested(cancel_event):
                logs.append("Trading Paints public showroom fallback cancelled because the iRacing session changed or ended.")
                break
            if disable_random_in_team_events and session_user_uses_team_target(user):
                skipped_team_event_targets += 1
                continue
            if user.is_ai:
                matched_ai_users += 1
                car_enabled_for_user = bool(enable_ai)
                helmet_enabled_for_user = bool(random_helmets_ai)
                suit_enabled_for_user = bool(random_suits_ai)
                if not (car_enabled_for_user or helmet_enabled_for_user or suit_enabled_for_user):
                    continue
            else:
                car_enabled_for_user = bool(enable_real_drivers)
                helmet_enabled_for_user = bool(random_helmets_real_drivers)
                suit_enabled_for_user = bool(random_suits_real_drivers)
                if not (car_enabled_for_user or helmet_enabled_for_user or suit_enabled_for_user):
                    continue
            is_local_target = session_user_is_local_target(session, user)
            if disable_random_for_local_user and is_local_target:
                skipped_local_targets += 1
                continue
            if is_local_target and not sync_my_livery_from_server:
                continue

            target_is_team = session_user_uses_team_target(user)
            target_id = int(user.team_id) if target_is_team else int(user.user_id)
            target_key = (target_is_team, target_id, user.directory.lower())
            accessory_target_key = (target_is_team, target_id)
            need_car = car_enabled_for_user and target_key not in existing_car_targets
            need_helmet = bool(random_helmets) and helmet_enabled_for_user and accessory_target_key not in existing_helmet_targets
            need_suit = bool(random_suits) and suit_enabled_for_user and accessory_target_key not in existing_suit_targets
            if not (need_car or need_helmet or need_suit):
                continue

            summary.attempted_targets += 1
            label = user.display_name or (f"AI {target_id}" if user.is_ai else f"user {target_id}")
            applied_items_for_target: list[SavedFile] = []
            car_still_needs_local = bool(need_car)
            helmet_still_needs_local = bool(need_helmet)
            suit_still_needs_local = bool(need_suit)

            if need_car:
                directory_key = canonicalize_car_directory(user.directory).lower()
                showroom_source = choose_tp_showroom_source(showroom_source_keys)
                showroom_cache_key = (directory_key, showroom_source)
                showroom_cache = showroom_cache_by_directory.setdefault(
                    showroom_cache_key,
                    {"cars": [], "sampled_pages": set(), "detected_total_pages": 0},
                )
                recent_scheme_ids = {
                    str(item).strip()
                    for item in recent_schemes_by_directory.get(directory_key, [])
                    if str(item).strip()
                }
                for _attempt in range(1, 5):
                    if _cancel_requested(cancel_event):
                        break
                    result = choose_showroom_paint_direct(
                        directory=user.directory,
                        mapping_path=mapping_path,
                        pages=TP_SHOWROOM_MAX_PAGES,
                        prefer_official=False,
                        choice_mode="random",
                        showroom_sources=[showroom_source],
                        exclude_scheme_ids=used_showroom_scheme_ids,
                        exclude_recent_scheme_ids=recent_scheme_ids,
                        showroom_cars=list(showroom_cache.get("cars") or []),
                        showroom_sampled_pages=set(showroom_cache.get("sampled_pages") or set()),
                        detected_total_pages=int(showroom_cache.get("detected_total_pages") or 0),
                        detect_total_pages=detect_showroom_total_pages,
                        minimum_unused_choices=1,
                        allow_reuse_existing_scheme=False,
                        log=logs.append,
                        cancel_event=cancel_event,
                    )
                    if result.showroom_cars:
                        showroom_cache["cars"] = list(result.showroom_cars)
                    if result.showroom_sampled_pages:
                        showroom_cache["sampled_pages"] = set(int(item) for item in result.showroom_sampled_pages)
                    if int(result.detected_total_pages or 0) > 0:
                        showroom_cache["detected_total_pages"] = int(result.detected_total_pages or 0)
                    if not result.ok:
                        logs.append(f"Public showroom random car fallback could not select a paint for {label} on {user.directory}: {result.message}")
                        break
                    chosen_scheme_id = str(result.chosen_scheme_id or "").strip()
                    if chosen_scheme_id:
                        used_showroom_scheme_ids.add(chosen_scheme_id)
                    saved_items = _download_and_save_direct_showroom_car_result(
                        session=session,
                        user=user,
                        result=result,
                        temp_dir=temp_root,
                        paints_dir=paints_dir,
                        retries=retries,
                        retry_backoff_seconds=retry_backoff_seconds,
                        source_label="fallback_online",
                        preserve_on_cleanup=False,
                        cancel_event=cancel_event,
                    )
                    if not saved_items:
                        logs.append(
                            f"Public showroom paint {chosen_scheme_id or '(unknown)'} for {label} on {user.directory} was unavailable or could not be saved; trying another paint."
                        )
                        continue
                    applied_items_for_target.extend(saved_items)
                    fallback_saved.extend(saved_items)
                    _record_saved_items(saved_items)
                    if saved_callback is not None and not _cancel_requested(cancel_event):
                        try:
                            saved_callback(saved_items, "fallback_online")
                        except Exception:
                            logging.debug("Public showroom fallback save callback failed", exc_info=True)
                    if chosen_scheme_id:
                        remember_tp_recent_scheme(recent_schemes_by_directory, directory_key, chosen_scheme_id)
                        recent_history_changed = True
                    if result.reused_previous_scheme:
                        summary.repeated_source_uses += 1
                    car_still_needs_local = False
                    title = str(result.chosen_title or "").strip()
                    source_label = tp_showroom_source_label(result.showroom_source or showroom_source)
                    logs.append(
                        f"Public showroom random car fallback applied to {'AI' if user.is_ai else 'driver'} {label} on {user.directory}: scheme {chosen_scheme_id}{f' - {title}' if title else ''} [{source_label}]."
                    )
                    break
                if car_still_needs_local:
                    logs.append(f"Public showroom car fallback could not cover {label} on {user.directory}; using the local random pool backup if available.")

            if helmet_still_needs_local:
                helmet_still_needs_local = not _apply_public_accessory_fallback_for_user(
                    user=user,
                    label=label,
                    accessory_kind="helmet",
                    applied_items_for_target=applied_items_for_target,
                )

            if suit_still_needs_local:
                suit_still_needs_local = not _apply_public_accessory_fallback_for_user(
                    user=user,
                    label=label,
                    accessory_kind="suit",
                    applied_items_for_target=applied_items_for_target,
                )

            if car_still_needs_local or helmet_still_needs_local or suit_still_needs_local:
                local_saved, item_logs, reused_existing_source = _apply_local_tp_random_fallback_assets_for_user(
                    session=session,
                    user=user,
                    paints_dir=paints_dir,
                    random_pool_dir=random_pool_dir,
                    ai_livery_root=ai_livery_root,
                    used_source_ids=local_fallback_used_source_ids,
                    need_car=car_still_needs_local,
                    need_helmet=helmet_still_needs_local,
                    need_suit=suit_still_needs_local,
                )
                logs.extend(item_logs)
                if reused_existing_source:
                    summary.repeated_source_uses += 1
                if local_saved:
                    applied_items_for_target.extend(local_saved)
                    fallback_saved.extend(local_saved)
                    _record_saved_items(local_saved)
                    if saved_callback is not None and not _cancel_requested(cancel_event):
                        try:
                            saved_callback(local_saved, "fallback_local")
                        except Exception:
                            logging.debug("Local fallback save callback failed after public showroom fallback", exc_info=True)

            if applied_items_for_target:
                summary.applied_targets += 1
            else:
                summary.missing_source_targets += 1
        if enable_ai and session.ai_driver_count > 0 and matched_ai_users == 0:
            logs.append("AI session detected, but the SDK did not expose direct AI paint targets. Use 'Randomize active AI roster' to build a local randomized roster from TP-sourced paints.")
        if skipped_team_event_targets > 0:
            logs.append(
                f"Random fallback in team events is disabled, so Nishizumi Paints skipped {skipped_team_event_targets} team target(s)."
            )
        if skipped_local_targets > 0:
            logs.append("Public showroom random fallback skipped the local driver because 'Do not apply random paints to myself' is enabled.")
        return fallback_saved, logs, summary
    finally:
        if recent_history_changed:
            try:
                save_tp_recent_schemes(recent_schemes_by_directory)
            except Exception:
                logging.debug("Could not save public showroom recent scheme history", exc_info=True)


def apply_tp_showroom_fallbacks(
    session: Session,
    saved: list[SavedFile],
    paints_dir: Path,
    enable_real_drivers: bool,
    enable_ai: bool,
    sync_my_livery_from_server: bool,
    random_helmets: bool = False,
    random_suits: bool = False,
    random_helmets_real_drivers: bool = False,
    random_helmets_ai: bool = False,
    random_suits_real_drivers: bool = False,
    random_suits_ai: bool = False,
    disable_random_in_team_events: bool = False,
    disable_random_for_local_user: bool = False,
    mapping_path: Path | None = None,
    profile_dir: Path | None = None,
    manifest_member_id: int | None = None,
    primary_fast_mode: bool = False,
    mule_profile_mode: bool = False,
    detect_showroom_total_pages: bool = False,
    showroom_sources: object = TP_SHOWROOM_DEFAULT_SOURCES,
    retries: int = 3,
    retry_backoff_seconds: float = 1.5,
    tp_fallback_lanes_mode: str = "session_total",
    tp_manual_max_lanes: int = 1,
    process_all_together: bool = False,
    retry_timed_out_fallbacks_indefinitely: bool = True,
    saved_callback: Callable[[list[SavedFile], str], None] | None = None,
    cancel_event: threading.Event | None = None,
    _thread_handoff_done: bool = False,
) -> tuple[list[SavedFile], list[str], RandomFallbackSummary]:
    return apply_tp_showroom_fallbacks_public(
        session=session,
        saved=saved,
        paints_dir=paints_dir,
        enable_real_drivers=enable_real_drivers,
        enable_ai=enable_ai,
        sync_my_livery_from_server=sync_my_livery_from_server,
        random_helmets=random_helmets,
        random_suits=random_suits,
        random_helmets_real_drivers=random_helmets_real_drivers,
        random_helmets_ai=random_helmets_ai,
        random_suits_real_drivers=random_suits_real_drivers,
        random_suits_ai=random_suits_ai,
        disable_random_in_team_events=disable_random_in_team_events,
        disable_random_for_local_user=disable_random_for_local_user,
        mapping_path=mapping_path,
        detect_showroom_total_pages=detect_showroom_total_pages,
        showroom_sources=showroom_sources,
        retries=retries,
        retry_backoff_seconds=retry_backoff_seconds,
        saved_callback=saved_callback,
        cancel_event=cancel_event,
    )

    if sync_playwright is not None and not _thread_handoff_done:
        return _run_tp_sync_api_in_thread(
            lambda: apply_tp_showroom_fallbacks(
                session=session,
                saved=saved,
                paints_dir=paints_dir,
                enable_real_drivers=enable_real_drivers,
                enable_ai=enable_ai,
                sync_my_livery_from_server=sync_my_livery_from_server,
                random_helmets=random_helmets,
                random_suits=random_suits,
                random_helmets_real_drivers=random_helmets_real_drivers,
                random_helmets_ai=random_helmets_ai,
                random_suits_real_drivers=random_suits_real_drivers,
                random_suits_ai=random_suits_ai,
                disable_random_in_team_events=disable_random_in_team_events,
                mapping_path=mapping_path,
                profile_dir=profile_dir,
                manifest_member_id=manifest_member_id,
                primary_fast_mode=primary_fast_mode,
                mule_profile_mode=mule_profile_mode,
                detect_showroom_total_pages=detect_showroom_total_pages,
                showroom_sources=showroom_sources,
                retries=retries,
                retry_backoff_seconds=retry_backoff_seconds,
                tp_fallback_lanes_mode=tp_fallback_lanes_mode,
                tp_manual_max_lanes=tp_manual_max_lanes,
                process_all_together=process_all_together,
                retry_timed_out_fallbacks_indefinitely=retry_timed_out_fallbacks_indefinitely,
                saved_callback=saved_callback,
                cancel_event=cancel_event,
                _thread_handoff_done=True,
            )
        )

    logs: list[str] = []
    fallback_saved: list[SavedFile] = []
    summary = RandomFallbackSummary()
    profile_dir = profile_dir or default_tp_showroom_profile_dir()
    effective_primary_fast_mode = True
    effective_mule_mode = False
    logs.append("Trading Paints online fallback is using the built-in protected fast path: the app keeps original-paint backup/restore protection while skipping the extra dashboard confirmation loop after each showroom swap.")
    if detect_showroom_total_pages:
        logs.append("Trading Paints showroom total page detection is enabled for this profile. The app will probe the showroom and log the detected total pages before filling the pool.")
    if retry_timed_out_fallbacks_indefinitely:
        logs.append(f"Trading Paints online fallback timeout policy: each online paint gets up to {TP_ONLINE_FALLBACK_TARGET_TIMEOUT_SECONDS:.0f}s first; if it times out after Trading Paints accepts the scheme, the app retries that same scheme once after {TP_ONLINE_FALLBACK_PRE_FINAL_RETRY_DELAY_SECONDS:.0f}s, then queues it for the final {TP_ONLINE_FALLBACK_FINAL_MAX_SECONDS / 60:.0f}-minute retry stage before using the local random pool.")
    else:
        logs.append(f"Trading Paints online fallback timeout policy: each online paint gets up to {TP_ONLINE_FALLBACK_TARGET_TIMEOUT_SECONDS:.0f}s first; if it times out after Trading Paints accepts the scheme, the app retries that same scheme once after {TP_ONLINE_FALLBACK_PRE_FINAL_RETRY_DELAY_SECONDS:.0f}s, then uses the local random pool.")
    if _cancel_requested(cancel_event):
        logs.append("Trading Paints showroom fallback cancelled before online fallback started because the iRacing session changed or ended.")
        return fallback_saved, logs, summary
    if not is_tp_login_confirmed(profile_dir):
        logs.append("Trading Paints showroom fallback is enabled, but the Trading Paints login has not been confirmed yet.")
        return fallback_saved, logs, summary

    existing_car_targets = {
        (bool(item.download_id.is_team_paint), int(item.download_id.user_id), item.download_id.directory.lower())
        for item in saved
        if item.download_id.paint_type is PaintType.CAR
    }
    existing_helmet_targets = {
        (bool(item.download_id.is_team_paint), int(item.download_id.user_id))
        for item in saved
        if item.download_id.paint_type is PaintType.HELMET
    }
    existing_suit_targets = {
        (bool(item.download_id.is_team_paint), int(item.download_id.user_id))
        for item in saved
        if item.download_id.paint_type is PaintType.SUIT
    }

    recent_schemes_by_directory = load_tp_recent_schemes()
    random_pool_dir = default_random_pool_dir()
    ai_livery_root = default_ai_livery_dir()
    local_fallback_used_source_ids: set[str] = set()
    local_fallback_lock = threading.Lock()
    lane_users_by_directory: dict[str, list[SessionUser]] = {}
    helmet_users: list[SessionUser] = []
    suit_users: list[SessionUser] = []
    skipped_team_event_targets = 0

    for candidate in sorted(session.users, key=lambda u: (u.is_ai, u.directory.lower(), u.user_id, u.team_id or 0)):
        if disable_random_in_team_events and session_user_uses_team_target(candidate):
            skipped_team_event_targets += 1
            continue
        if candidate.is_ai:
            car_enabled_for_candidate = bool(enable_ai)
            helmet_enabled_for_candidate = bool(random_helmets_ai)
            suit_enabled_for_candidate = bool(random_suits_ai)
            if not (car_enabled_for_candidate or helmet_enabled_for_candidate or suit_enabled_for_candidate):
                continue
        else:
            car_enabled_for_candidate = bool(enable_real_drivers)
            helmet_enabled_for_candidate = bool(random_helmets_real_drivers)
            suit_enabled_for_candidate = bool(random_suits_real_drivers)
            if not (car_enabled_for_candidate or helmet_enabled_for_candidate or suit_enabled_for_candidate):
                continue
        is_local_target = False
        if session.local_user_id is not None and candidate.user_id == session.local_user_id:
            is_local_target = True
        if session_user_uses_team_target(candidate) and session.local_team_id is not None and candidate.team_id == session.local_team_id:
            is_local_target = True
        if is_local_target and not sync_my_livery_from_server:
            continue

        target_is_team = session_user_uses_team_target(candidate)
        target_id = int(candidate.team_id) if target_is_team else int(candidate.user_id)
        target_key = (target_is_team, target_id, candidate.directory.lower())
        accessory_target_key = (target_is_team, target_id)
        if car_enabled_for_candidate and target_key not in existing_car_targets:
            directory_key = canonicalize_car_directory(candidate.directory).lower()
            lane_users_by_directory.setdefault(directory_key, []).append(candidate)
        if bool(random_helmets) and helmet_enabled_for_candidate and accessory_target_key not in existing_helmet_targets:
            helmet_users.append(candidate)
        if bool(random_suits) and suit_enabled_for_candidate and accessory_target_key not in existing_suit_targets:
            suit_users.append(candidate)

    if not lane_users_by_directory and not helmet_users and not suit_users:
        if skipped_team_event_targets > 0:
            logs.append(
                f"Random fallback in team events is disabled, so Nishizumi Paints skipped {skipped_team_event_targets} team target(s)."
            )
        return fallback_saved, logs, summary

    lane_group_count = len(lane_users_by_directory)
    lane_mode = normalize_tp_fallback_lanes_mode(tp_fallback_lanes_mode)
    manual_lane_cap = max(1, min(100, positive_int(tp_manual_max_lanes, 1)))
    if lane_group_count > 0:
        if lane_mode == "manual":
            max_lanes = min(lane_group_count, manual_lane_cap)
            logs.append(
                f"Trading Paints online fallback lanes active: {lane_group_count} car group(s), mode=manual, manual limit={manual_lane_cap}, using {max_lanes} concurrent lane(s)."
            )
        elif lane_mode == "session_total":
            max_lanes = lane_group_count
            logs.append(
                f"Trading Paints online fallback lanes active: {lane_group_count} car group(s), mode=Session Total, using all {max_lanes} concurrent lane(s)."
            )
        else:
            max_lanes = min(lane_group_count, 1)
            logs.append(
                f"Trading Paints online fallback lanes active: {lane_group_count} car group(s), mode=safe, using {max_lanes} concurrent lane(s)."
            )
    else:
        max_lanes = 0
    if helmet_users:
        logs.append(f"Trading Paints online accessory stage queued: helmet targets={len(helmet_users)}.")
    if suit_users:
        logs.append(f"Trading Paints online accessory stage queued: suit targets={len(suit_users)}.")
    if process_all_together and (helmet_users or suit_users):
        logs.append("Trading Paints online advanced parallel mode is enabled: cars, helmets, and suits will be processed together.")
    elif helmet_users or suit_users:
        logs.append("Trading Paints online fallback stage order: cars first, then helmets, then suits.")
    if skipped_team_event_targets > 0:
        logs.append(
            f"Random fallback in team events is disabled, so Nishizumi Paints skipped {skipped_team_event_targets} team target(s)."
        )

    ordered_lanes = sorted(
        lane_users_by_directory.items(),
        key=lambda item: (
            bool(item[1][0].is_ai) if item[1] else False,
            len(item[1]),
            item[0],
        ),
        reverse=True,
    )

    def _collect_stage_results(
        future_map: dict[concurrent.futures.Future, tuple[str, str]],
        *,
        helmet_target_count: int = 0,
        suit_target_count: int = 0,
    ) -> None:
        for future in concurrent.futures.as_completed(future_map):
            task_kind, task_key = future_map[future]
            if _cancel_requested(cancel_event):
                logs.append("Trading Paints online fallback stopped collecting stage results because the iRacing session changed or ended.")
                break
            try:
                lane_result = future.result()
            except Exception as exc:
                logging.debug("Trading Paints fallback task crashed for %s", task_key, exc_info=True)
                if task_kind == "car":
                    summary.missing_source_targets += len(lane_users_by_directory.get(task_key, []))
                elif task_kind == "helmet":
                    summary.missing_source_targets += int(helmet_target_count)
                elif task_kind == "suit":
                    summary.missing_source_targets += int(suit_target_count)
                logs.append(f"Trading Paints fallback task crashed for {task_key}: {exc}")
                continue

            fallback_saved.extend(list(lane_result.get("saved") or []))
            logs.extend(list(lane_result.get("logs") or []))
            lane_summary = lane_result.get("summary")
            if isinstance(lane_summary, RandomFallbackSummary):
                summary.attempted_targets += int(lane_summary.attempted_targets)
                summary.applied_targets += int(lane_summary.applied_targets)
                summary.missing_source_targets += int(lane_summary.missing_source_targets)
                summary.repeated_source_uses += int(lane_summary.repeated_source_uses)

            updated_recent = [str(item).strip() for item in (lane_result.get("recent_scheme_ids") or []) if str(item).strip()]
            if updated_recent:
                recent_schemes_by_directory[task_key] = updated_recent

    def _submit_car_lanes(executor) -> dict[concurrent.futures.Future, tuple[str, str]]:
        future_map: dict[concurrent.futures.Future, tuple[str, str]] = {}
        for lane_index, (directory_key, users) in enumerate(ordered_lanes):
            lane_kwargs = dict(
                lane_index=lane_index,
                users=list(users),
                session=session,
                paints_dir=paints_dir,
                mapping_path=mapping_path,
                profile_dir=profile_dir,
                manifest_member_id=manifest_member_id,
                effective_primary_fast_mode=effective_primary_fast_mode,
                effective_mule_mode=effective_mule_mode,
                detect_showroom_total_pages=detect_showroom_total_pages,
                retries=retries,
                retry_backoff_seconds=retry_backoff_seconds,
                saved_callback=saved_callback,
                initial_original_cache_entry=None,
                initial_recent_scheme_ids=list(recent_schemes_by_directory.get(directory_key, [])),
                random_pool_dir=random_pool_dir,
                ai_livery_root=ai_livery_root,
                local_fallback_used_source_ids=local_fallback_used_source_ids,
                local_fallback_lock=local_fallback_lock,
                retry_timed_out_fallbacks_indefinitely=retry_timed_out_fallbacks_indefinitely,
                cancel_event=cancel_event,
            )
            if sync_playwright is not None:
                future = executor.submit(
                    _run_tp_sync_api_in_thread,
                    lambda lane_kwargs=lane_kwargs: _process_tp_showroom_fallback_lane(**lane_kwargs),
                )
            else:
                future = executor.submit(_process_tp_showroom_fallback_lane, **lane_kwargs)
            future_map[future] = ("car", directory_key)
        return future_map

    if process_all_together:
        worker_count = max(1, max_lanes + (1 if helmet_users else 0) + (1 if suit_users else 0))
        with concurrent.futures.ThreadPoolExecutor(max_workers=worker_count, thread_name_prefix="TPFallbackLane") as executor:
            future_map = _submit_car_lanes(executor) if ordered_lanes else {}
            if helmet_users:
                future = executor.submit(
                    _process_tp_showroom_accessory_targets,
                    accessory_kind="helmet",
                    users=list(helmet_users),
                    session=session,
                    paints_dir=paints_dir,
                    profile_dir=profile_dir,
                    manifest_member_id=manifest_member_id,
                    effective_primary_fast_mode=effective_primary_fast_mode,
                    effective_mule_mode=effective_mule_mode,
                    detect_showroom_total_pages=detect_showroom_total_pages,
                    retries=retries,
                    retry_backoff_seconds=retry_backoff_seconds,
                    saved_callback=saved_callback,
                    initial_recent_scheme_ids=list(recent_schemes_by_directory.get(TP_DRIVER_HELMET_CACHE_KEY, [])),
                    random_pool_dir=random_pool_dir,
                    ai_livery_root=ai_livery_root,
                    local_fallback_used_source_ids=local_fallback_used_source_ids,
                    local_fallback_lock=local_fallback_lock,
                    retry_timed_out_fallbacks_indefinitely=retry_timed_out_fallbacks_indefinitely,
                    cancel_event=cancel_event,
                )
                future_map[future] = ("helmet", TP_DRIVER_HELMET_CACHE_KEY)
            if suit_users:
                future = executor.submit(
                    _process_tp_showroom_accessory_targets,
                    accessory_kind="suit",
                    users=list(suit_users),
                    session=session,
                    paints_dir=paints_dir,
                    profile_dir=profile_dir,
                    manifest_member_id=manifest_member_id,
                    effective_primary_fast_mode=effective_primary_fast_mode,
                    effective_mule_mode=effective_mule_mode,
                    detect_showroom_total_pages=detect_showroom_total_pages,
                    retries=retries,
                    retry_backoff_seconds=retry_backoff_seconds,
                    saved_callback=saved_callback,
                    initial_recent_scheme_ids=list(recent_schemes_by_directory.get(TP_DRIVER_SUIT_CACHE_KEY, [])),
                    random_pool_dir=random_pool_dir,
                    ai_livery_root=ai_livery_root,
                    local_fallback_used_source_ids=local_fallback_used_source_ids,
                    local_fallback_lock=local_fallback_lock,
                    retry_timed_out_fallbacks_indefinitely=retry_timed_out_fallbacks_indefinitely,
                    cancel_event=cancel_event,
                )
                future_map[future] = ("suit", TP_DRIVER_SUIT_CACHE_KEY)
            _collect_stage_results(future_map, helmet_target_count=len(helmet_users), suit_target_count=len(suit_users))
    else:
        if ordered_lanes:
            with concurrent.futures.ThreadPoolExecutor(max_workers=max(1, max_lanes), thread_name_prefix="TPFallbackCarLane") as executor:
                _collect_stage_results(_submit_car_lanes(executor))

        if helmet_users and not _cancel_requested(cancel_event):
            with concurrent.futures.ThreadPoolExecutor(max_workers=1, thread_name_prefix="TPFallbackHelmetStage") as executor:
                future = executor.submit(
                    _process_tp_showroom_accessory_targets,
                    accessory_kind="helmet",
                    users=list(helmet_users),
                    session=session,
                    paints_dir=paints_dir,
                    profile_dir=profile_dir,
                    manifest_member_id=manifest_member_id,
                    effective_primary_fast_mode=effective_primary_fast_mode,
                    effective_mule_mode=effective_mule_mode,
                    detect_showroom_total_pages=detect_showroom_total_pages,
                    retries=retries,
                    retry_backoff_seconds=retry_backoff_seconds,
                    saved_callback=saved_callback,
                    initial_recent_scheme_ids=list(recent_schemes_by_directory.get(TP_DRIVER_HELMET_CACHE_KEY, [])),
                    random_pool_dir=random_pool_dir,
                    ai_livery_root=ai_livery_root,
                    local_fallback_used_source_ids=local_fallback_used_source_ids,
                    local_fallback_lock=local_fallback_lock,
                    retry_timed_out_fallbacks_indefinitely=retry_timed_out_fallbacks_indefinitely,
                    cancel_event=cancel_event,
                )
                _collect_stage_results({future: ("helmet", TP_DRIVER_HELMET_CACHE_KEY)}, helmet_target_count=len(helmet_users))

        if suit_users and not _cancel_requested(cancel_event):
            with concurrent.futures.ThreadPoolExecutor(max_workers=1, thread_name_prefix="TPFallbackSuitStage") as executor:
                future = executor.submit(
                    _process_tp_showroom_accessory_targets,
                    accessory_kind="suit",
                    users=list(suit_users),
                    session=session,
                    paints_dir=paints_dir,
                    profile_dir=profile_dir,
                    manifest_member_id=manifest_member_id,
                    effective_primary_fast_mode=effective_primary_fast_mode,
                    effective_mule_mode=effective_mule_mode,
                    detect_showroom_total_pages=detect_showroom_total_pages,
                    retries=retries,
                    retry_backoff_seconds=retry_backoff_seconds,
                    saved_callback=saved_callback,
                    initial_recent_scheme_ids=list(recent_schemes_by_directory.get(TP_DRIVER_SUIT_CACHE_KEY, [])),
                    random_pool_dir=random_pool_dir,
                    ai_livery_root=ai_livery_root,
                    local_fallback_used_source_ids=local_fallback_used_source_ids,
                    local_fallback_lock=local_fallback_lock,
                    retry_timed_out_fallbacks_indefinitely=retry_timed_out_fallbacks_indefinitely,
                    cancel_event=cancel_event,
                )
                _collect_stage_results({future: ("suit", TP_DRIVER_SUIT_CACHE_KEY)}, suit_target_count=len(suit_users))

    save_tp_recent_schemes(recent_schemes_by_directory)
    return fallback_saved, logs, summary

def _build_fetch_context_payload(session: Session, user: SessionUser, superspeedway_variant: bool = False) -> dict[str, str] | None:
    context = session.trading_paints_context()
    if context is None:
        return None
    payload = dict(context)
    payload["list"] = user.trading_paints_list_value()
    if superspeedway_variant and session.is_superspeedway_track:
        payload["ss"] = "1"
    return payload
def _matches_context_manifest_entry(user: SessionUser, car: ET.Element) -> bool:
    car_id = (car.findtext("carid") or '').strip()
    if not car_id or car_id == "0":
        return False
    manifest_user = (car.findtext("userid") or '').strip()
    manifest_team = (car.findtext("teamid") or "0").strip() or "0"
    expected_user = str(user.user_id)
    expected_team = str(user.team_id or 0)
    if session_user_uses_team_target(user):
        return manifest_user == expected_user or manifest_team == expected_team
    return manifest_user == expected_user and manifest_team == expected_team
def _safe_ai_roster_folder_name(name: str, fallback: str) -> str:
    cleaned = (name or '').strip() or fallback
    cleaned = re.sub(r'[<>:"/\|?*]+', '_', cleaned)
    cleaned = cleaned.rstrip(' .')
    return cleaned or fallback
def _cleanup_ai_roster_dirs(ai_rosters_dir: Path) -> None:
    if not ai_rosters_dir.exists():
        return
    removed = 0
    for child in ai_rosters_dir.iterdir():
        if not child.is_dir():
            continue
        if (child / "roster.json").exists():
            continue
        try:
            shutil.rmtree(child, ignore_errors=False)
            removed += 1
        except Exception as exc:  # noqa: BLE001
            logging.debug("AI roster cleanup could not remove %s: %s", child, exc)
    if removed:
        logging.info("AI roster cleanup removed %s empty folder(s)", removed)
def _write_ai_roster_metadata(roster_dir: Path, roster: AIWebRosterItem | None = None, *, roster_id: str = "", name: str = "", is_local: bool = False, source_roster_id: str = "", source_name: str = "") -> None:
    payload = {
        "roster_id": roster.roster_id if roster is not None else str(roster_id or ''),
        "name": roster.name if roster is not None else str(name or ''),
        "roster_file": roster.roster_file if roster is not None else "",
        "is_local": bool(is_local),
        "source_roster_id": str(source_roster_id or ''),
        "source_name": str(source_name or ''),
    }
    (roster_dir / AI_ROSTER_META_FILENAME).write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
def _read_ai_roster_payload(roster_dir: Path) -> tuple[dict[str, list[dict]], list[dict]]:
    payload = json.loads((roster_dir / "roster.json").read_text(encoding="utf-8"))
    drivers = payload.get('drivers') if isinstance(payload, dict) else None
    if not isinstance(drivers, list):
        raise ValueError("AI roster JSON did not contain a drivers list")
    normalized_drivers = [_normalize_ai_driver_entry(driver) for driver in drivers if isinstance(driver, dict)]
    return {"drivers": normalized_drivers}, normalized_drivers
def _ai_roster_asset_id_from_filename(filename: str) -> str | None:
    name = Path(str(filename or '').strip()).name
    match = re.search(r"_(\d+)(?:_(?:ss|spec))*\.(?:tga|mip)$", name, re.IGNORECASE)
    if not match:
        return None
    return match.group(1)
def _ai_roster_spec_filename(car_tga_name: str) -> str:
    return f"{Path(str(car_tga_name or '').strip()).stem}_spec.mip"
def _ai_roster_car_is_numbered(filename: str) -> bool:
    return Path(str(filename or '').strip()).name.lower().startswith("car_num_")
def _ai_roster_car_paint_type(filename: str) -> PaintType:
    return PaintType.CAR_NUMBER if _ai_roster_car_is_numbered(filename) else PaintType.CAR
def _ai_roster_asset_url(asset_id: str, filename: str) -> str:
    if str(filename or '').lower().endswith(".mip"):
        return TRADING_PAINTS_SHOWROOM_MIP_URL.format(asset_id=asset_id)
    return TRADING_PAINTS_SHOWROOM_COMPRESSED_URL.format(asset_id=asset_id)
def _ai_roster_unavailable_marker_path(roster_dir: Path, filename: str) -> Path:
    return safe_join_under(roster_dir, Path(filename).name + AI_ROSTER_OPTIONAL_UNAVAILABLE_SUFFIX)
def _ai_roster_asset_marked_unavailable(roster_dir: Path, filename: str) -> bool:
    marker = _ai_roster_unavailable_marker_path(roster_dir, filename)
    if not marker.exists():
        return False
    try:
        age = time.time() - marker.stat().st_mtime
        if age > AI_ROSTER_OPTIONAL_UNAVAILABLE_TTL_SECONDS:
            marker.unlink(missing_ok=True)
            return False
    except OSError:
        return True
    return True
def _mark_ai_roster_asset_unavailable(roster_dir: Path, filename: str, url: str, status_code: int | None) -> None:
    marker = _ai_roster_unavailable_marker_path(roster_dir, filename)
    try:
        marker.write_text(
            json.dumps(
                {
                    "url": url,
                    "status_code": status_code,
                    "marked_at": time.time(),
                },
                indent=2,
            ),
            encoding="utf-8",
        )
    except OSError:
        logging.debug("Could not write AI optional asset unavailable marker for %s", filename, exc_info=True)
def _clear_ai_roster_asset_unavailable_marker(roster_dir: Path, filename: str) -> None:
    try:
        _ai_roster_unavailable_marker_path(roster_dir, filename).unlink(missing_ok=True)
    except OSError:
        logging.debug("Could not clear AI optional asset unavailable marker for %s", filename, exc_info=True)
def _probe_optional_ai_roster_asset_status(url: str) -> int | None:
    try:
        http = get_thread_http_session()
        with http.get(url, timeout=(5, 12), stream=True, headers={"Range": "bytes=0-0"}) as response:
            return int(response.status_code)
    except requests.RequestException:
        logging.debug("Could not probe optional AI roster asset endpoint %s", url, exc_info=True)
    except Exception:
        logging.debug("Unexpected error while probing optional AI roster asset endpoint %s", url, exc_info=True)
    return None
def _iter_ai_roster_asset_specs(drivers: list[dict]) -> list[tuple[str, str, str, bool]]:
    specs: list[tuple[str, str, str, bool]] = []
    seen: set[str] = set()
    for driver in drivers:
        if not isinstance(driver, dict):
            continue
        driver_name = str(driver.get('driverName') or driver.get('name') or '').strip()
        for field_name, default_kind in (
            ("carTgaName", "car"),
            ("helmetTgaName", "helmet"),
            ("suitTgaName", "suit"),
        ):
            filename = Path(str(driver.get(field_name) or '').strip()).name
            if not filename:
                continue
            asset_id = _ai_roster_asset_id_from_filename(filename)
            if not asset_id:
                continue
            kind = "car_num" if field_name == "carTgaName" and _ai_roster_car_is_numbered(filename) else default_kind
            if filename.lower() not in seen:
                seen.add(filename.lower())
                specs.append((filename, _ai_roster_asset_url(asset_id, filename), kind, False))
            if field_name == "carTgaName":
                spec_filename = _ai_roster_spec_filename(filename)
                if spec_filename.lower() not in seen:
                    seen.add(spec_filename.lower())
                    specs.append((spec_filename, _ai_roster_asset_url(asset_id, spec_filename), "car_spec", True))
    return specs
def _download_ai_roster_asset(roster_dir: Path, filename: str, url: str, optional: bool, retries: int, retry_backoff_seconds: float) -> str:
    destination = safe_join_under(roster_dir, Path(filename).name)
    if optional and _ai_roster_asset_marked_unavailable(roster_dir, filename):
        return "optional_unavailable"
    try:
        if destination.exists() and destination.stat().st_size > 0:
            if optional:
                status_code = _probe_optional_ai_roster_asset_status(url)
                if isinstance(status_code, int) and status_code in TP_UNAVAILABLE_DOWNLOAD_STATUS_CODES:
                    _mark_ai_roster_asset_unavailable(roster_dir, filename, url, status_code)
                    return "optional_unavailable"
                if isinstance(status_code, int) and 200 <= status_code < 400:
                    _clear_ai_roster_asset_unavailable_marker(roster_dir, filename)
            return "existing"
    except OSError:
        pass
    destination.parent.mkdir(parents=True, exist_ok=True)
    temp_download = destination.with_name(destination.name + ".download")
    temp_extract = destination.with_name(destination.name + ".tmp")
    last_exc: Exception | None = None
    for attempt in range(1, max(1, int(retries)) + 1):
        temp_download.unlink(missing_ok=True)
        temp_extract.unlink(missing_ok=True)
        try:
            http = get_thread_http_session()
            with http.get(url, timeout=(10, 90), stream=True) as response:
                response.raise_for_status()
                with temp_download.open("wb") as handle:
                    for chunk in response.iter_content(chunk_size=1024 * 1024):
                        if chunk:
                            handle.write(chunk)
            if url.lower().endswith(".bz2"):
                with temp_download.open("rb") as source, bz2.open(source, "rb") as decompressor, temp_extract.open("wb") as out:
                    shutil.copyfileobj(decompressor, out)
                temp_download.unlink(missing_ok=True)
            else:
                os.replace(temp_download, temp_extract)
            os.replace(temp_extract, destination)
            if optional:
                _clear_ai_roster_asset_unavailable_marker(roster_dir, filename)
            return "downloaded"
        except requests.RequestException as exc:
            last_exc = exc
            response = getattr(exc, "response", None)
            status_code = getattr(response, "status_code", None)
            if optional and isinstance(status_code, int) and status_code in TP_UNAVAILABLE_DOWNLOAD_STATUS_CODES:
                temp_download.unlink(missing_ok=True)
                temp_extract.unlink(missing_ok=True)
                _mark_ai_roster_asset_unavailable(roster_dir, filename, url, status_code)
                return "optional_unavailable"
            if attempt >= max(1, int(retries)):
                break
            time.sleep(compute_retry_delay(retry_backoff_seconds, attempt))
        except Exception as exc:  # noqa: BLE001
            last_exc = exc
            if attempt >= max(1, int(retries)):
                break
            time.sleep(compute_retry_delay(retry_backoff_seconds, attempt))
    temp_download.unlink(missing_ok=True)
    temp_extract.unlink(missing_ok=True)
    if optional:
        logging.debug("Optional AI roster asset %s could not be synced from %s: %s", filename, url, last_exc)
        return "optional_unavailable"
    logging.warning("AI roster asset %s could not be synced from %s: %s", filename, url, last_exc)
    return "failed"
def sync_ai_roster_collection_assets(roster_dir: Path, drivers: list[dict], retries: int, retry_backoff_seconds: float) -> tuple[int, int, int, int]:
    specs = _iter_ai_roster_asset_specs(drivers)
    if not specs:
        return 0, 0, 0, 0
    counts = Counter()
    worker_count = max(1, min(16, len(specs)))
    with concurrent.futures.ThreadPoolExecutor(max_workers=worker_count) as executor:
        future_to_spec = {
            executor.submit(_download_ai_roster_asset, roster_dir, filename, url, optional, retries, retry_backoff_seconds): (filename, url, optional)
            for filename, url, _kind, optional in specs
        }
        for future in concurrent.futures.as_completed(future_to_spec):
            try:
                counts[future.result()] += 1
            except Exception as exc:  # noqa: BLE001
                filename, url, optional = future_to_spec[future]
                counts["optional_unavailable" if optional else "failed"] += 1
                logging.warning("AI roster asset worker failed for %s from %s: %s", filename, url, exc)
    downloaded = int(counts.get("downloaded", 0))
    existing = int(counts.get("existing", 0))
    optional_unavailable = int(counts.get("optional_unavailable", 0))
    failed = int(counts.get("failed", 0))
    if downloaded or failed:
        logging.info(
            "AI roster assets synced for %s: %s downloaded, %s already present, %s optional unavailable, %s failed",
            roster_dir.name,
            downloaded,
            existing,
            optional_unavailable,
            failed,
        )
    else:
        logging.debug(
            "AI roster assets already present for %s: %s existing, %s optional unavailable",
            roster_dir.name,
            existing,
            optional_unavailable,
        )
    return downloaded, existing, optional_unavailable, failed
def _normalize_ai_match_text(value: object) -> str:
    return re.sub(r"\s+", " ", str(value or '').strip()).casefold()
def _normalize_ai_car_path(value: object) -> str:
    return normalize_directory(str(value or '').replace("\\", " "))
def _normalize_ai_car_number(value: object) -> str:
    text = str(value or '').strip()
    if not text:
        return "0"
    stripped = text.lstrip("0")
    return stripped or "0"
def _ai_roster_dir_is_generated_random(roster_dir: Path) -> bool:
    if roster_dir.name.casefold() == AI_GENERIC_RANDOM_ROSTER_NAME.casefold():
        return True
    meta = _load_ai_roster_metadata(roster_dir)
    source_name = str(meta.get("source_name") or '').casefold()
    return "generic ai session random fallback" in source_name
def _ai_roster_dir_is_local(roster_dir: Path) -> bool:
    meta = _load_ai_roster_metadata(roster_dir)
    if bool(meta.get("is_local")):
        return True
    return not bool(str(meta.get("roster_id") or '').strip() or str(meta.get("roster_file") or '').strip())
def _score_ai_roster_against_session(session: Session, drivers: list[dict]) -> tuple[int, int, int, int]:
    ai_users = [user for user in session.users if user.is_ai]
    if not ai_users or not drivers:
        return (0, 0, 0, len(ai_users))
    exact_matches = 0
    name_matches = 0
    index_matches = 0
    for user in ai_users:
        user_name = _normalize_ai_match_text(user.display_name)
        user_number = _normalize_ai_car_number(user.number)
        user_path = _normalize_ai_car_path(user.directory)
        matched_name = False
        for driver in drivers:
            if not isinstance(driver, dict):
                continue
            driver_name = _normalize_ai_match_text(driver.get('driverName') or driver.get('name'))
            if not user_name or driver_name != user_name:
                continue
            matched_name = True
            driver_number = _normalize_ai_car_number(driver.get('carNumber'))
            driver_path = _normalize_ai_car_path(driver.get('carPath'))
            if driver_number == user_number and (not user_path or not driver_path or driver_path == user_path):
                exact_matches += 1
            break
        if matched_name:
            name_matches += 1
        fallback_index = int(user.user_id) - 9700
        if 0 <= fallback_index < len(drivers):
            driver = drivers[fallback_index]
            driver_number = _normalize_ai_car_number(driver.get('carNumber') if isinstance(driver, dict) else None)
            driver_path = _normalize_ai_car_path(driver.get('carPath') if isinstance(driver, dict) else None)
            if driver_number == user_number and (not user_path or not driver_path or driver_path == user_path):
                index_matches += 1
    return (exact_matches, name_matches, index_matches, len(ai_users))
def _infer_active_ai_roster_dir_from_session(session: Session, ai_rosters_dir: Path) -> Path | None:
    if session.ai_driver_count <= 0 or not ai_rosters_dir.exists():
        return None
    ai_users = [user for user in session.users if user.is_ai]
    if not ai_users:
        return None
    name_threshold = max(5, (len(ai_users) + 3) // 4)
    exact_threshold = max(2, (len(ai_users) + 4) // 5)
    regular_candidates: list[tuple[int, int, int, float, Path]] = []
    generated_candidates: list[tuple[int, int, int, float, Path]] = []
    for child in ai_rosters_dir.iterdir():
        if not child.is_dir() or not (child / "roster.json").exists():
            continue
        try:
            _payload, drivers = _read_ai_roster_payload(child)
        except Exception:
            continue
        exact_matches, name_matches, index_matches, total_ai = _score_ai_roster_against_session(session, drivers)
        if exact_matches < exact_threshold and name_matches < name_threshold:
            continue
        try:
            freshness = float((child / "roster.json").stat().st_mtime)
        except OSError:
            freshness = 0.0
        candidate = (exact_matches, name_matches, index_matches, freshness, child)
        if _ai_roster_dir_is_generated_random(child):
            generated_candidates.append(candidate)
        else:
            regular_candidates.append(candidate)
    candidates = regular_candidates or generated_candidates
    if not candidates:
        return None
    candidates.sort(key=lambda item: (item[0], item[1], item[2], item[3]), reverse=True)
    return candidates[0][4]
def _find_roster_driver_for_session_ai(user: SessionUser, drivers: list[dict]) -> dict | None:
    user_name = _normalize_ai_match_text(user.display_name)
    user_number = _normalize_ai_car_number(user.number)
    user_path = _normalize_ai_car_path(user.directory)
    fallback_index = int(user.user_id) - 9700
    best_name_path_match: dict | None = None
    best_name_number_match: dict | None = None
    best_name_match: dict | None = None
    best_index_match: dict | None = None
    for index, driver in enumerate(drivers):
        if not isinstance(driver, dict):
            continue
        driver_name = _normalize_ai_match_text(driver.get('driverName') or driver.get('name'))
        driver_number = _normalize_ai_car_number(driver.get('carNumber'))
        driver_path = _normalize_ai_car_path(driver.get('carPath'))
        if user_name and driver_name == user_name:
            if driver_number == user_number and (not user_path or not driver_path or driver_path == user_path):
                return driver
            if user_path and driver_path == user_path and best_name_path_match is None:
                best_name_path_match = driver
            if user_number and driver_number == user_number and best_name_number_match is None:
                best_name_number_match = driver
            if best_name_match is None:
                best_name_match = driver
        if index == fallback_index:
            best_index_match = driver
    return best_name_path_match or best_name_number_match or best_name_match or best_index_match
def fetch_active_ai_roster_collection_files(session: Session, user: SessionUser, ai_rosters_dir: Path | None) -> list[DownloadFile]:
    if not user.is_ai or ai_rosters_dir is None:
        return []
    roster_dir = _find_active_ai_roster_dir(session, ai_rosters_dir)
    if roster_dir is None:
        logging.debug("AI collection lookup skipped for %s: active AI roster is not synced locally yet.", user.display_name or user.user_id)
        return []
    if _ai_roster_dir_is_local(roster_dir):
        logging.debug("AI collection lookup skipped for %s: active AI roster %s is local.", user.display_name or user.user_id, roster_dir.name)
        return []
    try:
        _payload, drivers = _read_ai_roster_payload(roster_dir)
    except Exception as exc:  # noqa: BLE001
        logging.debug("AI collection lookup could not read %s: %s", roster_dir, exc)
        return []
    driver = _find_roster_driver_for_session_ai(user, drivers)
    if not driver:
        logging.debug("AI collection lookup could not match session AI %s (%s) in roster %s", user.display_name or user.user_id, user.user_id, roster_dir.name)
        return []
    items: list[DownloadFile] = []
    car_tga_name = Path(str(driver.get('carTgaName') or '').strip()).name
    car_asset_id = _ai_roster_asset_id_from_filename(car_tga_name)
    if car_asset_id:
        car_paint_type = _ai_roster_car_paint_type(car_tga_name)
        is_numbered_car = car_paint_type is PaintType.CAR_NUMBER
        items.append(
            DownloadFile(
                download_id=DownloadId(
                    user_id=int(user.user_id),
                    directory=user.directory,
                    paint_type=car_paint_type,
                    is_team_paint=False,
                    is_superspeedway_variant=_paint_filename_is_superspeedway_variant(car_tga_name, car_paint_type),
                ),
                url=_ai_roster_asset_url(car_asset_id, car_tga_name),
            )
        )
        spec_name = _ai_roster_spec_filename(car_tga_name)
        if (roster_dir / spec_name).exists() and not _ai_roster_asset_marked_unavailable(roster_dir, spec_name):
            items.append(
                DownloadFile(
                    download_id=DownloadId(
                        user_id=int(user.user_id),
                        directory=user.directory,
                        paint_type=PaintType.CAR_SPEC,
                        is_team_paint=False,
                        is_superspeedway_variant=_paint_filename_is_superspeedway_variant(spec_name, PaintType.CAR_SPEC),
                        is_numbered_car_spec=is_numbered_car,
                    ),
                    url=_ai_roster_asset_url(car_asset_id, spec_name),
                    ai_roster_optional_filename=spec_name,
                    ai_roster_dir=roster_dir,
                )
            )
    return items
def _load_ai_roster_metadata(roster_dir: Path) -> dict[str, object]:
    meta_file = roster_dir / AI_ROSTER_META_FILENAME
    if meta_file.exists():
        try:
            data = json.loads(meta_file.read_text(encoding="utf-8"))
            if isinstance(data, dict):
                return data
        except Exception:
            pass
    return {}
def _find_active_ai_roster_dir(session: Session, ai_rosters_dir: Path) -> Path | None:
    if not ai_rosters_dir.exists():
        return None
    candidates: list[Path] = []
    if session.ai_roster_name:
        candidates.append(ai_rosters_dir / _safe_ai_roster_folder_name(session.ai_roster_name, f"AI_Roster_{session.ai_roster_id or 'unknown'}"))
    seen: set[Path] = set()
    for candidate in candidates:
        if candidate in seen:
            continue
        seen.add(candidate)
        if (candidate / "roster.json").exists():
            return candidate
    for child in ai_rosters_dir.iterdir():
        if not child.is_dir() or not (child / "roster.json").exists():
            continue
        meta = _load_ai_roster_metadata(child)
        if session.ai_roster_id and str(meta.get('roster_id') or '') == session.ai_roster_id:
            return child
        if session.ai_roster_name and str(meta.get('name') or '') == session.ai_roster_name:
            return child
    if not session.ai_roster_name and not session.ai_roster_id:
        inferred = _infer_active_ai_roster_dir_from_session(session, ai_rosters_dir)
        if inferred is not None:
            return inferred
    return None
def session_uses_trading_paints_ai_collection(session: Session, ai_rosters_dir: Path | None) -> bool:
    if ai_rosters_dir is None or session.ai_driver_count <= 0:
        return False
    roster_dir = _find_active_ai_roster_dir(session, ai_rosters_dir)
    if roster_dir is None:
        return False
    meta = _load_ai_roster_metadata(roster_dir)
    if bool(meta.get("is_local")):
        return False
    return bool(meta.get("roster_id") or meta.get("roster_file"))
def session_uses_local_ai_roster(session: Session, ai_rosters_dir: Path | None) -> bool:
    if ai_rosters_dir is None or session.ai_driver_count <= 0:
        return False
    roster_dir = _find_active_ai_roster_dir(session, ai_rosters_dir)
    if roster_dir is None:
        return False
    return _ai_roster_dir_is_local(roster_dir)

def _ai_roster_local_file(roster_dir: Path, filename: object) -> Path | None:
    name = Path(str(filename or "").strip()).name
    if not name:
        return None
    try:
        path = safe_join_under(roster_dir, name)
    except Exception:
        return None
    return path if path.exists() else None

def _apply_local_ai_roster_driver_to_session(
    *,
    session: Session,
    user: SessionUser,
    paints_dir: Path,
    roster_dir: Path,
    driver: dict,
    need_car: bool,
    need_helmet: bool,
    need_suit: bool,
) -> list[SavedFile]:
    target_id = int(user.user_id)
    base_kwargs = {
        "user_id": target_id,
        "directory": user.directory,
        "is_team_paint": False,
        "is_superspeedway_variant": False,
        "tp_title": f"Local AI roster {roster_dir.name}",
        "tp_source": "local_ai_roster",
    }
    saved_items: list[SavedFile] = []
    if need_car:
        car_name = Path(str(driver.get("carTgaName") or "").strip()).name
        car_source = _ai_roster_local_file(roster_dir, car_name)
        if car_source is not None:
            car_asset_id = _ai_roster_asset_id_from_filename(car_name) or ""
            car_paint_type = _ai_roster_car_paint_type(car_name)
            for paint_type, source_path in (
                (car_paint_type, car_source),
                (PaintType.CAR_SPEC, _ai_roster_local_file(roster_dir, _ai_roster_spec_filename(car_name))),
            ):
                if source_path is None:
                    continue
                copied = _copy_source_file_to_saved_targets(
                    source_path,
                    session.session_id,
                    DownloadId(
                        paint_type=paint_type,
                        tp_scheme_id=car_asset_id,
                        **base_kwargs,
                    ),
                    paints_dir,
                )
                if copied:
                    saved_items.extend(copied)
    if need_helmet:
        helmet_name = Path(str(driver.get("helmetTgaName") or "").strip()).name
        helmet_source = _ai_roster_local_file(roster_dir, helmet_name)
        if helmet_source is not None:
            copied = _copy_source_file_to_saved_targets(
                helmet_source,
                session.session_id,
                DownloadId(
                    paint_type=PaintType.HELMET,
                    tp_scheme_id=_ai_roster_asset_id_from_filename(helmet_name) or "",
                    **base_kwargs,
                ),
                paints_dir,
            )
            if copied:
                saved_items.extend(copied)
    if need_suit:
        suit_name = Path(str(driver.get("suitTgaName") or "").strip()).name
        suit_source = _ai_roster_local_file(roster_dir, suit_name)
        if suit_source is not None:
            copied = _copy_source_file_to_saved_targets(
                suit_source,
                session.session_id,
                DownloadId(
                    paint_type=PaintType.SUIT,
                    tp_scheme_id=_ai_roster_asset_id_from_filename(suit_name) or "",
                    **base_kwargs,
                ),
                paints_dir,
            )
            if copied:
                saved_items.extend(copied)
    return saved_items

def apply_local_ai_roster_live_paints(
    *,
    session: Session,
    saved: list[SavedFile],
    paints_dir: Path,
    ai_rosters_dir: Path | None,
    saved_callback: Callable[[list[SavedFile], str], None] | None = None,
) -> tuple[list[SavedFile], list[str]]:
    logs: list[str] = []
    applied: list[SavedFile] = []
    if ai_rosters_dir is None or session.ai_driver_count <= 0:
        return applied, logs
    if not _session_has_named_ai_roster(session):
        logs.append(
            "Local AI roster live apply skipped because the current AI session does not expose a roster name or ID. "
            "Nishizumi Paints will treat this as a live random AI session and apply paints directly to the session targets instead."
        )
        return applied, logs
    roster_dir = _find_active_ai_roster_dir(session, ai_rosters_dir)
    if roster_dir is None or not _ai_roster_dir_is_local(roster_dir):
        return applied, logs
    try:
        _payload, drivers = _read_ai_roster_payload(roster_dir)
    except Exception as exc:
        logs.append(f"Local AI roster live apply could not read roster {roster_dir.name}: {exc}")
        return applied, logs
    exact_matches, name_matches, index_matches, total_ai = _score_ai_roster_against_session(session, drivers)
    logs.append(
        f"Local AI roster live apply is mirroring roster {roster_dir.name} into the active session "
        f"({name_matches}/{total_ai} name matches, {exact_matches} exact, {index_matches} index)."
    )
    existing_car_targets = {
        (bool(item.download_id.is_team_paint), int(item.download_id.user_id), item.download_id.directory.lower())
        for item in saved
        if item.download_id.paint_type in {PaintType.CAR, PaintType.CAR_NUMBER}
    }
    existing_helmet_targets = {
        (bool(item.download_id.is_team_paint), int(item.download_id.user_id))
        for item in saved
        if item.download_id.paint_type is PaintType.HELMET
    }
    existing_suit_targets = {
        (bool(item.download_id.is_team_paint), int(item.download_id.user_id))
        for item in saved
        if item.download_id.paint_type is PaintType.SUIT
    }
    matched_users = 0
    copied_targets = 0
    copied_cars = 0
    copied_helmets = 0
    copied_suits = 0
    missing_targets = 0
    for user in sorted((item for item in session.users if item.is_ai), key=lambda item: (item.directory.lower(), item.user_id)):
        driver = _find_roster_driver_for_session_ai(user, drivers)
        if driver is None:
            continue
        matched_users += 1
        target_key = (False, int(user.user_id), user.directory.lower())
        accessory_key = (False, int(user.user_id))
        need_car = target_key not in existing_car_targets
        need_helmet = accessory_key not in existing_helmet_targets
        need_suit = accessory_key not in existing_suit_targets
        if not (need_car or need_helmet or need_suit):
            continue
        saved_items = _apply_local_ai_roster_driver_to_session(
            session=session,
            user=user,
            paints_dir=paints_dir,
            roster_dir=roster_dir,
            driver=driver,
            need_car=need_car,
            need_helmet=need_helmet,
            need_suit=need_suit,
        )
        if not saved_items:
            missing_targets += 1
            continue
        applied.extend(saved_items)
        copied_targets += 1
        for item in saved_items:
            if item.download_id.paint_type in {PaintType.CAR, PaintType.CAR_NUMBER}:
                copied_cars += 1
                existing_car_targets.add((False, int(item.download_id.user_id), item.download_id.directory.lower()))
            elif item.download_id.paint_type is PaintType.HELMET:
                copied_helmets += 1
                existing_helmet_targets.add((False, int(item.download_id.user_id)))
            elif item.download_id.paint_type is PaintType.SUIT:
                copied_suits += 1
                existing_suit_targets.add((False, int(item.download_id.user_id)))
        if saved_callback is not None:
            try:
                saved_callback(saved_items, "fallback_local")
            except Exception:
                logging.debug("Local AI roster live apply callback failed", exc_info=True)
    if applied:
        logs.append(
            f"Local AI roster live apply copied {copied_cars} car file(s), {copied_helmets} helmet file(s), and {copied_suits} suit file(s) "
            f"for {copied_targets} AI target(s) from roster {roster_dir.name}."
        )
    else:
        logs.append(
            f"Local AI roster live apply found roster {roster_dir.name}, but no usable roster paint files could be copied into the active session."
        )
    if matched_users < session.ai_driver_count:
        logs.append(
            f"Local AI roster live apply matched {matched_users}/{session.ai_driver_count} AI drivers to roster entries in {roster_dir.name}."
        )
    if missing_targets > 0:
        logs.append(
            f"Local AI roster live apply left {missing_targets} AI target(s) unchanged because the roster did not contain usable local files for those entries."
        )
    return applied, logs
def _normalize_ai_driver_entry(driver: dict) -> dict:
    normalized = dict(driver)
    car_id = _to_int_or_none(normalized.get('carId')) or 0
    car_class_id = _to_int_or_none(normalized.get('carClassId')) or 0
    car_design = str(normalized.get('carDesign') or '')
    if car_id in AI_SPECIAL_CAR_IDS_WITH_DEFAULT_DESIGN and car_class_id == 0 and (not car_design or not car_design.startswith("0")):
        normalized["carDesign"] = "0,,,"
    car_path = normalized.get('carPath')
    if isinstance(car_path, str) and car_path:
        normalized["carPath"] = car_path.replace(" ", "\\")
    return normalized
def _canonicalize_ai_roster_payload(raw_json: str) -> tuple[dict[str, list[dict]], list[dict]]:
    payload = json.loads(raw_json)
    drivers = payload.get('drivers') if isinstance(payload, dict) else None
    if not isinstance(drivers, list):
        raise ValueError("AI roster JSON did not contain a drivers list")
    normalized_drivers: list[dict] = []
    for driver in drivers:
        if isinstance(driver, dict):
            normalized_drivers.append(_normalize_ai_driver_entry(driver))
    return {"drivers": normalized_drivers}, normalized_drivers
def _build_ai_roster_notes(drivers: list[dict]) -> str:
    lines = ["Summary:", "", "", "", "Drivers:"]
    for driver in drivers:
        number = str(driver.get('carNumber') or "?")
        name = str(driver.get('driverName') or "Unknown Driver")
        lines.extend([f"{number}: {name}", "", "", ""])
    return "\n".join(lines).rstrip() + "\n"
def _write_ai_roster_files(roster_dir: Path, canonical_payload: dict[str, list[dict]], drivers: list[dict], roster: AIWebRosterItem | None = None, *, is_local: bool = False, source_roster_id: str = "", source_name: str = "") -> None:
    roster_dir.mkdir(parents=True, exist_ok=True)
    roster_json = json.dumps(canonical_payload, indent=2, ensure_ascii=False)
    (roster_dir / "roster.json").write_text(roster_json, encoding="utf-8")
    (roster_dir / "notes.txt").write_text(_build_ai_roster_notes(drivers), encoding="utf-8")
    _write_ai_roster_metadata(roster_dir, roster, is_local=is_local, source_roster_id=source_roster_id, source_name=source_name)
def fetch_ai_roster_list(member_id: int, retries: int, retry_backoff_seconds: float) -> list[AIWebRosterItem]:
    url = TRADING_PAINTS_COLLECTIONS_URL.format(member_id=member_id)
    last_exc: Exception | None = None
    for attempt in range(1, retries + 1):
        try:
            session = get_thread_http_session()
            response = session.get(url, timeout=30)
            response.raise_for_status()
            root = ET.fromstring(response.text)
            rosters: list[AIWebRosterItem] = []
            for item in root.findall(".//Collection"):
                roster_id = (item.findtext("ID") or '').strip()
                name = (item.findtext("Name") or '').strip()
                roster_file = (item.findtext("RosterFile") or '').strip()
                if not roster_id or not name or not roster_file:
                    continue
                rosters.append(AIWebRosterItem(roster_id=roster_id, name=name, roster_file=roster_file))
            return rosters
        except (requests.RequestException, ET.ParseError) as exc:
            last_exc = exc
            if attempt >= retries:
                break
            delay = compute_retry_delay(retry_backoff_seconds, attempt)
            logging.debug("AI roster list fetch failed for member %s (attempt %s/%s): %s. Retrying in %.1fs", member_id, attempt, retries, exc, delay)
            time.sleep(delay)
    assert last_exc is not None
    raise last_exc
def fetch_ai_roster_json(roster: AIWebRosterItem, retries: int, retry_backoff_seconds: float) -> str | None:
    last_exc: Exception | None = None
    for attempt in range(1, retries + 1):
        try:
            session = get_thread_http_session()
            response = session.get(roster.roster_file, timeout=30)
            response.raise_for_status()
            payload = response.text or ''
            if len(payload.strip()) <= 2:
                return None
            return payload
        except requests.RequestException as exc:
            last_exc = exc
            if attempt >= retries:
                break
            delay = compute_retry_delay(retry_backoff_seconds, attempt)
            logging.debug("AI roster JSON fetch failed for %s (attempt %s/%s): %s. Retrying in %.1fs", roster.name, attempt, retries, exc, delay)
            time.sleep(delay)
    if last_exc is not None:
        raise last_exc
    return None
def sync_ai_rosters(member_id: int, ai_rosters_dir: Path, retries: int, retry_backoff_seconds: float, do_cleanup: bool = True) -> AIRosterSyncResult:
    result = AIRosterSyncResult(member_id=member_id, ai_rosters_dir=ai_rosters_dir)
    ai_rosters_dir.mkdir(parents=True, exist_ok=True)
    started_at = time.monotonic()
    try:
        rosters = fetch_ai_roster_list(member_id, retries=retries, retry_backoff_seconds=retry_backoff_seconds)
        result.discovered = len(rosters)
        if not rosters:
            logging.info("AI roster sync found no Trading Paints AI carsets for member %s", member_id)
            return result
        for item in rosters:
            try:
                raw_json = fetch_ai_roster_json(item, retries=retries, retry_backoff_seconds=retry_backoff_seconds)
                if not raw_json:
                    result.failed += 1
                    logging.warning("AI roster sync skipped empty roster JSON for %s", item.name)
                    continue
                try:
                    canonical_payload, drivers = _canonicalize_ai_roster_payload(raw_json)
                except Exception as exc:  # noqa: BLE001
                    result.failed += 1
                    logging.warning("AI roster sync could not validate roster %s: %s", item.name, exc)
                    continue
                folder_name = _safe_ai_roster_folder_name(item.name, f"AI_Roster_{item.roster_id}")
                roster_dir = ai_rosters_dir / folder_name
                _write_ai_roster_files(roster_dir, canonical_payload, drivers, item)
                sync_ai_roster_collection_assets(
                    roster_dir=roster_dir,
                    drivers=drivers,
                    retries=retries,
                    retry_backoff_seconds=retry_backoff_seconds,
                )
                result.downloaded += 1
                logging.info("AI roster synced: %s (%s drivers)", item.name, len(drivers))
            except Exception as exc:  # noqa: BLE001
                result.failed += 1
                logging.warning("AI roster sync failed for %s: %s", item.name, exc)
        return result
    except Exception as exc:  # noqa: BLE001
        logging.warning("AI roster sync failed for member %s: %s", member_id, exc)
        return result
    finally:
        if do_cleanup:
            _cleanup_ai_roster_dirs(ai_rosters_dir)
        elapsed = time.monotonic() - started_at
        logging.info("AI roster sync complete for member %s: %s found, %s saved, %s failed in %.2fs", member_id, result.discovered, result.downloaded, result.failed, elapsed)
        if result.downloaded:
            logging.info("AI rosters were saved to %s", ai_rosters_dir)
            logging.info("If iRacing already loaded an AI roster, recreate the AI session to pick up newly synced carsets.")
def clone_active_ai_roster_to_local(session: Session | None, ai_rosters_dir: Path) -> tuple[bool, str]:
    if session is None:
        return False, "No current iRacing session is active."
    if not session.ai_roster_name and not session.ai_roster_id:
        return False, "The current session does not report an active AI roster."
    source_dir = _find_active_ai_roster_dir(session, ai_rosters_dir)
    if source_dir is None:
        return False, "The active Trading Paints AI roster has not been synced locally yet."
    try:
        canonical_payload, drivers = _read_ai_roster_payload(source_dir)
    except Exception as exc:
        return False, f"Could not read the active AI roster: {exc}"
    base_name = (session.ai_roster_name or source_dir.name).strip() or (source_dir.name or "AI Roster")
    local_name = f"{base_name}{AI_LOCAL_ROSTER_SUFFIX}"
    target_dir = ai_rosters_dir / _safe_ai_roster_folder_name(local_name, f"AI_Roster_{session.ai_roster_id or 'local'}{AI_LOCAL_ROSTER_SUFFIX}")
    if target_dir.exists():
        return False, f"A local AI roster folder already exists for {local_name}."
    target_dir.mkdir(parents=True, exist_ok=False)
    copied_files = 0
    for driver in drivers:
        car_tga_name = str(driver.get('carTgaName') or '').strip()
        helmet_tga_name = str(driver.get('helmetTgaName') or '').strip()
        suit_tga_name = str(driver.get('suitTgaName') or '').strip()
        for filename in (car_tga_name, helmet_tga_name, suit_tga_name):
            if not filename:
                continue
            src = source_dir / filename
            dest = target_dir / filename
            if src.exists():
                dest.parent.mkdir(parents=True, exist_ok=True)
                shutil.copy2(src, dest)
                copied_files += 1
                if filename.lower().endswith('.tga'):
                    spec_src = source_dir / filename[:-4].replace('car_', 'car_')
                    spec_src = source_dir / f"{Path(filename).stem}_spec.mip"
                    if spec_src.exists():
                        shutil.copy2(spec_src, target_dir / spec_src.name)
                        copied_files += 1
    _write_ai_roster_files(
        target_dir,
        canonical_payload,
        drivers,
        None,
        is_local=True,
        source_roster_id=session.ai_roster_id,
        source_name=session.ai_roster_name or base_name,
    )
    message = f"Created local AI roster '{local_name}' with {len(drivers)} driver(s)"
    if copied_files > 0:
        message += f" and copied {copied_files} local file(s)."
    else:
        message += "."
    return True, message
def _extract_ai_cache_numeric_id(filename: str) -> int | None:
    match = re.search(r"_(\d+)(?:_ss)?\.(?:tga|mip)$", filename, re.IGNORECASE)
    if not match:
        return None
    try:
        return int(match.group(1))
    except Exception:
        return None
def _next_ai_cache_id(ai_livery_car_dir: Path) -> str:
    ai_livery_car_dir.mkdir(parents=True, exist_ok=True)
    highest = 0
    for child in ai_livery_car_dir.iterdir():
        if not child.is_file():
            continue
        num = _extract_ai_cache_numeric_id(child.name)
        if num is not None and num > highest:
            highest = num
    return str(highest + 1)
def _copy_optional_file(src: Path | None, dest: Path) -> bool:
    if src is None or not src.exists():
        return False
    dest.parent.mkdir(parents=True, exist_ok=True)
    shutil.copy2(src, dest)
    return True
def _session_has_named_ai_roster(session: Session) -> bool:
    return bool(str(session.ai_roster_name or '').strip() or str(session.ai_roster_id or '').strip())
def _generic_ai_saved_file_map(session: Session, saved: list[SavedFile]) -> dict[int, dict[PaintType, list[SavedFile]]]:
    ai_target_ids = {int(user.user_id) for user in session.users if user.is_ai}
    grouped: dict[int, dict[PaintType, list[SavedFile]]] = {}
    allowed_types = {
        PaintType.CAR,
        PaintType.CAR_NUMBER,
        PaintType.CAR_SPEC,
        PaintType.CAR_DECAL,
        PaintType.HELMET,
        PaintType.SUIT,
    }
    for item in saved:
        download_id = item.download_id
        if download_id.is_team_paint or int(download_id.user_id) not in ai_target_ids:
            continue
        if download_id.paint_type not in allowed_types:
            continue
        if not item.file_path.exists():
            continue
        grouped.setdefault(int(download_id.user_id), {}).setdefault(download_id.paint_type, []).append(item)
    return grouped
def _choose_generic_ai_saved_file(file_map: dict[PaintType, list[SavedFile]], paint_types: Iterable[PaintType]) -> SavedFile | None:
    for want_ss in (False, True):
        for paint_type in paint_types:
            for item in file_map.get(paint_type, []):
                if bool(item.download_id.is_superspeedway_variant) == want_ss and item.file_path.exists():
                    return item
    return None
def _reset_generated_ai_roster_dir(ai_rosters_dir: Path, roster_dir: Path) -> None:
    root_abs = os.path.normcase(os.path.abspath(ai_rosters_dir))
    target_abs = os.path.normcase(os.path.abspath(roster_dir))
    if os.path.commonpath([root_abs, target_abs]) != root_abs or target_abs == root_abs:
        raise ValueError(f"Refusing to reset AI roster folder outside {ai_rosters_dir}")
    if roster_dir.exists():
        shutil.rmtree(roster_dir)
    roster_dir.mkdir(parents=True, exist_ok=False)
def _copy_saved_file_to_ai_roster(item: SavedFile | None, roster_dir: Path, filename: str) -> bool:
    if item is None or not item.file_path.exists():
        return False
    dest = safe_join_under(roster_dir, Path(filename).name)
    dest.parent.mkdir(parents=True, exist_ok=True)
    shutil.copy2(item.file_path, dest)
    return True
def _generic_ai_roster_driver_payload(
    session: Session,
    user: SessionUser,
    row_index: int,
    matched_driver: dict | None,
) -> dict:
    car_path = str((matched_driver or {}).get('carPath') or user.directory or '').strip().replace(" ", "\\")
    seed = f"{session.session_id.folder_name()}:{user.user_id}:{user.display_name}:{user.number}:{car_path}"
    return {
        "driverName": str(user.display_name or f"AI {user.user_id}").strip(),
        "carNumber": str(user.number or row_index + 1),
        "carId": _to_int_or_none((matched_driver or {}).get('carId')) or 0,
        "carClassId": _to_int_or_none((matched_driver or {}).get('carClassId')) or 0,
        "carPath": car_path,
        "id": str(uuid.uuid5(uuid.NAMESPACE_URL, f"nishizumi-generic-ai:{seed}")),
        "carDesign": str((matched_driver or {}).get('carDesign') or "0,000000,000000,FFFFFF"),
        "carTgaName": None,
        "helmetTgaName": None,
        "suitTgaName": None,
        "numberDesign": str((matched_driver or {}).get('numberDesign') or "0,0,ffffff,AAAAAA,000000"),
        "helmetDesign": str((matched_driver or {}).get('helmetDesign') or "0,000000,000000,FFFFFF"),
        "suitDesign": str((matched_driver or {}).get('suitDesign') or "0,000000,000000,FFFFFF"),
        "disableCarDecals": bool((matched_driver or {}).get('disableCarDecals', False)),
        "sponsor1": _to_int_or_none((matched_driver or {}).get('sponsor1')) or 0,
        "sponsor2": _to_int_or_none((matched_driver or {}).get('sponsor2')) or 0,
        "rowIndex": row_index,
        "driverSkill": _to_int_or_none((matched_driver or {}).get('driverSkill')) or 50,
        "driverAggression": _to_int_or_none((matched_driver or {}).get('driverAggression')) or 50,
        "driverOptimism": _to_int_or_none((matched_driver or {}).get('driverOptimism')) or 50,
        "driverSmoothness": _to_int_or_none((matched_driver or {}).get('driverSmoothness')) or 50,
        "pitCrewSkill": _to_int_or_none((matched_driver or {}).get('pitCrewSkill')) or 50,
        "strategyRiskiness": _to_int_or_none((matched_driver or {}).get('strategyRiskiness')) or 50,
        "driverAge": _to_int_or_none((matched_driver or {}).get('driverAge')) or 30,
    }
def _copy_random_fallbacks_to_ai_roster_driver(
    user: SessionUser,
    file_map: dict[PaintType, list[SavedFile]],
    roster_dir: Path,
    driver: dict,
) -> tuple[int, int, bool]:
    copied_files = 0
    accessories_with_paint = 0
    car_with_paint = False
    car_item = _choose_generic_ai_saved_file(file_map, (PaintType.CAR, PaintType.CAR_NUMBER))
    if car_item is not None:
        car_filename = f"car_num_{user.user_id}.tga" if car_item.download_id.paint_type is PaintType.CAR_NUMBER else f"car_{user.user_id}.tga"
        if _copy_saved_file_to_ai_roster(car_item, roster_dir, car_filename):
            driver["carTgaName"] = car_filename
            copied_files += 1
            car_with_paint = True
            spec_item = _choose_generic_ai_saved_file(file_map, (PaintType.CAR_SPEC,))
            if _copy_saved_file_to_ai_roster(spec_item, roster_dir, _ai_roster_spec_filename(car_filename)):
                copied_files += 1
    helmet_item = _choose_generic_ai_saved_file(file_map, (PaintType.HELMET,))
    if _copy_saved_file_to_ai_roster(helmet_item, roster_dir, f"helmet_{user.user_id}.tga"):
        driver["helmetTgaName"] = f"helmet_{user.user_id}.tga"
        copied_files += 1
        accessories_with_paint += 1
    suit_item = _choose_generic_ai_saved_file(file_map, (PaintType.SUIT,))
    if _copy_saved_file_to_ai_roster(suit_item, roster_dir, f"suit_{user.user_id}.tga"):
        driver["suitTgaName"] = f"suit_{user.user_id}.tga"
        copied_files += 1
        accessories_with_paint += 1
    return copied_files, accessories_with_paint, car_with_paint
def _update_active_local_ai_roster_from_random_fallbacks(
    session: Session,
    fallback_saved: list[SavedFile],
    ai_rosters_dir: Path,
    saved_by_user: dict[int, dict[PaintType, list[SavedFile]]],
) -> tuple[bool, str]:
    roster_dir = _find_active_ai_roster_dir(session, ai_rosters_dir)
    if roster_dir is None or not _ai_roster_dir_is_local(roster_dir):
        return False, ""
    try:
        _payload, drivers = _read_ai_roster_payload(roster_dir)
    except Exception as exc:  # noqa: BLE001
        return False, f"Could not read active local AI roster {roster_dir.name}: {exc}"
    ai_users = sorted(
        [user for user in session.users if user.is_ai],
        key=lambda user: (user.car_idx is None, user.car_idx if user.car_idx is not None else int(user.user_id), int(user.user_id)),
    )
    if not ai_users:
        return False, ""
    copied_files = 0
    cars_with_paint = 0
    accessories_with_paint = 0
    matched_targets = 0
    for user in ai_users:
        file_map = saved_by_user.get(int(user.user_id), {})
        if not file_map:
            continue
        driver = _find_roster_driver_for_session_ai(user, drivers)
        if not driver:
            continue
        matched_targets += 1
        copied, accessories, has_car = _copy_random_fallbacks_to_ai_roster_driver(user, file_map, roster_dir, driver)
        copied_files += copied
        accessories_with_paint += accessories
        if has_car:
            cars_with_paint += 1
    if copied_files <= 0:
        return False, f"Active local AI roster '{roster_dir.name}' was detected, but no matching random fallback files could be copied into it."
    roster_item = AIWebRosterItem(roster_id="", name=roster_dir.name, roster_file="")
    _write_ai_roster_files(
        roster_dir,
        {"drivers": drivers},
        drivers,
        roster_item,
        is_local=True,
        source_name="Local AI roster random fallback",
    )
    return True, (
        f"Updated active local AI roster '{roster_dir.name}' with random fallback paints: "
        f"{matched_targets}/{len(ai_users)} session AI target(s) matched, {cars_with_paint} car paint(s), "
        f"{accessories_with_paint} helmet/suit file(s), {copied_files} copied file(s). "
        f"Recreate the AI race with this same roster selected so iRacing reloads the roster paint references."
    )
def create_generic_ai_roster_from_random_fallbacks(
    session: Session,
    fallback_saved: list[SavedFile],
    ai_rosters_dir: Path | None,
) -> tuple[bool, str]:
    if ai_rosters_dir is None or session.ai_driver_count <= 0:
        return False, ""
    ai_users = sorted(
        [user for user in session.users if user.is_ai],
        key=lambda user: (user.car_idx is None, user.car_idx if user.car_idx is not None else int(user.user_id), int(user.user_id)),
    )
    if not ai_users:
        return False, ""
    saved_by_user = _generic_ai_saved_file_map(session, fallback_saved)
    if not saved_by_user:
        return False, ""
    updated_local_roster, local_roster_message = _update_active_local_ai_roster_from_random_fallbacks(
        session,
        fallback_saved,
        ai_rosters_dir,
        saved_by_user,
    )
    if local_roster_message:
        return updated_local_roster, local_roster_message
    if _session_has_named_ai_roster(session):
        return False, ""
    roster_folder = _safe_ai_roster_folder_name(AI_GENERIC_RANDOM_ROSTER_NAME, AI_GENERIC_RANDOM_ROSTER_FOLDER_FALLBACK)
    roster_dir = ai_rosters_dir / roster_folder
    try:
        ai_rosters_dir.mkdir(parents=True, exist_ok=True)
        _reset_generated_ai_roster_dir(ai_rosters_dir, roster_dir)
    except Exception as exc:  # noqa: BLE001
        return False, f"Could not create generic AI random roster folder: {exc}"
    drivers: list[dict] = []
    copied_files = 0
    cars_with_paint = 0
    accessories_with_paint = 0
    session_ai_drivers = [dict(driver) for driver in session.ai_drivers if isinstance(driver, dict)]
    for row_index, user in enumerate(ai_users):
        matched_driver = _find_roster_driver_for_session_ai(user, session_ai_drivers)
        driver = _generic_ai_roster_driver_payload(session, user, row_index, matched_driver)
        file_map = saved_by_user.get(int(user.user_id), {})
        copied, accessories, has_car = _copy_random_fallbacks_to_ai_roster_driver(user, file_map, roster_dir, driver)
        copied_files += copied
        accessories_with_paint += accessories
        if has_car:
            cars_with_paint += 1
        drivers.append(_normalize_ai_driver_entry(driver))
    if cars_with_paint <= 0:
        shutil.rmtree(roster_dir, ignore_errors=True)
        return False, "Generic AI random fallback saved files, but no car paints were available to build an AI roster."
    roster_item = AIWebRosterItem(roster_id="", name=AI_GENERIC_RANDOM_ROSTER_NAME, roster_file="")
    _write_ai_roster_files(
        roster_dir,
        {"drivers": drivers},
        drivers,
        roster_item,
        is_local=True,
        source_name="Generic AI session random fallback",
    )
    return True, (
        f"Generic AI session detected: iRacing will not load random paints live from temporary 9700-series IDs. "
        f"Created local AI roster '{AI_GENERIC_RANDOM_ROSTER_NAME}' at {roster_dir} with {cars_with_paint}/{len(ai_users)} car paint(s) "
        f"and {accessories_with_paint} helmet/suit file(s). Recreate the AI race and select this roster to see the random paints."
    )
def _prefill_local_ai_roster_accessory(
    *,
    roster_dir: Path,
    driver: dict,
    kind: str,
    used_scheme_ids: set[str],
    recent_scheme_ids: set[str],
    showroom_cache: dict[str, object],
    temp_root: Path,
    temp_paints_root: Path,
    retries: int,
    retry_backoff_seconds: float,
    detect_showroom_total_pages: bool,
    cancel_event: threading.Event | None = None,
) -> tuple[bool, int, str]:
    for _attempt in range(1, 5):
        if _cancel_requested(cancel_event):
            return False, 0, "cancelled"
        result = choose_showroom_accessory_direct(
            accessory_kind=kind,
            pages=TP_SHOWROOM_MAX_PAGES,
            prefer_official=False,
            choice_mode="random",
            exclude_scheme_ids=used_scheme_ids,
            exclude_recent_scheme_ids=recent_scheme_ids,
            showroom_cars=list(showroom_cache.get("cars") or []),
            showroom_sampled_pages=set(showroom_cache.get("sampled_pages") or set()),
            detected_total_pages=int(showroom_cache.get("detected_total_pages") or 0),
            detect_total_pages=detect_showroom_total_pages,
            minimum_unused_choices=1,
            allow_reuse_existing_scheme=False,
            log=logging.debug,
            cancel_event=cancel_event,
        )
        _update_prefill_showroom_cache(showroom_cache, result)
        if not result.ok:
            return False, 0, result.message
        scheme_id = str(result.chosen_scheme_id or "").strip()
        if scheme_id:
            used_scheme_ids.add(scheme_id)
        saved_items = _download_public_showroom_result_for_ai_roster_prefill(
            kind=kind,
            directory=kind,
            result=result,
            temp_dir=temp_root,
            temp_paints_dir=temp_paints_root,
            retries=retries,
            retry_backoff_seconds=retry_backoff_seconds,
            cancel_event=cancel_event,
        )
        copied, copied_files = _copy_prefill_saved_items_to_ai_roster_driver(
            kind=kind,
            scheme_id=scheme_id,
            saved_items=saved_items,
            roster_dir=roster_dir,
            driver=driver,
        )
        if copied:
            return True, copied_files, scheme_id
        if saved_items:
            delete_saved(saved_items, paints_root=temp_paints_root)
    return False, 0, f"public showroom {kind} asset was unavailable"
def prefill_local_ai_rosters_from_showroom(
    *,
    ai_rosters_dir: Path,
    temp_dir: Path,
    retries: int,
    retry_backoff_seconds: float,
    include_cars: bool = True,
    include_helmets: bool = True,
    include_suits: bool = True,
    mapping_path: Path | None = None,
    detect_showroom_total_pages: bool = False,
    cancel_event: threading.Event | None = None,
) -> LocalAIRosterPrefillResult:
    result = LocalAIRosterPrefillResult()
    if not (include_cars or include_helmets or include_suits):
        return result
    if ai_rosters_dir is None or not ai_rosters_dir.exists():
        return result
    mapping_path = mapping_path or default_tp_showroom_mapping_path()
    temp_root = temp_dir / f"local_ai_roster_prefill_{os.getpid()}_{int(time.time() * 1000)}"
    temp_paints_root = temp_root / "paint"
    recent_schemes = load_tp_recent_schemes()
    recent_changed = False
    showroom_cache_by_directory: dict[str, dict[str, object]] = {}
    showroom_cache_by_accessory_kind: dict[str, dict[str, object]] = {}
    local_names: list[str] = []
    logging.info("Local AI roster prefill scan started.")
    try:
        for roster_dir in sorted(ai_rosters_dir.iterdir(), key=lambda item: item.name.casefold()):
            if _cancel_requested(cancel_event):
                break
            if not roster_dir.is_dir() or not (roster_dir / "roster.json").exists():
                continue
            result.rosters_scanned += 1
            if not _ai_roster_dir_is_local(roster_dir):
                continue
            result.local_rosters += 1
            local_names.append(roster_dir.name)
            try:
                _payload, drivers = _read_ai_roster_payload(roster_dir)
            except Exception as exc:  # noqa: BLE001
                result.failed += 1
                logging.warning("Local AI roster prefill could not read %s: %s", roster_dir.name, exc)
                continue
            if not drivers:
                continue
            used_car_scheme_ids = _ai_roster_existing_scheme_ids(drivers, ("carTgaName",))
            used_helmet_scheme_ids = _ai_roster_existing_scheme_ids(drivers, ("helmetTgaName",))
            used_suit_scheme_ids = _ai_roster_existing_scheme_ids(drivers, ("suitTgaName",))
            roster_changed = False
            roster_driver_updates = 0
            roster_files_copied = 0
            roster_cars = 0
            roster_helmets = 0
            roster_suits = 0
            for driver_index, driver in enumerate(drivers, start=1):
                if _cancel_requested(cancel_event):
                    break
                if not isinstance(driver, dict):
                    continue
                driver_changed = False
                driver_name = str(driver.get("driverName") or driver.get("name") or f"driver {driver_index}").strip()
                directory = str(driver.get("carPath") or "").strip().replace("\\", " ")
                if include_cars and _ai_roster_driver_needs_asset(roster_dir, driver, "carTgaName"):
                    directory_key = canonicalize_car_directory(directory).lower()
                    showroom_cache = showroom_cache_by_directory.setdefault(
                        directory_key,
                        {"cars": [], "sampled_pages": set(), "detected_total_pages": 0},
                    )
                    recent_scheme_ids = {
                        str(item).strip()
                        for item in recent_schemes.get(directory_key, [])
                        if str(item).strip()
                    }
                    ok, copied_files, scheme_id = _prefill_local_ai_roster_car(
                        roster_dir=roster_dir,
                        driver=driver,
                        directory=directory,
                        mapping_path=mapping_path,
                        used_scheme_ids=used_car_scheme_ids,
                        recent_scheme_ids=recent_scheme_ids,
                        showroom_cache=showroom_cache,
                        temp_root=temp_root,
                        temp_paints_root=temp_paints_root,
                        retries=retries,
                        retry_backoff_seconds=retry_backoff_seconds,
                        detect_showroom_total_pages=detect_showroom_total_pages,
                        cancel_event=cancel_event,
                    )
                    if ok:
                        roster_changed = True
                        driver_changed = True
                        roster_files_copied += copied_files
                        roster_cars += 1
                        if scheme_id:
                            remember_tp_recent_scheme(recent_schemes, directory_key, scheme_id)
                            recent_changed = True
                    else:
                        result.failed += 1
                        logging.info("Local AI roster prefill skipped car for %s in %s: %s", driver_name, roster_dir.name, scheme_id)
                if include_helmets and _ai_roster_driver_needs_asset(roster_dir, driver, "helmetTgaName"):
                    showroom_cache = showroom_cache_by_accessory_kind.setdefault(
                        "helmet",
                        {"cars": [], "sampled_pages": set(), "detected_total_pages": 0},
                    )
                    recent_scheme_ids = {
                        str(item).strip()
                        for item in recent_schemes.get(TP_DRIVER_HELMET_CACHE_KEY, [])
                        if str(item).strip()
                    }
                    ok, copied_files, scheme_id = _prefill_local_ai_roster_accessory(
                        roster_dir=roster_dir,
                        driver=driver,
                        kind="helmet",
                        used_scheme_ids=used_helmet_scheme_ids,
                        recent_scheme_ids=recent_scheme_ids,
                        showroom_cache=showroom_cache,
                        temp_root=temp_root,
                        temp_paints_root=temp_paints_root,
                        retries=retries,
                        retry_backoff_seconds=retry_backoff_seconds,
                        detect_showroom_total_pages=detect_showroom_total_pages,
                        cancel_event=cancel_event,
                    )
                    if ok:
                        roster_changed = True
                        driver_changed = True
                        roster_files_copied += copied_files
                        roster_helmets += 1
                        if scheme_id:
                            remember_tp_recent_scheme(recent_schemes, TP_DRIVER_HELMET_CACHE_KEY, scheme_id)
                            recent_changed = True
                    else:
                        result.failed += 1
                        logging.info("Local AI roster prefill skipped helmet for %s in %s: %s", driver_name, roster_dir.name, scheme_id)
                if include_suits and _ai_roster_driver_needs_asset(roster_dir, driver, "suitTgaName"):
                    showroom_cache = showroom_cache_by_accessory_kind.setdefault(
                        "suit",
                        {"cars": [], "sampled_pages": set(), "detected_total_pages": 0},
                    )
                    recent_scheme_ids = {
                        str(item).strip()
                        for item in recent_schemes.get(TP_DRIVER_SUIT_CACHE_KEY, [])
                        if str(item).strip()
                    }
                    ok, copied_files, scheme_id = _prefill_local_ai_roster_accessory(
                        roster_dir=roster_dir,
                        driver=driver,
                        kind="suit",
                        used_scheme_ids=used_suit_scheme_ids,
                        recent_scheme_ids=recent_scheme_ids,
                        showroom_cache=showroom_cache,
                        temp_root=temp_root,
                        temp_paints_root=temp_paints_root,
                        retries=retries,
                        retry_backoff_seconds=retry_backoff_seconds,
                        detect_showroom_total_pages=detect_showroom_total_pages,
                        cancel_event=cancel_event,
                    )
                    if ok:
                        roster_changed = True
                        driver_changed = True
                        roster_files_copied += copied_files
                        roster_suits += 1
                        if scheme_id:
                            remember_tp_recent_scheme(recent_schemes, TP_DRIVER_SUIT_CACHE_KEY, scheme_id)
                            recent_changed = True
                    else:
                        result.failed += 1
                        logging.info("Local AI roster prefill skipped suit for %s in %s: %s", driver_name, roster_dir.name, scheme_id)
                if driver_changed:
                    roster_driver_updates += 1
            if roster_changed:
                roster_item = AIWebRosterItem(roster_id="", name=roster_dir.name, roster_file="")
                _write_ai_roster_files(
                    roster_dir,
                    {"drivers": drivers},
                    drivers,
                    roster_item,
                    is_local=True,
                    source_name="Local AI roster public showroom prefill",
                )
                result.rosters_updated += 1
                result.drivers_updated += roster_driver_updates
                result.files_copied += roster_files_copied
                result.cars += roster_cars
                result.helmets += roster_helmets
                result.suits += roster_suits
                logging.info(
                    "Local AI roster prefill updated %s: %s driver(s), %s car(s), %s helmet(s), %s suit(s), %s copied file(s). Recreate/select this AI roster before starting the race so iRacing reads the new paint references.",
                    roster_dir.name,
                    roster_driver_updates,
                    roster_cars,
                    roster_helmets,
                    roster_suits,
                    roster_files_copied,
                )
        if recent_changed:
            save_tp_recent_schemes(recent_schemes)
    finally:
        try:
            shutil.rmtree(temp_root, ignore_errors=True)
        except Exception:
            logging.debug("Could not clean local AI roster prefill temp folder %s", temp_root, exc_info=True)
    if result.local_rosters <= 0:
        logging.info("Local AI roster prefill scan complete: no local AI roster folders found in %s.", ai_rosters_dir)
    elif result.rosters_updated <= 0 and result.failed > 0:
        logging.info("Local AI roster prefill scan complete: %s local roster(s) checked; no roster was updated and %s asset(s) were unavailable or unmapped.", result.local_rosters, result.failed)
    elif result.rosters_updated <= 0:
        logging.info("Local AI roster prefill scan complete: %s local roster(s) checked; no missing enabled paint references.", result.local_rosters)
    else:
        logging.info(
            "Local AI roster prefill scan complete: %s/%s local roster(s) updated, %s driver(s), %s copied file(s), %s failed asset(s).",
            result.rosters_updated,
            result.local_rosters,
            result.drivers_updated,
            result.files_copied,
            result.failed,
        )
    return result
def import_saved_paint_groups_to_ai_livery(saved: list[SavedFile], session: Session | None, ai_livery_root: Path, only_local_user: bool = False) -> tuple[int, int]:
    grouped: dict[tuple[str, int, bool], dict[PaintType, Path]] = {}
    local_user_id = session.local_user_id if session is not None else None
    for saved_file in saved:
        paint_type = saved_file.download_id.paint_type
        if paint_type not in {PaintType.CAR, PaintType.CAR_SPEC, PaintType.CAR_DECAL}:
            continue
        if only_local_user and (local_user_id is None or saved_file.download_id.user_id != local_user_id):
            continue
        key = (saved_file.download_id.directory, saved_file.download_id.user_id, saved_file.download_id.is_team_paint)
        grouped.setdefault(key, {})[paint_type] = saved_file.file_path
    copied_sets = 0
    copied_files = 0
    for (directory, _target_id, _is_team), file_map in grouped.items():
        car_src = file_map.get(PaintType.CAR)
        if car_src is None or not car_src.exists():
            continue
        car_dir = ai_livery_root / directory
        new_id = _next_ai_cache_id(car_dir)
        if _copy_optional_file(car_src, car_dir / f"car_{new_id}.tga"):
            copied_files += 1
        if _copy_optional_file(file_map.get(PaintType.CAR_SPEC), car_dir / f"car_spec_{new_id}.mip"):
            copied_files += 1
        if _copy_optional_file(file_map.get(PaintType.CAR_DECAL), car_dir / f"decal_{new_id}.tga"):
            copied_files += 1
        copied_sets += 1
    return copied_sets, copied_files

def _parse_saved_paint_filename(path: Path) -> tuple[PaintType, str, int, bool, bool] | None:
    parent_name = path.parent.name
    paints_root_name = path.parent.parent.name if path.parent.parent != path.parent else ""
    directory = "__accessories__" if parent_name.lower() == "paint" or paints_root_name.lower() == "paint" else parent_name
    name = path.name.lower()
    patterns: list[tuple[PaintType, str]] = [
        (PaintType.CAR, r"^car_(team_)?(\d+)(?:(_ss))?\.tga$"),
        (PaintType.CAR_NUMBER, r"^car_num_(team_)?(\d+)(?:(_ss))?\.tga$"),
        (PaintType.CAR_SPEC, r"^car_spec_(team_)?(\d+)(?:_spec)?(?:(_ss))?\.mip$"),
        (PaintType.CAR_DECAL, r"^decal_(team_)?(\d+)(?:(_ss))?\.tga$"),
        (PaintType.HELMET, r"^helmet_(team_)?(\d+)\.tga$"),
        (PaintType.SUIT, r"^suit_(team_)?(\d+)\.tga$"),
    ]
    for paint_type, pattern in patterns:
        match = re.match(pattern, name, re.IGNORECASE)
        if not match:
            continue
        is_team = bool(match.group(1))
        target_id = int(match.group(2))
        is_ss = bool(match.group(3)) if match.lastindex and match.lastindex >= 3 else False
        return paint_type, directory, target_id, is_team, is_ss
    return None

def rebuild_random_pool_from_paints_root(
    paints_root: Path,
    random_pool_dir: Path,
    max_pool_gb: float,
    *,
    max_pool_car_gb: float | None = None,
    max_pool_helmet_gb: float | None = None,
    max_pool_suit_gb: float | None = None,
) -> tuple[int, int, int, int]:
    grouped: dict[tuple[str, int, bool], dict[PaintType, tuple[Path, bool]]] = {}
    if not paints_root.exists():
        return 0, 0, 0, 0
    for child in paints_root.rglob('*'):
        if not child.is_file():
            continue
        parsed = _parse_saved_paint_filename(child)
        if parsed is None:
            continue
        paint_type, directory, target_id, is_team, is_ss = parsed
        key = (directory, target_id, is_team)
        existing = grouped.setdefault(key, {}).get(paint_type)
        if existing is None or (existing[1] and not is_ss):
            grouped.setdefault(key, {})[paint_type] = (child, is_ss)
    saved: list[SavedFile] = []
    synthetic_session = SessionId(0, None)
    for (directory, target_id, is_team), file_map in grouped.items():
        for paint_type, path_and_ss in file_map.items():
            source_path, is_ss = path_and_ss
            saved.append(
                SavedFile(
                    session_id=synthetic_session,
                    download_id=DownloadId(
                        user_id=target_id,
                        directory=directory,
                        paint_type=paint_type,
                        is_team_paint=is_team,
                        is_superspeedway_variant=is_ss,
                    ),
                    file_path=source_path,
                )
            )
    added_sets, added_files, _detail_logs, pool_bytes_after, pool_freed_bytes = archive_saved_tp_sets_to_random_pool(
        saved,
        random_pool_dir,
        max_pool_gb,
        max_pool_car_gb=max_pool_car_gb,
        max_pool_helmet_gb=max_pool_helmet_gb,
        max_pool_suit_gb=max_pool_suit_gb,
    )
    return added_sets, added_files, pool_bytes_after, pool_freed_bytes

def fetch_context_files(
    session: Session,
    user: SessionUser,
    retries: int,
    retry_backoff_seconds: float,
    cancel_event: threading.Event | None = None,
    superspeedway_variant: bool = False,
) -> list[DownloadFile]:
    payload = _build_fetch_context_payload(session, user, superspeedway_variant=superspeedway_variant)
    if payload is None:
        raise RuntimeError("Trading Paints context is unavailable for this session.")
    last_exc: Exception | None = None
    for url in TRADING_PAINTS_FETCH_CONTEXT_URLS:
        for attempt in range(1, retries + 1):
            if _cancel_requested(cancel_event):
                return []
            try:
                http = get_thread_http_session()
                resp = http.post(url, data=payload, timeout=30)
                resp.raise_for_status()
                root = ET.fromstring(resp.text)
                files: list[DownloadFile] = []
                for car in root.findall(".//Car"):
                    if not _matches_context_manifest_entry(user, car):
                        continue
                    file_url = (car.findtext("file") or '').strip()
                    type_raw = (car.findtext("type") or '').strip().lower()
                    directory = (car.findtext("directory") or '').strip()
                    team_id_text = (car.findtext("teamid") or "0").strip() or "0"
                    if not file_url or not type_raw:
                        continue
                    if not directory and type_raw.startswith("car"):
                        continue
                    try:
                        paint_type = PaintType(type_raw)
                    except ValueError:
                        logging.debug(
                            "Skipping unknown contextual paint type '%s' for user %s",
                            type_raw,
                            user.user_id,
                        )
                        continue
                    response_team_id = _to_int_or_none(team_id_text)
                    is_team_paint = bool(response_team_id and response_team_id > 0 and paint_type in TEAM_PAINT_TYPES)
                    target_user_id = int(response_team_id) if is_team_paint else user.user_id
                    target_directory = directory or user.directory
                    files.append(
                        DownloadFile(
                            download_id=DownloadId(
                                user_id=target_user_id,
                                directory=target_directory,
                                paint_type=paint_type,
                                is_team_paint=is_team_paint,
                                is_superspeedway_variant=_manifest_file_url_is_superspeedway_variant(file_url, paint_type),
                            ),
                            url=file_url,
                        )
                    )
                if files:
                    logging.debug(
                        "Context fetch succeeded for user %s via %s with %s file(s) (list=%s)",
                        user.user_id,
                        url,
                        len(files),
                        payload.get('list', ''),
                    )
                    return files
                logging.debug(
                    "Context fetch returned no matching files for user %s via %s (attempt %s/%s, list=%s)",
                    user.user_id,
                    url,
                    attempt,
                    retries,
                    payload.get('list', ''),
                )
                return []
            except (requests.RequestException, ET.ParseError, RuntimeError) as exc:
                last_exc = exc
                if attempt >= retries:
                    break
                delay = compute_retry_delay(retry_backoff_seconds, attempt)
                logging.debug(
                    "Context manifest fetch failed for user %s via %s (attempt %s/%s): %s. Retrying in %.1fs",
                    user.user_id,
                    url,
                    attempt,
                    retries,
                    exc,
                    delay,
                )
                if cancel_event is not None:
                    cancel_event.wait(delay)
                else:
                    time.sleep(delay)
    assert last_exc is not None
    raise last_exc
def _apply_special_variant_flags(session: Session, user: SessionUser, items: list[DownloadFile]) -> list[DownloadFile]:
    _ = user
    return _select_manifest_variants_for_session(session, items)
def _fetch_user_files_for_session(
    session: Session,
    user_id: int,
    retries: int,
    retry_backoff_seconds: float,
    cancel_event: threading.Event | None = None,
) -> list[DownloadFile]:
    if session.is_superspeedway_track:
        try:
            ss_items = fetch_user_files(
                user_id,
                retries,
                retry_backoff_seconds,
                cancel_event=cancel_event,
                superspeedway_variant=True,
            )
            if _manifest_has_car_related_items(ss_items):
                if _manifest_has_superspeedway_variant(ss_items):
                    logging.debug("Trading Paints fetch_user.php returned server _ss car asset(s) for user %s.", user_id)
                else:
                    logging.debug("Trading Paints fetch_user.php returned regular car asset(s) for user %s after _ss request.", user_id)
                return _select_manifest_variants_for_session(session, ss_items)
            logging.debug("Trading Paints fetch_user.php returned no car assets for user %s after _ss request; retrying regular manifest.", user_id)
        except Exception as exc:  # noqa: BLE001
            logging.debug("Trading Paints fetch_user.php _ss request failed for user %s; retrying regular manifest: %s", user_id, exc)
    return _select_manifest_variants_for_session(
        session,
        fetch_user_files(user_id, retries, retry_backoff_seconds, cancel_event=cancel_event),
    )
def _fetch_context_files_for_session(
    session: Session,
    user: SessionUser,
    retries: int,
    retry_backoff_seconds: float,
    cancel_event: threading.Event | None = None,
) -> list[DownloadFile]:
    if session.is_superspeedway_track:
        try:
            ss_items = fetch_context_files(
                session,
                user,
                retries,
                retry_backoff_seconds,
                cancel_event=cancel_event,
                superspeedway_variant=True,
            )
            if _manifest_has_car_related_items(ss_items):
                if _manifest_has_superspeedway_variant(ss_items):
                    logging.debug("Trading Paints fetch.php returned server _ss car asset(s) for user %s.", user.user_id)
                else:
                    logging.debug("Trading Paints fetch.php returned regular car asset(s) for user %s after _ss request.", user.user_id)
                return _select_manifest_variants_for_session(session, ss_items)
            logging.debug("Trading Paints fetch.php returned no car assets for user %s after _ss request; retrying regular manifest.", user.user_id)
        except Exception as exc:  # noqa: BLE001
            logging.debug("Trading Paints fetch.php _ss request failed for user %s; retrying regular manifest: %s", user.user_id, exc)
    return _select_manifest_variants_for_session(
        session,
        fetch_context_files(session, user, retries, retry_backoff_seconds, cancel_event=cancel_event),
    )
def fetch_best_manifest_files(
    session: Session,
    user: SessionUser,
    retries: int,
    retry_backoff_seconds: float,
    ai_rosters_dir: Path | None = None,
    cancel_event: threading.Event | None = None,
) -> list[DownloadFile]:
    if _cancel_requested(cancel_event):
        return []
    if user.is_ai:
        ai_collection_items = fetch_active_ai_roster_collection_files(session, user, ai_rosters_dir)
        if ai_collection_items:
            return _apply_special_variant_flags(session, user, ai_collection_items)
        logging.debug(
            "AI collection manifest unavailable for %s (%s); skipping normal team manifest lookup.",
            user.display_name or f"AI {user.user_id}",
            user.user_id,
        )
        return []
    context = session.trading_paints_context()
    if context is None:
        logging.debug(
            "No Trading Paints context available for session %s; falling back to fetch_user for user %s",
            session.session_id.folder_name(),
            user.user_id,
        )
        return _fetch_user_files_for_session(session, user.user_id, retries, retry_backoff_seconds, cancel_event=cancel_event)
    try:
        return _fetch_context_files_for_session(session, user, retries, retry_backoff_seconds, cancel_event=cancel_event)
    except Exception as exc:
        logging.warning(
            "Context fetch.php manifest failed for user %s; falling back to fetch_user.php: %s",
            user.user_id,
            exc,
        )
        return _fetch_user_files_for_session(session, user.user_id, retries, retry_backoff_seconds, cancel_event=cancel_event)
SAFE_PAINT_DIRECTORY_RE = re.compile(r"^[A-Za-z0-9._ -]+$")
def normalize_directory(value: str) -> str:
    normalized = value.strip().lower()
    normalized = re.sub(r"[^a-z0-9]+", "_", normalized)
    normalized = re.sub(r"_+", "_", normalized).strip("_")
    return normalized

def sanitize_paint_directory(value: str, *, fallback: str = "misc") -> str:
    text = str(value or '').strip()
    if not text:
        text = str(fallback or '').strip()
    text = text.replace("/", "\\")
    parts = [part.strip() for part in text.split("\\") if part.strip()]
    if len(parts) != 1:
        raise ValueError(f"Unsafe paint directory: {value!r}")
    part = parts[0]
    if part in {".", ".."}:
        raise ValueError(f"Unsafe paint directory: {value!r}")
    if ":" in part:
        raise ValueError(f"Unsafe paint directory: {value!r}")
    if part.endswith(".") or part.endswith(" "):
        raise ValueError(f"Unsafe paint directory: {value!r}")
    if not SAFE_PAINT_DIRECTORY_RE.fullmatch(part):
        raise ValueError(f"Unsafe paint directory: {value!r}")
    return part

def safe_join_under(root: Path, *parts: str) -> Path:
    """Join paths while guaranteeing the final path stays under ``root``.

    This intentionally uses ``abspath``/``normpath`` + ``commonpath`` instead of
    ``Path.resolve(strict=False)``. In some Windows environments, ``resolve`` can
    transiently produce path forms that do not compare equal under heavy threaded
    save/download bursts (for example different drive/path prefixes for not-yet-
    materialized children). Normalized absolute paths are stable here and still
    safely block traversal outside ``root``.
    """
    root.mkdir(parents=True, exist_ok=True)
    root_norm = os.path.abspath(os.path.normpath(str(root)))
    candidate = root.joinpath(*parts)
    candidate_norm = os.path.abspath(os.path.normpath(str(candidate)))
    try:
        common = os.path.commonpath([root_norm, candidate_norm])
    except ValueError:
        raise ValueError(f"Path escaped base directory: {candidate}")
    if os.path.normcase(common) != os.path.normcase(root_norm):
        raise ValueError(f"Path escaped base directory: {candidate}")
    return Path(candidate_norm)
def is_user_file(session_user: SessionUser, item: DownloadFile) -> bool:
    if item.download_id.paint_type in {PaintType.HELMET, PaintType.SUIT}:
        return True
    if item.download_id.directory.lower() == session_user.directory.lower():
        return True
    normalized_manifest = normalize_directory(item.download_id.directory)
    normalized_session = normalize_directory(session_user.directory)
    if normalized_manifest == normalized_session:
        logging.debug(
            "Directory matched after normalization: '%s' -> '%s', '%s' -> '%s'",
            item.download_id.directory,
            normalized_manifest,
            session_user.directory,
            normalized_session,
        )
        return True
    return False
TEAM_PAINT_TYPES = {
    PaintType.CAR,
    PaintType.CAR_DECAL,
    PaintType.CAR_NUMBER,
    PaintType.CAR_SPEC,
    PaintType.HELMET,
    PaintType.SUIT,
}
def uses_team_target(session_user: SessionUser, item: DownloadFile) -> bool:
    return (
        session_user_uses_team_target(session_user)
        and item.download_id.paint_type in TEAM_PAINT_TYPES
        and bool(item.download_id.is_team_paint)
    )
def normalize_download_for_session_user(session_user: SessionUser, item: DownloadFile) -> DownloadFile:
    target_user_id = item.download_id.user_id
    is_team_paint = item.download_id.is_team_paint
    if uses_team_target(session_user, item):
        target_user_id = int(session_user.team_id)
        is_team_paint = True

    target_directory = item.download_id.directory
    if _is_car_related_paint_type(item.download_id.paint_type):
        preferred_directory = str(session_user.directory or '').strip() or item.download_id.directory
        target_directory = sanitize_paint_directory(preferred_directory, fallback="misc")

    if (
        item.download_id.user_id == target_user_id
        and item.download_id.directory == target_directory
        and item.download_id.is_team_paint == is_team_paint
    ):
        return item

    return DownloadFile(
        download_id=replace(
            item.download_id,
            user_id=target_user_id,
            directory=target_directory,
            is_team_paint=is_team_paint,
        ),
        url=item.url,
        ai_roster_optional_filename=item.ai_roster_optional_filename,
        ai_roster_dir=item.ai_roster_dir,
    )
def download_file(
    session_id: SessionId,
    temp_root: Path,
    item: DownloadFile,
    retries: int,
    retry_backoff_seconds: float,
    ordinal: int | None = None,
    total: int | None = None,
    batch_monitor: TransferBatchMonitor | None = None,
    cancel_event: threading.Event | None = None,
) -> DownloadedFile | None:
    if _cancel_requested(cancel_event):
        return None
    parsed = urllib.parse.urlparse(item.url)
    name = Path(parsed.path).name
    if not name:
        return None
    try:
        safe_dir = sanitize_paint_directory(item.download_id.directory, fallback="misc")
    except ValueError as exc:
        logging.warning(
            "Skipping download with unsafe directory %r for %s: %s",
            item.download_id.directory,
            item.url,
            exc,
        )
        return None
    base_temp_dir = temp_root / session_id.folder_name()
    base_temp_dir.mkdir(parents=True, exist_ok=True)
    dest_dir = safe_join_under(base_temp_dir, safe_dir)
    dest_dir.mkdir(parents=True, exist_ok=True)
    url_hash = hashlib.sha1(item.url.encode("utf-8", errors="ignore")).hexdigest()[:12]
    temp_name = f"{item.download_id.paint_type.value}_{item.download_id.user_id}_{url_hash}_{name}"
    dest_file = dest_dir / temp_name
    last_exc: Exception | None = None
    progress_prefix = f"[{ordinal}/{total}] " if ordinal is not None and total else ""
    task_started_at = batch_monitor.begin() if batch_monitor is not None else time.monotonic()
    bytes_downloaded_total = 0
    success = False
    skipped_unavailable_status: int | None = None
    try:
        for attempt in range(1, retries + 1):
            if _cancel_requested(cancel_event):
                dest_file.unlink(missing_ok=True)
                logging.info(
                    "%sSkipping download for user %s %s because the iRacing session changed or ended",
                    progress_prefix,
                    item.download_id.user_id,
                    item.download_id.paint_type.value,
                )
                return None
            logging.debug(
                "%sDownloading %s for user %s (%s) [attempt %s/%s]",
                progress_prefix,
                item.download_id.paint_type.value,
                item.download_id.user_id,
                item.download_id.directory,
                attempt,
                retries,
            )
            try:
                session = get_thread_http_session()
                with session.get(item.url, timeout=(10, 90), stream=True) as response:
                    response.raise_for_status()
                    with dest_file.open("wb") as f:
                        for chunk in response.iter_content(chunk_size=1024 * 1024):
                            if _cancel_requested(cancel_event):
                                logging.info(
                                    "%sCancelled download for user %s %s because the iRacing session changed or ended",
                                    progress_prefix,
                                    item.download_id.user_id,
                                    item.download_id.paint_type.value,
                                )
                                return None
                            if chunk:
                                bytes_downloaded_total += len(chunk)
                                f.write(chunk)
                logging.debug("%sDownloaded to temp file: %s", progress_prefix, dest_file)
                success = True
                return DownloadedFile(
                    session_id=session_id,
                    download_id=item.download_id,
                    file_path=dest_file,
                )
            except requests.RequestException as exc:
                last_exc = exc
                dest_file.unlink(missing_ok=True)
                response = getattr(exc, "response", None)
                status_code = getattr(response, "status_code", None)
                if isinstance(status_code, int) and status_code in TP_UNAVAILABLE_DOWNLOAD_STATUS_CODES:
                    skipped_unavailable_status = status_code
                    break
                if attempt >= retries:
                    break
                delay = compute_retry_delay(retry_backoff_seconds, attempt)
                logging.warning(
                    "%sFailed download %s on attempt %s/%s: %s. Retrying in %.1fs",
                    progress_prefix,
                    item.url,
                    attempt,
                    retries,
                    exc,
                    delay,
                )
                if cancel_event is not None:
                    cancel_event.wait(delay)
                else:
                    time.sleep(delay)
            except Exception:
                dest_file.unlink(missing_ok=True)
                raise
        if skipped_unavailable_status is not None:
            if item.ai_roster_dir is not None and item.ai_roster_optional_filename:
                _mark_ai_roster_asset_unavailable(
                    item.ai_roster_dir,
                    item.ai_roster_optional_filename,
                    item.url,
                    skipped_unavailable_status,
                )
            logging.info(
                "%sSkipping unavailable Trading Paints asset %s after HTTP %s; this source cannot be downloaded for the current account.",
                progress_prefix,
                item.url,
                skipped_unavailable_status,
            )
        elif last_exc is not None:
            logging.warning("%sFailed download %s after %s attempts: %s", progress_prefix, item.url, retries, last_exc)
        return None
    finally:
        if batch_monitor is not None:
            batch_monitor.end(task_started_at, success=success, bytes_count=bytes_downloaded_total)
def save_path_for(download_id: DownloadId, paints_dir: Path) -> Path:
    uid = download_id.user_id
    team_suffix = f"team_{uid}" if download_id.is_team_paint else str(uid)
    ss_suffix = "_ss" if download_id.is_superspeedway_variant else ""
    if download_id.paint_type is PaintType.CAR:
        safe_dir = sanitize_paint_directory(download_id.directory, fallback="misc")
        return safe_join_under(paints_dir, safe_dir, f"car_{team_suffix}{ss_suffix}.tga")
    if download_id.paint_type is PaintType.CAR_DECAL:
        safe_dir = sanitize_paint_directory(download_id.directory, fallback="misc")
        return safe_join_under(paints_dir, safe_dir, f"decal_{team_suffix}{ss_suffix}.tga")
    if download_id.paint_type is PaintType.CAR_NUMBER:
        safe_dir = sanitize_paint_directory(download_id.directory, fallback="misc")
        return safe_join_under(paints_dir, safe_dir, f"car_num_{team_suffix}{ss_suffix}.tga")
    if download_id.paint_type is PaintType.CAR_SPEC:
        safe_dir = sanitize_paint_directory(download_id.directory, fallback="misc")
        if download_id.is_numbered_car_spec:
            return safe_join_under(paints_dir, safe_dir, f"car_spec_{team_suffix}_spec{ss_suffix}.mip")
        return safe_join_under(paints_dir, safe_dir, f"car_spec_{team_suffix}{ss_suffix}.mip")
    if download_id.paint_type is PaintType.HELMET:
        return safe_join_under(paints_dir, f"helmet_{team_suffix}.tga")
    if download_id.paint_type is PaintType.SUIT:
        return safe_join_under(paints_dir, f"suit_{team_suffix}.tga")
    raise ValueError(f"Unsupported paint type: {download_id.paint_type}")
def save_paths_for(download_id: DownloadId, paints_dir: Path) -> list[Path]:
    return [save_path_for(download_id, paints_dir)]
def _should_retry_save_exception(exc: Exception) -> bool:
    if isinstance(exc, PermissionError):
        return True
    if isinstance(exc, OSError):
        winerror = getattr(exc, "winerror", None)
        if winerror in {5, 32}:
            return True
        errno_value = getattr(exc, "errno", None)
        if errno_value in {13, 16}:
            return True
        message = str(exc).lower()
        if "access is denied" in message or "being used by another process" in message:
            return True
    return False


def move_or_extract(
    downloaded: DownloadedFile,
    paints_dir: Path,
    batch_monitor: TransferBatchMonitor | None = None,
    retries: int = 3,
    retry_backoff_seconds: float = 0.35,
    cancel_event: threading.Event | None = None,
) -> list[SavedFile] | None:
    if _cancel_requested(cancel_event):
        return None
    src = downloaded.file_path
    dest_paths = save_paths_for(downloaded.download_id, paints_dir)
    primary_dest = dest_paths[0]
    primary_dest.parent.mkdir(parents=True, exist_ok=True)
    temp_primary_dest = primary_dest.with_name(primary_dest.name + ".tmp")
    task_started_at = batch_monitor.begin() if batch_monitor is not None else time.monotonic()
    saved_bytes = 0
    success = False
    saved_paths: list[Path] = []
    retries = max(1, int(retries))
    retry_backoff_seconds = max(0.05, float(retry_backoff_seconds))
    last_exc: Exception | None = None
    try:
        for attempt in range(1, retries + 1):
            if _cancel_requested(cancel_event):
                return None
            try:
                temp_primary_dest.unlink(missing_ok=True)
                if src.suffix.lower() == ".bz2":
                    with src.open("rb") as source, bz2.open(source, "rb") as decompressor, temp_primary_dest.open(
                        "wb"
                    ) as out:
                        shutil.copyfileobj(decompressor, out)
                else:
                    shutil.copy2(src, temp_primary_dest)
                os.replace(temp_primary_dest, primary_dest)
                saved_paths = [primary_dest]
                for extra_dest in dest_paths[1:]:
                    extra_dest.parent.mkdir(parents=True, exist_ok=True)
                    temp_extra_dest = extra_dest.with_name(extra_dest.name + ".tmp")
                    temp_extra_dest.unlink(missing_ok=True)
                    shutil.copy2(primary_dest, temp_extra_dest)
                    os.replace(temp_extra_dest, extra_dest)
                    saved_paths.append(extra_dest)
                src.unlink(missing_ok=True)
                for saved_path in saved_paths:
                    try:
                        saved_bytes += int(saved_path.stat().st_size)
                    except OSError:
                        pass
                success = True
                break
            except Exception as exc:  # noqa: BLE001
                last_exc = exc
                temp_primary_dest.unlink(missing_ok=True)
                for extra_dest in dest_paths[1:]:
                    extra_dest.with_name(extra_dest.name + ".tmp").unlink(missing_ok=True)
                if attempt < retries and _should_retry_save_exception(exc):
                    delay = retry_backoff_seconds * attempt
                    logging.warning(
                        "Retrying save for user %s %s (attempt %s/%s) after save error: %s. Waiting %.2fs",
                        downloaded.download_id.user_id,
                        downloaded.download_id.paint_type.value,
                        attempt,
                        retries,
                        exc,
                        delay,
                    )
                    if cancel_event is not None:
                        cancel_event.wait(delay)
                    else:
                        time.sleep(delay)
                    continue
                raise
        if not success:
            if last_exc is not None:
                raise last_exc
            raise RuntimeError(f"Save failed for {src}")
    except Exception as exc:  # noqa: BLE001
        logging.error("Failed to save %s -> %s: %s", src, ", ".join(str(p) for p in dest_paths), exc)
        return None
    finally:
        if batch_monitor is not None:
            batch_monitor.end(task_started_at, success=success, bytes_count=saved_bytes)
    for saved_path in saved_paths:
        logging.debug("Saved paint file: %s", saved_path)
    return [
        SavedFile(
            session_id=downloaded.session_id,
            download_id=downloaded.download_id,
            file_path=saved_path,
        )
        for saved_path in saved_paths
    ]
def _remove_empty_parent_dirs(path: Path, stop_at: Path | None = None) -> None:
    current = path.parent
    stop_resolved = stop_at.resolve() if stop_at is not None and stop_at.exists() else None
    while True:
        try:
            current_resolved = current.resolve()
        except Exception:
            current_resolved = current
        if stop_resolved is not None and current_resolved == stop_resolved:
            break
        try:
            current.rmdir()
        except OSError:
            break
        parent = current.parent
        if parent == current:
            break
        current = parent
def _hard_delete_file(path: Path, paints_root: Path | None = None, retries: int = 8, delay: float = 0.12) -> bool:
    for attempt in range(1, retries + 1):
        try:
            path.unlink(missing_ok=True)
        except FileNotFoundError:
            return True
        except PermissionError:
            try:
                os.chmod(path, 0o666)
            except Exception:
                pass
        except OSError as exc:
            logging.debug("Delete attempt %s failed for %s: %s", attempt, path, exc)
        if not path.exists():
            _remove_empty_parent_dirs(path, stop_at=paints_root)
            return True
        if attempt < retries:
            time.sleep(delay)
    if path.exists():
        logging.warning("Could not fully delete paint file: %s", path)
        return False
    _remove_empty_parent_dirs(path, stop_at=paints_root)
    return True
def _safe_replay_pack_name(name: str) -> str:
    cleaned = re.sub(r'[<>:"/\\|?*]+', '_', (name or '').strip())
    cleaned = cleaned.strip().strip('.')
    return cleaned or 'Replay'

def _session_fingerprint_key(session: Session) -> str:
    normalized_users = [
        {
            "kind": user.effective_target_key()[0],
            "id": int(user.effective_target_key()[1]),
            "directory": user.directory.lower(),
        }
        for user in sorted(session.users, key=lambda u: ((u.team_id or 0) > 0, u.team_id or 0, u.user_id, u.directory.lower()))
    ]
    payload = {
        "session_id": session.session_id.folder_name(),
        "users": normalized_users,
        "context": {
            "team_racing": bool(session.team_racing),
            "event_time_raw": (session.event_time_raw or '10:00 am').strip().lower(),
            "series_id": int(session.series_id or 0),
            "league_id": int(session.league_id or 0),
            "load_num_textures": bool(session.load_num_textures),
            "track_name": normalize_directory(session.track_name),
            "track_config_name": normalize_directory(session.track_config_name),
            "is_superspeedway_track": bool(session.is_superspeedway_track),
        },
    }
    return json.dumps(payload, sort_keys=True, separators=(',', ':'))

def _download_id_to_dict(download_id: DownloadId) -> dict[str, object]:
    return {
        "user_id": int(download_id.user_id),
        "directory": download_id.directory,
        "paint_type": download_id.paint_type.value,
        "is_team_paint": bool(download_id.is_team_paint),
        "is_superspeedway_variant": bool(download_id.is_superspeedway_variant),
        "is_numbered_car_spec": bool(download_id.is_numbered_car_spec),
        "preserve_on_cleanup": bool(getattr(download_id, "preserve_on_cleanup", False)),
        "tp_scheme_id": str(getattr(download_id, "tp_scheme_id", "") or ""),
        "tp_title": str(getattr(download_id, "tp_title", "") or ""),
        "tp_source_link": str(getattr(download_id, "tp_source_link", "") or ""),
        "tp_source": str(getattr(download_id, "tp_source", "") or ""),
    }

def _download_id_from_dict(payload: dict[str, object]) -> DownloadId:
    return DownloadId(
        user_id=int(payload.get('user_id') or 0),
        directory=str(payload.get('directory') or ''),
        paint_type=PaintType(str(payload.get('paint_type') or PaintType.CAR.value)),
        is_team_paint=bool(payload.get('is_team_paint')),
        is_superspeedway_variant=bool(payload.get('is_superspeedway_variant')),
        is_numbered_car_spec=bool(payload.get('is_numbered_car_spec')),
        preserve_on_cleanup=bool(payload.get('preserve_on_cleanup')),
        tp_scheme_id=str(payload.get("tp_scheme_id") or ""),
        tp_title=str(payload.get("tp_title") or ""),
        tp_source_link=str(payload.get("tp_source_link") or ""),
        tp_source=str(payload.get("tp_source") or ""),
    )

def _replay_pack_index_path(replay_packs_dir: Path) -> Path:
    return replay_packs_dir / REPLAY_PACK_INDEX_FILENAME

def _load_replay_pack_index(replay_packs_dir: Path) -> dict[str, dict[str, object]]:
    path = _replay_pack_index_path(replay_packs_dir)
    if not path.exists():
        return {}
    try:
        raw = json.loads(path.read_text(encoding='utf-8'))
    except Exception:
        return {}
    packs = raw.get('packs') if isinstance(raw, dict) else None
    if not isinstance(packs, dict):
        return {}
    normalized: dict[str, dict[str, object]] = {}
    for key, value in packs.items():
        if isinstance(key, str) and isinstance(value, dict):
            normalized[key.lower()] = value
    return normalized

def _save_replay_pack_index(replay_packs_dir: Path, packs: dict[str, dict[str, object]]) -> None:
    replay_packs_dir.mkdir(parents=True, exist_ok=True)
    path = _replay_pack_index_path(replay_packs_dir)
    temp = path.with_name(path.name + '.tmp')
    temp.write_text(json.dumps({"packs": packs}, indent=2, sort_keys=True), encoding='utf-8')
    os.replace(temp, path)

def _snapshot_replay_files(replay_dir: Path) -> dict[str, dict[str, object]]:
    snapshot: dict[str, dict[str, object]] = {}
    if not replay_dir.exists():
        return snapshot
    try:
        replay_files = sorted(replay_dir.glob('*.rpy'))
    except Exception:
        return snapshot
    for replay_file in replay_files:
        try:
            stat = replay_file.stat()
        except OSError:
            continue
        snapshot[str(replay_file.resolve()).lower()] = {
            "path": replay_file,
            "size": int(stat.st_size),
            "mtime": float(stat.st_mtime),
        }
    return snapshot

def _replay_dir_change_token(replay_dir: Path) -> tuple[int, int]:
    try:
        stat = replay_dir.stat()
        return (int(getattr(stat, "st_mtime_ns", int(stat.st_mtime * 1_000_000_000))), int(stat.st_size))
    except OSError:
        return (0, 0)

def _write_replay_pack_manifest(pack_dir: Path, manifest: dict[str, object]) -> None:
    pack_dir.mkdir(parents=True, exist_ok=True)
    manifest_path = pack_dir / REPLAY_PACK_MANIFEST_FILENAME
    temp_path = manifest_path.with_name(manifest_path.name + '.tmp')
    temp_path.write_text(json.dumps(manifest, indent=2, sort_keys=True), encoding='utf-8')
    os.replace(temp_path, manifest_path)

def _load_replay_pack_manifest(pack_dir: Path) -> dict[str, object] | None:
    manifest_path = pack_dir / REPLAY_PACK_MANIFEST_FILENAME
    if not manifest_path.exists():
        return None
    try:
        raw = json.loads(manifest_path.read_text(encoding='utf-8'))
    except Exception:
        return None
    return raw if isinstance(raw, dict) else None

def _copy_saved_files_into_replay_pack(
    replay_file: Path,
    session: Session | None,
    saved: list[SavedFile],
    paints_root: Path,
    replay_packs_dir: Path,
) -> tuple[bool, str]:
    if session is None or not saved:
        return False, 'Current session paints are not available yet, so no replay pack was created.'
    replay_packs_dir.mkdir(parents=True, exist_ok=True)
    replay_file_resolved = replay_file.resolve()
    replay_key = str(replay_file_resolved).lower()
    pack_name = _safe_replay_pack_name(replay_file.stem)
    pack_dir = replay_packs_dir / pack_name
    existing_index = _load_replay_pack_index(replay_packs_dir)
    existing_entry = existing_index.get(replay_key)
    if existing_entry is not None:
        old_pack_name = str(existing_entry.get('pack_name') or pack_name)
        old_pack_dir = replay_packs_dir / old_pack_name
        if old_pack_dir != pack_dir and old_pack_dir.exists():
            shutil.rmtree(old_pack_dir, ignore_errors=True)
    if pack_dir.exists():
        shutil.rmtree(pack_dir, ignore_errors=True)
    paint_root = pack_dir / 'paint'
    copied_items: list[dict[str, object]] = []
    seen_rel_paths: set[str] = set()
    for item in saved:
        try:
            relative = item.file_path.resolve().relative_to(paints_root.resolve())
        except Exception:
            continue
        relative_key = relative.as_posix()
        if relative_key in seen_rel_paths:
            continue
        if not item.file_path.exists():
            continue
        destination = paint_root / relative
        destination.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(item.file_path, destination)
        copied_items.append({
            "relative_path": relative_key,
            "download_id": _download_id_to_dict(item.download_id),
        })
        seen_rel_paths.add(relative_key)
    if not copied_items:
        shutil.rmtree(pack_dir, ignore_errors=True)
        return False, 'The replay was detected, but there were no saved paint files left to archive.'
    manifest = {
        "replay_file_path": str(replay_file_resolved),
        "replay_file_name": replay_file.name,
        "pack_name": pack_name,
        "created_at": time.time(),
        "source_session_id": session.session_id.folder_name(),
        "session_fingerprint_key": _session_fingerprint_key(session),
        "saved_files": copied_items,
    }
    _write_replay_pack_manifest(pack_dir, manifest)
    existing_index[replay_key] = {
        "replay_file_path": str(replay_file_resolved),
        "replay_file_name": replay_file.name,
        "pack_name": pack_name,
        "created_at": manifest["created_at"],
        "source_session_id": manifest["source_session_id"],
        "session_fingerprint_key": manifest["session_fingerprint_key"],
    }
    _save_replay_pack_index(replay_packs_dir, existing_index)
    return True, f"Replay pack '{pack_name}' captured from session {session.session_id.folder_name()} with {len(copied_items)} file(s)"

def _delete_replay_pack_for_missing_file(replay_file_key: str, replay_packs_dir: Path, packs: dict[str, dict[str, object]]) -> str | None:
    entry = packs.pop(replay_file_key, None)
    if entry is None:
        return None
    pack_name = str(entry.get('pack_name') or '').strip()
    if not pack_name:
        _save_replay_pack_index(replay_packs_dir, packs)
        return None
    pack_dir = replay_packs_dir / pack_name
    shutil.rmtree(pack_dir, ignore_errors=True)
    _save_replay_pack_index(replay_packs_dir, packs)
    replay_name = str(entry.get('replay_file_name') or Path(replay_file_key).name)
    return f"Replay pack '{pack_name}' removed because replay file '{replay_name}' no longer exists"

def reconcile_replay_pack_index(replay_dir: Path, replay_packs_dir: Path) -> list[str]:
    current_files = _snapshot_replay_files(replay_dir)
    packs = _load_replay_pack_index(replay_packs_dir)
    logs: list[str] = []
    dirty = False
    for replay_key in list(packs.keys()):
        if replay_key in current_files:
            continue
        entry = packs.pop(replay_key, None)
        if entry is None:
            continue
        pack_name = str(entry.get('pack_name') or '').strip()
        if pack_name:
            shutil.rmtree(replay_packs_dir / pack_name, ignore_errors=True)
            replay_name = str(entry.get('replay_file_name') or Path(replay_key).name)
            logs.append(f"Replay pack '{pack_name}' removed because replay file '{replay_name}' no longer exists")
        dirty = True
    if dirty:
        _save_replay_pack_index(replay_packs_dir, packs)
    return logs

def sync_replay_packs_for_folder(
    replay_dir: Path,
    replay_packs_dir: Path,
    known_files: dict[str, dict[str, object]],
    current_session: Session | None,
    saved: list[SavedFile],
    paints_root: Path,
    known_packs: dict[str, dict[str, object]] | None = None,
) -> tuple[dict[str, dict[str, object]], dict[str, dict[str, object]]]:
    current_files = _snapshot_replay_files(replay_dir)
    packs = dict(known_packs) if known_packs is not None else _load_replay_pack_index(replay_packs_dir)
    added_keys = sorted(set(current_files) - set(known_files), key=lambda key: str(current_files[key]['path']))
    removed_keys = sorted(set(known_files) - set(current_files))
    dirty = False
    if removed_keys:
        for replay_key in removed_keys:
            entry = packs.pop(replay_key, None)
            if entry is None:
                continue
            pack_name = str(entry.get('pack_name') or '').strip()
            if pack_name:
                shutil.rmtree(replay_packs_dir / pack_name, ignore_errors=True)
                replay_name = str(entry.get('replay_file_name') or Path(replay_key).name)
                logging.info("Replay pack '%s' removed because replay file '%s' was deleted", pack_name, replay_name)
            dirty = True
    if added_keys:
        for replay_key in added_keys:
            replay_path = current_files[replay_key]['path']
            ok, message = _copy_saved_files_into_replay_pack(replay_path, current_session, saved, paints_root, replay_packs_dir)
            if ok:
                logging.info(message)
            else:
                logging.debug("Replay file '%s' detected but replay pack capture was skipped: %s", replay_path.name, message)
        packs = _load_replay_pack_index(replay_packs_dir)
    elif dirty:
        _save_replay_pack_index(replay_packs_dir, packs)
    return current_files, packs

def restore_replay_pack_for_session(
    session: Session,
    paints_root: Path,
    replay_packs_dir: Path,
    packs: dict[str, dict[str, object]] | None = None,
) -> tuple[list[SavedFile], str | None]:
    packs = packs if packs is not None else _load_replay_pack_index(replay_packs_dir)
    wanted_key = _session_fingerprint_key(session)
    candidates = [entry for entry in packs.values() if str(entry.get('session_fingerprint_key') or '') == wanted_key]
    if not candidates:
        return [], None
    candidates.sort(key=lambda entry: float(entry.get('created_at') or 0.0), reverse=True)
    for entry in candidates:
        pack_name = str(entry.get('pack_name') or '').strip()
        if not pack_name:
            continue
        replay_path = Path(str(entry.get('replay_file_path') or ''))
        if replay_path and str(replay_path) and not replay_path.exists():
            continue
        pack_dir = replay_packs_dir / pack_name
        manifest = _load_replay_pack_manifest(pack_dir)
        if manifest is None:
            continue
        items = manifest.get('saved_files')
        if not isinstance(items, list):
            continue
        restored: list[SavedFile] = []
        for item in items:
            if not isinstance(item, dict):
                continue
            relative_path = Path(str(item.get('relative_path') or ''))
            if not str(relative_path):
                continue
            source_path = pack_dir / 'paint' / relative_path
            if not source_path.exists():
                continue
            try:
                download_id = _download_id_from_dict(item.get('download_id') if isinstance(item.get('download_id'), dict) else {})
            except Exception:
                continue
            destination = paints_root / relative_path
            destination.parent.mkdir(parents=True, exist_ok=True)
            temp_destination = destination.with_name(destination.name + '.tmp')
            temp_destination.unlink(missing_ok=True)
            shutil.copy2(source_path, temp_destination)
            os.replace(temp_destination, destination)
            restored.append(SavedFile(session_id=session.session_id, download_id=download_id, file_path=destination))
        if restored:
            restored.sort(key=lambda s: (s.download_id.is_team_paint, s.download_id.user_id, s.download_id.directory.lower(), s.download_id.paint_type.value))
            return restored, pack_name
    return [], None

def delete_saved(
    files: Iterable[SavedFile],
    keep_targets: set[tuple[bool, int]] | None = None,
    paints_root: Path | None = None,
) -> list[SavedFile]:
    kept: list[SavedFile] = []
    to_delete: list[SavedFile] = []
    for f in files:
        target_key = (bool(f.download_id.is_team_paint), int(f.download_id.user_id))
        if bool(getattr(f.download_id, "preserve_on_cleanup", False)):
            kept.append(f)
        elif keep_targets and target_key in keep_targets:
            kept.append(f)
        else:
            to_delete.append(f)
    if not to_delete:
        return kept
    worker_count = max(1, min(16, len(to_delete)))
    with concurrent.futures.ThreadPoolExecutor(max_workers=worker_count) as executor:
        future_to_item = {
            executor.submit(_hard_delete_file, item.file_path, paints_root): item
            for item in to_delete
        }
        for future in concurrent.futures.as_completed(future_to_item):
            item = future_to_item[future]
            try:
                deleted = future.result()
            except Exception as exc:
                deleted = False
                logging.debug("Delete worker crashed for %s: %s", item.file_path, exc)
            if not deleted and item.file_path.exists():
                logging.warning("Paint file still present after delete attempts: %s", item.file_path)
    return kept
def _collect_wanted_downloads(
    session: Session,
    manifest_workers: int,
    retries: int,
    retry_backoff_seconds: float,
    sync_my_livery_from_server: bool,
    ai_rosters_dir: Path | None = None,
    cancel_event: threading.Event | None = None,
) -> list[DownloadFile]:
    wanted_items: list[DownloadFile] = []
    users_sorted = sorted(session.users, key=lambda u: u.user_id)
    manifest_workers = max(1, int(manifest_workers))
    if not users_sorted:
        return wanted_items
    with concurrent.futures.ThreadPoolExecutor(max_workers=manifest_workers) as executor:
        future_to_user = {
            executor.submit(fetch_best_manifest_files, session, user, retries, retry_backoff_seconds, ai_rosters_dir, cancel_event): user
            for user in users_sorted
            if not _cancel_requested(cancel_event)
        }
        completed = 0
        total_users = len(future_to_user)
        for future in concurrent.futures.as_completed(future_to_user):
            user = future_to_user[future]
            completed += 1
            if _cancel_requested(cancel_event):
                logging.info("Manifest progress %s/%s • session changed or ended; stopping manifest collection", completed, total_users)
                continue
            if not sync_my_livery_from_server:
                local_team_match = session_user_uses_team_target(user) and session.local_team_id is not None and user.team_id == session.local_team_id
                local_user_match = session.local_user_id is not None and user.user_id == session.local_user_id
                if local_team_match or local_user_match:
                    target_label = f"team {user.team_id}" if local_team_match and user.team_id is not None else f"user {user.user_id}"
                    logging.info("Manifest progress %s/%s • %s skipped local sync", completed, total_users, target_label)
                    continue
            try:
                all_files = future.result()
            except Exception as exc:  # noqa: BLE001
                logging.warning(
                    "Manifest progress %s/%s • user %s failed after retries: %s",
                    completed,
                    total_users,
                    user.user_id,
                    exc,
                )
                continue
            user_wanted = [normalize_download_for_session_user(user, f) for f in all_files if is_user_file(user, f)]
            if user.is_ai:
                label = f"AI {user.display_name or user.user_id} ({user.user_id})"
            else:
                label = f"team {user.team_id}" if session_user_uses_team_target(user) else f"user {user.user_id}"
            if _should_emit_stage_progress(completed, total_users):
                logging.info(
                    "Manifest progress %s/%s • %s: %s matching files",
                    completed,
                    total_users,
                    label,
                    len(user_wanted),
                )
            if not user_wanted and all_files:
                manifest_dirs = sorted({f.download_id.directory for f in all_files})
                logging.debug(
                    "No matching car files for source user %s (session dir='%s', team_id=%s). Manifest dirs=%s",
                    user.user_id,
                    user.directory,
                    user.team_id,
                    manifest_dirs,
                )
            elif not all_files:
                logging.debug("Manifest returned no files for source user %s", user.user_id)
            wanted_items.extend(user_wanted)
    wanted_items.sort(
        key=lambda f: (
            f.download_id.is_team_paint,
            f.download_id.user_id,
            f.download_id.directory.lower(),
            f.download_id.paint_type.value,
        )
    )
    return wanted_items
def _dedupe_download_items(items: list[DownloadFile]) -> list[DownloadFile]:
    unique: dict[tuple[int, str, PaintType], DownloadFile] = {}
    for item in items:
        key = (
            item.download_id.is_team_paint,
            item.download_id.user_id,
            item.download_id.directory.lower(),
            item.download_id.paint_type,
            item.download_id.is_numbered_car_spec,
        )
        unique[key] = item
    deduped = sorted(
        unique.values(),
        key=lambda f: (
            f.download_id.is_team_paint,
            f.download_id.user_id,
            f.download_id.directory.lower(),
            f.download_id.paint_type.value,
        ),
    )
    removed = len(items) - len(deduped)
    if removed > 0:
        logging.debug("Removed %s duplicate manifest item(s) before download", removed)
    return deduped
def _download_items_parallel(
    session: Session,
    temp_dir: Path,
    items: list[DownloadFile],
    download_workers: int,
    retries: int,
    retry_backoff_seconds: float,
    cancel_event: threading.Event | None = None,
) -> tuple[list[DownloadedFile], StageTransferStats]:
    if not items:
        return [], StageTransferStats(stage_name="downloads")
    downloads: list[DownloadedFile] = []
    download_workers = max(1, int(download_workers))
    total = len(items)
    batch_monitor = TransferBatchMonitor("downloads", requested_workers=download_workers, total_items=total)
    with concurrent.futures.ThreadPoolExecutor(max_workers=download_workers) as executor:
        future_to_item: dict[concurrent.futures.Future[DownloadedFile | None], tuple[int, DownloadFile]] = {}
        for index, item in enumerate(items, start=1):
            if _cancel_requested(cancel_event):
                break
            future = executor.submit(
                download_file,
                session.session_id,
                temp_dir,
                item,
                retries,
                retry_backoff_seconds,
                index,
                total,
                batch_monitor,
                cancel_event,
            )
            future_to_item[future] = (index, item)
        completed = 0
        for future in concurrent.futures.as_completed(future_to_item):
            index, item = future_to_item[future]
            completed += 1
            if _cancel_requested(cancel_event):
                logging.info("Download progress %s/%s • session changed or ended; stopping download result collection", completed, total)
                continue
            try:
                result = future.result()
            except Exception as exc:  # noqa: BLE001
                logging.error(
                    "Download progress %s/%s • worker crashed for user %s %s: %s",
                    completed,
                    total,
                    item.download_id.user_id,
                    item.download_id.paint_type.value,
                    exc,
                )
                continue
            if result is not None:
                downloads.append(result)
                if _should_emit_stage_progress(completed, total):
                    logging.info(
                        "Download progress %s/%s • completed user %s %s",
                        completed,
                        total,
                        item.download_id.user_id,
                        item.download_id.paint_type.value,
                    )
            else:
                logging.warning(
                    "Download progress %s/%s • failed user %s %s",
                    completed,
                    total,
                    item.download_id.user_id,
                    item.download_id.paint_type.value,
                )
    downloads.sort(
        key=lambda d: (
            d.download_id.is_team_paint,
            d.download_id.user_id,
            d.download_id.directory.lower(),
            d.download_id.paint_type.value,
        )
    )
    return downloads, batch_monitor.snapshot()
def resolve_save_workers(
    download_workers_mode: str,
    download_workers: int,
    item_count: int,
    manual_workers: int,
) -> int:
    if item_count <= 0:
        return 0
    mode = normalize_download_workers_mode(download_workers_mode)
    if mode == "manual":
        return max(1, min(100, positive_int(manual_workers, 8)))
    if mode == "session_total":
        return max(1, int(item_count))
    if mode == "safe":
        return _resolve_safe_workers(item_count, TP_SAFE_SAVE_WORKER_CAP)
    tuned = min(item_count, max(2, min(download_workers, 16)))
    return max(1, tuned)
def _save_downloads_parallel(
    downloads: list[DownloadedFile],
    paints_dir: Path,
    save_workers: int,
    saved_callback: Callable[[DownloadedFile, list[SavedFile]], None] | None = None,
    retries: int = 3,
    retry_backoff_seconds: float = 0.35,
    cancel_event: threading.Event | None = None,
) -> tuple[list[SavedFile], StageTransferStats]:
    if not downloads:
        return [], StageTransferStats(stage_name="saves")
    saved: list[SavedFile] = []
    save_workers = max(1, int(save_workers))
    total = len(downloads)
    batch_monitor = TransferBatchMonitor("saves", requested_workers=save_workers, total_items=total)
    with concurrent.futures.ThreadPoolExecutor(max_workers=save_workers) as executor:
        future_to_item: dict[concurrent.futures.Future[list[SavedFile] | None], tuple[int, DownloadedFile]] = {}
        for index, downloaded in enumerate(downloads, start=1):
            if _cancel_requested(cancel_event):
                break
            future = executor.submit(move_or_extract, downloaded, paints_dir, batch_monitor, retries, retry_backoff_seconds, cancel_event)
            future_to_item[future] = (index, downloaded)
        completed = 0
        for future in concurrent.futures.as_completed(future_to_item):
            _index, downloaded = future_to_item[future]
            completed += 1
            cancelled_while_saving = _cancel_requested(cancel_event)
            if cancelled_while_saving:
                logging.info("Save progress %s/%s • session changed or ended; collecting completed save result for cleanup", completed, total)
            try:
                result = future.result()
            except Exception as exc:  # noqa: BLE001
                logging.error(
                    "Save progress %s/%s • worker crashed for user %s %s: %s",
                    completed,
                    total,
                    downloaded.download_id.user_id,
                    downloaded.download_id.paint_type.value,
                    exc,
                )
                continue
            if result:
                saved.extend(result)
                if _should_emit_stage_progress(completed, total):
                    logging.info(
                        "Save progress %s/%s • completed user %s %s (%s file(s))",
                        completed,
                        total,
                        downloaded.download_id.user_id,
                        downloaded.download_id.paint_type.value,
                        len(result),
                    )
                if saved_callback is not None and not cancelled_while_saving:
                    try:
                        saved_callback(downloaded, result)
                    except Exception:
                        logging.debug("Save progress callback failed", exc_info=True)
            else:
                logging.warning(
                    "Save progress %s/%s • failed user %s %s",
                    completed,
                    total,
                    downloaded.download_id.user_id,
                    downloaded.download_id.paint_type.value,
                )
    saved.sort(
        key=lambda s: (
            s.download_id.is_team_paint,
            s.download_id.user_id,
            s.download_id.directory.lower(),
            s.download_id.paint_type.value,
        )
    )
    return saved, batch_monitor.snapshot()
def process_session(
    session: Session,
    paints_dir: Path,
    temp_dir: Path,
    ai_rosters_dir: Path | None,
    max_concurrent_manifests: int,
    max_concurrent_downloads: int,
    download_workers_mode: str,
    manual_manifest_workers: int,
    manual_download_workers: int,
    manual_save_workers: int,
    retries: int,
    retry_backoff_seconds: float,
    sync_my_livery_from_server: bool,
    random_fallback_real_drivers: bool,
    random_fallback_ai: bool,
    random_helmets: bool,
    random_suits: bool,
    random_helmets_real_drivers: bool,
    random_helmets_ai: bool,
    random_suits_real_drivers: bool,
    random_suits_ai: bool,
    disable_random_in_team_events: bool,
    disable_random_for_local_user: bool,
    ai_collection_skip_random_cars: bool,
    ai_collection_skip_random_helmets: bool,
    ai_collection_skip_random_suits: bool,
    keep_tp_paints_in_random_pool: bool,
    max_random_pool_gb: float,
    max_random_pool_car_gb: float = 3.0,
    max_random_pool_helmet_gb: float = 1.0,
    max_random_pool_suit_gb: float = 1.0,
    tp_fallback_mode: str = "online",
    tp_manifest_member_id_override: int = 0,
    tp_primary_fast_mode: bool = True,
    tp_mule_profile_fast_mode: bool = False,
    tp_detect_showroom_total_pages: bool = False,
    tp_fallback_lanes_mode: str = "session_total",
    tp_manual_max_lanes: int = 1,
    tp_process_all_online_fallbacks_together: bool = True,
    tp_retry_timed_out_fallbacks_indefinitely: bool = True,
    tp_collection_pool_sources: str = "",
    tp_collection_pool_allow_showroom_fallback: bool = True,
    tp_collection_pool_repeat_when_strict: bool = False,
    tp_showroom_sources: str = TP_SHOWROOM_DEFAULT_SOURCES,
    progress_callback: Callable[..., None] | None = None,
    reload_reader: IracingSdkReader | None = None,
    auto_refresh_paints: bool = False,
    cancel_event: threading.Event | None = None,
    prior_saved: list[SavedFile] | None = None,
) -> tuple[list[SavedFile], ThroughputMonitorSnapshot, list[SessionDriverSnapshot]]:
    session_temp = temp_dir / session.session_id.folder_name()
    if session_temp.exists():
        shutil.rmtree(session_temp, ignore_errors=True)
    logging.info("Session users discovered: %s", len(session.users))
    context_fields = session.trading_paints_context()
    if context_fields is not None:
        logging.info(
            "Trading Paints context active: team=%s user=%s night=%s series=%s league=%s numbers=%s",
            context_fields.get('team', '0'),
            context_fields.get('user', '0'),
            context_fields.get('night', '10:00 am'),
            context_fields.get('series', '0'),
            context_fields.get('league', '0'),
            context_fields.get('numbers', 'False'),
        )
    else:
        logging.info("Trading Paints context unavailable; using fetch_user.php fallback manifests")
    inferred_ai_roster_dir = _find_active_ai_roster_dir(session, ai_rosters_dir) if ai_rosters_dir is not None and session.ai_driver_count > 0 else None
    if inferred_ai_roster_dir is not None and not _session_has_named_ai_roster(session):
        try:
            _payload, inferred_drivers = _read_ai_roster_payload(inferred_ai_roster_dir)
            exact_matches, name_matches, index_matches, total_ai = _score_ai_roster_against_session(session, inferred_drivers)
            local_label = "local" if _ai_roster_dir_is_local(inferred_ai_roster_dir) else "Trading Paints synced"
            logging.info(
                "Inferred active %s AI roster from session drivers: %s (%s/%s name matches, %s exact, %s index)",
                local_label,
                inferred_ai_roster_dir.name,
                name_matches,
                total_ai,
                exact_matches,
                index_matches,
            )
        except Exception:
            logging.debug("Could not summarize inferred AI roster %s", inferred_ai_roster_dir, exc_info=True)
    if session.is_superspeedway_track:
        logging.info(
            "Superspeedway session detected for track %s (%s); server _ss car variants will be requested and preferred when Trading Paints provides them",
            session.track_display_name or session.track_name or "unknown",
            session.track_config_name or "default",
        )
    mode = normalize_download_workers_mode(download_workers_mode)
    manifest_workers = resolve_manifest_workers(
        len(session.users),
        download_workers_mode=mode,
        auto_cap=max_concurrent_manifests,
        manual_workers=manual_manifest_workers,
    )
    wanted_items = _collect_wanted_downloads(
        session=session,
        manifest_workers=manifest_workers,
        retries=retries,
        retry_backoff_seconds=retry_backoff_seconds,
        sync_my_livery_from_server=sync_my_livery_from_server,
        ai_rosters_dir=ai_rosters_dir,
        cancel_event=cancel_event,
    )
    wanted_items = _dedupe_download_items(wanted_items)
    progress_statuses = build_session_stage_statuses(session, wanted_items, sync_my_livery_from_server)
    reload_debouncer = TextureReloadDebouncer(reload_reader, session, debounce_seconds=0.2) if auto_refresh_paints else None

    def _emit_progress_rows(saved_items: list[SavedFile] | None = None) -> None:
        if progress_callback is None:
            return
        try:
            progress_callback(build_session_driver_rows(session, progress_statuses), list(saved_items or []))
        except Exception:
            logging.debug("Session progress callback failed", exc_info=True)

    def _on_saved_items(_downloaded: DownloadedFile, saved_items: list[SavedFile]) -> None:
        _apply_saved_file_statuses(session, progress_statuses, saved_items, "downloaded")
        _emit_progress_rows(saved_items)
        if reload_debouncer is not None:
            reload_debouncer.request_saved_items(saved_items)

    def _on_fallback_saved_items(saved_items: list[SavedFile], status_code: str) -> None:
        _apply_saved_file_statuses(session, progress_statuses, saved_items, status_code)
        _emit_progress_rows(saved_items)
        if reload_debouncer is not None:
            reload_debouncer.request_saved_items(saved_items)

    _emit_progress_rows()
    download_workers = resolve_download_workers(
        len(wanted_items),
        download_workers_mode=mode,
        auto_cap=max_concurrent_downloads,
        manual_workers=manual_download_workers,
    )
    save_workers = resolve_save_workers(
        download_workers_mode=mode,
        download_workers=download_workers,
        item_count=len(wanted_items),
        manual_workers=manual_save_workers,
    )

    def _cancelled_result(
        stage_name: str,
        server_saved_items: list[SavedFile] | None = None,
        fallback_saved_items: list[SavedFile] | None = None,
        downloads_count: int = 0,
        download_stats_snapshot: StageTransferStats | None = None,
        save_stats_snapshot: StageTransferStats | None = None,
    ) -> tuple[list[SavedFile], ThroughputMonitorSnapshot, list[SessionDriverSnapshot]]:
        server_saved_items = _mark_saved_files_for_driver_overrides(session, list(server_saved_items or []))
        fallback_saved_items = _mark_saved_files_for_driver_overrides(session, list(fallback_saved_items or []))
        combined_saved = server_saved_items + fallback_saved_items
        if reload_debouncer is not None:
            reload_debouncer.flush(force=True)
        shutil.rmtree(session_temp, ignore_errors=True)
        fallback_mode_for_rows = str(tp_fallback_mode or "local").strip().lower()
        final_rows = build_session_driver_rows(
            session,
            build_session_final_statuses(
                session,
                wanted_items=wanted_items,
                server_saved=server_saved_items,
                fallback_saved=fallback_saved_items,
                sync_my_livery_from_server=sync_my_livery_from_server,
                replay_mode=False,
                fallback_mode=fallback_mode_for_rows,
            ),
        )
        if progress_callback is not None:
            try:
                progress_callback(final_rows, combined_saved)
            except Exception:
                logging.debug("Session progress callback failed during cancelled stage", exc_info=True)
        download_stats_snapshot = download_stats_snapshot or StageTransferStats(stage_name="downloads")
        save_stats_snapshot = save_stats_snapshot or StageTransferStats(stage_name="saves")
        logging.info(
            "Session %s cancelled during %s because the active iRacing session changed or ended: %s queued, %s downloaded, %s saved",
            session.session_id.folder_name(),
            stage_name,
            len(wanted_items),
            downloads_count,
            len(combined_saved),
        )
        return (
            combined_saved,
            ThroughputMonitorSnapshot(
                session_name=f"{session.session_id.folder_name()} [cancelled]",
                worker_mode=f"{mode}-cancelled",
                manifest_workers=manifest_workers,
                download_workers=download_workers,
                save_workers=save_workers,
                queued_items=len(wanted_items),
                downloaded_items=downloads_count,
                saved_items=len(combined_saved),
                download_stage_seconds=download_stats_snapshot.stage_seconds,
                save_stage_seconds=save_stats_snapshot.stage_seconds,
                download_files_per_second=download_stats_snapshot.files_per_second,
                save_files_per_second=save_stats_snapshot.files_per_second,
                average_download_seconds=download_stats_snapshot.average_item_seconds,
                average_save_seconds=save_stats_snapshot.average_item_seconds,
                average_download_mbps=download_stats_snapshot.megabits_per_second,
                peak_active_downloads=download_stats_snapshot.peak_active_items,
                effective_parallelism=download_stats_snapshot.effective_parallelism,
                ceiling_hint=build_tp_ceiling_hint(download_stats_snapshot),
                updated_at=time.time(),
            ),
            final_rows,
        )

    if _cancel_requested(cancel_event):
        return _cancelled_result("manifest")
    if mode == "manual":
        logging.info(
            "Queued %s matching downloads with fixed workers: manifests=%s, downloads=%s, saves=%s",
            len(wanted_items),
            manifest_workers,
            download_workers,
            save_workers,
        )
        logging.debug(
            "Worker detail: mode=manual, users=%s, items=%s, manual_manifest_workers=%s, manual_download_workers=%s, manual_save_workers=%s",
            len(session.users),
            len(wanted_items),
            manual_manifest_workers,
            manual_download_workers,
            manual_save_workers,
        )
    elif mode == "session_total":
        logging.info(
            "Queued %s matching downloads with Session Total workers: manifests=%s, downloads=%s, saves=%s",
            len(wanted_items),
            manifest_workers,
            download_workers,
            save_workers,
        )
        logging.debug(
            "Worker detail: mode=session_total, users=%s, items=%s",
            len(session.users),
            len(wanted_items),
        )
    else:
        logging.info(
            "Queued %s matching downloads with Safe workers: manifests=%s, downloads=%s, saves=%s",
            len(wanted_items),
            manifest_workers,
            download_workers,
            save_workers,
        )
        logging.debug(
            "Worker detail: mode=safe, users=%s, manifest_cap=%s, items=%s, download_cap=%s",
            len(session.users),
            max_concurrent_manifests,
            len(wanted_items),
            max_concurrent_downloads,
        )
    downloads, download_stats = _download_items_parallel(
        session=session,
        temp_dir=temp_dir,
        items=wanted_items,
        download_workers=download_workers,
        retries=retries,
        retry_backoff_seconds=retry_backoff_seconds,
        cancel_event=cancel_event,
    )
    if _cancel_requested(cancel_event):
        return _cancelled_result(
            "download",
            downloads_count=len(downloads),
            download_stats_snapshot=download_stats,
        )
    saved, save_stats = _save_downloads_parallel(
        downloads=downloads,
        paints_dir=paints_dir,
        save_workers=save_workers,
        saved_callback=_on_saved_items,
        retries=retries,
        retry_backoff_seconds=retry_backoff_seconds,
        cancel_event=cancel_event,
    )
    if _cancel_requested(cancel_event):
        return _cancelled_result(
            "save",
            server_saved_items=saved,
            downloads_count=len(downloads),
            download_stats_snapshot=download_stats,
            save_stats_snapshot=save_stats,
        )
    override_saved, override_logs = apply_driver_paint_overrides(
        session=session,
        saved=saved,
        paints_dir=paints_dir,
        saved_callback=_on_fallback_saved_items,
    )
    if override_saved:
        saved.extend(override_saved)
        saved.sort(
            key=lambda s: (
                s.download_id.is_team_paint,
                s.download_id.user_id,
                s.download_id.directory.lower(),
                s.download_id.paint_type.value,
            )
        )
    for line in override_logs:
        logging.info(line)
    if _cancel_requested(cancel_event):
        return _cancelled_result(
            "driver override",
            server_saved_items=saved,
            downloads_count=len(downloads),
            download_stats_snapshot=download_stats,
            save_stats_snapshot=save_stats,
        )
    local_ai_roster_saved: list[SavedFile] = []
    local_ai_roster_logs: list[str] = []
    if _session_has_named_ai_roster(session) and session_uses_local_ai_roster(session, ai_rosters_dir):
        local_ai_roster_saved, local_ai_roster_logs = apply_local_ai_roster_live_paints(
            session=session,
            saved=saved,
            paints_dir=paints_dir,
            ai_rosters_dir=ai_rosters_dir,
            saved_callback=_on_fallback_saved_items,
        )
    if local_ai_roster_saved:
        saved.extend(local_ai_roster_saved)
        saved.sort(
            key=lambda s: (
                s.download_id.is_team_paint,
                s.download_id.user_id,
                s.download_id.directory.lower(),
                s.download_id.paint_type.value,
            )
        )
    for line in local_ai_roster_logs:
        logging.info(line)
    if _cancel_requested(cancel_event):
        return _cancelled_result(
            "local AI roster live apply",
            server_saved_items=saved,
            downloads_count=len(downloads),
            download_stats_snapshot=download_stats,
            save_stats_snapshot=save_stats,
        )
    random_pool_dir = default_random_pool_dir()
    ai_livery_root = default_ai_livery_dir()
    tp_saved_file_count = len(saved)
    tp_saved_set_count = len(_group_saved_car_sets(saved))
    fallback_mode = str(tp_fallback_mode or "local").strip().lower()
    tp_manifest_member_id = resolve_tp_manifest_member_id(tp_manifest_member_id_override, session.local_user_id)
    effective_random_fallback_ai = bool(random_fallback_ai)
    effective_random_helmets_ai = bool(random_helmets_ai)
    effective_random_suits_ai = bool(random_suits_ai)
    if session_uses_trading_paints_ai_collection(session, ai_rosters_dir):
        skipped_ai_random_kinds: list[str] = []
        if ai_collection_skip_random_cars and effective_random_fallback_ai:
            effective_random_fallback_ai = False
            skipped_ai_random_kinds.append("cars")
        if ai_collection_skip_random_helmets and effective_random_helmets_ai:
            effective_random_helmets_ai = False
            skipped_ai_random_kinds.append("helmets")
        if ai_collection_skip_random_suits and effective_random_suits_ai:
            effective_random_suits_ai = False
            skipped_ai_random_kinds.append("suits")
        if skipped_ai_random_kinds:
            logging.info(
                "Trading Paints AI collection roster random fallback guard active for %s: skipping random AI %s.",
                session.ai_roster_name or session.ai_roster_id or "active AI roster",
                ", ".join(skipped_ai_random_kinds),
            )
    elif _session_has_named_ai_roster(session) and session_uses_local_ai_roster(session, ai_rosters_dir) and (
        effective_random_fallback_ai or effective_random_helmets_ai or effective_random_suits_ai
    ):
        active_roster_dir = _find_active_ai_roster_dir(session, ai_rosters_dir) if ai_rosters_dir is not None else None
        skipped_ai_random_kinds: list[str] = []
        if effective_random_fallback_ai:
            effective_random_fallback_ai = False
            skipped_ai_random_kinds.append("cars")
        if effective_random_helmets_ai:
            effective_random_helmets_ai = False
            skipped_ai_random_kinds.append("helmets")
        if effective_random_suits_ai:
            effective_random_suits_ai = False
            skipped_ai_random_kinds.append("suits")
        if skipped_ai_random_kinds:
            logging.info(
                "Local AI roster active for %s: skipping session random AI %s so local roster paints stay stable. Local roster prefill runs at app startup and after AI roster sync to fill missing files before the race is created.",
                active_roster_dir.name if active_roster_dir is not None else (session.ai_roster_name or session.ai_roster_id or "active AI roster"),
                ", ".join(skipped_ai_random_kinds),
            )
    elif session.ai_driver_count > 0 and not _session_has_named_ai_roster(session) and (
        effective_random_fallback_ai or effective_random_helmets_ai or effective_random_suits_ai
    ):
        logging.info(
            "Unnamed AI session detected: applying random paints directly to the live AI car targets. Nishizumi Paints will not create or update a local AI roster for this session."
        )
    collection_ids = parse_tp_collection_ids_from_text(tp_collection_pool_sources)
    collection_saved: list[SavedFile] = []
    collection_logs: list[str] = []
    collection_summary = RandomFallbackSummary()
    fallback_base_saved = saved
    if fallback_mode == "online" and collection_ids:
        collection_used_source_ids = _tp_collection_used_source_ids_from_saved(prior_saved)
        collection_saved, collection_logs, collection_summary = apply_tp_collection_pool_fallbacks(
            session=session,
            saved=saved,
            paints_dir=paints_dir,
            temp_dir=temp_dir,
            collection_ids=collection_ids,
            enable_real_drivers=random_fallback_real_drivers,
            enable_ai=effective_random_fallback_ai,
            sync_my_livery_from_server=sync_my_livery_from_server,
            random_helmets=random_helmets,
            random_suits=random_suits,
            random_helmets_real_drivers=random_helmets_real_drivers,
            random_helmets_ai=effective_random_helmets_ai,
            random_suits_real_drivers=random_suits_real_drivers,
            random_suits_ai=effective_random_suits_ai,
            disable_random_in_team_events=disable_random_in_team_events,
            disable_random_for_local_user=disable_random_for_local_user,
            mapping_path=default_tp_showroom_mapping_path(),
            profile_dir=default_tp_showroom_profile_dir(),
            manifest_member_id=tp_manifest_member_id,
            retries=retries,
            retry_backoff_seconds=retry_backoff_seconds,
            saved_callback=_on_fallback_saved_items,
            used_source_ids_seed=collection_used_source_ids,
            cancel_event=cancel_event,
            strict_collection_only=not bool(tp_collection_pool_allow_showroom_fallback),
            allow_repeating_when_exhausted=bool(
                tp_collection_pool_repeat_when_strict and not bool(tp_collection_pool_allow_showroom_fallback)
            ),
        )
        for line in collection_logs:
            logging.info(line)
        if collection_saved:
            fallback_base_saved = saved + collection_saved

    if fallback_mode == "online" and (not collection_ids or bool(tp_collection_pool_allow_showroom_fallback)):
        fallback_saved, fallback_logs, fallback_summary = apply_tp_showroom_fallbacks(
            session=session,
            saved=fallback_base_saved,
            paints_dir=paints_dir,
            enable_real_drivers=random_fallback_real_drivers,
            enable_ai=effective_random_fallback_ai,
            sync_my_livery_from_server=sync_my_livery_from_server,
            random_helmets=random_helmets,
            random_suits=random_suits,
            random_helmets_real_drivers=random_helmets_real_drivers,
            random_helmets_ai=effective_random_helmets_ai,
            random_suits_real_drivers=random_suits_real_drivers,
            random_suits_ai=effective_random_suits_ai,
            disable_random_in_team_events=disable_random_in_team_events,
            disable_random_for_local_user=disable_random_for_local_user,
            mapping_path=default_tp_showroom_mapping_path(),
            profile_dir=default_tp_showroom_profile_dir(),
            manifest_member_id=tp_manifest_member_id,
            primary_fast_mode=bool(tp_primary_fast_mode),
            mule_profile_mode=bool(tp_mule_profile_fast_mode),
            detect_showroom_total_pages=False,
            retries=retries,
            retry_backoff_seconds=retry_backoff_seconds,
            tp_fallback_lanes_mode=tp_fallback_lanes_mode,
            tp_manual_max_lanes=tp_manual_max_lanes,
            process_all_together=bool(tp_process_all_online_fallbacks_together),
            retry_timed_out_fallbacks_indefinitely=bool(tp_retry_timed_out_fallbacks_indefinitely),
            showroom_sources=tp_showroom_sources,
            saved_callback=_on_fallback_saved_items,
            cancel_event=cancel_event,
        )
    elif fallback_mode == "online":
        fallback_saved, fallback_logs, fallback_summary = [], [
            "Trading Paints collection pool handled configured collections only; normal public showroom coverage is disabled, so collection paints will be reused within the session if the selected pool runs out."
        ], RandomFallbackSummary()
    else:
        fallback_saved, fallback_logs, fallback_summary = apply_local_tp_random_fallbacks(
            session=session,
            saved=saved,
            paints_dir=paints_dir,
            random_pool_dir=random_pool_dir,
            ai_livery_root=ai_livery_root,
            enable_real_drivers=random_fallback_real_drivers,
            enable_ai=effective_random_fallback_ai,
            sync_my_livery_from_server=sync_my_livery_from_server,
            random_helmets=random_helmets,
            random_suits=random_suits,
            random_helmets_real_drivers=random_helmets_real_drivers,
            random_helmets_ai=effective_random_helmets_ai,
            random_suits_real_drivers=random_suits_real_drivers,
            random_suits_ai=effective_random_suits_ai,
            disable_random_in_team_events=disable_random_in_team_events,
            disable_random_for_local_user=disable_random_for_local_user,
            saved_callback=_on_fallback_saved_items,
            cancel_event=cancel_event,
        )
    if collection_saved or collection_logs:
        collection_misses_for_summary = (
            0
            if fallback_mode == "online" and collection_ids and bool(tp_collection_pool_allow_showroom_fallback)
            else collection_summary.missing_source_targets
        )
        fallback_saved = collection_saved + fallback_saved
        fallback_summary = RandomFallbackSummary(
            attempted_targets=collection_summary.attempted_targets + fallback_summary.attempted_targets,
            applied_targets=collection_summary.applied_targets + fallback_summary.applied_targets,
            missing_source_targets=collection_misses_for_summary + fallback_summary.missing_source_targets,
            repeated_source_uses=collection_summary.repeated_source_uses + fallback_summary.repeated_source_uses,
        )
    if _cancel_requested(cancel_event):
        return _cancelled_result(
            "fallback",
            server_saved_items=saved,
            fallback_saved_items=fallback_saved,
            downloads_count=len(downloads),
            download_stats_snapshot=download_stats,
            save_stats_snapshot=save_stats,
        )
    for line in fallback_logs:
        logging.info(line)
    if reload_debouncer is not None:
        reload_debouncer.flush(force=True)
    saved = _mark_saved_files_for_driver_overrides(session, saved)
    fallback_saved = _mark_saved_files_for_driver_overrides(session, fallback_saved)
    server_saved = list(saved)
    if fallback_saved:
        saved.extend(fallback_saved)
        saved.sort(
            key=lambda s: (
                s.download_id.is_team_paint,
                s.download_id.user_id,
                s.download_id.directory.lower(),
                s.download_id.paint_type.value,
            )
        )
    if keep_tp_paints_in_random_pool:
        pool_saved = list(saved)
        if fallback_mode == "online" and (session.local_user_id is not None or session.local_team_id is not None):
            filtered_pool_saved: list[SavedFile] = []
            skipped_local_pool = False
            for item in pool_saved:
                skip_item = False
                if session.local_user_id is not None and not item.download_id.is_team_paint and int(item.download_id.user_id) == int(session.local_user_id):
                    skip_item = True
                if session.local_team_id is not None and item.download_id.is_team_paint and int(item.download_id.user_id) == int(session.local_team_id):
                    skip_item = True
                if skip_item:
                    skipped_local_pool = True
                    continue
                filtered_pool_saved.append(item)
            pool_saved = filtered_pool_saved
            if skipped_local_pool:
                logging.info("Random TP pool skipped the local user's own saved files to avoid caching a temporary showroom-swapped livery.")
        archived_sets, archived_files, archived_logs, pool_bytes_after, pool_freed_bytes = archive_saved_tp_sets_to_random_pool(
            pool_saved,
            random_pool_dir,
            max_random_pool_gb,
            max_pool_car_gb=max_random_pool_car_gb,
            max_pool_helmet_gb=max_random_pool_helmet_gb,
            max_pool_suit_gb=max_random_pool_suit_gb,
        )
        if archived_sets > 0:
            logging.info(
                "Random TP pool updated with %s set(s) and %s file(s) after fallback resolution",
                archived_sets,
                archived_files,
            )
            for line in archived_logs:
                logging.info(line)
        else:
            logging.debug("Random TP pool is enabled, but this session did not add any new reusable car paint set to the pool")
        if pool_freed_bytes > 0:
            logging.info(
                "Random TP pool trimmed by %.2f GB to honor the configured limit of %.2f GB",
                pool_freed_bytes / float(1024 ** 3),
                clamp_random_pool_gb(max_random_pool_gb),
            )
        logging.info(
            "Random TP pool usage: %.2f GB / %.2f GB",
            pool_bytes_after / float(1024 ** 3),
            clamp_random_pool_gb(max_random_pool_gb),
        )
    else:
        logging.info(
            "Random TP pool archival is disabled, so deleting downloaded livery will remove those files permanently instead of recycling them into the local fallback pool"
        )
    shutil.rmtree(session_temp, ignore_errors=True)
    logging.info(
        "Session summary • TP files saved=%s • TP car sets=%s • fallback mode=%s • recycled to pool=%s set(s)/%s file(s) • random fallback applied=%s target(s)/%s file(s) • random fallback misses=%s • repeated random source uses=%s",
        tp_saved_file_count,
        tp_saved_set_count,
        fallback_mode,
        archived_sets if keep_tp_paints_in_random_pool else 0,
        archived_files if keep_tp_paints_in_random_pool else 0,
        fallback_summary.applied_targets,
        len(fallback_saved),
        fallback_summary.missing_source_targets,
        fallback_summary.repeated_source_uses,
    )
    logging.info(
        "Session %s complete: %s queued, %s downloaded, %s saved",
        session.session_id.folder_name(),
        len(wanted_items),
        len(downloads),
        len(saved),
    )
    monitor_snapshot = ThroughputMonitorSnapshot(
        session_name=session.session_id.folder_name(),
        worker_mode=mode,
        manifest_workers=manifest_workers,
        download_workers=download_workers,
        save_workers=save_workers,
        queued_items=len(wanted_items),
        downloaded_items=len(downloads),
        saved_items=len(saved),
        download_stage_seconds=download_stats.stage_seconds,
        save_stage_seconds=save_stats.stage_seconds,
        download_files_per_second=download_stats.files_per_second,
        save_files_per_second=save_stats.files_per_second,
        average_download_seconds=download_stats.average_item_seconds,
        average_save_seconds=save_stats.average_item_seconds,
        average_download_mbps=download_stats.megabits_per_second,
        peak_active_downloads=download_stats.peak_active_items,
        effective_parallelism=download_stats.effective_parallelism,
        ceiling_hint=build_tp_ceiling_hint(download_stats),
        updated_at=time.time(),
    )
    logging.info(
        "TP monitor • requested downloads=%s, peak active=%s, download stage=%.2fs, avg file=%.2fs, throughput=%.2f files/s, avg rate=%.1f Mbps, effective parallelism=%.1f, hint=%s",
        download_workers,
        download_stats.peak_active_items,
        download_stats.stage_seconds,
        download_stats.average_item_seconds,
        download_stats.files_per_second,
        download_stats.megabits_per_second,
        download_stats.effective_parallelism,
        monitor_snapshot.ceiling_hint,
    )
    logging.info(
        "Save monitor • requested saves=%s, save stage=%.2fs, avg file=%.2fs, throughput=%.2f files/s",
        save_workers,
        save_stats.stage_seconds,
        save_stats.average_item_seconds,
        save_stats.files_per_second,
    )
    final_rows = build_session_driver_rows(
        session,
        build_session_final_statuses(
            session,
            wanted_items=wanted_items,
            server_saved=server_saved,
            fallback_saved=fallback_saved,
            sync_my_livery_from_server=sync_my_livery_from_server,
            replay_mode=False,
            fallback_mode=fallback_mode,
        ),
    )
    if progress_callback is not None:
        try:
            progress_callback(final_rows, saved)
        except Exception:
            logging.debug("Session progress callback failed during final stage", exc_info=True)
    return saved, monitor_snapshot, final_rows
def should_use_sdk(args: argparse.Namespace) -> bool:
    return args.iracing_sdk or args.session_yaml is None
def create_sdk_reader() -> IracingSdkReader | None:
    try:
        import irsdk as irsdk_module
    except ImportError:
        logging.error(
            "iRacing SDK mode requested but package 'irsdk' is not installed. "
            "Install it with: pip install pyirsdk"
        )
        return None
    sdk = irsdk_module.IRSDK()
    try:
        started = bool(sdk.startup())
    except Exception as exc:  # noqa: BLE001
        logging.debug("Initial SDK startup() raised an exception: %s", exc)
        started = False
    if started and getattr(sdk, "is_connected", False):
        logging.info("Connected to iRacing SDK")
    else:
        logging.info("iRacing SDK watcher started. Waiting for iRacing/session...")
    return IracingSdkReader(sdk=sdk)
def close_sdk_reader(reader: IracingSdkReader | None) -> None:
    if reader is None:
        return
    try:
        reader.sdk.shutdown()
    except Exception:
        pass
def _read_session_info_update(sdk: object) -> int:
    try:
        value = getattr(sdk, "session_info_update", None)
        if value is not None:
            return int(value)
    except Exception:  # noqa: BLE001
        pass
    try:
        value = sdk["SessionInfoUpdate"]
        if value is not None:
            return int(value)
    except Exception:  # noqa: BLE001
        pass
    return 0
def read_session_from_sdk(reader: IracingSdkReader) -> tuple[SdkPollState, Session | None]:
    sdk = reader.sdk
    try:
        if not sdk.is_initialized:
            if not sdk.startup():
                logging.debug("SDK not initialized and startup() failed")
                return SdkPollState.INACTIVE, None
    except Exception as exc:  # noqa: BLE001
        logging.debug("SDK startup() failed while polling: %s", exc)
        return SdkPollState.INACTIVE, None
    if not sdk.is_connected:
        logging.debug("SDK initialized but not connected to an active iRacing session")
        reader.last_update = None
        reader.last_full_session_refresh_at = 0.0
        return SdkPollState.INACTIVE, None
    try:
        sdk.freeze_var_buffer_latest()
    except Exception as exc:  # noqa: BLE001
        logging.debug("freeze_var_buffer_latest() failed: %s", exc)
    now = time.monotonic()
    update = _read_session_info_update(sdk)
    if reader.last_update is not None and update == reader.last_update:
        if now - float(reader.last_full_session_refresh_at or 0.0) < SDK_UNCHANGED_FORCE_REFRESH_SECONDS:
            logging.debug("SessionInfoUpdate unchanged (%s); skipping this poll", update)
            return SdkPollState.UNCHANGED, None
        logging.debug("SessionInfoUpdate unchanged (%s), but forcing a periodic full session refresh", update)
    try:
        weekend = sdk["WeekendInfo"]
        driver_info = sdk["DriverInfo"]
    except Exception as exc:  # noqa: BLE001
        logging.debug("Failed to read session sections from SDK: %s", exc)
        reader.last_update = update
        return SdkPollState.INVALID, None
    if not isinstance(weekend, dict):
        logging.debug("WeekendInfo missing or invalid (type=%s)", type(weekend).__name__)
        reader.last_update = update
        return SdkPollState.INVALID, None
    if not isinstance(driver_info, dict):
        logging.debug("DriverInfo missing or invalid (type=%s)", type(driver_info).__name__)
        reader.last_update = update
        return SdkPollState.INVALID, None
    load_num_textures = False
    try:
        load_num_value = sdk["LoadNumTextures"]
        load_num_textures = _to_boolish(load_num_value, default=False)
    except Exception as exc:  # noqa: BLE001
        logging.debug("Could not read LoadNumTextures from SDK: %s", exc)
    session = _build_session_from_parts(weekend, driver_info, load_num_textures=load_num_textures)
    reader.last_update = update
    reader.last_full_session_refresh_at = now
    if session is not None and (session.local_user_id is None or session.local_user_id <= 0):
        fallback_local_user_id = _read_sdk_local_user_id(sdk)
        if fallback_local_user_id is not None and fallback_local_user_id > 0:
            session = replace(session, local_user_id=fallback_local_user_id)
            logging.debug("Recovered local user ID %s from SDK fallback fields", fallback_local_user_id)
    if session is None:
        logging.debug("SDK returned session data, but it could not be converted into a Session")
        return SdkPollState.INVALID, None
    logging.debug(
        "Loaded session from SDK (update=%s, session=%s, users=%s)",
        update,
        session.session_id.folder_name(),
        len(session.users),
    )
    return SdkPollState.SESSION, session
def start_session_cancel_monitor(
    *,
    expected_fingerprint: tuple[SessionId, tuple[bool, str, int, int, bool, str, str, bool]],
    cancel_event: threading.Event,
    stop_event: threading.Event,
    reader: IracingSdkReader | None = None,
    expected_session_info_update: int | None = None,
    poll_seconds: float = SESSION_CANCEL_POLL_SECONDS,
) -> threading.Thread:
    def _monitor() -> None:
        monitor_reader = reader
        owned_reader = False
        last_checked_update = expected_session_info_update
        try:
            if monitor_reader is None:
                monitor_reader = create_sdk_reader()
                owned_reader = True
            while not stop_event.is_set() and not cancel_event.is_set():
                if monitor_reader is None:
                    cancel_event.set()
                    logging.info("Cancelling active paint pipeline because the iRacing SDK monitor could not be opened.")
                    break
                sdk = monitor_reader.sdk
                try:
                    if not sdk.is_initialized and not sdk.startup():
                        cancel_event.set()
                        logging.info("Cancelling active paint pipeline because the iRacing SDK monitor is inactive.")
                        break
                    if not sdk.is_connected:
                        cancel_event.set()
                        logging.info("Cancelling active paint pipeline because the iRacing session ended or became invalid.")
                        break
                    try:
                        sdk.freeze_var_buffer_latest()
                    except Exception:
                        pass
                    update = _read_session_info_update(sdk)
                except Exception:
                    cancel_event.set()
                    logging.info("Cancelling active paint pipeline because the iRacing SDK monitor failed.")
                    break
                if last_checked_update is not None and update == last_checked_update:
                    stop_event.wait(max(0.25, float(poll_seconds)))
                    continue
                last_checked_update = update
                saved_reader_update = getattr(monitor_reader, "last_update", None)
                saved_reader_refresh_at = getattr(monitor_reader, "last_full_session_refresh_at", 0.0)
                try:
                    poll_state, observed_session = read_session_from_sdk(monitor_reader)
                finally:
                    if not owned_reader:
                        monitor_reader.last_update = saved_reader_update
                        monitor_reader.last_full_session_refresh_at = saved_reader_refresh_at
                if poll_state in {SdkPollState.INACTIVE, SdkPollState.INVALID}:
                    cancel_event.set()
                    logging.info("Cancelling active paint pipeline because the iRacing session ended or became invalid.")
                    break
                if observed_session is not None and session_cancel_fingerprint(observed_session) != expected_fingerprint:
                    cancel_event.set()
                    logging.info("Cancelling active paint pipeline because the iRacing session identity or context changed while processing.")
                    break
                stop_event.wait(max(0.25, float(poll_seconds)))
        finally:
            if owned_reader:
                close_sdk_reader(monitor_reader)

    monitor = threading.Thread(target=_monitor, name="NishizumiSessionCancelMonitor", daemon=True)
    monitor.start()
    return monitor
def has_replay_pack_for_session(
    session: Session,
    replay_packs_dir: Path,
    packs: dict[str, dict[str, object]] | None = None,
) -> bool:
    packs = packs if packs is not None else _load_replay_pack_index(replay_packs_dir)
    wanted_key = _session_fingerprint_key(session)
    for entry in packs.values():
        if str(entry.get('session_fingerprint_key') or '').strip() != wanted_key:
            continue
        pack_name = str(entry.get('pack_name') or '').strip()
        if not pack_name:
            continue
        replay_path = Path(str(entry.get('replay_file_path') or ''))
        if str(replay_path) and not replay_path.exists():
            continue
        pack_dir = replay_packs_dir / pack_name
        if (pack_dir / REPLAY_PACK_MANIFEST_FILENAME).exists():
            return True
    return False

def _read_replay_mode_active(reader: IracingSdkReader) -> bool:
    sdk = reader.sdk
    try:
        if not sdk.is_initialized and not sdk.startup():
            return False
    except Exception:
        return False
    if not sdk.is_connected:
        return False
    try:
        sdk.freeze_var_buffer_latest()
    except Exception:
        pass
    try:
        replay_playing = sdk["IsReplayPlaying"]
        if replay_playing is not None and bool(replay_playing):
            return True
    except Exception:
        pass
    for key in ("ReplayFrameNum", "ReplayFrameNumEnd", "ReplaySessionNum", "ReplaySessionTime"):
        try:
            value = sdk[key]
        except Exception:
            continue
        if value is None:
            continue
        try:
            numeric = float(value)
        except Exception:
            continue
        if numeric not in (0.0, -1.0):
            return True
    return False
def _read_ok_to_reload_textures(reader: IracingSdkReader) -> bool | None:
    sdk = reader.sdk
    try:
        if not sdk.is_initialized:
            if not sdk.startup():
                return None
    except Exception as exc:  # noqa: BLE001
        logging.debug("SDK startup() failed while checking OkToReloadTextures: %s", exc)
        return None
    if not sdk.is_connected:
        return None
    try:
        sdk.freeze_var_buffer_latest()
    except Exception as exc:  # noqa: BLE001
        logging.debug("freeze_var_buffer_latest() failed while checking OkToReloadTextures: %s", exc)
    try:
        value = sdk["OkToReloadTextures"]
    except Exception as exc:  # noqa: BLE001
        logging.debug("Could not read OkToReloadTextures from SDK: %s", exc)
        return None
    if value is None:
        return None
    return bool(value)
def trigger_texture_reload(reader: IracingSdkReader, car_idx: int | None = None) -> bool:
    sdk = reader.sdk
    try:
        if not sdk.is_initialized:
            if not sdk.startup():
                logging.warning("Could not initialize SDK to trigger texture reload")
                return False
    except Exception as exc:  # noqa: BLE001
        logging.warning("SDK startup() failed before texture reload: %s", exc)
        return False
    if not sdk.is_connected:
        logging.debug("SDK not connected; cannot trigger texture reload right now")
        return False
    if car_idx is not None and int(car_idx) >= 0:
        reload_single = getattr(sdk, "reload_texture", None)
        if callable(reload_single):
            try:
                reload_single(int(car_idx))
            except Exception as exc:  # noqa: BLE001
                logging.warning("Failed to trigger iRacing per-car texture reload for carIdx %s: %s", car_idx, exc)
            else:
                logging.info("Triggered iRacing texture reload via SDK for carIdx %s", car_idx)
                return True
        else:
            logging.debug("This irsdk package does not expose reload_texture(); falling back to reload_all_textures()")
    reload_method = getattr(sdk, "reload_all_textures", None)
    if not callable(reload_method):
        logging.warning("This irsdk package does not expose reload_all_textures(); cannot auto-refresh paints")
        return False
    try:
        reload_method()
    except Exception as exc:  # noqa: BLE001
        logging.warning("Failed to trigger iRacing texture reload: %s", exc)
        return False
    logging.info("Triggered iRacing texture reload via SDK")
    return True
def maybe_trigger_pending_texture_reload(
    reader: IracingSdkReader,
    pending_reload: PendingTextureReload | None,
    active_fingerprint: tuple[SessionId, tuple[tuple[int, str], ...]] | None,
    force_after_seconds: float = 15.0,
) -> bool:
    if pending_reload is None:
        return False
    if active_fingerprint != pending_reload.fingerprint:
        return False
    ok_to_reload = _read_ok_to_reload_textures(reader)
    elapsed = max(0.0, time.monotonic() - pending_reload.first_requested_at)
    if ok_to_reload is False:
        if elapsed < max(force_after_seconds, 0.0):
            if not pending_reload.wait_log_emitted:
                logging.info("Waiting for iRacing to allow texture reload before refreshing paints...")
                pending_reload.wait_log_emitted = True
            return False
        logging.warning(
            "OkToReloadTextures stayed false for %.1fs; attempting forced texture reload anyway",
            elapsed,
        )
    elif ok_to_reload is None and not pending_reload.wait_log_emitted:
        logging.debug("OkToReloadTextures unavailable; trying texture reload anyway")
        pending_reload.wait_log_emitted = True
    return trigger_texture_reload(reader)
