class BoundedLogQueue:
    def __init__(self, maxlen: int = LOG_QUEUE_LIMIT) -> None:
        self._items: deque[str] = deque(maxlen=max(1, int(maxlen)))
        self._lock = threading.Lock()
    def put_nowait(self, item: str) -> None:
        with self._lock:
            self._items.append(str(item))
    def get_nowait(self) -> str:
        with self._lock:
            if not self._items:
                raise queue.Empty
            return self._items.popleft()


class QueueLogHandler(logging.Handler):
    def __init__(self, target_queue: BoundedLogQueue) -> None:
        super().__init__()
        self.target_queue = target_queue
    def emit(self, record: logging.LogRecord) -> None:
        try:
            self.target_queue.put_nowait(self.format(record))
        except Exception:
            pass
def get_manifest_cap_from_download_cap(download_cap: int) -> int:
    capped = max(1, download_cap)
    if capped <= 4:
        return 3
    if capped <= 8:
        return 5
    if capped <= 12:
        return 7
    if capped <= 16:
        return 8
    return 10
def build_tp_ceiling_hint(download_stats: StageTransferStats) -> str:
    if download_stats.completed_items <= 0:
        return "Not enough data yet"
    requested = max(1, int(download_stats.requested_workers))
    if download_stats.total_items < min(requested, 12):
        return "Need a larger session to probe the limit"
    effective = max(0.0, float(download_stats.effective_parallelism))
    if effective <= 0.0:
        return "Not enough data yet"
    if requested <= max(4, int(round(effective + 1.0))):
        return "No clear TP ceiling seen yet at this worker count"
    low = max(1, int(round(effective * 0.90)))
    high = max(low, int(round(effective * 1.10)))
    if high - low <= 1:
        return f"Approx observed ceiling: ~{int(round(effective))} parallel downloads"
    return f"Approx observed ceiling: ~{low}-{high} parallel downloads"
class DownloaderService:
    def __init__(self, config: AppConfig, log_queue: BoundedLogQueue | None = None) -> None:
        self._config = replace(config)
        self._lock = threading.Lock()
        self._stop_event = threading.Event()
        self._thread: threading.Thread | None = None
        self._status = "Stopped"
        self._status_callback: Callable[[str], None] | None = None
        self._log_queue = log_queue
        self._force_refresh_event = threading.Event()
        self._clear_current_event = threading.Event()
        self._sync_ai_rosters_event = threading.Event()
        self._global_texture_reload_event = threading.Event()
        self._monitor_snapshot = ThroughputMonitorSnapshot()
        self._runtime_snapshot = RuntimeSnapshot()
        self._runtime_snapshot_version = 0
        self._pending_driver_override_applies: list[PendingDriverOverrideApply] = []
    def set_status_callback(self, callback: Callable[[str], None]) -> None:
        self._status_callback = callback
    def _set_status(self, value: str) -> None:
        if self._status == value:
            return
        self._status = value
        if self._status_callback is not None:
            try:
                self._status_callback(value)
            except Exception:
                pass
    def get_status(self) -> str:
        return self._status
    def get_monitor_snapshot(self) -> ThroughputMonitorSnapshot:
        with self._lock:
            return replace(self._monitor_snapshot)
    def get_runtime_snapshot_version(self) -> int:
        with self._lock:
            return int(self._runtime_snapshot_version)
    def get_runtime_snapshot(self) -> RuntimeSnapshot:
        with self._lock:
            current_session = self._runtime_snapshot.current_session
            last_saved = list(self._runtime_snapshot.last_saved)
            last_known_member_id = self._runtime_snapshot.last_known_member_id
            session_rows = list(getattr(self._runtime_snapshot, "session_rows", []))
            replay_mode_active = bool(getattr(self._runtime_snapshot, "replay_mode_active", False))
        return RuntimeSnapshot(
            current_session=current_session,
            last_saved=last_saved,
            last_known_member_id=last_known_member_id,
            session_rows=session_rows,
            replay_mode_active=replay_mode_active,
        )
    def _queue_driver_override_apply_locked(self, session: Session, entry: dict[str, object]) -> None:
        normalized = _normalize_driver_paint_override_entry(entry)
        if normalized is None:
            return
        request = PendingDriverOverrideApply(
            session_fingerprint=session_cancel_fingerprint(session),
            entry=normalized,
        )
        request_key = _driver_paint_override_key(
            int(normalized["user_id"]),
            str(normalized["kind"]),
            str(normalized.get("directory") or ""),
        )
        updated: list[PendingDriverOverrideApply] = []
        for existing in self._pending_driver_override_applies:
            existing_key = _driver_paint_override_key(
                int(existing.entry.get("user_id") or 0),
                str(existing.entry.get("kind") or ""),
                str(existing.entry.get("directory") or ""),
            )
            if existing.session_fingerprint == request.session_fingerprint and existing_key == request_key:
                continue
            updated.append(existing)
        updated.append(request)
        self._pending_driver_override_applies = updated
    def _drain_pending_driver_override_applies(
        self,
        session: Session | None,
        paints_dir: Path,
        sdk_reader: IracingSdkReader | None,
    ) -> bool:
        if session is None:
            return False
        session_fingerprint = session_cancel_fingerprint(session)
        with self._lock:
            pending = [
                request
                for request in self._pending_driver_override_applies
                if request.session_fingerprint == session_fingerprint
            ]
            self._pending_driver_override_applies = [
                request
                for request in self._pending_driver_override_applies
                if request.session_fingerprint != session_fingerprint
            ]
        if not pending:
            return False
        reapplied_saved: list[SavedFile] = []
        reapplied_requests: list[PendingDriverOverrideApply] = []
        applied_any = False
        for request in pending:
            matched_user = _find_session_user_for_driver_override_entry(session, request.entry)
            if matched_user is None:
                logging.debug(
                    "Queued driver override reapply skipped because the session user was not found: user=%s kind=%s",
                    request.entry.get("user_id"),
                    request.entry.get("kind"),
                )
                continue
            try:
                saved_items = _apply_cached_driver_paint_override_for_user(
                    session=session,
                    user=matched_user,
                    paints_dir=paints_dir,
                    entry=request.entry,
                )
            except Exception as exc:
                logging.warning(
                    "Could not reapply queued driver override for user %s %s: %s",
                    request.entry.get("user_id"),
                    request.entry.get("kind"),
                    exc,
                )
                continue
            if not saved_items:
                logging.debug(
                    "Queued driver override reapply found no cached files for user %s %s",
                    request.entry.get("user_id"),
                    request.entry.get("kind"),
                )
                continue
            if self.register_manual_saved_paints(session, saved_items, "override", queue_reapply=False):
                applied_any = True
                reapplied_requests.append(request)
                reapplied_saved.extend(saved_items)
        if not reapplied_saved:
            return applied_any
        reload_triggered = bool(sdk_reader is not None and _try_incremental_texture_reload(sdk_reader, session, reapplied_saved))
        if not reload_triggered:
            with self._lock:
                for request in reapplied_requests:
                    self._queue_driver_override_apply_locked(session, request.entry)
        return applied_any
    def _update_runtime_snapshot(
        self,
        current_session: Session | None,
        last_saved: list[SavedFile],
        last_known_member_id: int | None,
        session_rows: list[SessionDriverSnapshot] | None = None,
        replay_mode_active: bool = False,
    ) -> None:
        if session_rows is None:
            session_rows = build_session_driver_rows(current_session)
        with self._lock:
            self._runtime_snapshot = RuntimeSnapshot(
                current_session=current_session,
                last_saved=list(last_saved),
                last_known_member_id=last_known_member_id,
                session_rows=list(session_rows),
                replay_mode_active=bool(replay_mode_active),
            )
            self._runtime_snapshot_version += 1
    def _update_runtime_progress_snapshot(
        self,
        current_session: Session,
        base_saved: list[SavedFile],
        last_known_member_id: int | None,
        base_rows: list[SessionDriverSnapshot],
        progress_rows: list[SessionDriverSnapshot],
        incremental_saved: list[SavedFile] | None = None,
        replay_mode_active: bool = False,
    ) -> None:
        incoming_saved = list(incremental_saved or [])
        with self._lock:
            runtime_session = self._runtime_snapshot.current_session
            same_session = runtime_session is not None and session_cancel_fingerprint(runtime_session) == session_cancel_fingerprint(current_session)
            saved_base = list(self._runtime_snapshot.last_saved) if same_session else list(base_saved or [])
            merged_saved = merge_saved_files(saved_base, incoming_saved)
            runtime_rows = list(self._runtime_snapshot.session_rows) if same_session else []
        row_base = runtime_rows or list(base_rows or [])
        session_rows = merge_session_driver_rows(current_session, row_base, list(progress_rows or []))
        preserved_items = [
            item
            for item in merged_saved
            if bool(getattr(item.download_id, "preserve_on_cleanup", False))
        ]
        if preserved_items:
            statuses = _session_statuses_from_rows(session_rows)
            _apply_saved_file_statuses(current_session, statuses, preserved_items, "override")
            session_rows = build_session_driver_rows(current_session, statuses)
        self._update_runtime_snapshot(
            current_session,
            merged_saved,
            last_known_member_id,
            session_rows=session_rows,
            replay_mode_active=replay_mode_active,
        )
    def reset_monitor_snapshot(self) -> None:
        with self._lock:
            self._monitor_snapshot = ThroughputMonitorSnapshot()
    def _update_monitor_snapshot(self, snapshot: ThroughputMonitorSnapshot) -> None:
        with self._lock:
            best_effective = max(self._monitor_snapshot.best_effective_parallelism, snapshot.effective_parallelism)
            best_fps = max(self._monitor_snapshot.best_download_files_per_second, snapshot.download_files_per_second)
            snapshot.best_effective_parallelism = best_effective
            snapshot.best_download_files_per_second = best_fps
            snapshot.updated_at = time.time()
            self._monitor_snapshot = replace(snapshot)
    def is_running(self) -> bool:
        return self._thread is not None and self._thread.is_alive()
    def update_config(self, config: AppConfig) -> None:
        normalized = enforce_hidden_tp_speed_modes(replace(config))
        with self._lock:
            self._config = normalized
        root = logging.getLogger()
        root.setLevel(logging.DEBUG if normalized.verbose else logging.INFO)
        logging.debug(
            "Config updated: download_mode=%s, manual_manifest_workers=%s, manual_download_workers=%s, manual_save_workers=%s, auto_refresh=%s, cleanup_before_fetch=%s, cleanup_on_exit=%s",
            self._config.download_workers_mode,
            self._config.manual_manifest_workers,
            self._config.manual_download_workers,
            self._config.manual_save_workers,
            self._config.auto_refresh_paints,
            self._config.cleanup_before_fetch,
            self._config.delete_downloaded_livery,
        )
    def get_config(self) -> AppConfig:
        with self._lock:
            return replace(self._config)
    def register_manual_saved_paints(
        self,
        session: Session,
        saved_items: list[SavedFile],
        status_code: str = "override",
        *,
        override_entry: dict[str, object] | None = None,
        queue_reapply: bool = True,
    ) -> bool:
        if not saved_items:
            return False
        with self._lock:
            current_session = self._runtime_snapshot.current_session
            if current_session is None or session_cancel_fingerprint(current_session) != session_cancel_fingerprint(session):
                return False
            last_saved = merge_saved_files(list(self._runtime_snapshot.last_saved), list(saved_items))
            statuses = _session_statuses_from_rows(list(self._runtime_snapshot.session_rows))
            _apply_saved_file_statuses(current_session, statuses, list(saved_items), status_code)
            session_rows = build_session_driver_rows(current_session, statuses)
            self._runtime_snapshot = RuntimeSnapshot(
                current_session=current_session,
                last_saved=last_saved,
                last_known_member_id=self._runtime_snapshot.last_known_member_id,
                session_rows=session_rows,
                replay_mode_active=bool(self._runtime_snapshot.replay_mode_active),
            )
            self._runtime_snapshot_version += 1
            if queue_reapply and override_entry is not None:
                self._queue_driver_override_apply_locked(current_session, override_entry)
            return True
    def drop_manual_saved_paint_preserve(self, session: Session, user_id: int, kind: str, directory: str = "") -> bool:
        with self._lock:
            current_session = self._runtime_snapshot.current_session
            if current_session is None or session_cancel_fingerprint(current_session) != session_cancel_fingerprint(session):
                return False
            changed = False
            updated_saved: list[SavedFile] = []
            unpreserved_items: list[SavedFile] = []
            for item in self._runtime_snapshot.last_saved:
                if (
                    bool(getattr(item.download_id, "preserve_on_cleanup", False))
                    and _saved_file_matches_driver_override(current_session, item, user_id, kind, directory)
                ):
                    updated_item = SavedFile(
                        session_id=item.session_id,
                        download_id=replace(item.download_id, preserve_on_cleanup=False),
                        file_path=item.file_path,
                    )
                    updated_saved.append(updated_item)
                    unpreserved_items.append(updated_item)
                    changed = True
                else:
                    updated_saved.append(item)
            if not changed:
                return False
            statuses = _session_statuses_from_rows(list(self._runtime_snapshot.session_rows))
            _apply_saved_file_statuses(current_session, statuses, unpreserved_items, "downloaded")
            session_rows = build_session_driver_rows(current_session, statuses)
            self._runtime_snapshot = RuntimeSnapshot(
                current_session=current_session,
                last_saved=updated_saved,
                last_known_member_id=self._runtime_snapshot.last_known_member_id,
                session_rows=session_rows,
                replay_mode_active=bool(self._runtime_snapshot.replay_mode_active),
            )
            self._runtime_snapshot_version += 1
            return True
    def merge_runtime_manual_overrides(
        self,
        session: Session,
        processed_saved: list[SavedFile],
        processed_rows: list[SessionDriverSnapshot],
    ) -> tuple[list[SavedFile], list[SessionDriverSnapshot]]:
        with self._lock:
            current_session = self._runtime_snapshot.current_session
            if current_session is None or session_cancel_fingerprint(current_session) != session_cancel_fingerprint(session):
                return processed_saved, processed_rows
            manual_items = [
                item
                for item in self._runtime_snapshot.last_saved
                if bool(getattr(item.download_id, "preserve_on_cleanup", False))
            ]
        if not manual_items:
            return processed_saved, processed_rows
        merged_saved = merge_saved_files(list(processed_saved), manual_items)
        statuses = _session_statuses_from_rows(list(processed_rows))
        _apply_saved_file_statuses(session, statuses, manual_items, "override")
        return merged_saved, build_session_driver_rows(session, statuses)
    def request_refresh_now(self) -> None:
        self._force_refresh_event.set()
    def request_clear_current_downloads(self) -> None:
        self._clear_current_event.set()
    def request_sync_ai_rosters_now(self) -> None:
        self._sync_ai_rosters_event.set()
    def request_global_texture_reload(self) -> None:
        self._global_texture_reload_event.set()
    def start(self) -> None:
        if self.is_running():
            return
        self._stop_event.clear()
        self._thread = threading.Thread(target=self._run_forever, name="NishizumiPaintsService", daemon=True)
        self._thread.start()
    def stop(self, join_timeout: float = 5.0) -> None:
        self._stop_event.set()
        thread = self._thread
        if thread is not None and thread.is_alive():
            thread.join(timeout=join_timeout)
        self._thread = None
        self._set_status("Stopped")
    def _install_logging(self) -> None:
        config = self.get_config()
        setup_logging(config.verbose)
        if self._log_queue is not None:
            handler = QueueLogHandler(self._log_queue)
            handler.setFormatter(logging.Formatter("%(asctime)s %(levelname)s %(message)s", "%Y-%m-%d %H:%M:%S"))
            root = logging.getLogger()
            if not any(isinstance(existing, QueueLogHandler) for existing in root.handlers):
                handler.setLevel(logging.NOTSET)
                root.addHandler(handler)
        for existing in logging.getLogger().handlers:
            existing.setLevel(logging.NOTSET)
        logging.debug("Verbose logging active")
    def _cleanup_saved(
        self,
        saved: list[SavedFile],
        keep_my_livery_locally: bool,
        preserve_targets: set[tuple[bool, int]] | None,
        reason: str,
        paints_root: Path | None = None,
        fallback_member_id: int | None = None,
        fallback_team_id: int | None = None,
    ) -> list[SavedFile]:
        keep_targets = _merge_preserve_targets(
            preserve_targets,
            fallback_member_id=fallback_member_id,
            fallback_team_id=fallback_team_id,
        ) if keep_my_livery_locally else set()
        if keep_my_livery_locally and not keep_targets:
            logging.warning("Keep my livery locally is enabled, but no local iRacing member/team target could be resolved for this cleanup pass.")
        if not saved:
            return []
        logging.info(reason)
        kept = delete_saved(saved, keep_targets=keep_targets, paints_root=paints_root)
        if keep_targets and kept:
            labels = []
            for is_team, target_id in sorted(keep_targets):
                labels.append(f"team {target_id}" if is_team else f"user {target_id}")
            logging.info("Kept %s local livery file(s) for your local targets (%s)", len(kept), ", ".join(labels))
        return kept
    def _run_forever(self) -> None:
        crash_count = 0
        while not self._stop_event.is_set():
            try:
                self._run_loop()
                crash_count = 0
                break
            except Exception as exc:  # noqa: BLE001
                crash_count += 1
                logging.error("Service loop crashed (%s): %s", crash_count, exc)
                logging.debug("Service crash traceback\n%s", traceback.format_exc())
                self._set_status("Recovering")
                self._stop_event.wait(min(5.0, 1.0 + crash_count))
    def _run_loop(self) -> None:
        self._install_logging()
        self._set_status("Starting")
        startup_config = self.get_config()
        paints_dir = default_paints_dir(startup_config)
        temp_dir = default_temp_dir()
        replay_dir = default_replay_dir(startup_config)
        replay_packs_dir = default_replay_packs_dir()
        paints_dir.mkdir(parents=True, exist_ok=True)
        temp_dir.mkdir(parents=True, exist_ok=True)
        replay_dir.mkdir(parents=True, exist_ok=True)
        replay_packs_dir.mkdir(parents=True, exist_ok=True)
        logging.info("Using iRacing documents folder: %s", resolve_iracing_documents_dir(startup_config))
        cleanup_stale_temp_dirs(temp_dir)
        sdk_reader: IracingSdkReader | None = None
        next_sdk_open_at = 0.0
        last_session: SessionId | None = None
        current_session: Session | None = None
        last_processed_session: Session | None = None
        last_session_fingerprint: tuple[SessionId, tuple[tuple[int, str], ...]] | None = None
        last_session_preserve_targets: set[tuple[bool, int]] = set()
        last_saved: list[SavedFile] = []
        session_rows: list[SessionDriverSnapshot] = []
        last_known_member_id: int | None = None
        last_known_team_id: int | None = None
        last_ai_roster_sync_member_id: int | None = None
        last_poll_state: SdkPollState | None = None
        replay_mode_active = False
        known_replay_files = _snapshot_replay_files(replay_dir)
        for line in reconcile_replay_pack_index(replay_dir, replay_packs_dir):
            logging.info(line)
        replay_pack_index = _load_replay_pack_index(replay_packs_dir)
        next_replay_pack_scan_at = 0.0
        next_replay_pack_full_scan_at = time.monotonic() + REPLAY_PACK_FULL_SCAN_SECONDS
        last_replay_dir_token = _replay_dir_change_token(replay_dir)
        inactive_cleanup_done = False
        reopen_sdk_after_inactive = False
        local_ai_roster_prefill_done = False
        def _maybe_sync_replay_packs(
            config: AppConfig,
            *,
            current_session_arg: Session | None,
            saved_arg: list[SavedFile],
            force: bool = False,
        ) -> None:
            nonlocal known_replay_files, replay_pack_index, next_replay_pack_scan_at, next_replay_pack_full_scan_at, last_replay_dir_token
            if not getattr(config, "auto_manage_replay_packs", True):
                return
            now = time.monotonic()
            if not force and now < next_replay_pack_scan_at:
                return
            replay_dir_token = _replay_dir_change_token(replay_dir)
            should_scan = force or replay_dir_token != last_replay_dir_token or now >= next_replay_pack_full_scan_at
            active_capture_context = current_session_arg is not None and bool(saved_arg)
            next_replay_pack_scan_at = now + (REPLAY_PACK_ACTIVE_SCAN_SECONDS if active_capture_context else REPLAY_PACK_IDLE_SCAN_SECONDS)
            if not should_scan:
                return
            known_replay_files, replay_pack_index = sync_replay_packs_for_folder(
                replay_dir=replay_dir,
                replay_packs_dir=replay_packs_dir,
                known_files=known_replay_files,
                current_session=current_session_arg,
                saved=saved_arg,
                paints_root=paints_dir,
                known_packs=replay_pack_index,
            )
            last_replay_dir_token = _replay_dir_change_token(replay_dir)
            next_replay_pack_full_scan_at = now + REPLAY_PACK_FULL_SCAN_SECONDS
        def _maybe_prefill_local_ai_rosters(config: AppConfig, *, force: bool = False) -> None:
            nonlocal local_ai_roster_prefill_done
            if local_ai_roster_prefill_done and not force:
                return
            local_ai_roster_prefill_done = True
            include_cars = bool(getattr(config, "random_fallback_ai", True))
            include_helmets = bool(getattr(config, "random_helmets_ai", getattr(config, "random_helmets", True)))
            include_suits = bool(getattr(config, "random_suits_ai", getattr(config, "random_suits", True)))
            if not (include_cars or include_helmets or include_suits):
                logging.debug("Local AI roster prefill skipped because AI random paints are disabled.")
                return
            try:
                self._set_status("Prefilling local AI rosters")
                prefill_local_ai_rosters_from_showroom(
                    ai_rosters_dir=default_ai_rosters_dir(config),
                    temp_dir=temp_dir,
                    retries=positive_int(config.retries, 3),
                    retry_backoff_seconds=max(config.retry_backoff_seconds, 0.1),
                    include_cars=include_cars,
                    include_helmets=include_helmets,
                    include_suits=include_suits,
                    mapping_path=default_tp_showroom_mapping_path(),
                    detect_showroom_total_pages=False,
                    cancel_event=self._stop_event,
                )
            except Exception as exc:  # noqa: BLE001
                logging.warning("Local AI roster prefill failed: %s", exc)
                logging.debug("Local AI roster prefill traceback\n%s", traceback.format_exc())
            finally:
                self._set_status("Watching")
        self._update_runtime_snapshot(current_session, last_saved, last_known_member_id, session_rows=session_rows, replay_mode_active=replay_mode_active)
        try:
            while not self._stop_event.is_set():
                config = self.get_config()
                current_paints_dir = default_paints_dir(config)
                current_replay_dir = default_replay_dir(config)
                if current_paints_dir != paints_dir:
                    paints_dir = current_paints_dir
                    paints_dir.mkdir(parents=True, exist_ok=True)
                    logging.info("Using custom iRacing paint folder: %s", paints_dir)
                if current_replay_dir != replay_dir:
                    replay_dir = current_replay_dir
                    replay_dir.mkdir(parents=True, exist_ok=True)
                    known_replay_files = _snapshot_replay_files(replay_dir)
                    for line in reconcile_replay_pack_index(replay_dir, replay_packs_dir):
                        logging.info(line)
                    replay_pack_index = _load_replay_pack_index(replay_packs_dir)
                    next_replay_pack_scan_at = 0.0
                    next_replay_pack_full_scan_at = 0.0
                    last_replay_dir_token = _replay_dir_change_token(replay_dir)
                    logging.info("Using custom iRacing replay folder: %s", replay_dir)
                _maybe_prefill_local_ai_rosters(config)
                _maybe_sync_replay_packs(config, current_session_arg=current_session, saved_arg=last_saved)
                if self._force_refresh_event.is_set() and sdk_reader is not None:
                    sdk_reader.last_update = None
                if self._clear_current_event.is_set():
                    self._clear_current_event.clear()
                    if last_saved:
                        last_saved = self._cleanup_saved(
                            saved=last_saved,
                            keep_my_livery_locally=config.keep_my_livery_locally,
                            preserve_targets=last_session_preserve_targets,
                            reason="Manual clear requested. Removing current downloaded paints",
                            paints_root=paints_dir,
                            fallback_member_id=last_known_member_id,
                            fallback_team_id=last_known_team_id,
                        )
                        self._update_runtime_snapshot(current_session, last_saved, last_known_member_id, session_rows=session_rows, replay_mode_active=replay_mode_active)
                    else:
                        logging.info("Manual clear requested, but there are no current downloaded paints to remove")
                if self._sync_ai_rosters_event.is_set():
                    self._sync_ai_rosters_event.clear()
                    member_id_for_sync = resolve_ai_roster_member_id(
                        getattr(config, "ai_roster_member_id_override", 0),
                        last_known_member_id,
                    )
                    if member_id_for_sync is None or member_id_for_sync <= 0:
                        logging.info("Manual AI roster sync requested, but no iRacing member ID is known yet. Fill the AI roster member ID in the AI tab or join any iRacing session first.")
                    else:
                        self._set_status("Syncing AI rosters")
                        sync_ai_rosters(
                            member_id=member_id_for_sync,
                            ai_rosters_dir=default_ai_rosters_dir(config),
                            retries=positive_int(config.retries, 3),
                            retry_backoff_seconds=max(config.retry_backoff_seconds, 0.1),
                            do_cleanup=True,
                        )
                        last_ai_roster_sync_member_id = member_id_for_sync
                        self._set_status("Watching")
                    _maybe_prefill_local_ai_rosters(config, force=True)
                ai_roster_override_member_id = normalize_tp_member_id(getattr(config, "ai_roster_member_id_override", 0))
                if (
                    config.sync_ai_rosters_from_server
                    and ai_roster_override_member_id > 0
                    and last_ai_roster_sync_member_id != ai_roster_override_member_id
                ):
                    self._set_status("Syncing AI rosters")
                    logging.info("AI roster sync using configured AI tab member ID %s", ai_roster_override_member_id)
                    sync_ai_rosters(
                        member_id=ai_roster_override_member_id,
                        ai_rosters_dir=default_ai_rosters_dir(config),
                        retries=positive_int(config.retries, 3),
                        retry_backoff_seconds=max(config.retry_backoff_seconds, 0.1),
                        do_cleanup=True,
                    )
                    last_ai_roster_sync_member_id = ai_roster_override_member_id
                    self._set_status("Watching")
                    _maybe_prefill_local_ai_rosters(config, force=True)
                if self._global_texture_reload_event.is_set():
                    self._global_texture_reload_event.clear()
                    if sdk_reader is None:
                        logging.info("Manual global texture reload requested, but the iRacing SDK is not connected yet.")
                    elif trigger_texture_reload(sdk_reader):
                        logging.info("Manual global texture reload requested from General tab.")
                    else:
                        logging.info("Manual global texture reload requested, but the texture refresh could not be triggered right now.")
                self._set_status("Watching")
                if sdk_reader is None:
                    now = time.monotonic()
                    if now < next_sdk_open_at:
                        self._stop_event.wait(min(max(config.poll_seconds, 0.2), max(0.0, next_sdk_open_at - now)))
                        continue
                    sdk_reader = create_sdk_reader()
                    if sdk_reader is None:
                        self._set_status("SDK unavailable")
                        self._stop_event.wait(max(config.poll_seconds, 0.5))
                        continue
                poll_state, session = read_session_from_sdk(sdk_reader)
                if poll_state != last_poll_state:
                    logging.debug("Poll state changed: %s -> %s", last_poll_state, poll_state)
                    last_poll_state = poll_state
                if poll_state in {SdkPollState.INACTIVE, SdkPollState.INVALID}:
                    if not inactive_cleanup_done:
                        inactive_cleanup_done = True
                        reopen_sdk_after_inactive = True
                        _maybe_sync_replay_packs(config, current_session_arg=current_session, saved_arg=last_saved)
                        if last_saved and config.delete_downloaded_livery:
                            inactive_reason = (
                                f"No active valid session detected. Clearing paints from previous session {last_session}"
                                if last_session is not None
                                else "No active valid session detected. Clearing carried-over paints from the previous run"
                            )
                            last_saved = self._cleanup_saved(
                                saved=last_saved,
                                keep_my_livery_locally=config.keep_my_livery_locally,
                                preserve_targets=last_session_preserve_targets,
                                reason=inactive_reason,
                                paints_root=paints_dir,
                                fallback_member_id=last_known_member_id,
                                fallback_team_id=last_known_team_id,
                            )
                        with self._lock:
                            self._pending_driver_override_applies = []
                        last_session = None
                        current_session = None
                        last_processed_session = None
                        session_rows = []
                        replay_mode_active = False
                        last_session_fingerprint = None
                        last_session_preserve_targets = set()
                        self._update_runtime_snapshot(None, last_saved, last_known_member_id, session_rows=[])
                    self._stop_event.wait(max(config.poll_seconds, 0.2))
                    continue
                if poll_state is SdkPollState.UNCHANGED:
                    if current_session is not None and self._drain_pending_driver_override_applies(current_session, paints_dir, sdk_reader):
                        runtime_snapshot = self.get_runtime_snapshot()
                        last_saved = list(runtime_snapshot.last_saved)
                        session_rows = list(runtime_snapshot.session_rows)
                    self._stop_event.wait(max(config.poll_seconds, 0.2))
                    continue
                assert session is not None
                if reopen_sdk_after_inactive and sdk_reader is not None:
                    logging.debug("Reopening iRacing SDK after inactivity before trusting the next active session snapshot")
                    close_sdk_reader(sdk_reader)
                    sdk_reader = None
                    next_sdk_open_at = time.monotonic() + max(config.poll_seconds, 0.2)
                    reopen_sdk_after_inactive = False
                    self._stop_event.wait(max(config.poll_seconds, 0.2))
                    continue
                inactive_cleanup_done = False
                reopen_sdk_after_inactive = False
                current_session = session
                if self._drain_pending_driver_override_applies(session, paints_dir, sdk_reader):
                    runtime_snapshot = self.get_runtime_snapshot()
                    last_saved = list(runtime_snapshot.last_saved)
                    session_rows = list(runtime_snapshot.session_rows)
                base_session_rows = build_session_driver_rows(session)
                if session.local_user_id is not None and session.local_user_id > 0:
                    last_known_member_id = session.local_user_id
                if session.local_team_id is not None and session.local_team_id > 0:
                    last_known_team_id = session.local_team_id
                if session.ai_driver_count > 0:
                    logging.info(
                        "AI session context detected: ai_drivers=%s%s",
                        session.ai_driver_count,
                        f" | roster={session.ai_roster_id} {session.ai_roster_name}" if (session.ai_roster_id or session.ai_roster_name) else "",
                    )
                member_id_for_auto_ai_sync = resolve_ai_roster_member_id(
                    getattr(config, "ai_roster_member_id_override", 0),
                    session.local_user_id,
                )
                if (
                    config.sync_ai_rosters_from_server
                    and member_id_for_auto_ai_sync is not None
                    and member_id_for_auto_ai_sync > 0
                    and last_ai_roster_sync_member_id != member_id_for_auto_ai_sync
                ):
                    self._set_status("Syncing AI rosters")
                    sync_ai_rosters(
                        member_id=member_id_for_auto_ai_sync,
                        ai_rosters_dir=default_ai_rosters_dir(config),
                        retries=positive_int(config.retries, 3),
                        retry_backoff_seconds=max(config.retry_backoff_seconds, 0.1),
                        do_cleanup=True,
                    )
                    last_ai_roster_sync_member_id = member_id_for_auto_ai_sync
                    self._set_status("Watching")
                    _maybe_prefill_local_ai_rosters(config, force=True)
                current_fingerprint = session.fingerprint()
                replay_mode_active = bool(
                    getattr(config, "auto_manage_replay_packs", True)
                    and sdk_reader is not None
                    and _read_replay_mode_active(sdk_reader)
                    and has_replay_pack_for_session(session, replay_packs_dir, replay_pack_index)
                )
                forced_refresh = self._force_refresh_event.is_set()
                if last_session_fingerprint == current_fingerprint and not forced_refresh:
                    existing_rows = session_rows
                    session_rows = merge_session_driver_rows(session, list(existing_rows), []) if existing_rows else base_session_rows
                    self._update_runtime_snapshot(
                        current_session,
                        last_saved,
                        last_known_member_id,
                        session_rows=session_rows,
                        replay_mode_active=replay_mode_active,
                    )
                    self._stop_event.wait(max(config.poll_seconds, 0.2))
                    continue
                previous_session = last_processed_session
                previous_rows = list(session_rows)
                previous_user_map = _session_user_map(previous_session)
                current_user_map = _session_user_map(session)
                same_session_identity = last_session == session.session_id
                roster_changed_same_session = bool(
                    not forced_refresh
                    and same_session_identity
                    and previous_session is not None
                    and set(previous_user_map) != set(current_user_map)
                )
                added_user_keys = sorted(set(current_user_map) - set(previous_user_map)) if roster_changed_same_session else []
                removed_user_keys = sorted(set(previous_user_map) - set(current_user_map)) if roster_changed_same_session else []
                session_to_process = session
                if roster_changed_same_session:
                    logging.info(
                        "Session roster changed inside the same session %s: +%s target(s), -%s target(s). The paint sync will only fetch the new targets now.",
                        session.session_id.folder_name(),
                        len(added_user_keys),
                        len(removed_user_keys),
                    )
                    session_rows = merge_session_driver_rows(session, previous_rows, [])
                    self._update_runtime_snapshot(
                        current_session,
                        last_saved,
                        last_known_member_id,
                        session_rows=session_rows,
                        replay_mode_active=replay_mode_active,
                    )
                    if not added_user_keys:
                        last_session = session.session_id
                        last_processed_session = session
                        last_session_fingerprint = current_fingerprint
                        last_session_preserve_targets = _merge_preserve_targets(
                            session.local_preserve_targets(),
                            fallback_member_id=last_known_member_id,
                            fallback_team_id=last_known_team_id,
                        )
                        self._set_status(f"Watching • {session.session_id.folder_name()}")
                        self._stop_event.wait(max(config.poll_seconds, 0.2))
                        continue
                    session_to_process = replace(session, users={current_user_map[key] for key in added_user_keys})
                else:
                    self._update_runtime_snapshot(current_session, last_saved, last_known_member_id, session_rows=base_session_rows, replay_mode_active=replay_mode_active)
                    session_rows = base_session_rows
                if forced_refresh:
                    self._force_refresh_event.clear()
                    logging.info("Manual re-download requested for session %s", session.session_id.folder_name())
                if last_saved and config.cleanup_before_fetch and not roster_changed_same_session:
                    reason = (
                        f"Refreshing current session files before new fetch for {session.session_id.folder_name()}"
                        if current_fingerprint == last_session_fingerprint or same_session_identity
                        else (
                            f"Deleting paints from previous session {last_session}"
                            if last_session is not None
                            else f"Deleting carried-over paints before processing {session.session_id.folder_name()}"
                        )
                    )
                    last_saved = self._cleanup_saved(
                        saved=last_saved,
                        keep_my_livery_locally=config.keep_my_livery_locally,
                        preserve_targets=last_session_preserve_targets,
                        reason=reason,
                        paints_root=paints_dir,
                        fallback_member_id=last_known_member_id,
                        fallback_team_id=last_known_team_id,
                    )
                self._set_status(f"Processing {session.session_id.folder_name()}")
                logging.info("Processing session %s", session.session_id.folder_name())
                restored_saved: list[SavedFile] = []
                restored_pack_name: str | None = None
                if replay_mode_active and getattr(config, "auto_manage_replay_packs", True):
                    restored_saved, restored_pack_name = restore_replay_pack_for_session(
                        session=session,
                        paints_root=paints_dir,
                        replay_packs_dir=replay_packs_dir,
                        packs=replay_pack_index,
                    )
                if restored_saved:
                    last_saved = restored_saved
                    session_rows = build_session_driver_rows(
                        session,
                        build_session_final_statuses(
                            session,
                            wanted_items=[],
                            server_saved=restored_saved,
                            fallback_saved=[],
                            sync_my_livery_from_server=config.sync_my_livery_from_server,
                            replay_mode=True,
                        ),
                    )
                    logging.info(
                        "Replay pack '%s' restored for replay session %s with %s file(s)",
                        restored_pack_name or "unknown",
                        session.session_id.folder_name(),
                        len(restored_saved),
                    )
                    monitor_snapshot = ThroughputMonitorSnapshot(
                        session_name=f"{session.session_id.folder_name()} [replay]",
                        worker_mode="replay-pack",
                        saved_items=len(restored_saved),
                    )
                    self._update_runtime_snapshot(current_session, last_saved, last_known_member_id, session_rows=session_rows, replay_mode_active=True)
                else:
                    session_cancel_event = threading.Event()
                    session_cancel_monitor = start_session_cancel_monitor(
                        expected_fingerprint=session_cancel_fingerprint(session),
                        cancel_event=session_cancel_event,
                        stop_event=self._stop_event,
                        reader=sdk_reader,
                        expected_session_info_update=sdk_reader.last_update if sdk_reader is not None else None,
                        poll_seconds=SESSION_CANCEL_POLL_SECONDS,
                    )
                    processing_cancelled = False
                    try:
                        processed_saved, monitor_snapshot, processed_rows = process_session(
                            session=session_to_process,
                            paints_dir=paints_dir,
                            temp_dir=temp_dir,
                            ai_rosters_dir=default_ai_rosters_dir(config),
                            max_concurrent_manifests=get_manifest_cap_from_download_cap(config.max_concurrent_downloads),
                            max_concurrent_downloads=config.max_concurrent_downloads,
                            download_workers_mode=config.download_workers_mode,
                            manual_download_workers=config.manual_download_workers,
                            manual_manifest_workers=config.manual_manifest_workers,
                            manual_save_workers=config.manual_save_workers,
                            retries=positive_int(config.retries, 3),
                            retry_backoff_seconds=max(config.retry_backoff_seconds, 0.1),
                            sync_my_livery_from_server=config.sync_my_livery_from_server,
                            random_fallback_real_drivers=config.random_fallback_real_drivers,
                            random_fallback_ai=config.random_fallback_ai,
                            random_helmets=bool(getattr(config, "random_helmets", True)),
                            random_suits=bool(getattr(config, "random_suits", True)),
                            random_helmets_real_drivers=bool(getattr(config, "random_helmets_real_drivers", getattr(config, "random_helmets", True))),
                            random_helmets_ai=bool(getattr(config, "random_helmets_ai", getattr(config, "random_helmets", True))),
                            random_suits_real_drivers=bool(getattr(config, "random_suits_real_drivers", getattr(config, "random_suits", True))),
                            random_suits_ai=bool(getattr(config, "random_suits_ai", getattr(config, "random_suits", True))),
                            disable_random_in_team_events=bool(getattr(config, "disable_random_in_team_events", True)),
                            disable_random_for_local_user=bool(getattr(config, "disable_random_for_local_user", False)),
                            ai_collection_skip_random_cars=bool(getattr(config, "ai_collection_skip_random_cars", True)),
                            ai_collection_skip_random_helmets=bool(getattr(config, "ai_collection_skip_random_helmets", True)),
                            ai_collection_skip_random_suits=bool(getattr(config, "ai_collection_skip_random_suits", True)),
                            keep_tp_paints_in_random_pool=getattr(config, "keep_tp_paints_in_random_pool", False),
                            max_random_pool_gb=getattr(config, "max_random_pool_gb", 5.0),
                            max_random_pool_car_gb=getattr(config, "max_random_pool_car_gb", 3.0),
                            max_random_pool_helmet_gb=getattr(config, "max_random_pool_helmet_gb", 1.0),
                            max_random_pool_suit_gb=getattr(config, "max_random_pool_suit_gb", 1.0),
                            tp_fallback_mode=getattr(config, "tp_fallback_mode", "local"),
                            tp_manifest_member_id_override=getattr(config, "tp_manifest_member_id_override", 0),
                            tp_primary_fast_mode=bool(getattr(config, "tp_primary_fast_mode", True)),
                            tp_mule_profile_fast_mode=bool(getattr(config, "tp_mule_profile_fast_mode", False)),
                            tp_detect_showroom_total_pages=False,
                            tp_fallback_lanes_mode=getattr(config, "tp_fallback_lanes_mode", "session_total"),
                            tp_manual_max_lanes=int(getattr(config, "tp_manual_max_lanes", 1) or 1),
                            tp_process_all_online_fallbacks_together=bool(getattr(config, "tp_process_all_online_fallbacks_together", True)),
                            tp_retry_timed_out_fallbacks_indefinitely=bool(getattr(config, "tp_retry_timed_out_fallbacks_indefinitely", True)),
                            tp_collection_pool_sources=getattr(config, "tp_collection_pool_sources", ""),
                            tp_collection_pool_allow_showroom_fallback=bool(getattr(config, "tp_collection_pool_allow_showroom_fallback", True)),
                            tp_collection_pool_repeat_when_strict=bool(getattr(config, "tp_collection_pool_repeat_when_strict", False)),
                            tp_showroom_sources=normalize_tp_showroom_sources(getattr(config, "tp_showroom_sources", TP_SHOWROOM_DEFAULT_SOURCES)),
                            progress_callback=lambda rows, saved_items=None, _session=session, _existing=previous_rows, _replay=replay_mode_active: self._update_runtime_progress_snapshot(
                                _session,
                                last_saved,
                                last_known_member_id,
                                _existing,
                                rows,
                                incremental_saved=list(saved_items or []),
                                replay_mode_active=_replay,
                            ),
                            reload_reader=sdk_reader,
                            auto_refresh_paints=bool(config.auto_refresh_paints),
                            cancel_event=session_cancel_event,
                            prior_saved=last_saved,
                        )
                        processing_cancelled = session_cancel_event.is_set()
                    finally:
                        session_cancel_event.set()
                        session_cancel_monitor.join(timeout=1.0)
                    if not processing_cancelled:
                        processed_saved, processed_rows = self.merge_runtime_manual_overrides(
                            session,
                            processed_saved,
                            processed_rows,
                        )
                    if processing_cancelled:
                        if processed_saved and config.delete_downloaded_livery:
                            processed_saved = self._cleanup_saved(
                                saved=processed_saved,
                                keep_my_livery_locally=config.keep_my_livery_locally,
                                preserve_targets=session.local_preserve_targets(),
                                reason=f"Session changed or ended while processing {session.session_id.folder_name()}. Removing partially saved paints",
                                paints_root=paints_dir,
                                fallback_member_id=last_known_member_id,
                                fallback_team_id=last_known_team_id,
                            )
                        self._update_monitor_snapshot(monitor_snapshot)
                        if sdk_reader is not None:
                            logging.debug("Closing SDK after session cancellation so the next poll starts fresh")
                            close_sdk_reader(sdk_reader)
                            sdk_reader = None
                            next_sdk_open_at = time.monotonic() + max(config.poll_seconds, 0.5)
                        current_session = None
                        last_processed_session = None
                        last_session_fingerprint = None
                        session_rows = []
                        self._update_runtime_snapshot(None, last_saved, last_known_member_id, session_rows=[], replay_mode_active=False)
                        self._set_status("Watching")
                        self._stop_event.wait(max(config.poll_seconds, 0.2))
                        continue
                    if roster_changed_same_session:
                        last_saved = merge_saved_files(last_saved, processed_saved)
                        session_rows = merge_session_driver_rows(session, previous_rows, processed_rows)
                    else:
                        last_saved = processed_saved
                        session_rows = processed_rows
                self._update_monitor_snapshot(monitor_snapshot)
                last_session = session.session_id
                last_processed_session = session
                last_session_fingerprint = current_fingerprint
                last_session_preserve_targets = _merge_preserve_targets(
                    session.local_preserve_targets(),
                    fallback_member_id=last_known_member_id,
                    fallback_team_id=last_known_team_id,
                )
                self._update_runtime_snapshot(current_session, last_saved, last_known_member_id, session_rows=session_rows, replay_mode_active=replay_mode_active)
                if self._drain_pending_driver_override_applies(current_session, paints_dir, sdk_reader):
                    runtime_snapshot = self.get_runtime_snapshot()
                    last_saved = list(runtime_snapshot.last_saved)
                    session_rows = list(runtime_snapshot.session_rows)
                self._set_status(f"Watching • {session.session_id.folder_name()}")
                self._stop_event.wait(max(config.poll_seconds, 0.2))
        finally:
            final_config = self.get_config()
            if last_saved and final_config.delete_downloaded_livery:
                self._cleanup_saved(
                    saved=last_saved,
                    keep_my_livery_locally=final_config.keep_my_livery_locally,
                    preserve_targets=last_session_preserve_targets,
                    reason="Cleaning up session paints before exit",
                    paints_root=paints_dir,
                )
            self._update_runtime_snapshot(None, last_saved if "last_saved" in locals() else [], last_known_member_id if "last_known_member_id" in locals() else None, session_rows=[])
            close_sdk_reader(sdk_reader)
            self._set_status("Stopped")
class WindowsTrayIcon:
    def __init__(self, on_restore: Callable[[], None], on_exit: Callable[[], None] | None = None) -> None:
        self.on_restore = on_restore
        self.on_exit = on_exit
        self._thread: threading.Thread | None = None
        self._ready = threading.Event()
        self._visible = False
        self._started = False
        self._hwnd = None
        self._wndproc = None
        self._class_name = f"NishizumiPaintsTrayWindow_{id(self)}"
        self._tooltip = APP_TOOLTIP
        self._stop_requested = False
        self._icon_handle = None
        self._ctypes = None
        self._NOTIFYICONDATAW = None
        self._shell32 = None
        self._user32 = None
    def is_supported(self) -> bool:
        return sys.platform == "win32"
    def start(self) -> bool:
        if not self.is_supported():
            return False
        if self._thread is not None:
            return self._started
        self._thread = threading.Thread(target=self._message_loop, name="NishizumiPaintsTray", daemon=True)
        self._thread.start()
        self._ready.wait(timeout=2.0)
        return self._started
    def show(self, tooltip: str = APP_TOOLTIP) -> bool:
        self._tooltip = tooltip[:120]
        if not self.start():
            return False
        if self._visible:
            return True
        return self._add_icon()
    def hide(self) -> None:
        if self._started and self._visible:
            self._notify_icon(self._nim_delete())
            self._visible = False
    def stop(self) -> None:
        self.hide()
        if self._started and self._hwnd is not None:
            self._post_close()
        thread = self._thread
        if thread is not None and thread.is_alive():
            thread.join(timeout=2.0)
        self._thread = None
        self._started = False
    def _message_loop(self) -> None:
        import ctypes
        from ctypes import wintypes
        user32 = ctypes.windll.user32
        kernel32 = ctypes.windll.kernel32
        POINT = wintypes.POINT
        MF_STRING = 0x00000000
        TPM_LEFTALIGN = 0x0000
        TPM_BOTTOMALIGN = 0x0020
        TPM_RIGHTBUTTON = 0x0002
        TPM_RETURNCMD = 0x0100
        WM_DESTROY = 0x0002
        WM_CLOSE = 0x0010
        WM_APP = 0x8000
        self._wm_trayicon = WM_APP + 1
        self._wm_lbuttondblclk = 0x0203
        self._wm_rbuttonup = 0x0205
        self._menu_open_id = 1001
        self._menu_exit_id = 1002
        class GUID(ctypes.Structure):
            _fields_ = [
                ("Data1", wintypes.DWORD),
                ("Data2", wintypes.WORD),
                ("Data3", wintypes.WORD),
                ("Data4", ctypes.c_ubyte * 8),
            ]
        class NOTIFYICONDATAW(ctypes.Structure):
            _fields_ = [
                ("cbSize", wintypes.DWORD),
                ("hWnd", wintypes.HWND),
                ("uID", wintypes.UINT),
                ("uFlags", wintypes.UINT),
                ("uCallbackMessage", wintypes.UINT),
                ("hIcon", wintypes.HANDLE),
                ("szTip", wintypes.WCHAR * 128),
                ("dwState", wintypes.DWORD),
                ("dwStateMask", wintypes.DWORD),
                ("szInfo", wintypes.WCHAR * 256),
                ("uTimeoutOrVersion", wintypes.UINT),
                ("szInfoTitle", wintypes.WCHAR * 64),
                ("dwInfoFlags", wintypes.DWORD),
                ("guidItem", GUID),
                ("hBalloonIcon", wintypes.HANDLE),
            ]
        self._ctypes = ctypes
        self._NOTIFYICONDATAW = NOTIFYICONDATAW
        self._shell32 = ctypes.windll.shell32
        self._user32 = user32
        self._WM_CLOSE = WM_CLOSE
        self._POINT = POINT
        LPARAM_T = ctypes.c_ssize_t
        LRESULT_T = ctypes.c_ssize_t
        user32.DefWindowProcW.argtypes = [wintypes.HWND, wintypes.UINT, wintypes.WPARAM, LPARAM_T]
        user32.DefWindowProcW.restype = LRESULT_T
        def show_context_menu(hwnd) -> int:
            menu = user32.CreatePopupMenu()
            if not menu:
                return 0
            try:
                user32.AppendMenuW(menu, MF_STRING, self._menu_open_id, "Open app")
                user32.AppendMenuW(menu, MF_STRING, self._menu_exit_id, "Exit")
                pt = POINT()
                user32.GetCursorPos(ctypes.byref(pt))
                user32.SetForegroundWindow(hwnd)
                command = user32.TrackPopupMenu(
                    menu,
                    TPM_LEFTALIGN | TPM_BOTTOMALIGN | TPM_RIGHTBUTTON | TPM_RETURNCMD,
                    pt.x,
                    pt.y,
                    0,
                    hwnd,
                    None,
                )
                if command == self._menu_open_id:
                    try:
                        self.on_restore()
                    except Exception:
                        pass
                elif command == self._menu_exit_id and self.on_exit is not None:
                    try:
                        self.on_exit()
                    except Exception:
                        pass
                user32.PostMessageW(hwnd, 0, 0, 0)
                return int(command or 0)
            finally:
                user32.DestroyMenu(menu)
        WNDPROCTYPE = ctypes.WINFUNCTYPE(LRESULT_T, wintypes.HWND, wintypes.UINT, wintypes.WPARAM, LPARAM_T)
        def wndproc(hwnd, msg, wparam, lparam):
            if msg == self._wm_trayicon and lparam == self._wm_lbuttondblclk:
                try:
                    self.on_restore()
                except Exception:
                    pass
                return 0
            if msg == self._wm_trayicon and lparam == self._wm_rbuttonup:
                show_context_menu(hwnd)
                return 0
            if msg == WM_CLOSE:
                user32.DestroyWindow(hwnd)
                return 0
            if msg == WM_DESTROY:
                self.hide()
                user32.PostQuitMessage(0)
                return 0
            return user32.DefWindowProcW(hwnd, msg, wparam, lparam)
        self._wndproc = WNDPROCTYPE(wndproc)
        class WNDCLASSW(ctypes.Structure):
            _fields_ = [
                ("style", wintypes.UINT),
                ("lpfnWndProc", WNDPROCTYPE),
                ("cbClsExtra", ctypes.c_int),
                ("cbWndExtra", ctypes.c_int),
                ("hInstance", wintypes.HINSTANCE),
                ("hIcon", wintypes.HANDLE),
                ("hCursor", wintypes.HANDLE),
                ("hbrBackground", wintypes.HANDLE),
                ("lpszMenuName", wintypes.LPCWSTR),
                ("lpszClassName", wintypes.LPCWSTR),
            ]
        hinstance = kernel32.GetModuleHandleW(None)
        wndclass = WNDCLASSW()
        wndclass.lpfnWndProc = self._wndproc
        wndclass.lpszClassName = self._class_name
        wndclass.hInstance = hinstance
        atom = user32.RegisterClassW(ctypes.byref(wndclass))
        if not atom and ctypes.GetLastError() != 1410:
            self._ready.set()
            return
        hwnd = user32.CreateWindowExW(
            0,
            self._class_name,
            self._class_name,
            0,
            0,
            0,
            0,
            0,
            0,
            0,
            hinstance,
            0,
        )
        if not hwnd:
            self._ready.set()
            return
        self._hwnd = hwnd
        self._started = True
        self._ready.set()
        msg = wintypes.MSG()
        while user32.GetMessageW(ctypes.byref(msg), 0, 0, 0) != 0:
            user32.TranslateMessage(ctypes.byref(msg))
            user32.DispatchMessageW(ctypes.byref(msg))
        try:
            user32.UnregisterClassW(self._class_name, hinstance)
        except Exception:
            pass
    def _make_nid(self):
        nid = self._NOTIFYICONDATAW()
        nid.cbSize = self._ctypes.sizeof(self._NOTIFYICONDATAW)
        nid.hWnd = self._hwnd
        nid.uID = 1
        nid.uFlags = 0x00000001 | 0x00000002 | 0x00000004
        nid.uCallbackMessage = self._wm_trayicon
        nid.hIcon = self._load_tray_icon()
        nid.szTip = self._tooltip
        return nid
    def _load_tray_icon(self):
        if self._icon_handle is not None:
            return self._icon_handle
        try:
            IMAGE_ICON = 1
            LR_LOADFROMFILE = 0x00000010
            LR_DEFAULTSIZE = 0x00000040
            icon_path = str(resource_path(APP_ICON_ICO_RESOURCE))
            if os.path.exists(icon_path):
                handle = self._user32.LoadImageW(0, icon_path, IMAGE_ICON, 0, 0, LR_LOADFROMFILE | LR_DEFAULTSIZE)
                if handle:
                    self._icon_handle = handle
                    return handle
        except Exception:
            pass
        self._icon_handle = self._user32.LoadIconW(0, 32512)
        return self._icon_handle
    def _notify_icon(self, message: int) -> bool:
        if self._hwnd is None:
            return False
        nid = self._make_nid()
        return bool(self._shell32.Shell_NotifyIconW(message, self._ctypes.byref(nid)))
    @staticmethod
    def _nim_add() -> int:
        return 0x00000000
    @staticmethod
    def _nim_delete() -> int:
        return 0x00000002
    def _add_icon(self) -> bool:
        ok = self._notify_icon(self._nim_add())
        self._visible = ok
        return ok
    def _post_close(self) -> None:
        self._user32.PostMessageW(self._hwnd, self._WM_CLOSE, 0, 0)
class DownloaderUI:
    def __init__(self, launched_from_autostart: bool = False) -> None:
        import tkinter as tk
        from tkinter import filedialog, messagebox, scrolledtext, simpledialog, ttk
        self.tk = tk
        self.ttk = ttk
        self.messagebox = messagebox
        self.filedialog = filedialog
        self.scrolledtext = scrolledtext
