        easy_suits_box.pack(side="left", anchor="n")
        ttk.Checkbutton(
            easy_suits_box,
            text="Real Drivers",
            variable=self.random_suits_real_var,
            command=self.on_setting_changed,
        ).pack(anchor="w")
        ttk.Checkbutton(
            easy_suits_box,
            text="AI",
            variable=self.random_suits_ai_var,
            command=self.on_setting_changed,
        ).pack(anchor="w", pady=(4, 0))

        easy_status = ttk.LabelFrame(easy_top, text="Status", padding=8)
        easy_status.grid(row=0, column=1, sticky="ew")
        easy_status.columnconfigure(0, weight=1)
        ttk.Label(easy_status, textvariable=self.status_var, font=("Segoe UI", 10, "bold"), foreground="#0b63b6").grid(row=0, column=0, sticky="w")
        ttk.Label(easy_status, textvariable=self.session_summary_var, justify="left").grid(row=1, column=0, sticky="w", pady=(4, 0))
        ttk.Label(easy_status, textvariable=self.session_status_summary_var, justify="left", foreground="#555555", wraplength=860).grid(row=2, column=0, sticky="w", pady=(4, 0))
        ttk.Label(easy_status, textvariable=self.update_status_var, justify="left", foreground="#555555").grid(row=3, column=0, sticky="w", pady=(4, 0))

