    def on_tp_manual_max_lanes_changed(self) -> None:
        try:
            value = int(self.tp_manual_max_lanes_var.get())
        except Exception:
            value = max(1, min(100, int(getattr(self.config, "tp_manual_max_lanes", 1) or 1)))
        value = max(1, min(100, value))
        self.tp_manual_max_lanes_var.set(value)
