    def clean_tp_collection_pool_now(self) -> None:
        prompt = (
            "Enter a Trading Paints collection ID or URL to clean only that collection.\n\n"
            "Leave blank to clean the cache for all configured collection pools."
        )
        try:
            response = self.simpledialog.askstring(APP_NAME, prompt, parent=self.root)
        except Exception as exc:
            self._append_log(f"Collection cache cleanup dialog failed: {exc}")
            return
        if response is None:
            return
        collection_ids = parse_tp_collection_ids_from_text(response)
        if response.strip() and not collection_ids:
            self._append_log("Collection cache cleanup skipped: no valid Trading Paints collection ID or URL was entered.")
            return
        target_id = collection_ids[0] if collection_ids else None
        if target_id is None:
            try:
                confirmed = self.messagebox.askyesno(
                    APP_NAME,
                    "You left the collection ID blank.\n\nThis will clean the cache for every Trading Paints collection pool. Do you want to continue?",
                    parent=self.root,
                )
            except Exception as exc:
                self._append_log(f"Collection cache cleanup confirmation failed: {exc}")
                return
            if not confirmed:
                self._append_log("Collection cache cleanup cancelled before clearing all collection caches.")
                return
        try:
            removed_collections, removed_files, freed_bytes = clear_tp_collection_pool_cache(default_tp_collection_pool_dir(), target_id)
            target_label = f"collection {target_id}" if target_id else "all collections"
            self._append_log(
                f"Trading Paints collection cache cleared for {target_label}: removed {removed_collections} collection cache(s), {removed_files} file(s), and freed {freed_bytes / float(1024 ** 3):.2f} GB."
            )
        except Exception as exc:
            self._append_log(f"Trading Paints collection cache cleanup failed: {exc}")
        self._refresh_tp_collection_pool_summary()
