        quick_start_docs_status_label.pack(anchor="w", pady=(10, 0))

        def _refresh_quick_start_docs_status() -> None:
            path_value = normalize_optional_path(quick_start_docs_state.get("path") or "")
            auto_found = bool(quick_start_docs_state.get("auto_found"))
            confirmed = bool(quick_start_docs_state.get("confirmed"))
            if confirmed and path_value:
                quick_start_docs_status_var.set(
                    f"Confirmed. Nishizumi Paints will use this folder: {path_value}"
                )
                quick_start_docs_status_label.configure(foreground="#176d2b")
                quick_start_docs_confirm_button.state(["disabled"])
            elif path_value:
                if auto_found:
                    quick_start_docs_status_var.set(
                        "Automatic search found this iRacing folder. Make sure it is correct, then click 'Use this folder'."
                    )
                    quick_start_docs_status_label.configure(foreground="#0b63b6")
                    quick_start_docs_confirm_button.state(["!disabled"])
                else:
                    quick_start_docs_status_var.set(
                        "Use the selected folder if it is the one that contains paint, replay, and airosters."
                    )
                    quick_start_docs_status_label.configure(foreground="#0b63b6")
                    quick_start_docs_confirm_button.state(["!disabled"])
            else:
                quick_start_docs_status_var.set(
                    "Automatic search did not find the iRacing folder in your Documents location. Choose it manually to continue."
                )
                quick_start_docs_status_label.configure(foreground="#b00020")
                quick_start_docs_confirm_button.state(["disabled"])
                quick_start_docs_var.set("Automatic search did not find the iRacing folder yet.")

        def _confirm_quick_start_docs_path(selected: str, *, auto_found: bool) -> bool:
            normalized_selected = normalize_optional_path(resolve_iracing_documents_dir(selected))
            if not normalized_selected:
                return False
            confirmed = self.messagebox.askyesno(
                APP_NAME,
                f"Use this iRacing Documents folder?\n\n{normalized_selected}\n\nThis folder should contain paint, replay, and airosters.",
                parent=wizard,
            )
            if not confirmed:
                return False
            self._apply_iracing_documents_dir_without_restart(normalized_selected)
            quick_start_docs_state["confirmed"] = True
            quick_start_docs_state["path"] = normalized_selected
            quick_start_docs_state["auto_found"] = bool(auto_found)
            quick_start_docs_var.set(normalized_selected)
            _refresh_quick_start_docs_status()
            if callable(self._quick_start_nav_refresh):
                self._quick_start_nav_refresh()
            return True

        def _choose_quick_start_docs_manually() -> None:
            selected = self._choose_iracing_documents_dir_via_dialog(parent=wizard, initial_dir=quick_start_docs_state.get("path") or self.iracing_documents_dir_var.get())
            if not selected:
                return
            quick_start_docs_state["confirmed"] = False
            quick_start_docs_state["path"] = normalize_optional_path(resolve_iracing_documents_dir(selected))
            quick_start_docs_state["auto_found"] = False
            quick_start_docs_var.set(quick_start_docs_state["path"] or selected)
            _refresh_quick_start_docs_status()
            _confirm_quick_start_docs_path(quick_start_docs_state["path"], auto_found=False)

        quick_start_docs_confirm_button.configure(command=lambda: _confirm_quick_start_docs_path(quick_start_docs_state.get("path") or quick_start_docs_var.get(), auto_found=bool(quick_start_docs_state.get("auto_found"))))
        quick_start_docs_choose_button.configure(command=_choose_quick_start_docs_manually)
        _refresh_quick_start_docs_status()
